  SELECT NULL, 'Solo Lectura', 'Global read-only role', 1, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM dual
  WHERE NOT EXISTS (
    SELECT 1 FROM role r WHERE r.id_property IS NULL AND r.name = 'Solo Lectura' AND r.deleted_at IS NULL
