  SELECT id_role INTO v_owner_role_id FROM role WHERE id_property IS NULL AND name = 'Owner/Admin' AND deleted_at IS NULL ORDER BY id_role DESC LIMIT 1;
  SELECT id_role INTO v_ops_role_id FROM role WHERE id_property IS NULL AND name = 'Operaciones' AND deleted_at IS NULL ORDER BY id_role DESC LIMIT 1;
  SELECT id_role INTO v_front_role_id FROM role WHERE id_property IS NULL AND name = 'Recepcion' AND deleted_at IS NULL ORDER BY id_role DESC LIMIT 1;
  SELECT id_role INTO v_fin_role_id FROM role WHERE id_property IS NULL AND name = 'Finanzas' AND deleted_at IS NULL ORDER BY id_role DESC LIMIT 1;
  SELECT id_role INTO v_ro_role_id FROM role WHERE id_property IS NULL AND name = 'Solo Lectura' AND deleted_at IS NULL ORDER BY id_role DESC LIMIT 1;

  DELETE FROM role_permission
  WHERE id_role IN (v_owner_role_id, v_ops_role_id, v_front_role_id, v_fin_role_id, v_ro_role_id);

  INSERT INTO role_permission (id_role, id_permission, allow, is_active, deleted_at, created_at, created_by, updated_at)
  SELECT v_owner_role_id, p.id_permission, 1, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM permission p
  WHERE p.deleted_at IS NULL AND p.is_active = 1;

  INSERT INTO role_permission (id_role, id_permission, allow, is_active, deleted_at, created_at, created_by, updated_at)
  SELECT v_ops_role_id, p.id_permission, 1, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM permission p
  WHERE p.deleted_at IS NULL
    AND p.is_active = 1
    AND p.code NOT IN (
      'users.view','users.create','users.edit','users.assign_roles','users.assign_properties','users.manage_roles',
      'settings.edit'
    );

  INSERT INTO role_permission (id_role, id_permission, allow, is_active, deleted_at, created_at, created_by, updated_at)
  SELECT v_front_role_id, p.id_permission, 1, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM permission p
  WHERE p.deleted_at IS NULL
    AND p.is_active = 1
    AND p.code IN (
      'dashboard.view','calendar.view','reservations.view','guests.view','messages.view',
      'payments.view','calendar.create_hold','calendar.move_reservation','calendar.register_payment',
      'reservations.create','reservations.edit','reservations.status_change','reservations.manage_folio',
      'reservations.post_charge','reservations.post_payment','reservations.note_edit',
      'guests.create','guests.edit','messages.send','payments.post','payments.edit'
    );

  INSERT INTO role_permission (id_role, id_permission, allow, is_active, deleted_at, created_at, created_by, updated_at)
  SELECT v_fin_role_id, p.id_permission, 1, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM permission p
  WHERE p.deleted_at IS NULL
    AND p.is_active = 1
    AND p.code IN (
      'dashboard.view','calendar.view','reservations.view','payments.view','incomes.view','obligations.view','reports.view',
      'payments.post','payments.edit','incomes.reconcile','obligations.pay','reports.run'
    );

  INSERT INTO role_permission (id_role, id_permission, allow, is_active, deleted_at, created_at, created_by, updated_at)
  SELECT v_ro_role_id, p.id_permission, 1, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM permission p
  WHERE p.deleted_at IS NULL
    AND p.is_active = 1
    AND (p.code LIKE '%.view' OR p.code = 'reports.run');

  INSERT INTO user_property (
    id_user, id_property, is_primary, title, notes, is_active, deleted_at, created_at, created_by, updated_at
  )
  SELECT
    au.id_user, pr.id_property, 0, NULL, NULL, 1, NULL, NOW(), p_actor_user_id, NOW()
  FROM app_user au
  JOIN property pr
    ON pr.id_company = au.id_company
   AND pr.deleted_at IS NULL
   AND pr.is_active = 1
  WHERE au.id_company = v_company_id
    AND au.deleted_at IS NULL
    AND au.is_active = 1
    AND COALESCE(au.is_owner, 0) = 0
    AND NOT EXISTS (
      SELECT 1
      FROM user_property up_any
      JOIN property pr_any ON pr_any.id_property = up_any.id_property
      WHERE up_any.id_user = au.id_user
        AND up_any.deleted_at IS NULL
        AND up_any.is_active = 1
        AND pr_any.id_company = v_company_id
        AND pr_any.deleted_at IS NULL
    )
    AND NOT EXISTS (
      SELECT 1
      FROM user_property up_exists
      WHERE up_exists.id_user = au.id_user
        AND up_exists.id_property = pr.id_property
        AND up_exists.deleted_at IS NULL
    );

  SELECT 'ok' AS status, v_company_id AS id_company, 'seed_complete' AS message;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_accounting_report_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE, IN `p_lodging_ids` TEXT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_accounting_base;
  CREATE TEMPORARY TABLE tmp_accounting_base AS
  SELECT
    li.id_line_item AS id_payment,
    li.id_folio,
    li.id_line_item_catalog AS payment_catalog_id,
    li.amount_cents AS payment_amount_cents,
    li.method AS payment_method,
    COALESCE(NULLIF(payc.item_name, ''), NULLIF(li.method, ''), 'Sin concepto') AS payment_catalog_name,
    COALESCE(li.service_date, DATE(li.created_at)) AS payment_date,
    li.created_at AS payment_created_at,
    r.id_reservation,
    r.code AS reservation_code,
    r.source AS reservation_source,
    r.id_ota_account,
    oa.ota_name,
    oa.external_code AS ota_external_code,
    oa.platform AS ota_platform,
    r.check_in_date,
    r.check_out_date,
    r.nights,
    r.adults,
    r.children,
    r.currency AS reservation_currency,
    g.names AS guest_names,
    g.last_name AS guest_last_name,
    f.currency AS folio_currency,
    p.code AS property_code,
    p.name AS property_name
  FROM line_item li
  JOIN folio f ON f.id_folio = li.id_folio AND f.deleted_at IS NULL
  JOIN reservation r ON r.id_reservation = f.id_reservation AND r.deleted_at IS NULL
  JOIN property p ON p.id_property = r.id_property
  LEFT JOIN line_item_catalog payc
    ON payc.id_line_item_catalog = li.id_line_item_catalog
   AND payc.deleted_at IS NULL
  LEFT JOIN ota_account oa
    ON oa.id_ota_account = r.id_ota_account
   AND oa.deleted_at IS NULL
   AND oa.is_active = 1
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  WHERE li.item_type = 'payment'
    AND li.deleted_at IS NULL
    AND li.is_active = 1
    AND p.id_company = v_company_id
    AND (v_property_id IS NULL OR p.id_property = v_property_id)
    AND (p_from IS NULL OR DATE(li.created_at) >= p_from)
    AND (p_to IS NULL OR DATE(li.created_at) <= p_to);

  SELECT *
  FROM tmp_accounting_base
  ORDER BY payment_created_at DESC, id_payment DESC;

  DROP TEMPORARY TABLE IF EXISTS tmp_accounting_folios;
  CREATE TEMPORARY TABLE tmp_accounting_folios (
    id_folio BIGINT PRIMARY KEY
  );
  INSERT IGNORE INTO tmp_accounting_folios (id_folio)
  SELECT DISTINCT id_folio
  FROM tmp_accounting_base
  WHERE id_folio IS NOT NULL;

  SELECT
    li.id_line_item,
    rel.id_parent_sale_item AS id_parent_sale_item,
    li.id_line_item_catalog AS id_sale_item_catalog,
    li.id_folio,
    li.service_date,
    li.amount_cents
  FROM line_item li
  JOIN tmp_accounting_folios tf ON tf.id_folio = li.id_folio
  LEFT JOIN (
    SELECT
      c.id_line_item AS child_sale_item_id,
      COALESCE(
        MIN(
          CASE
            WHEN COALESCE(c.description,'') = CONCAT(COALESCE(cc.item_name,''), ' / ', COALESCE(pc.item_name,''))
            THEN p.id_line_item
            ELSE NULL
          END
        ),
        MIN(p.id_line_item)
      ) AS id_parent_sale_item
    FROM line_item c
    JOIN tmp_accounting_folios tfc ON tfc.id_folio = c.id_folio
    LEFT JOIN line_item_catalog cc
      ON cc.id_line_item_catalog = c.id_line_item_catalog
    JOIN line_item_catalog_parent lcp
      ON lcp.id_sale_item_catalog = c.id_line_item_catalog
     AND lcp.deleted_at IS NULL
     AND lcp.is_active = 1
    LEFT JOIN line_item_catalog pc
      ON pc.id_line_item_catalog = lcp.id_parent_sale_item_catalog
    JOIN line_item p
      ON p.id_folio = c.id_folio
     AND p.item_type = 'sale_item'
     AND p.id_line_item_catalog = lcp.id_parent_sale_item_catalog
     AND p.deleted_at IS NULL
     AND p.is_active = 1
     AND p.id_line_item <> c.id_line_item
     AND (p.service_date <=> c.service_date)
    WHERE c.item_type = 'sale_item'
      AND c.deleted_at IS NULL
      AND c.is_active = 1
    GROUP BY c.id_line_item
  ) rel ON rel.child_sale_item_id = li.id_line_item
  WHERE li.item_type = 'sale_item'
    AND li.deleted_at IS NULL
    AND li.is_active = 1;

  DROP TEMPORARY TABLE IF EXISTS tmp_accounting_sale_items;
  CREATE TEMPORARY TABLE tmp_accounting_sale_items (
    id_sale_item BIGINT PRIMARY KEY
  );
  INSERT IGNORE INTO tmp_accounting_sale_items (id_sale_item)
  SELECT id_line_item
  FROM line_item li
  JOIN tmp_accounting_folios tf ON tf.id_folio = li.id_folio
  WHERE li.item_type = 'sale_item'
    AND li.deleted_at IS NULL
    AND li.is_active = 1;

  SELECT
    MIN(ti.id_line_item) AS id_line_item,
    s.id_line_item AS id_sale_item,
    tr.id_line_item_catalog AS id_tax_rule,
    COALESCE(SUM(ti.amount_cents),0) AS amount_cents
  FROM line_item s
  JOIN tmp_accounting_sale_items ts ON ts.id_sale_item = s.id_line_item
  JOIN line_item_catalog_parent lcp
    ON lcp.id_parent_sale_item_catalog = s.id_line_item_catalog
   AND lcp.deleted_at IS NULL
   AND lcp.is_active = 1
  JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = lcp.id_sale_item_catalog
   AND tr.catalog_type = 'tax_rule'
  LEFT JOIN line_item ti
    ON ti.id_folio = s.id_folio
   AND ti.item_type = 'tax_item'
   AND ti.id_line_item_catalog = tr.id_line_item_catalog
   AND ti.deleted_at IS NULL
   AND ti.is_active = 1
   AND (ti.service_date <=> s.service_date)
  WHERE s.item_type = 'sale_item'
    AND s.deleted_at IS NULL
    AND s.is_active = 1
  GROUP BY s.id_line_item, tr.id_line_item_catalog;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_activity_book` (IN `p_company_id` BIGINT, IN `p_activity_id` BIGINT, IN `p_reservation_id` BIGINT, IN `p_scheduled_at` DATETIME, IN `p_num_adults` INT, IN `p_num_children` INT, IN `p_price_cents` INT, IN `p_currency` VARCHAR(10), IN `p_status` VARCHAR(32))   proc:BEGIN
  DECLARE v_activity BIGINT;
  DECLARE v_reservation BIGINT;
  DECLARE v_price INT;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_created_by BIGINT;

  IF p_company_id IS NULL OR p_company_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company id is required';
  END IF;
  IF p_activity_id IS NULL OR p_activity_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Activity id is required';
  END IF;
  IF p_reservation_id IS NULL OR p_reservation_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
  END IF;
  IF p_scheduled_at IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Scheduled date is required';
  END IF;

  SELECT id_activity, base_price_cents, currency
    INTO v_activity, v_price, v_currency
  FROM activity
  WHERE id_activity = p_activity_id
    AND id_company = p_company_id
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_activity IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown activity';
  END IF;

  SELECT r.id_reservation
    INTO v_reservation
  FROM reservation r
  JOIN property p ON p.id_property = r.id_property
  WHERE r.id_reservation = p_reservation_id
    AND p.id_company = p_company_id
    AND r.deleted_at IS NULL
  LIMIT 1;

  IF v_reservation IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown reservation for company';
  END IF;

  SET v_price = COALESCE(p_price_cents, v_price, 0);
  SET v_currency = COALESCE(NULLIF(p_currency, ''), v_currency, 'MXN');
  SELECT MIN(u.id_user)
    INTO v_created_by
  FROM app_user u
  WHERE u.id_company = p_company_id
    AND u.deleted_at IS NULL;

  INSERT INTO activity_booking
    (id_activity, id_reservation, scheduled_at, status, num_adults, num_children, price_cents, currency, created_by, created_at, updated_at)
  VALUES
    (v_activity, v_reservation, p_scheduled_at, COALESCE(NULLIF(p_status, ''), 'confirmed'),
     COALESCE(p_num_adults, 0), COALESCE(p_num_children, 0), v_price, v_currency, v_created_by, NOW(), NOW());

  INSERT INTO activity_booking_reservation
    (id_booking, id_reservation, is_active, deleted_at, created_at, created_by, updated_at)
  VALUES
    (LAST_INSERT_ID(), v_reservation, 1, NULL, NOW(), NULL, NOW())
  ON DUPLICATE KEY UPDATE
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  SELECT
    b.id_booking,
    b.scheduled_at,
    b.status,
    b.num_adults,
    b.num_children,
    b.price_cents,
    b.currency,
    a.code AS activity_code,
    a.name AS activity_name,
    r.code AS reservation_code
  FROM activity_booking b
  JOIN activity a ON a.id_activity = b.id_activity
  JOIN reservation r ON r.id_reservation = b.id_reservation
  WHERE b.id_booking = LAST_INSERT_ID();
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_activity_bookings_list` (IN `p_type` VARCHAR(10), IN `p_company_id` BIGINT, IN `p_company_code` VARCHAR(32), IN `p_property_id` BIGINT, IN `p_property_code` VARCHAR(32), IN `p_activity_id` BIGINT, IN `p_activity_code` VARCHAR(32), IN `p_from` DATETIME, IN `p_to` DATETIME, IN `p_booking_id` BIGINT)   BEGIN
  DECLARE v_company BIGINT;
  DECLARE v_property BIGINT;
  DECLARE v_activity BIGINT;

  -- Company
  IF p_company_id IS NOT NULL AND p_company_id <> 0 THEN
    SET v_company = p_company_id;
  ELSEIF p_company_code IS NOT NULL AND p_company_code <> '' THEN
    SELECT id_company INTO v_company FROM company WHERE code = p_company_code LIMIT 1;
  END IF;

  -- Property
  IF p_property_id IS NOT NULL AND p_property_id <> 0 THEN
    SET v_property = p_property_id;
  ELSEIF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property FROM property WHERE code = p_property_code LIMIT 1;
  END IF;

  -- Activity
  IF p_activity_id IS NOT NULL AND p_activity_id <> 0 THEN
    SET v_activity = p_activity_id;
  ELSEIF p_activity_code IS NOT NULL AND p_activity_code <> '' THEN
    SELECT id_activity INTO v_activity FROM activity WHERE code = p_activity_code LIMIT 1;
  END IF;

  SELECT
    b.id_booking,
    b.id_activity,
    a.type            AS activity_type,
    a.code            AS activity_code,
    a.name            AS activity_name,
    p.name            AS property_name,
    c.code            AS company_code,
    b.scheduled_at,
    (b.num_adults + b.num_children) AS pax,
    b.status,
    b.price_cents,
    b.currency,
    b.num_adults,
    b.num_children,
    b.notes,
    COALESCE(br.linked_count, CASE WHEN b.id_reservation IS NULL THEN 0 ELSE 1 END) AS linked_reservation_count,
    COALESCE(br.linked_ids_csv, CASE WHEN b.id_reservation IS NULL THEN '' ELSE CAST(b.id_reservation AS CHAR) END) AS linked_reservation_ids_csv,
    COALESCE(br.linked_codes, COALESCE(r_primary.code, '')) AS linked_reservation_codes,
    COALESCE(br.linked_guest_names, NULLIF(TRIM(CONCAT_WS(' ', COALESCE(g_primary.names, ''), COALESCE(g_primary.last_name, ''))), '')) AS linked_guest_names,
    COALESCE(br.first_reservation_id, b.id_reservation) AS id_reservation,
    COALESCE(r_first.code, r_primary.code) AS reservation_code,
    COALESCE(g_first.names, g_primary.names) AS guest_names,
    COALESCE(g_first.last_name, g_primary.last_name) AS guest_last_name,
    COALESCE(g_first.email, g_primary.email) AS guest_email,
    b.id_reservation AS id_primary_reservation,
    r_primary.code   AS primary_reservation_code
  FROM activity_booking b
  JOIN activity a ON a.id_activity = b.id_activity
  JOIN company  c ON c.id_company   = a.id_company
  LEFT JOIN property p ON p.id_property = a.id_property
  LEFT JOIN reservation r_primary ON r_primary.id_reservation = b.id_reservation
  LEFT JOIN guest g_primary ON g_primary.id_guest = r_primary.id_guest
  LEFT JOIN (
    SELECT
      x.id_booking,
      COUNT(DISTINCT x.id_reservation) AS linked_count,
      MIN(x.id_reservation) AS first_reservation_id,
      GROUP_CONCAT(DISTINCT CAST(x.id_reservation AS CHAR) ORDER BY x.id_reservation SEPARATOR ',') AS linked_ids_csv,
      GROUP_CONCAT(DISTINCT COALESCE(r.code, '') ORDER BY r.code SEPARATOR ' | ') AS linked_codes,
      GROUP_CONCAT(
        DISTINCT NULLIF(TRIM(CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, ''))), '')
        ORDER BY r.code
        SEPARATOR ' | '
      ) AS linked_guest_names
    FROM (
      SELECT abr.id_booking, abr.id_reservation
      FROM activity_booking_reservation abr
      WHERE abr.deleted_at IS NULL
        AND COALESCE(abr.is_active, 1) = 1

      UNION ALL

      SELECT b2.id_booking, b2.id_reservation
      FROM activity_booking b2
      WHERE b2.id_reservation IS NOT NULL
        AND NOT EXISTS (
          SELECT 1
          FROM activity_booking_reservation abr2
          WHERE abr2.id_booking = b2.id_booking
            AND abr2.deleted_at IS NULL
            AND COALESCE(abr2.is_active, 1) = 1
        )
    ) x
    JOIN reservation r
      ON r.id_reservation = x.id_reservation
     AND r.deleted_at IS NULL
    LEFT JOIN guest g ON g.id_guest = r.id_guest
    GROUP BY x.id_booking
  ) br ON br.id_booking = b.id_booking
  LEFT JOIN reservation r_first ON r_first.id_reservation = br.first_reservation_id
  LEFT JOIN guest g_first ON g_first.id_guest = r_first.id_guest
  WHERE (p_type IS NULL OR a.type = p_type)
    AND (v_company IS NULL OR a.id_company = v_company)
    AND (v_property IS NULL OR a.id_property = v_property)
    AND (v_activity IS NULL OR a.id_activity = v_activity)
    AND (p_booking_id IS NULL OR p_booking_id = 0 OR b.id_booking = p_booking_id)
    AND (p_from IS NULL OR b.scheduled_at >= p_from)
    AND (p_to   IS NULL OR b.scheduled_at <  p_to)
    AND (b.deleted_at IS NULL)
  ORDER BY b.scheduled_at, a.name, b.id_booking;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_activity_booking_upsert` (IN `p_company_id` BIGINT, IN `p_booking_id` BIGINT, IN `p_activity_id` BIGINT, IN `p_reservation_ids_csv` TEXT, IN `p_scheduled_at` DATETIME, IN `p_num_adults` INT, IN `p_num_children` INT, IN `p_price_cents` INT, IN `p_currency` VARCHAR(10), IN `p_status` VARCHAR(32), IN `p_notes` TEXT, IN `p_user_id` BIGINT, IN `p_action` VARCHAR(16))   proc:BEGIN
  DECLARE v_action VARCHAR(16);
  DECLARE v_booking BIGINT;
  DECLARE v_activity BIGINT;
  DECLARE v_price INT;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_status VARCHAR(32);
  DECLARE v_user BIGINT;
  DECLARE v_primary_reservation BIGINT;
  DECLARE v_valid_res_count INT DEFAULT 0;
  DECLARE v_csv LONGTEXT;
  DECLARE v_token VARCHAR(64);
  DECLARE v_pos INT;

  IF p_company_id IS NULL OR p_company_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company id is required';
  END IF;

  SET v_action = LOWER(COALESCE(NULLIF(TRIM(p_action), ''), 'save'));
  IF v_action NOT IN ('save', 'cancel', 'delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported activity booking action';
  END IF;

  SET v_user = NULLIF(p_user_id, 0);
  IF v_user IS NULL THEN
    SELECT MIN(u.id_user)
      INTO v_user
    FROM app_user u
    WHERE u.id_company = p_company_id
      AND u.deleted_at IS NULL;
  END IF;

  IF p_booking_id IS NOT NULL AND p_booking_id > 0 THEN
    SELECT b.id_booking
      INTO v_booking
    FROM activity_booking b
    JOIN activity a
      ON a.id_activity = b.id_activity
    WHERE b.id_booking = p_booking_id
      AND b.deleted_at IS NULL
      AND a.id_company = p_company_id
      AND a.deleted_at IS NULL
    LIMIT 1;
  ELSE
    SET v_booking = NULL;
  END IF;

  IF v_action IN ('cancel', 'delete') AND v_booking IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Booking not found for company';
  END IF;

  IF v_action = 'delete' THEN
    UPDATE activity_booking
       SET deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_booking = v_booking;

    UPDATE activity_booking_reservation
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_booking = v_booking
       AND deleted_at IS NULL;

    SELECT
      v_booking AS id_booking,
      'deleted' AS action,
      'ok' AS status;
    LEAVE proc;
  END IF;

  IF v_action = 'cancel' THEN
    UPDATE activity_booking
       SET status = 'cancelled',
           notes = TRIM(CONCAT_WS(' | ', NULLIF(notes, ''), NULLIF(TRIM(p_notes), ''))),
           updated_at = NOW()
     WHERE id_booking = v_booking;

    SELECT
      b.id_booking,
      b.status,
      b.scheduled_at,
      b.num_adults,
      b.num_children,
      b.price_cents,
      b.currency
    FROM activity_booking b
    WHERE b.id_booking = v_booking
    LIMIT 1;
    LEAVE proc;
  END IF;

  IF p_activity_id IS NULL OR p_activity_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Activity id is required';
  END IF;
  IF p_scheduled_at IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Scheduled date is required';
  END IF;

  SELECT a.id_activity, a.base_price_cents, a.currency
    INTO v_activity, v_price, v_currency
  FROM activity a
  WHERE a.id_activity = p_activity_id
    AND a.id_company = p_company_id
    AND a.deleted_at IS NULL
  LIMIT 1;

  IF v_activity IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown activity for company';
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_activity_booking_res_ids;
  CREATE TEMPORARY TABLE tmp_activity_booking_res_ids (
    seq INT NOT NULL AUTO_INCREMENT,
    id_reservation BIGINT NOT NULL,
    PRIMARY KEY (seq),
    UNIQUE KEY uk_tmp_activity_booking_res (id_reservation)
  ) ENGINE = MEMORY;

  SET v_csv = COALESCE(p_reservation_ids_csv, '');
  SET v_csv = REPLACE(v_csv, ';', ',');
  SET v_csv = REPLACE(v_csv, '|', ',');
  SET v_csv = REPLACE(v_csv, ' ', '');

  csv_loop: WHILE v_csv <> '' DO
    SET v_pos = LOCATE(',', v_csv);
    IF v_pos = 0 THEN
      SET v_token = v_csv;
      SET v_csv = '';
    ELSE
      SET v_token = SUBSTRING(v_csv, 1, v_pos - 1);
      SET v_csv = SUBSTRING(v_csv, v_pos + 1);
    END IF;

    IF v_token IS NOT NULL AND v_token <> '' AND v_token REGEXP '^[0-9]+$' THEN
      INSERT IGNORE INTO tmp_activity_booking_res_ids (id_reservation)
      VALUES (CAST(v_token AS UNSIGNED));
    END IF;
  END WHILE csv_loop;

  DELETE t
  FROM tmp_activity_booking_res_ids t
  LEFT JOIN reservation r
    ON r.id_reservation = t.id_reservation
   AND r.deleted_at IS NULL
  LEFT JOIN property pr
    ON pr.id_property = r.id_property
  WHERE r.id_reservation IS NULL
     OR pr.id_company <> p_company_id
     OR pr.deleted_at IS NOT NULL;

  SELECT COUNT(*)
    INTO v_valid_res_count
  FROM tmp_activity_booking_res_ids;

  IF v_valid_res_count = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'At least one valid reservation is required';
  END IF;

  SELECT t.id_reservation
    INTO v_primary_reservation
  FROM tmp_activity_booking_res_ids t
  ORDER BY t.seq
  LIMIT 1;

  SET v_price = COALESCE(p_price_cents, v_price, 0);
  SET v_currency = COALESCE(NULLIF(TRIM(p_currency), ''), v_currency, 'MXN');
  SET v_status = COALESCE(NULLIF(TRIM(p_status), ''), 'confirmed');

  IF v_booking IS NULL THEN
    INSERT INTO activity_booking
      (id_activity, id_reservation, scheduled_at, status, num_adults, num_children, price_cents, currency, notes, created_by, created_at, updated_at)
    VALUES
      (v_activity, v_primary_reservation, p_scheduled_at, v_status, COALESCE(p_num_adults, 0), COALESCE(p_num_children, 0), v_price, v_currency, NULLIF(p_notes, ''), v_user, NOW(), NOW());
    SET v_booking = LAST_INSERT_ID();
  ELSE
    UPDATE activity_booking
       SET id_activity = v_activity,
           id_reservation = v_primary_reservation,
           scheduled_at = p_scheduled_at,
           status = v_status,
           num_adults = COALESCE(p_num_adults, num_adults),
           num_children = COALESCE(p_num_children, num_children),
           price_cents = v_price,
           currency = v_currency,
           notes = NULLIF(p_notes, ''),
           updated_at = NOW()
     WHERE id_booking = v_booking;
  END IF;

  UPDATE activity_booking_reservation abr
  LEFT JOIN tmp_activity_booking_res_ids t
    ON t.id_reservation = abr.id_reservation
  SET abr.is_active = 0,
      abr.deleted_at = NOW(),
      abr.updated_at = NOW()
  WHERE abr.id_booking = v_booking
    AND abr.deleted_at IS NULL
    AND COALESCE(abr.is_active, 1) = 1
    AND t.id_reservation IS NULL;

  INSERT INTO activity_booking_reservation
    (id_booking, id_reservation, is_active, deleted_at, created_at, created_by, updated_at)
  SELECT
    v_booking,
    t.id_reservation,
    1,
    NULL,
    NOW(),
    v_user,
    NOW()
  FROM tmp_activity_booking_res_ids t
  ON DUPLICATE KEY UPDATE
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  SELECT
    b.id_booking,
    b.id_activity,
    b.id_reservation,
    b.scheduled_at,
    b.status,
    b.num_adults,
    b.num_children,
    b.price_cents,
    b.currency,
    b.notes,
    COALESCE(linked.linked_reservation_count, 0) AS linked_reservation_count,
    COALESCE(linked.linked_reservation_ids_csv, '') AS linked_reservation_ids_csv
  FROM activity_booking b
  LEFT JOIN (
    SELECT
      abr.id_booking,
      COUNT(*) AS linked_reservation_count,
      GROUP_CONCAT(CAST(abr.id_reservation AS CHAR) ORDER BY abr.id_reservation SEPARATOR ',') AS linked_reservation_ids_csv
    FROM activity_booking_reservation abr
    WHERE abr.deleted_at IS NULL
      AND COALESCE(abr.is_active, 1) = 1
    GROUP BY abr.id_booking
  ) linked ON linked.id_booking = b.id_booking
  WHERE b.id_booking = v_booking
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_activity_cancel` (IN `p_booking_id` BIGINT, IN `p_note` TEXT)   proc:BEGIN
  DECLARE v_exists BIGINT;
  SELECT id_booking INTO v_exists FROM activity_booking WHERE id_booking = p_booking_id LIMIT 1;
  IF v_exists IS NULL THEN
    SELECT 'ERROR' AS status, 'Unknown booking id' AS message; LEAVE proc;
  END IF;

  UPDATE activity_booking
     SET status='cancelled',
         notes = CONCAT(COALESCE(notes,''), CASE WHEN p_note IS NULL OR p_note='' THEN '' ELSE CONCAT(' | ', p_note) END),
         updated_at = NOW()
   WHERE id_booking = p_booking_id;

  SELECT
    b.id_booking, b.status, b.scheduled_at, b.price_cents, b.currency,
    a.type AS activity_type, a.code AS activity_code, a.name AS activity_name,
    g.names AS guest_names, g.last_name AS guest_last_name, g.email AS guest_email
  FROM activity_booking b
  JOIN activity a ON a.id_activity=b.id_activity
  LEFT JOIN (
    SELECT
      abr.id_booking,
      MIN(abr.id_reservation) AS id_reservation
    FROM activity_booking_reservation abr
    WHERE abr.deleted_at IS NULL
      AND COALESCE(abr.is_active, 1) = 1
    GROUP BY abr.id_booking
  ) abr0 ON abr0.id_booking = b.id_booking
  JOIN reservation r
    ON r.id_reservation = COALESCE(abr0.id_reservation, b.id_reservation)
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  WHERE b.id_booking = p_booking_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_activity_upsert` (IN `p_id_company` BIGINT, IN `p_id_property` BIGINT, IN `p_code` VARCHAR(32), IN `p_name` VARCHAR(120), IN `p_type` VARCHAR(10), IN `p_description` TEXT, IN `p_duration_minutes` INT, IN `p_base_price_cents` INT, IN `p_id_sale_item_catalog` BIGINT, IN `p_currency` VARCHAR(10), IN `p_capacity_default` INT, IN `p_location` VARCHAR(255), IN `p_is_active` TINYINT)   proc:BEGIN
  DECLARE v_id_activity BIGINT;
  DECLARE v_sale_item_catalog BIGINT;

  IF p_type NOT IN ('tour','vibe') THEN
    SELECT 'ERROR' AS status, 'type must be tour or vibe' AS message; LEAVE proc;
  END IF;

  IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog <> 0 THEN
    SELECT sic.id_line_item_catalog
      INTO v_sale_item_catalog
    FROM line_item_catalog sic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = sic.id_category
    WHERE sic.id_line_item_catalog = p_id_sale_item_catalog
      AND sic.catalog_type = 'sale_item'
      AND sic.deleted_at IS NULL
      AND sic.is_active = 1
      AND cat.id_company = p_id_company
      AND cat.deleted_at IS NULL
    LIMIT 1;

    IF v_sale_item_catalog IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown sale item catalog for company';
    END IF;
  ELSE
    SET v_sale_item_catalog = NULL;
  END IF;

  SELECT id_activity INTO v_id_activity
  FROM activity
  WHERE code = p_code
    AND id_company = p_id_company
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_activity IS NULL THEN
    INSERT INTO activity
    (id_company, id_property, id_sale_item_catalog, code, name, type, description, duration_minutes,
     base_price_cents, currency, capacity_default, location, is_active, created_at, updated_at)
    VALUES
    (p_id_company, NULLIF(p_id_property,0), v_sale_item_catalog, p_code, p_name, p_type, p_description, p_duration_minutes,
     COALESCE(p_base_price_cents,0), COALESCE(p_currency,'MXN'), p_capacity_default, p_location,
     COALESCE(p_is_active,1), NOW(), NOW());
    SET v_id_activity = LAST_INSERT_ID();
  ELSE
    UPDATE activity
      SET id_company = p_id_company,
          id_property = NULLIF(p_id_property,0),
          id_sale_item_catalog = v_sale_item_catalog,
          name = p_name,
          type = p_type,
          description = p_description,
          duration_minutes = p_duration_minutes,
          base_price_cents = COALESCE(p_base_price_cents, base_price_cents),
          currency = COALESCE(p_currency, currency),
          capacity_default = p_capacity_default,
          location = p_location,
          is_active = COALESCE(p_is_active, is_active),
          updated_at = NOW()
    WHERE id_activity = v_id_activity;
  END IF;

  SELECT a.*,
         c.code AS company_code, c.legal_name AS company_name,
         p.code AS property_code, p.name AS property_name
  FROM activity a
  JOIN company  c ON c.id_company  = a.id_company
  LEFT JOIN property p ON p.id_property = a.id_property
  WHERE a.id_activity = v_id_activity;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_app_user_upsert` (IN `p_company_code` VARCHAR(100), IN `p_id_user` BIGINT, IN `p_email` VARCHAR(255), IN `p_password` VARCHAR(255), IN `p_names` VARCHAR(255), IN `p_last_name` VARCHAR(255), IN `p_maiden_name` VARCHAR(255), IN `p_phone` VARCHAR(100), IN `p_locale` VARCHAR(20), IN `p_timezone` VARCHAR(64), IN `p_is_owner` TINYINT, IN `p_is_active` TINYINT, IN `p_display_name` VARCHAR(255), IN `p_notes` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_existing_id BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();
  DECLARE v_full_name VARCHAR(600);

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_email IS NULL OR p_email = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Email is required';
  END IF;
  IF p_names IS NULL OR p_names = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Names are required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  CALL sp_authz_assert(
    p_company_code,
    p_actor_user_id,
    'users.edit',
    NULL,
    NULL
  );

  /* Check for conflicting email inside the company */
  SELECT id_user
    INTO v_existing_id
  FROM app_user
  WHERE email = p_email
    AND id_company = v_company_id
    AND deleted_at IS NULL
    AND (p_id_user IS NULL OR p_id_user = 0 OR id_user <> p_id_user)
  LIMIT 1;

  IF v_existing_id IS NOT NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Email already in use for this company';
  END IF;

  SET v_full_name = TRIM(CONCAT(
    COALESCE(NULLIF(p_names, ''), ''),
    ' ',
    COALESCE(NULLIF(p_last_name, ''), ''),
    ' ',
    COALESCE(NULLIF(p_maiden_name, ''), '')
  ));

  IF p_id_user IS NULL OR p_id_user = 0 THEN
    INSERT INTO app_user (
      id_company,
      id_reg,
      email,
      password_hash,
      phone,
      names,
      last_name,
      maiden_name,
      full_name,
      display_name,
      locale,
      timezone,
      is_owner,
      is_active,
      notes,
      created_at,
      updated_at
    ) VALUES (
      v_company_id,
      COALESCE(NULLIF(p_actor_user_id, 0), NULL),
      p_email,
      NULLIF(p_password, ''),
      NULLIF(p_phone, ''),
      p_names,
      NULLIF(p_last_name, ''),
      NULLIF(p_maiden_name, ''),
      NULLIF(v_full_name, ''),
      COALESCE(NULLIF(p_display_name, ''), NULLIF(v_full_name, ''), p_email),
      COALESCE(NULLIF(p_locale, ''), 'es-MX'),
      COALESCE(NULLIF(p_timezone, ''), 'America/Mexico_City'),
      COALESCE(p_is_owner, 0),
      COALESCE(p_is_active, 1),
      NULLIF(p_notes, ''),
      v_now,
      v_now
    );
    SET p_id_user = LAST_INSERT_ID();
  ELSE
    UPDATE app_user
    SET
      email = p_email,
      password_hash = CASE WHEN p_password IS NOT NULL AND p_password <> '' THEN p_password ELSE password_hash END,
      phone = COALESCE(NULLIF(p_phone, ''), phone),
      names = p_names,
      last_name = NULLIF(p_last_name, ''),
      maiden_name = NULLIF(p_maiden_name, ''),
      full_name = NULLIF(v_full_name, ''),
      display_name = COALESCE(NULLIF(p_display_name, ''), NULLIF(v_full_name, ''), p_email),
      locale = COALESCE(NULLIF(p_locale, ''), locale),
      timezone = COALESCE(NULLIF(p_timezone, ''), timezone),
      is_owner = COALESCE(p_is_owner, is_owner),
      is_active = COALESCE(p_is_active, is_active),
      notes = COALESCE(NULLIF(p_notes, ''), notes),
      updated_at = v_now
    WHERE id_user = p_id_user
      AND id_company = v_company_id
      AND deleted_at IS NULL;

    IF ROW_COUNT() = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'User not found or belongs to another company';
    END IF;
  END IF;

  SELECT
    au.id_user,
    au.email,
    au.names,
    au.last_name,
    au.maiden_name,
    au.display_name,
    au.phone,
    au.locale,
    au.timezone,
    au.is_owner,
    au.is_active,
    au.notes
  FROM app_user au
  WHERE au.id_user = p_id_user
    AND au.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_authz_assert` (IN `p_company_code` VARCHAR(100), IN `p_actor_user_id` BIGINT, IN `p_permission_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_mode` VARCHAR(16))   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_user_company_id BIGINT;
  DECLARE v_mode VARCHAR(16) DEFAULT '';
  DECLARE v_is_owner TINYINT DEFAULT 0;
  DECLARE v_has_permission TINYINT DEFAULT 0;
  DECLARE v_has_property TINYINT DEFAULT 1;
  DECLARE v_property_exists TINYINT DEFAULT 0;
  DECLARE v_allowed TINYINT DEFAULT 0;
  DECLARE v_reason VARCHAR(255) DEFAULT '';
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_actor_user_id IS NULL OR p_actor_user_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Actor user id is required';
  END IF;
  IF p_permission_code IS NULL OR TRIM(p_permission_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Permission code is required';
  END IF;

  SET v_property_code = NULLIF(TRIM(COALESCE(p_property_code, '')), '');

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
    AND c.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_mode = LOWER(TRIM(COALESCE(NULLIF(p_mode, ''), '')));
  IF v_mode NOT IN ('audit', 'enforce') THEN
    SELECT LOWER(TRIM(COALESCE(ac.authz_mode, 'audit')))
      INTO v_mode
    FROM pms_authz_config ac
    WHERE ac.id_company = v_company_id
    LIMIT 1;
  END IF;
  IF v_mode NOT IN ('audit', 'enforce') THEN
    SET v_mode = 'audit';
  END IF;

  SELECT au.id_company, COALESCE(au.is_owner, 0)
    INTO v_user_company_id, v_is_owner
  FROM app_user au
  WHERE au.id_user = p_actor_user_id
    AND au.deleted_at IS NULL
    AND au.is_active = 1
  LIMIT 1;

  IF v_user_company_id IS NULL OR v_user_company_id <> v_company_id THEN
    SET v_reason = 'actor_not_in_company_or_inactive';
    SET v_allowed = 0;
  ELSE
    IF v_is_owner = 1 THEN
      SET v_has_permission = 1;
      SET v_has_property = 1;
    ELSE
      SELECT CASE WHEN EXISTS (
        SELECT 1
        FROM user_role ur
        JOIN role r
          ON r.id_role = ur.id_role
         AND r.deleted_at IS NULL
         AND r.is_active = 1
        LEFT JOIN property pr_role
          ON pr_role.id_property = r.id_property
        JOIN role_permission rp
          ON rp.id_role = r.id_role
         AND rp.deleted_at IS NULL
         AND rp.is_active = 1
         AND COALESCE(rp.allow, 1) = 1
        JOIN permission p
          ON p.id_permission = rp.id_permission
         AND p.deleted_at IS NULL
         AND p.is_active = 1
        WHERE ur.id_user = p_actor_user_id
          AND ur.deleted_at IS NULL
          AND ur.is_active = 1
          AND p.code = p_permission_code
          AND (
            r.id_property IS NULL
            OR (
              pr_role.id_company = v_company_id
              AND pr_role.deleted_at IS NULL
            )
          )
      ) THEN 1 ELSE 0 END
        INTO v_has_permission;

      IF v_property_code IS NOT NULL THEN
        SELECT CASE WHEN EXISTS (
          SELECT 1
          FROM property pr
          WHERE pr.code = v_property_code
            AND pr.id_company = v_company_id
            AND pr.deleted_at IS NULL
        ) THEN 1 ELSE 0 END
          INTO v_property_exists;

        IF v_property_exists = 0 THEN
          SET v_has_property = 0;
        ELSE
          SELECT CASE WHEN EXISTS (
            SELECT 1
            FROM user_property up
            JOIN property pr
              ON pr.id_property = up.id_property
             AND pr.id_company = v_company_id
             AND pr.deleted_at IS NULL
            WHERE up.id_user = p_actor_user_id
              AND up.deleted_at IS NULL
              AND up.is_active = 1
              AND pr.code = v_property_code
          ) THEN 1 ELSE 0 END
            INTO v_has_property;
        END IF;
      ELSE
        SET v_has_property = 1;
      END IF;
    END IF;

    IF v_has_permission = 0 THEN
      SET v_reason = 'permission_denied';
    ELSEIF v_has_property = 0 THEN
      SET v_reason = 'property_scope_denied';
    ELSE
      SET v_reason = '';
    END IF;

    SET v_allowed = CASE WHEN v_has_permission = 1 AND v_has_property = 1 THEN 1 ELSE 0 END;
  END IF;

  IF v_allowed = 0 THEN
    INSERT INTO pms_authz_audit (
      id_company,
      id_user,
      permission_code,
      property_code,
      authz_mode,
      allowed,
      reason,
      context_json,
      created_at
    ) VALUES (
      v_company_id,
      p_actor_user_id,
      p_permission_code,
      v_property_code,
      v_mode,
      0,
      v_reason,
      CONCAT(
        '{\"company_code\":\"', REPLACE(COALESCE(p_company_code, ''), '\"', '\\\"'),
        '\",\"permission_code\":\"', REPLACE(COALESCE(p_permission_code, ''), '\"', '\\\"'),
        '\",\"property_code\":\"', REPLACE(COALESCE(v_property_code, ''), '\"', '\\\"'),
        '\",\"mode\":\"', REPLACE(COALESCE(v_mode, ''), '\"', '\\\"'),
        '\"}'
      ),
      NOW()
    );

    IF v_mode = 'enforce' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'AUTHZ_DENIED';
    END IF;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_create_reservation` (IN `p_property_code` VARCHAR(32), IN `p_room_code` VARCHAR(64), IN `p_check_in_str` VARCHAR(32), IN `p_check_out_str` VARCHAR(32), IN `p_guest_email` VARCHAR(255), IN `p_guest_names` VARCHAR(255), IN `p_guest_last_name` VARCHAR(255), IN `p_guest_maiden_name` VARCHAR(255), IN `p_guest_phone` VARCHAR(32), IN `p_adults` INT, IN `p_children` INT, IN `p_lodging_catalog_id` BIGINT, IN `p_total_cents_override` INT, IN `p_fixed_child_unit_price_cents` INT, IN `p_fixed_child_total_cents` INT, IN `p_source` VARCHAR(120), IN `p_id_ota_account` BIGINT, IN `p_id_user` INT)   proc:BEGIN
  DECLARE v_id_company    INT;
  DECLARE v_company_code  VARCHAR(100);
  DECLARE v_id_property   INT;
  DECLARE v_id_room       INT;
  DECLARE v_id_category   INT;
  DECLARE v_base_cents    INT DEFAULT 0;
  DECLARE v_total_cents   INT DEFAULT 0;
  DECLARE v_lodging_total INT DEFAULT 0;
  DECLARE v_fixed_child_total INT DEFAULT 0;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_rate_breakdown TEXT;
  DECLARE v_use_rateplan TINYINT DEFAULT 0;
  DECLARE v_id_guest      INT;
  DECLARE v_id_res        INT;
  DECLARE v_code          VARCHAR(32);
  DECLARE v_overlap_cnt   INT DEFAULT 0;
  DECLARE v_block_overlap_cnt INT DEFAULT 0;
  DECLARE v_nights        INT DEFAULT 0;
  DECLARE v_snapshot      TEXT;
  DECLARE v_breakdown     TEXT;
  DECLARE v_last_name     VARCHAR(511);
  DECLARE v_maiden_name   VARCHAR(255);
  DECLARE v_full_name     VARCHAR(600);
  DECLARE v_id_user_eff   INT;
  DECLARE v_id_folio      BIGINT;
  DECLARE v_lodging_catalog_id BIGINT;
  DECLARE v_parent_sale_item_id BIGINT;
  DECLARE v_child_catalog_id BIGINT;
  DECLARE v_child_sale_item_id BIGINT;
  DECLARE v_parent_item_name VARCHAR(255);
  DECLARE v_child_item_name VARCHAR(255);
  DECLARE v_child_desc TEXT;
  DECLARE v_source VARCHAR(32);
  DECLARE v_id_ota_account BIGINT DEFAULT NULL;
  DECLARE v_id_reservation_source BIGINT DEFAULT NULL;
  DECLARE v_ota_platform VARCHAR(32);
  DECLARE v_source_name VARCHAR(120);
  DECLARE v_in_tx TINYINT DEFAULT 0;
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_has_total_override TINYINT DEFAULT 0;

  DECLARE EXIT HANDLER FOR SQLEXCEPTION
  BEGIN
    IF v_in_tx = 1 THEN
      ROLLBACK;
      SET v_in_tx = 0;
    END IF;
    RESIGNAL;
  END;

  -- Normalizar email vacio a NULL para evitar duplicados con string vacio
  SET p_guest_email = NULLIF(TRIM(p_guest_email), '');

  -- 1) Parsear fechas desde cadenas probando varios formatos
  SET v_check_in = COALESCE(
    STR_TO_DATE(p_check_in_str,  '%Y-%m-%d'),
    STR_TO_DATE(p_check_in_str,  '%d/%m/%Y'),
    STR_TO_DATE(p_check_in_str,  '%m/%d/%Y'),
    STR_TO_DATE(p_check_in_str,  '%d-%m-%Y'),
    STR_TO_DATE(p_check_in_str,  '%m-%d-%Y'),
    STR_TO_DATE(p_check_in_str,  '%Y/%m/%d')
  );

  SET v_check_out = COALESCE(
    STR_TO_DATE(p_check_out_str, '%Y-%m-%d'),
    STR_TO_DATE(p_check_out_str, '%d/%m/%Y'),
    STR_TO_DATE(p_check_out_str, '%m/%d/%Y'),
    STR_TO_DATE(p_check_out_str, '%d-%m-%Y'),
    STR_TO_DATE(p_check_out_str, '%m-%d-%Y'),
    STR_TO_DATE(p_check_out_str, '%Y/%m/%d')
  );

  IF v_check_in IS NULL OR v_check_out IS NULL THEN
    SELECT 'ERROR' AS status, 'invalid date format (use YYYY-MM-DD, DD/MM/YYYY, MM/DD/YYYY, etc.)' AS message; LEAVE proc;
  END IF;

  SET v_nights = DATEDIFF(v_check_out, v_check_in);
  IF v_nights <= 0 THEN
    SELECT 'ERROR' AS status, 'check_out must be after check_in' AS message; LEAVE proc;
  END IF;

  IF p_adults IS NULL OR p_adults < 1 THEN
    SELECT 'ERROR' AS status, 'at least 1 adult is required' AS message; LEAVE proc;
  END IF;

  -- Email formato (solo si se proporciona)
  IF p_guest_email IS NOT NULL AND p_guest_email <> '' THEN
    IF p_guest_email NOT REGEXP '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$' THEN
      SELECT 'ERROR' AS status, 'invalid email format' AS message; LEAVE proc;
    END IF;
  END IF;

  -- 2) Hospedaje y compania
  SELECT p.id_property, p.id_company, c.code
    INTO v_id_property, v_id_company, v_company_code
  FROM property p
  JOIN company c ON c.id_company = p.id_company
  WHERE p.code = p_property_code
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SELECT 'ERROR' AS status, 'Unknown property code' AS message; LEAVE proc;
  END IF;

  IF p_total_cents_override IS NOT NULL AND p_total_cents_override >= 0 THEN
    SET v_has_total_override = 1;
  END IF;

  IF p_lodging_catalog_id IS NULL OR p_lodging_catalog_id = 0 THEN
    IF NOT (v_has_total_override = 1 AND GREATEST(p_total_cents_override, 0) = 0) THEN
      SELECT 'ERROR' AS status, 'Lodging catalog is required' AS message; LEAVE proc;
    END IF;
  END IF;

  IF p_lodging_catalog_id IS NOT NULL AND p_lodging_catalog_id > 0 THEN
    SELECT pslc.id_sale_item_catalog
      INTO v_lodging_catalog_id
    FROM pms_settings_lodging_catalog pslc
    WHERE pslc.id_company = v_id_company
      AND (pslc.id_property = v_id_property OR pslc.id_property IS NULL)
      AND pslc.id_sale_item_catalog = p_lodging_catalog_id
      AND pslc.deleted_at IS NULL
      AND pslc.is_active = 1
    LIMIT 1;

    IF v_lodging_catalog_id IS NULL THEN
      SELECT 'ERROR' AS status, 'Lodging catalog not allowed for property' AS message; LEAVE proc;
    END IF;
  END IF;

  -- 3) Habitacion + categoria + precio base
  SELECT r.id_room, r.id_category, COALESCE(rc.default_base_price_cents,0), COALESCE(r.id_rateplan, rc.id_rateplan)
    INTO v_id_room, v_id_category, v_base_cents, v_id_rateplan
  FROM room r
  JOIN roomcategory rc ON rc.id_category = r.id_category
  WHERE r.id_property = v_id_property
    AND r.code = p_room_code
  LIMIT 1;

  IF v_id_room IS NULL THEN
    SELECT 'ERROR' AS status, 'Unknown room code for that property' AS message; LEAVE proc;
  END IF;

  SET v_rate_breakdown = NULL;
  IF v_id_rateplan IS NOT NULL THEN
    CALL sp_rateplan_calc_total(
      v_id_property,
      v_id_rateplan,
      v_id_room,
      v_id_category,
      v_check_in,
      v_check_out,
      v_lodging_total,
      v_base_cents,
      v_rate_breakdown
    );
    SET v_use_rateplan = 1;
  ELSE
    SET v_lodging_total = v_base_cents * v_nights;
  END IF;
  IF p_fixed_child_total_cents IS NOT NULL AND p_fixed_child_total_cents > 0 THEN
    SET v_fixed_child_total = p_fixed_child_total_cents;
  ELSEIF p_fixed_child_unit_price_cents IS NOT NULL AND p_fixed_child_unit_price_cents > 0 THEN
    SET v_fixed_child_total = p_fixed_child_unit_price_cents * v_nights;
  ELSE
    SET v_fixed_child_total = 0;
  END IF;
  SET v_total_cents = v_lodging_total + v_fixed_child_total;
  IF v_has_total_override = 1 THEN
    SET v_total_cents = GREATEST(p_total_cents_override, 0);
    SET v_lodging_total = v_total_cents - v_fixed_child_total;
    IF v_lodging_total < 0 THEN
      SET v_lodging_total = 0;
    END IF;
  END IF;

  -- 4) Disponibilidad [in, out)
  SELECT COUNT(*) INTO v_overlap_cnt
  FROM reservation
  WHERE id_room = v_id_room
    AND (deleted_at IS NULL)
    AND (is_active IS NULL OR is_active = 1)
    AND COALESCE(status, 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
    AND NOT (check_out_date <= v_check_in OR check_in_date >= v_check_out);

  IF v_overlap_cnt > 0 THEN
    SELECT 'ERROR' AS status, 'Room not available for requested dates' AS message; LEAVE proc;
  END IF;

  SELECT COUNT(*) INTO v_block_overlap_cnt
  FROM room_block
  WHERE id_room = v_id_room
    AND deleted_at IS NULL
    AND is_active = 1
    AND start_date < v_check_out
    AND end_date > v_check_in;

  IF v_block_overlap_cnt > 0 THEN
    SELECT 'ERROR' AS status, 'Room is blocked for requested dates' AS message; LEAVE proc;
  END IF;

  -- 5) Resolver id_user efectivo (3 por defecto, luego alguno activo, luego cualquiera)
  SET v_id_user_eff = NULL;
  IF p_id_user IS NOT NULL AND p_id_user <> 0 THEN
    SELECT id_user INTO v_id_user_eff FROM app_user WHERE id_user = p_id_user LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT id_user INTO v_id_user_eff FROM app_user WHERE id_user = 3 LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT id_user INTO v_id_user_eff FROM app_user WHERE is_active=1 ORDER BY id_user LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT id_user INTO v_id_user_eff FROM app_user ORDER BY id_user LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT 'ERROR' AS status, 'no app_user available to assign' AS message; LEAVE proc;
  END IF;

  CALL sp_authz_assert(
    v_company_code,
    v_id_user_eff,
    'reservations.create',
    p_property_code,
    NULL
  );

  START TRANSACTION;
  SET v_in_tx = 1;

  -- 6) Apellidos combinados (opcionales)
  SET v_last_name = NULLIF(TRIM(COALESCE(p_guest_last_name, '')), '');
  SET v_maiden_name = NULLIF(TRIM(COALESCE(p_guest_maiden_name, '')), '');
  SET v_full_name = NULLIF(TRIM(CONCAT_WS(' ', NULLIF(TRIM(COALESCE(p_guest_names, '')), ''), v_last_name, v_maiden_name)), '');

  SET v_source = NULLIF(TRIM(COALESCE(p_source, '')), '');
  SET v_source_name = NULL;

  SET v_id_ota_account = NULL;
  SET v_id_reservation_source = NULL;
  SET v_ota_platform = NULL;
  IF p_id_ota_account IS NOT NULL AND p_id_ota_account > 0 THEN
    SELECT oa.id_ota_account, oa.platform
      INTO v_id_ota_account, v_ota_platform
    FROM ota_account oa
    WHERE oa.id_ota_account = p_id_ota_account
      AND oa.id_company = v_id_company
      AND oa.deleted_at IS NULL
      AND oa.is_active = 1
    LIMIT 1;

    IF v_id_ota_account IS NULL OR v_id_ota_account <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid ota account for company';
    END IF;

    SET v_ota_platform = LOWER(TRIM(COALESCE(v_ota_platform, 'other')));
      SET v_source = CASE
        WHEN v_ota_platform = 'booking' THEN 'Booking'
        WHEN v_ota_platform = 'airbnb' OR v_ota_platform = 'abb' THEN 'Airbnb'
        WHEN v_ota_platform = 'expedia' THEN 'Expedia'
        ELSE 'OTA'
      END;
    SET v_id_reservation_source = NULL;
  ELSE
    SELECT oa.id_ota_account, oa.platform
      INTO v_id_ota_account, v_ota_platform
    FROM ota_account_lodging_catalog oalc
    JOIN ota_account oa
      ON oa.id_ota_account = oalc.id_ota_account
     AND oa.id_company = v_id_company
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
    WHERE oalc.id_line_item_catalog = v_lodging_catalog_id
      AND oalc.deleted_at IS NULL
      AND oalc.is_active = 1
    ORDER BY oalc.sort_order, oa.id_ota_account
    LIMIT 1;

    IF v_id_ota_account IS NOT NULL AND v_id_ota_account > 0 THEN
      SET v_ota_platform = LOWER(TRIM(COALESCE(v_ota_platform, 'other')));
      SET v_source = CASE
        WHEN v_ota_platform = 'booking' THEN 'Booking'
        WHEN v_ota_platform = 'airbnb' OR v_ota_platform = 'abb' THEN 'Airbnb'
        WHEN v_ota_platform = 'expedia' THEN 'Expedia'
        ELSE 'OTA'
      END;
      SET v_id_reservation_source = NULL;
    ELSE
      IF v_source IS NOT NULL AND v_source REGEXP '^[0-9]+$' THEN
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source, v_source_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_reservation_source = CAST(v_source AS UNSIGNED)
          AND rsc.id_company = v_id_company
          AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
        ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END
        LIMIT 1;
      ELSEIF v_source IS NOT NULL THEN
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source, v_source_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_id_company
          AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
          AND TRIM(COALESCE(rsc.source_name, '')) COLLATE utf8mb4_unicode_ci
              = TRIM(COALESCE(v_source, '')) COLLATE utf8mb4_unicode_ci
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
        ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END
        LIMIT 1;
      END IF;

      IF v_id_reservation_source IS NULL OR v_id_reservation_source <= 0 THEN
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source, v_source_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_id_company
          AND rsc.id_property IS NULL
          AND TRIM(COALESCE(rsc.source_name, '')) COLLATE utf8mb4_unicode_ci = 'Directo'
          AND rsc.deleted_at IS NULL
        LIMIT 1;
      END IF;

      IF v_id_reservation_source IS NULL OR v_id_reservation_source <= 0 THEN
        SET v_id_reservation_source = NULL;
        SET v_source_name = 'Directo';
      END IF;

      SET v_source = COALESCE(NULLIF(TRIM(v_source_name), ''), 'Directo');
    END IF;
  END IF;

  -- 7) Reusar guest por email (evita duplicados) si se proporciona
  IF p_guest_email IS NOT NULL AND p_guest_email <> '' THEN
    SELECT id_guest INTO v_id_guest
    FROM guest
    WHERE email = p_guest_email
    LIMIT 1;

    IF v_id_guest IS NULL THEN
      INSERT INTO guest (email, phone, names, last_name, maiden_name, full_name, language, is_active, created_at, updated_at)
      VALUES (p_guest_email, p_guest_phone, NULLIF(p_guest_names,''), v_last_name, v_maiden_name, v_full_name, 'es', 1, NOW(), NOW());
      SET v_id_guest = LAST_INSERT_ID();
    ELSE
      UPDATE guest
        SET names = COALESCE(NULLIF(p_guest_names,''), names),
            last_name = COALESCE(v_last_name, last_name),
            maiden_name = COALESCE(v_maiden_name, maiden_name),
            full_name = NULLIF(TRIM(CONCAT_WS(' ',
              COALESCE(NULLIF(p_guest_names,''), names),
              COALESCE(v_last_name, last_name),
              COALESCE(v_maiden_name, maiden_name)
            )), ''),
            phone = COALESCE(NULLIF(p_guest_phone,''), phone),
            updated_at = NOW()
      WHERE id_guest = v_id_guest;
    END IF;
  ELSE
    SET v_id_guest = NULL;
    IF (p_guest_names IS NOT NULL AND p_guest_names <> '')
      OR (p_guest_phone IS NOT NULL AND p_guest_phone <> '')
      OR (v_last_name IS NOT NULL AND v_last_name <> '') THEN
      INSERT INTO guest (email, phone, names, last_name, maiden_name, full_name, language, is_active, created_at, updated_at)
      VALUES (NULL, NULLIF(p_guest_phone,''), NULLIF(p_guest_names,''), v_last_name, v_maiden_name, v_full_name, 'es', 1, NOW(), NOW());
      SET v_id_guest = LAST_INSERT_ID();
    END IF;
  END IF;

  -- 8) Código y JSON-like strings
  SET v_code = CONCAT('SP-', UPPER(HEX(FLOOR(RAND()*99999999))));
  IF v_has_total_override = 1 THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"override_total"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(v_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(v_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  ELSEIF v_use_rateplan = 1 AND v_rate_breakdown IS NOT NULL AND v_rate_breakdown <> '' THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"rateplan",',
        '"rateplan_id":', v_id_rateplan,
      '}'
    );
    SET v_breakdown = v_rate_breakdown;
  ELSE
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"default_base_price_cents"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(v_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(v_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  END IF;

  -- 9) Insert reserva con fechas YA normalizadas
  INSERT INTO reservation (
    id_user, id_guest, id_room, id_property, id_category,
    code, status, source, id_ota_account, id_reservation_source,
    check_in_date, check_out_date,
    adults, children, currency,
    total_price_cents, balance_due_cents,
    rate_snapshot_json, price_breakdown_json,
    is_active, created_at, updated_at
  ) VALUES (
    v_id_user_eff, v_id_guest, v_id_room, v_id_property, v_id_category,
    v_code, 'confirmado', v_source, v_id_ota_account, v_id_reservation_source,
    v_check_in, v_check_out,
    p_adults, COALESCE(p_children,0), 'MXN',
    v_total_cents, v_total_cents,
    v_snapshot, v_breakdown,
    1, NOW(), NOW()
  );

  SET v_id_res = LAST_INSERT_ID();

  IF v_total_cents > 0 THEN
    -- 10.1) Crear folio en cero; el total real se calcula desde line_item
    INSERT INTO folio (
      id_reservation,
      folio_name,
      status,
      currency,
      total_cents,
      balance_cents,
      due_date,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_id_res,
      'Principal',
      'open',
      'MXN',
      0,
      0,
      v_check_out,
      1,
      NOW(),
      p_id_user,
      NOW()
    );
    SET v_id_folio = LAST_INSERT_ID();

    CALL sp_sale_item_upsert(
      'create',
      0,
      v_id_folio,
      v_id_res,
      v_lodging_catalog_id,
      CONCAT('Reserva ', v_code),
      v_check_in,
      v_nights,
      CASE
        WHEN v_has_total_override = 1 OR v_use_rateplan = 1
          THEN CEILING(v_lodging_total / v_nights)
        ELSE v_base_cents
      END,
      CASE
        WHEN v_has_total_override = 1 OR v_use_rateplan = 1
          THEN (CEILING(v_lodging_total / v_nights) * v_nights) - v_lodging_total
        ELSE 0
      END,
      'posted',
      p_id_user
    );

    IF (p_fixed_child_total_cents IS NOT NULL AND p_fixed_child_total_cents > 0)
       OR (p_fixed_child_unit_price_cents IS NOT NULL AND p_fixed_child_unit_price_cents > 0) THEN
      SELECT id_line_item
        INTO v_parent_sale_item_id
      FROM line_item
      WHERE id_folio = v_id_folio
        AND id_line_item_catalog = v_lodging_catalog_id
        AND deleted_at IS NULL
      ORDER BY id_line_item DESC
      LIMIT 1;

      SELECT id_line_item_catalog
        INTO v_child_catalog_id
      FROM line_item_catalog_parent lcp
      JOIN line_item_catalog lic
        ON lic.id_line_item_catalog = lcp.id_sale_item_catalog
       AND lic.catalog_type IN ('sale_item','tax_rule','payment','obligation','income')
      WHERE lcp.id_parent_sale_item_catalog = v_lodging_catalog_id
        AND lcp.deleted_at IS NULL
        AND lcp.is_active = 1
        AND lcp.percent_value IS NULL
        AND lic.deleted_at IS NULL
        AND lic.is_active = 1
      ORDER BY lic.id_line_item_catalog
      LIMIT 1;

      IF v_child_catalog_id IS NOT NULL THEN
        SET v_parent_item_name = NULL;
        SET v_child_item_name = NULL;
        SET v_child_desc = NULL;

        SELECT item_name
          INTO v_parent_item_name
        FROM line_item_catalog
        WHERE id_line_item_catalog = v_lodging_catalog_id
        LIMIT 1;

        SELECT item_name
          INTO v_child_item_name
        FROM line_item_catalog
        WHERE id_line_item_catalog = v_child_catalog_id
        LIMIT 1;

        SET v_child_desc = CONCAT(
          COALESCE(NULLIF(TRIM(v_child_item_name), ''), CONCAT('Catalog#', v_child_catalog_id)),
          ' / ',
          COALESCE(NULLIF(TRIM(v_parent_item_name), ''), CONCAT('Catalog#', v_lodging_catalog_id))
        );

        SELECT id_line_item
          INTO v_child_sale_item_id
        FROM line_item
        WHERE id_folio = v_id_folio
          AND id_line_item_catalog = v_child_catalog_id
          AND (service_date <=> v_check_in)
          AND deleted_at IS NULL
        ORDER BY id_line_item DESC
        LIMIT 1;

        IF v_child_sale_item_id IS NOT NULL THEN
          CALL sp_sale_item_upsert(
            'update',
            v_child_sale_item_id,
            v_id_folio,
            v_id_res,
            v_child_catalog_id,
            v_child_desc,
            v_check_in,
            CASE
              WHEN p_fixed_child_total_cents IS NOT NULL AND p_fixed_child_total_cents > 0 THEN 1
              ELSE v_nights
            END,
            CASE
              WHEN p_fixed_child_total_cents IS NOT NULL AND p_fixed_child_total_cents > 0 THEN p_fixed_child_total_cents
              ELSE p_fixed_child_unit_price_cents
            END,
            0,
            'posted',
            p_id_user
          );
        ELSE
          CALL sp_sale_item_upsert(
            'create',
            0,
            v_id_folio,
            v_id_res,
            v_child_catalog_id,
            v_child_desc,
            v_check_in,
            CASE
              WHEN p_fixed_child_total_cents IS NOT NULL AND p_fixed_child_total_cents > 0 THEN 1
              ELSE v_nights
            END,
            CASE
              WHEN p_fixed_child_total_cents IS NOT NULL AND p_fixed_child_total_cents > 0 THEN p_fixed_child_total_cents
              ELSE p_fixed_child_unit_price_cents
            END,
            0,
            'posted',
            p_id_user
          );
        END IF;
      END IF;
    END IF;

    CALL sp_line_item_percent_derived_upsert(
      v_id_folio,
      v_id_res,
      v_lodging_catalog_id,
      v_check_in,
      p_id_user
    );
  END IF;

  COMMIT;
  SET v_in_tx = 0;

  -- 10) Salida con contexto
  SELECT
    r.*,
    g.email       AS guest_email,
    g.names       AS guest_names,
    g.last_name   AS guest_last_name,
    g.phone       AS guest_phone,
    rm.code       AS room_code,
    rm.name       AS room_name,
    rc.code       AS category_code,
    rc.name       AS category_name,
    pr.code       AS property_code,
    pr.name       AS property_name
  FROM reservation r
  LEFT JOIN guest g    ON g.id_guest     = r.id_guest
  JOIN room rm         ON rm.id_room     = r.id_room
  JOIN roomcategory rc ON rc.id_category = r.id_category
  JOIN property pr     ON pr.id_property = r.id_property
  WHERE r.id_reservation = v_id_res;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_create_reservation_hold` (IN `p_property_code` VARCHAR(32), IN `p_room_code` VARCHAR(64), IN `p_check_in` DATE, IN `p_check_out` DATE, IN `p_notes` TEXT, IN `p_id_user` INT)   proc:BEGIN
  DECLARE v_id_company    INT;
  DECLARE v_company_code  VARCHAR(100);
  DECLARE v_id_property   INT;
  DECLARE v_id_room       INT;
  DECLARE v_id_category   INT;
  DECLARE v_currency      VARCHAR(10);
  DECLARE v_base_cents    INT DEFAULT 0;
  DECLARE v_total_cents   INT DEFAULT 0;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_rate_breakdown TEXT;
  DECLARE v_use_rateplan TINYINT DEFAULT 0;
  DECLARE v_id_res        INT;
  DECLARE v_code          VARCHAR(32);
  DECLARE v_overlap_cnt   INT DEFAULT 0;
  DECLARE v_block_overlap_cnt INT DEFAULT 0;
  DECLARE v_nights        INT DEFAULT 0;
  DECLARE v_snapshot      TEXT;
  DECLARE v_breakdown     TEXT;
  DECLARE v_id_user_eff   INT;
  DECLARE v_id_reservation_source BIGINT DEFAULT NULL;
  DECLARE v_source_name VARCHAR(120) DEFAULT 'Directo';

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_room_code IS NULL OR p_room_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room code is required';
  END IF;
  IF p_check_in IS NULL OR p_check_out IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Check-in/out dates are required';
  END IF;

  SET v_nights = DATEDIFF(p_check_out, p_check_in);
  IF v_nights <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'check_out must be after check_in';
  END IF;

  SELECT p.id_property, p.id_company, p.currency, c.code
    INTO v_id_property, v_id_company, v_currency, v_company_code
  FROM property p
  JOIN company c ON c.id_company = p.id_company
  WHERE p.code = p_property_code
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SELECT r.id_room, r.id_category, COALESCE(rc.default_base_price_cents,0), COALESCE(r.id_rateplan, rc.id_rateplan)
    INTO v_id_room, v_id_category, v_base_cents, v_id_rateplan
  FROM room r
  JOIN roomcategory rc ON rc.id_category = r.id_category
  WHERE r.id_property = v_id_property
    AND r.code = p_room_code
    AND r.deleted_at IS NULL
  LIMIT 1;

  IF v_id_room IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown room code for that property';
  END IF;

  SET v_rate_breakdown = NULL;
  IF v_id_rateplan IS NOT NULL THEN
    CALL sp_rateplan_calc_total(
      v_id_property,
      v_id_rateplan,
      v_id_room,
      v_id_category,
      p_check_in,
      p_check_out,
      v_total_cents,
      v_base_cents,
      v_rate_breakdown
    );
    SET v_use_rateplan = 1;
  ELSE
    SET v_total_cents = v_base_cents * v_nights;
  END IF;
  IF v_currency IS NULL OR v_currency = '' THEN
    SET v_currency = 'MXN';
  END IF;

  SELECT COUNT(*) INTO v_overlap_cnt
  FROM reservation
  WHERE id_room = v_id_room
    AND deleted_at IS NULL
    AND (is_active IS NULL OR is_active = 1)
    AND COALESCE(status, 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
    AND NOT (check_out_date <= p_check_in OR check_in_date >= p_check_out);

  IF v_overlap_cnt > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room not available for requested dates';
  END IF;

  SELECT COUNT(*) INTO v_block_overlap_cnt
  FROM room_block
  WHERE id_room = v_id_room
    AND deleted_at IS NULL
    AND is_active = 1
    AND start_date < p_check_out
    AND end_date > p_check_in;

  IF v_block_overlap_cnt > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room is blocked for requested dates';
  END IF;

  SET v_id_user_eff = NULL;
  IF p_id_user IS NOT NULL AND p_id_user <> 0 THEN
    SELECT id_user INTO v_id_user_eff FROM app_user WHERE id_user = p_id_user LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT id_user INTO v_id_user_eff FROM app_user WHERE id_user = 3 LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT id_user INTO v_id_user_eff FROM app_user WHERE is_active=1 ORDER BY id_user LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SELECT id_user INTO v_id_user_eff FROM app_user ORDER BY id_user LIMIT 1;
  END IF;
  IF v_id_user_eff IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'no app_user available to assign';
  END IF;

  CALL sp_authz_assert(
    v_company_code,
    v_id_user_eff,
    'calendar.create_hold',
    p_property_code,
    NULL
  );

  SELECT rsc.id_reservation_source, rsc.source_name
    INTO v_id_reservation_source, v_source_name
  FROM reservation_source_catalog rsc
  WHERE rsc.id_company = v_id_company
    AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
    AND LOWER(TRIM(COALESCE(rsc.source_name, ''))) = 'directo'
    AND rsc.deleted_at IS NULL
    AND rsc.is_active = 1
  ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END
  LIMIT 1;

  IF v_id_reservation_source IS NULL OR v_id_reservation_source <= 0 THEN
    SET v_id_reservation_source = NULL;
    SET v_source_name = 'Directo';
  END IF;

  SET v_code = CONCAT('AP-', UPPER(HEX(FLOOR(RAND()*99999999))));
  IF v_use_rateplan = 1 AND v_rate_breakdown IS NOT NULL AND v_rate_breakdown <> '' THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"rateplan",',
        '"rateplan_id":', v_id_rateplan,
      '}'
    );
    SET v_breakdown = v_rate_breakdown;
  ELSE
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"default_base_price_cents"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(p_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(p_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  END IF;

  INSERT INTO reservation (
    id_user, id_guest, id_room, id_property, id_category,
    code, status, source, id_reservation_source,
    check_in_date, check_out_date,
    adults, children, currency,
    total_price_cents, balance_due_cents,
    rate_snapshot_json, price_breakdown_json,
    notes_internal,
    is_active, created_at, updated_at
  ) VALUES (
    v_id_user_eff, NULL, v_id_room, v_id_property, v_id_category,
    v_code, 'apartado', COALESCE(v_source_name, 'Directo'), v_id_reservation_source,
    p_check_in, p_check_out,
    1, 0, v_currency,
    v_total_cents, v_total_cents,
    v_snapshot, v_breakdown,
    p_notes,
    1, NOW(), NOW()
  );

  SET v_id_res = LAST_INSERT_ID();

  SELECT
    r.*,
    rm.code AS room_code,
    rm.name AS room_name,
    rc.code AS category_code,
    rc.name AS category_name,
    pr.code AS property_code,
    pr.name AS property_name
  FROM reservation r
  JOIN room rm         ON rm.id_room     = r.id_room
  JOIN roomcategory rc ON rc.id_category = r.id_category
  JOIN property pr     ON pr.id_property = r.id_property
  WHERE r.id_reservation = v_id_res;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_create_room_block` (IN `p_property_code` VARCHAR(100), IN `p_room_code` VARCHAR(100), IN `p_check_in` VARCHAR(32), IN `p_check_out` VARCHAR(32), IN `p_notes` TEXT, IN `p_actor_user` BIGINT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_check_in_text VARCHAR(32);
  DECLARE v_check_out_text VARCHAR(32);
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_code VARCHAR(32);
  DECLARE v_actor BIGINT;
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_existing_block BIGINT DEFAULT NULL;
  DECLARE v_res_overlap INT DEFAULT 0;
  DECLARE v_block_overlap INT DEFAULT 0;

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_room_code IS NULL OR p_room_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room code is required';
  END IF;

  SET v_check_in_text = TRIM(COALESCE(p_check_in, ''));
  SET v_check_out_text = TRIM(COALESCE(p_check_out, ''));

  IF v_check_in_text = '' OR v_check_out_text = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Start and end dates are required';
  END IF;

  SET v_check_in = COALESCE(
    STR_TO_DATE(v_check_in_text, '%Y-%m-%d'),
    STR_TO_DATE(v_check_in_text, '%d/%m/%Y'),
    STR_TO_DATE(v_check_in_text, '%m/%d/%Y'),
    STR_TO_DATE(v_check_in_text, '%d-%m-%Y'),
    STR_TO_DATE(v_check_in_text, '%m-%d-%Y'),
    STR_TO_DATE(v_check_in_text, '%Y/%m/%d')
  );

  SET v_check_out = COALESCE(
    STR_TO_DATE(v_check_out_text, '%Y-%m-%d'),
    STR_TO_DATE(v_check_out_text, '%d/%m/%Y'),
    STR_TO_DATE(v_check_out_text, '%m/%d/%Y'),
    STR_TO_DATE(v_check_out_text, '%d-%m-%Y'),
    STR_TO_DATE(v_check_out_text, '%m-%d-%Y'),
    STR_TO_DATE(v_check_out_text, '%Y/%m/%d')
  );

  IF v_check_in IS NULL OR v_check_out IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid date format (use YYYY-MM-DD, DD/MM/YYYY, MM/DD/YYYY, etc.)';
  END IF;
  IF v_check_out <= v_check_in THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Check-out must be after check-in';
  END IF;

  SELECT p.id_property, c.code
    INTO v_id_property, v_company_code
  FROM property p
  JOIN company c ON c.id_company = p.id_company
  WHERE p.code = p_property_code
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SELECT id_room
    INTO v_id_room
  FROM room
  WHERE id_property = v_id_property
    AND code = p_room_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_room IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown room code for that property';
  END IF;

  IF p_actor_user IS NOT NULL AND p_actor_user <> 0 THEN
    SELECT id_user INTO v_actor FROM app_user WHERE id_user = p_actor_user LIMIT 1;
  END IF;

  CALL sp_authz_assert(
    v_company_code,
    COALESCE(v_actor, p_actor_user),
    'calendar.manage_block',
    p_property_code,
    NULL
  );

  SELECT id_room_block
    INTO v_existing_block
  FROM room_block
  WHERE id_room = v_id_room
    AND start_date = v_check_in
    AND end_date = v_check_out
    AND deleted_at IS NULL
    AND is_active = 1
  ORDER BY id_room_block DESC
  LIMIT 1;

  IF v_existing_block IS NOT NULL THEN
    UPDATE room_block
       SET description = COALESCE(NULLIF(p_notes, ''), description),
           id_user = COALESCE(v_actor, id_user),
           updated_at = NOW()
     WHERE id_room_block = v_existing_block;

    SELECT
      rb.id_room_block,
      rb.code,
      rb.description,
      rb.start_date,
      rb.end_date,
      rb.is_active,
      rb.deleted_at,
      rb.created_at,
      rb.updated_at,
      rb.id_room,
      rm.code AS room_code,
      rm.name AS room_name,
      rb.id_property,
      pr.code AS property_code,
      pr.name AS property_name,
      rb.id_user
    FROM room_block rb
    JOIN room rm ON rm.id_room = rb.id_room
    JOIN property pr ON pr.id_property = rb.id_property
    WHERE rb.id_room_block = v_existing_block;
    LEAVE proc;
  END IF;

  SELECT COUNT(*)
    INTO v_res_overlap
  FROM reservation
  WHERE id_room = v_id_room
    AND deleted_at IS NULL
    AND COALESCE(status, 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
    AND check_in_date < v_check_out
    AND check_out_date > v_check_in;

  IF v_res_overlap > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room already has reservations for those dates';
  END IF;

  SELECT COUNT(*)
    INTO v_block_overlap
  FROM room_block
  WHERE id_room = v_id_room
    AND deleted_at IS NULL
    AND is_active = 1
    AND start_date < v_check_out
    AND end_date > v_check_in;

  IF v_block_overlap > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room already has blocks for those dates';
  END IF;

  SET v_code = CONCAT('BLK-', UPPER(HEX(FLOOR(RAND() * 9999999))));

  INSERT INTO room_block (
    id_room,
    id_property,
    id_user,
    code,
    description,
    start_date,
    end_date,
    is_active,
    created_at,
    updated_at
  ) VALUES (
    v_id_room,
    v_id_property,
    v_actor,
    v_code,
    NULLIF(p_notes, ''),
    v_check_in,
    v_check_out,
    1,
    NOW(),
    NOW()
  );

  SELECT
    rb.id_room_block,
    rb.code,
    rb.description,
    rb.start_date,
    rb.end_date,
    rb.is_active,
    rb.deleted_at,
    rb.created_at,
    rb.updated_at,
    rb.id_room,
    rm.code AS room_code,
    rm.name AS room_name,
    rb.id_property,
    pr.code AS property_code,
    pr.name AS property_name,
    rb.id_user
  FROM room_block rb
  JOIN room rm ON rm.id_room = rb.id_room
  JOIN property pr ON pr.id_property = rb.id_property
  WHERE rb.id_room_block = LAST_INSERT_ID();
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_fix_all_folio_totals` ()   BEGIN
  DECLARE v_done TINYINT DEFAULT 0;
  DECLARE v_id_folio BIGINT;

  DECLARE cur CURSOR FOR
    SELECT f.id_folio
    FROM folio f
    WHERE f.deleted_at IS NULL;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

  OPEN cur;
  folio_loop: LOOP
    FETCH cur INTO v_id_folio;
    IF v_done = 1 THEN
      LEAVE folio_loop;
    END IF;

    CALL sp_folio_recalc(v_id_folio);
  END LOOP;
  CLOSE cur;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_folio_recalc` (IN `p_id_folio` BIGINT)   BEGIN
  DECLARE v_total_cents INT DEFAULT 0;
  DECLARE v_items_cents INT DEFAULT 0;
  DECLARE v_tax_cents INT DEFAULT 0;
  DECLARE v_discount_cents INT DEFAULT 0;
  DECLARE v_payments_cents INT DEFAULT 0;
  DECLARE v_refunds_cents INT DEFAULT 0;
  DECLARE v_balance_cents INT DEFAULT 0;
  DECLARE v_reservation_id BIGINT DEFAULT 0;

  IF p_id_folio IS NULL OR p_id_folio = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio id is required';
  END IF;

  /* Visible tree in folio: roots + independent children + descendants add_to_father_total=1 of visible nodes */
  WITH RECURSIVE visible_tree AS (
    SELECT
      si.id_line_item,
      si.id_line_item_catalog,
      si.item_type,
      COALESCE(si.amount_cents, 0) AS amount_cents,
      COALESCE(si.discount_amount_cents, 0) AS discount_amount_cents,
      COALESCE(si.service_date, DATE(si.created_at)) AS service_key,
      CAST(si.id_line_item AS CHAR(3000)) AS visit_path
    FROM line_item si
    LEFT JOIN line_item_catalog sic
      ON sic.id_line_item_catalog = si.id_line_item_catalog
    WHERE si.id_folio = p_id_folio
      AND si.item_type IN ('sale_item', 'tax_item')
      AND si.deleted_at IS NULL
      AND si.is_active = 1
      AND (si.status IS NULL OR si.status NOT IN ('void','canceled'))
      AND (
        sic.id_line_item_catalog IS NULL
        OR COALESCE(
          (
            SELECT lcp_vis.show_in_folio_relation
            FROM line_item_catalog_parent lcp_vis
            JOIN line_item p_vis
              ON p_vis.id_folio = si.id_folio
             AND p_vis.id_line_item_catalog = lcp_vis.id_parent_sale_item_catalog
             AND p_vis.deleted_at IS NULL
             AND p_vis.is_active = 1
             AND (p_vis.status IS NULL OR p_vis.status NOT IN ('void','canceled'))
             AND (p_vis.service_date <=> si.service_date)
            LEFT JOIN line_item_catalog plic_vis
              ON plic_vis.id_line_item_catalog = p_vis.id_line_item_catalog
            WHERE lcp_vis.id_sale_item_catalog = si.id_line_item_catalog
              AND lcp_vis.deleted_at IS NULL
              AND lcp_vis.is_active = 1
              AND (
                COALESCE(si.description, '') = CONCAT(COALESCE(sic.item_name, ''), ' / ', COALESCE(plic_vis.item_name, ''))
                OR (
                  (COALESCE(si.description, '') = '' OR INSTR(COALESCE(si.description, ''), ' / ') = 0)
                  AND (
                    SELECT COUNT(*)
                    FROM line_item_catalog_parent lcp_cnt_vis
                    WHERE lcp_cnt_vis.id_sale_item_catalog = si.id_line_item_catalog
                      AND lcp_cnt_vis.deleted_at IS NULL
                      AND lcp_cnt_vis.is_active = 1
                  ) = 1
                )
              )
            ORDER BY p_vis.id_line_item DESC
            LIMIT 1
          ),
          sic.show_in_folio,
          1
        ) = 1
      )
      AND (
        NOT EXISTS (
          SELECT 1
          FROM line_item_catalog_parent lcp_rel
          WHERE lcp_rel.id_sale_item_catalog = si.id_line_item_catalog
            AND lcp_rel.deleted_at IS NULL
            AND lcp_rel.is_active = 1
        )
        OR EXISTS (
          SELECT 1
          FROM line_item_catalog_parent lcp_rel
          WHERE lcp_rel.id_sale_item_catalog = si.id_line_item_catalog
            AND lcp_rel.deleted_at IS NULL
            AND lcp_rel.is_active = 1
            AND COALESCE(lcp_rel.add_to_father_total, 1) = 0
        )
        OR EXISTS (
          SELECT 1
          FROM line_item_catalog_parent lcp_rel
          JOIN line_item p
            ON p.id_folio = si.id_folio
           AND p.id_line_item_catalog = lcp_rel.id_parent_sale_item_catalog
           AND p.deleted_at IS NULL
           AND p.is_active = 1
           AND (p.status IS NULL OR p.status NOT IN ('void','canceled'))
           AND (p.service_date <=> si.service_date)
          LEFT JOIN line_item_catalog plic
            ON plic.id_line_item_catalog = p.id_line_item_catalog
          WHERE lcp_rel.id_sale_item_catalog = si.id_line_item_catalog
            AND lcp_rel.deleted_at IS NULL
            AND lcp_rel.is_active = 1
            AND COALESCE(lcp_rel.add_to_father_total, 1) = 0
            AND (
              COALESCE(si.description, '') = CONCAT(COALESCE(sic.item_name, ''), ' / ', COALESCE(plic.item_name, ''))
              OR (
                (COALESCE(si.description, '') = '' OR INSTR(COALESCE(si.description, ''), ' / ') = 0)
                AND (
                  SELECT COUNT(*)
                  FROM line_item_catalog_parent lcp_cnt
                  WHERE lcp_cnt.id_sale_item_catalog = si.id_line_item_catalog
                    AND lcp_cnt.deleted_at IS NULL
                    AND lcp_cnt.is_active = 1
                ) = 1
              )
            )
        )
      )

    UNION ALL

    SELECT
      ch.id_line_item,
      ch.id_line_item_catalog,
      ch.item_type,
      COALESCE(ch.amount_cents, 0) AS amount_cents,
      COALESCE(ch.discount_amount_cents, 0) AS discount_amount_cents,
      COALESCE(ch.service_date, DATE(ch.created_at)) AS service_key,
      CONCAT(vt.visit_path, ',', ch.id_line_item) AS visit_path
    FROM visible_tree vt
    JOIN line_item parent_li
      ON parent_li.id_line_item = vt.id_line_item
    JOIN line_item_catalog_parent lcp_rel
      ON lcp_rel.id_parent_sale_item_catalog = parent_li.id_line_item_catalog
     AND lcp_rel.deleted_at IS NULL
     AND lcp_rel.is_active = 1
     AND COALESCE(lcp_rel.add_to_father_total, 1) = 1
    JOIN line_item ch
      ON ch.id_folio = parent_li.id_folio
     AND ch.id_line_item_catalog = lcp_rel.id_sale_item_catalog
     AND ch.item_type IN ('sale_item', 'tax_item')
     AND ch.deleted_at IS NULL
     AND ch.is_active = 1
     AND (ch.status IS NULL OR ch.status NOT IN ('void','canceled'))
     AND (COALESCE(ch.service_date, DATE(ch.created_at)) <=> COALESCE(parent_li.service_date, DATE(parent_li.created_at)))
    LEFT JOIN line_item_catalog ch_cat
      ON ch_cat.id_line_item_catalog = ch.id_line_item_catalog
    LEFT JOIN line_item_catalog p_cat
      ON p_cat.id_line_item_catalog = parent_li.id_line_item_catalog
    WHERE (
        ch_cat.id_line_item_catalog IS NULL
        OR (
          ch_cat.deleted_at IS NULL
          AND ch_cat.is_active = 1
          AND COALESCE(lcp_rel.show_in_folio_relation, ch_cat.show_in_folio, 1) = 1
        )
      )
      AND (
        COALESCE(ch.description, '') = CONCAT(COALESCE(ch_cat.item_name, ''), ' / ', COALESCE(p_cat.item_name, ''))
        OR (
          (COALESCE(ch.description, '') = '' OR INSTR(COALESCE(ch.description, ''), ' / ') = 0)
          AND (
            SELECT COUNT(*)
            FROM line_item_catalog_parent lcp_cnt
            WHERE lcp_cnt.id_sale_item_catalog = ch.id_line_item_catalog
              AND lcp_cnt.deleted_at IS NULL
              AND lcp_cnt.is_active = 1
          ) = 1
        )
      )
      AND FIND_IN_SET(CAST(ch.id_line_item AS CHAR), vt.visit_path) = 0
  )
  SELECT
    COALESCE(SUM(CASE WHEN z.item_type = 'sale_item' THEN z.amount_cents ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN z.item_type = 'sale_item' THEN z.discount_amount_cents ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN z.item_type = 'tax_item' THEN z.amount_cents ELSE 0 END), 0)
    INTO v_items_cents, v_discount_cents, v_tax_cents
  FROM (
    SELECT
      vt.id_line_item,
      MAX(vt.item_type) AS item_type,
      MAX(vt.amount_cents) AS amount_cents,
      MAX(vt.discount_amount_cents) AS discount_amount_cents
    FROM visible_tree vt
    GROUP BY vt.id_line_item
  ) z;

  SET v_total_cents = v_items_cents + v_tax_cents - v_discount_cents;

  SELECT COALESCE(SUM(p.amount_cents), 0)
    INTO v_payments_cents
  FROM line_item p
  LEFT JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = p.id_line_item_catalog
  WHERE p.item_type = 'payment'
    AND p.id_folio = p_id_folio
    AND p.deleted_at IS NULL
    AND p.is_active = 1
    AND (p.status IS NULL OR p.status NOT IN ('void','canceled'))
    AND (
      p.id_line_item_catalog IS NULL
      OR COALESCE(lic.show_in_folio, 1) = 1
    );

  SELECT COALESCE(SUM(r.amount_cents), 0)
    INTO v_refunds_cents
  FROM refund r
  JOIN line_item p
    ON p.id_line_item = r.id_payment
   AND p.item_type = 'payment'
  LEFT JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = p.id_line_item_catalog
  WHERE p.id_folio = p_id_folio
    AND r.deleted_at IS NULL
    AND r.is_active = 1
    AND (
      p.id_line_item_catalog IS NULL
      OR COALESCE(lic.show_in_folio, 1) = 1
    );

  SET v_balance_cents = v_total_cents - v_payments_cents + v_refunds_cents;

  UPDATE folio
     SET total_cents = v_total_cents,
         balance_cents = v_balance_cents,
         updated_at = NOW()
   WHERE id_folio = p_id_folio;

  SELECT f.id_reservation
    INTO v_reservation_id
  FROM folio f
  WHERE f.id_folio = p_id_folio
  LIMIT 1;

  IF v_reservation_id IS NOT NULL AND v_reservation_id > 0 THEN
    UPDATE reservation r
    JOIN (
      SELECT
        f.id_reservation,
        COALESCE(SUM(f.total_cents), 0) AS reservation_total_cents,
        COALESCE(SUM(f.balance_cents), 0) AS reservation_balance_cents
      FROM folio f
      WHERE f.id_reservation = v_reservation_id
        AND f.deleted_at IS NULL
        AND COALESCE(f.is_active, 1) = 1
      GROUP BY f.id_reservation
    ) x ON x.id_reservation = r.id_reservation
       SET r.total_price_cents = x.reservation_total_cents,
           r.balance_due_cents = x.reservation_balance_cents,
           r.updated_at = NOW()
     WHERE r.id_reservation = v_reservation_id;
  END IF;

  SELECT v_total_cents AS total_cents,
         v_payments_cents AS payments_cents,
         v_refunds_cents AS refunds_cents,
         v_balance_cents AS balance_cents;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_folio_upsert` (IN `p_action` VARCHAR(16), IN `p_id_folio` BIGINT, IN `p_id_reservation` BIGINT, IN `p_folio_name` VARCHAR(255), IN `p_due_date` DATE, IN `p_bill_to_type` VARCHAR(64), IN `p_bill_to_id` BIGINT, IN `p_notes` TEXT, IN `p_currency` VARCHAR(10), IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_id_res BIGINT;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_id_folio BIGINT;
  DECLARE v_item_count INT DEFAULT 0;
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;

  IF p_action NOT IN ('create','close','reopen','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for folio';
  END IF;

  IF p_action IN ('create') THEN
    IF p_id_reservation IS NULL OR p_id_reservation = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'reservation id is required';
    END IF;
    SELECT r.id_reservation, r.currency, c.code, p.code
      INTO v_id_res, v_currency, v_company_code, v_property_code
    FROM reservation r
    JOIN property p ON p.id_property = r.id_property
    JOIN company c ON c.id_company = p.id_company
    WHERE r.id_reservation = p_id_reservation
      AND r.deleted_at IS NULL
    LIMIT 1;
    IF v_id_res IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'reservation not found';
    END IF;

    CALL sp_authz_assert(
      v_company_code,
      p_created_by,
      'reservations.manage_folio',
      v_property_code,
      NULL
    );

    SET v_currency = COALESCE(NULLIF(p_currency,''), v_currency, 'MXN');

    INSERT INTO folio (
      id_reservation,
      folio_name,
      status,
      currency,
      total_cents,
      balance_cents,
      due_date,
      bill_to_type,
      bill_to_id,
      notes,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_id_res,
      COALESCE(NULLIF(p_folio_name,''), 'Principal'),
      'open',
      v_currency,
      0,
      0,
      p_due_date,
      NULLIF(p_bill_to_type,''),
      p_bill_to_id,
      p_notes,
      1,
      NOW(),
      p_created_by,
      NOW()
    );
    SET v_id_folio = LAST_INSERT_ID();
    CALL sp_folio_recalc(v_id_folio);
    SELECT * FROM folio WHERE id_folio = v_id_folio;
    LEAVE proc;
  END IF;

  /* close / reopen / update requires a folio id */
  IF p_id_folio IS NULL OR p_id_folio = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio id is required';
  END IF;

  SELECT id_folio INTO v_id_folio
  FROM folio
  WHERE id_folio = p_id_folio
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_folio IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio not found';
  END IF;

  SELECT c.code, p.code
    INTO v_company_code, v_property_code
  FROM folio f
  JOIN reservation r
    ON r.id_reservation = f.id_reservation
  JOIN property p
    ON p.id_property = r.id_property
  JOIN company c
    ON c.id_company = p.id_company
  WHERE f.id_folio = v_id_folio
  LIMIT 1;

  CALL sp_authz_assert(
    v_company_code,
    p_created_by,
    'reservations.manage_folio',
    v_property_code,
    NULL
  );

  IF p_action = 'close' THEN
    UPDATE folio
       SET status = 'closed',
           is_active = 0,
           updated_at = NOW()
     WHERE id_folio = v_id_folio;
  ELSEIF p_action = 'reopen' THEN
    UPDATE folio
       SET status = 'open',
           is_active = 1,
           updated_at = NOW()
     WHERE id_folio = v_id_folio;
  ELSEIF p_action = 'update' THEN
    UPDATE folio
       SET folio_name = COALESCE(NULLIF(p_folio_name,''), folio_name),
           due_date = COALESCE(p_due_date, due_date),
           bill_to_type = COALESCE(NULLIF(p_bill_to_type,''), bill_to_type),
           bill_to_id = COALESCE(p_bill_to_id, bill_to_id),
           notes = COALESCE(p_notes, notes),
           updated_at = NOW()
     WHERE id_folio = v_id_folio;
  ELSEIF p_action = 'delete' THEN
    SELECT COUNT(*) INTO v_item_count
      FROM line_item si
     WHERE si.item_type = 'sale_item'
       AND si.id_folio = v_id_folio
       AND si.deleted_at IS NULL;
    IF v_item_count > 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio has charges and cannot be deleted';
    END IF;
    UPDATE folio
       SET status = 'deleted',
           is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_folio = v_id_folio;
    SELECT * FROM folio WHERE id_folio = v_id_folio;
    LEAVE proc;
  END IF;

  CALL sp_folio_recalc(v_id_folio);
  SELECT * FROM folio WHERE id_folio = v_id_folio;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_get_company_activities` (IN `p_company_code` VARCHAR(100))   BEGIN
    SELECT
        a.id_activity,
        a.code             AS activity_code,
        a.name             AS activity_name,
        a.type             AS activity_type,
        a.description,
        a.duration_minutes,
        a.base_price_cents,
        a.currency,
        a.capacity_default,
        a.location,
        a.is_active,
        a.updated_at,
        a.id_sale_item_catalog,
        sic.item_name      AS sale_item_name,
        sc.category_name   AS sale_item_category,
        p.id_property,
        p.code             AS property_code,
        p.name             AS property_name
    FROM activity AS a
    INNER JOIN company AS c ON c.id_company = a.id_company
    LEFT JOIN property AS p ON p.id_property = a.id_property
    LEFT JOIN line_item_catalog sic
      ON sic.id_line_item_catalog = a.id_sale_item_catalog
     AND sic.catalog_type = 'sale_item'
    LEFT JOIN sale_item_category sc ON sc.id_sale_item_category = sic.id_category
      AND sc.id_company = a.id_company
      AND sc.deleted_at IS NULL
    WHERE c.code = p_company_code
      AND c.deleted_at IS NULL
      AND a.deleted_at IS NULL
      AND a.is_active = 1
    ORDER BY a.type, a.name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_get_company_properties` (IN `p_company_code` VARCHAR(100))   BEGIN
    -- Active properties for the given company
    SELECT
        p.id_property,
        p.code AS property_code,
        p.name AS property_name,
        p.description,
        p.city,
        p.state,
        p.country,
        p.currency
    FROM property AS p
    INNER JOIN company AS c ON c.id_company = p.id_company
    WHERE c.code = p_company_code
      AND c.deleted_at IS NULL
      AND p.is_active = 1
      AND p.deleted_at IS NULL
    ORDER BY p.name;

    -- Active room categories per property
    SELECT
        rc.id_category,
        rc.id_property,
        p.code AS property_code,
        rc.code AS category_code,
        rc.name AS category_name,
        rc.description,
        rc.max_occupancy,
        rc.default_floor_cents,
        rc.default_ceil_cents,
        rc.image_url
    FROM roomcategory AS rc
    INNER JOIN property AS p ON p.id_property = rc.id_property
    INNER JOIN company AS c ON c.id_company = p.id_company
    WHERE c.code = p_company_code
      AND c.deleted_at IS NULL
      AND rc.is_active = 1
      AND rc.deleted_at IS NULL
    ORDER BY rc.id_property, rc.name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_get_room_block` (IN `p_room_block_id` BIGINT)   BEGIN
  IF p_room_block_id IS NULL OR p_room_block_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Block id is required';
  END IF;

  SELECT
    rb.id_room_block,
    rb.code,
    rb.description,
    rb.start_date,
    rb.end_date,
    rb.is_active,
    rb.created_at,
    rb.updated_at,
    rb.id_user,
    rm.id_room,
    rm.code AS room_code,
    rm.name AS room_name,
    pr.id_property,
    pr.code AS property_code,
    pr.name AS property_name
  FROM room_block rb
  JOIN room rm ON rm.id_room = rb.id_room
  JOIN property pr ON pr.id_property = rb.id_property
  WHERE rb.id_room_block = p_room_block_id
    AND rb.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_guest_backfill_full_name` ()   BEGIN
  UPDATE guest
     SET full_name = NULLIF(TRIM(CONCAT_WS(' ',
           NULLIF(TRIM(COALESCE(names, '')), ''),
           NULLIF(TRIM(COALESCE(last_name, '')), ''),
           NULLIF(TRIM(COALESCE(maiden_name, '')), '')
         )), ''),
         updated_at = NOW()
   WHERE deleted_at IS NULL;

  SELECT ROW_COUNT() AS affected_rows;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_guest_upsert` (IN `p_email` VARCHAR(255), IN `p_names` VARCHAR(255), IN `p_last_name` VARCHAR(255), IN `p_maiden_name` VARCHAR(255), IN `p_phone` VARCHAR(100), IN `p_language` VARCHAR(10), IN `p_marketing_opt` TINYINT, IN `p_blacklisted` TINYINT, IN `p_notes` TEXT)   proc:BEGIN
  DECLARE v_id_guest BIGINT;

  IF (p_email IS NULL OR p_email = '') AND (p_names IS NULL OR p_names = '') AND (p_phone IS NULL OR p_phone = '') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Guest name or phone is required';
  END IF;

  IF p_email IS NOT NULL AND p_email <> '' THEN
    SELECT id_guest INTO v_id_guest
    FROM guest
    WHERE email = p_email
    LIMIT 1;
  END IF;

  IF v_id_guest IS NULL THEN
    INSERT INTO guest (
      id_user,
      email,
      phone,
      names,
      last_name,
      maiden_name,
      full_name,
      language,
      marketing_opt_in,
      blacklisted,
      notes_internal,
      created_at,
      updated_at
    ) VALUES (
      NULL,
      NULLIF(p_email, ''),
      NULLIF(p_phone, ''),
      p_names,
      NULLIF(p_last_name, ''),
      NULLIF(p_maiden_name, ''),
      NULLIF(TRIM(CONCAT_WS(' ',
        NULLIF(TRIM(COALESCE(p_names, '')), ''),
        NULLIF(TRIM(COALESCE(p_last_name, '')), ''),
        NULLIF(TRIM(COALESCE(p_maiden_name, '')), '')
      )), ''),
      COALESCE(NULLIF(p_language,''), 'es'),
      COALESCE(p_marketing_opt, 0),
      COALESCE(p_blacklisted, 0),
      NULLIF(p_notes, ''),
      NOW(),
      NOW()
    );
    SET v_id_guest = LAST_INSERT_ID();
  ELSE
    UPDATE guest
    SET
      phone = COALESCE(NULLIF(p_phone,''), phone),
      names = COALESCE(NULLIF(p_names,''), names),
      last_name = COALESCE(NULLIF(p_last_name,''), last_name),
      maiden_name = COALESCE(NULLIF(p_maiden_name,''), maiden_name),
      full_name = NULLIF(TRIM(CONCAT_WS(' ',
        COALESCE(NULLIF(p_names,''), names),
        COALESCE(NULLIF(p_last_name,''), last_name),
        COALESCE(NULLIF(p_maiden_name,''), maiden_name)
      )), ''),
      language = COALESCE(NULLIF(p_language,''), language),
      marketing_opt_in = COALESCE(p_marketing_opt, marketing_opt_in),
      blacklisted = COALESCE(p_blacklisted, blacklisted),
      notes_internal = COALESCE(NULLIF(p_notes,''), notes_internal),
      updated_at = NOW()
    WHERE id_guest = v_id_guest;
  END IF;

  SELECT * FROM guest WHERE id_guest = v_id_guest;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_import_reservations_one_paste` ()   BEGIN
  DECLARE done INT DEFAULT 0;
  DECLARE v_id_import BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_room_name VARCHAR(255);
  DECLARE v_guest_name VARCHAR(255);
  DECLARE v_amount_raw VARCHAR(64);
  DECLARE v_check_in_raw VARCHAR(20);
  DECLARE v_check_out_raw VARCHAR(20);
  DECLARE v_origin_raw VARCHAR(120);

  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_amount_decimal DECIMAL(12,2);
  DECLARE v_id_company BIGINT;
  DECLARE v_id_user BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_id_guest BIGINT;
  DECLARE v_id_ota_account BIGINT;
  DECLARE v_id_reservation_source BIGINT;
  DECLARE v_source_name VARCHAR(120);
  DECLARE v_overlap_cnt INT DEFAULT 0;
  DECLARE v_block_overlap_cnt INT DEFAULT 0;
  DECLARE v_code VARCHAR(120);
  DECLARE v_new_reservation_id BIGINT;
  DECLARE v_note_text TEXT;
  DECLARE v_reason VARCHAR(500);
  DECLARE v_status VARCHAR(16);
  DECLARE v_origin_norm VARCHAR(120);
  DECLARE v_input_rows INT DEFAULT 0;

  DECLARE v_sql_error TINYINT DEFAULT 0;
  DECLARE v_sql_message TEXT DEFAULT '';

  DECLARE cur CURSOR FOR
    SELECT id_import, id_property, TRIM(room_name), TRIM(guest_name), TRIM(COALESCE(amount_raw,'')),
           TRIM(check_in_raw), TRIM(check_out_raw), TRIM(origin_raw)
    FROM tmp_reservation_import_input
    ORDER BY id_import;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
  DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
  BEGIN
    SET v_sql_error = 1;
    GET DIAGNOSTICS CONDITION 1 v_sql_message = MESSAGE_TEXT;
  END;

  TRUNCATE TABLE tmp_reservation_import_log;

  SELECT COUNT(*) INTO v_input_rows
  FROM tmp_reservation_import_input;

  IF v_input_rows = 0 THEN
    SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'tmp_reservation_import_input esta vacia. No hay filas para importar.';
  END IF;

  OPEN cur;
  read_loop: LOOP
    /* Evita que NOT FOUND de SELECT ... INTO corte el cursor */
    SET done = 0;
    FETCH cur INTO v_id_import, v_id_property, v_room_name, v_guest_name, v_amount_raw, v_check_in_raw, v_check_out_raw, v_origin_raw;
    IF done = 1 THEN
      LEAVE read_loop;
    END IF;

    SET v_reason = NULL;
    SET v_status = 'inserted';
    SET v_sql_error = 0;
    SET v_sql_message = '';
    SET v_new_reservation_id = NULL;
    SET v_code = NULL;
    SET v_id_ota_account = NULL;
    SET v_id_reservation_source = NULL;
    SET v_source_name = NULL;

    row_proc: BEGIN
      SET v_check_in = STR_TO_DATE(v_check_in_raw, '%Y-%m-%d');
      SET v_check_out = STR_TO_DATE(v_check_out_raw, '%Y-%m-%d');
      IF v_check_in IS NULL OR v_check_out IS NULL OR v_check_out <= v_check_in THEN
        SET v_reason = CONCAT('fechas invalidas: ', v_check_in_raw, ' -> ', v_check_out_raw);
        LEAVE row_proc;
      END IF;

      IF v_amount_raw <> '' AND REPLACE(v_amount_raw, ',', '') REGEXP '^-?[0-9]+(\\.[0-9]+)?$' THEN
        SET v_amount_decimal = CAST(REPLACE(v_amount_raw, ',', '') AS DECIMAL(12,2));
      ELSE
        SET v_amount_decimal = NULL;
      END IF;

      SELECT p.id_company INTO v_id_company
      FROM property p
      WHERE p.id_property = v_id_property
        AND p.deleted_at IS NULL
      LIMIT 1;
      IF v_id_company IS NULL THEN
        SET v_reason = 'propiedad no existe';
        LEAVE row_proc;
      END IF;

      SELECT u.id_user INTO v_id_user
      FROM app_user u
      WHERE u.id_company = v_id_company
        AND u.deleted_at IS NULL
        AND COALESCE(u.is_active,1)=1
      ORDER BY COALESCE(u.is_owner,0) DESC, u.id_user
      LIMIT 1;
      IF v_id_user IS NULL THEN
        SET v_reason = 'sin usuario activo para empresa';
        LEAVE row_proc;
      END IF;

      SELECT r.id_room, r.id_category
        INTO v_id_room, v_id_category
      FROM room r
      WHERE r.id_property = v_id_property
        AND r.deleted_at IS NULL
        AND COALESCE(r.is_active,1)=1
        AND (
          TRIM(COALESCE(r.name,'')) COLLATE utf8mb4_unicode_ci = v_room_name COLLATE utf8mb4_unicode_ci
          OR TRIM(COALESCE(r.code,'')) COLLATE utf8mb4_unicode_ci = v_room_name COLLATE utf8mb4_unicode_ci
        )
      ORDER BY
        CASE WHEN TRIM(COALESCE(r.name,'')) COLLATE utf8mb4_unicode_ci = v_room_name COLLATE utf8mb4_unicode_ci THEN 0 ELSE 1 END,
        r.id_room
      LIMIT 1;
      IF v_id_room IS NULL THEN
        SET v_reason = CONCAT('habitacion no encontrada: ', v_room_name);
        LEAVE row_proc;
      END IF;

      INSERT INTO guest (id_user, names, language, is_active, created_at, created_by, updated_at)
      VALUES (v_id_user, v_guest_name, 'es', 1, NOW(), v_id_user, NOW());
      SET v_id_guest = LAST_INSERT_ID();

      SET v_origin_norm = LOWER(REPLACE(REPLACE(TRIM(COALESCE(v_origin_raw,'')), '&', ''), ' ', ''));
      IF v_origin_norm IN ('airbnb','airbb') THEN
        SELECT oa.id_ota_account INTO v_id_ota_account
        FROM ota_account oa
        WHERE oa.id_company = v_id_company
          AND oa.id_property = v_id_property
          AND oa.deleted_at IS NULL
          AND oa.is_active = 1
          AND (LOWER(TRIM(COALESCE(oa.platform,'')))='airbnb' OR LOWER(TRIM(COALESCE(oa.ota_name,''))) LIKE '%airbnb%')
        ORDER BY oa.id_ota_account LIMIT 1;
        SET v_source_name = 'Airbnb';
      ELSEIF v_origin_norm = 'booking' THEN
        SELECT oa.id_ota_account INTO v_id_ota_account
        FROM ota_account oa
        WHERE oa.id_company = v_id_company
          AND oa.id_property = v_id_property
          AND oa.deleted_at IS NULL
          AND oa.is_active = 1
          AND (LOWER(TRIM(COALESCE(oa.platform,'')))='booking' OR LOWER(TRIM(COALESCE(oa.ota_name,''))) LIKE '%booking%')
        ORDER BY oa.id_ota_account LIMIT 1;
        SET v_source_name = 'Booking';
      ELSEIF v_origin_norm = 'expedia' THEN
        SELECT oa.id_ota_account INTO v_id_ota_account
        FROM ota_account oa
        WHERE oa.id_company = v_id_company
          AND oa.id_property = v_id_property
          AND oa.deleted_at IS NULL
          AND oa.is_active = 1
          AND (LOWER(TRIM(COALESCE(oa.platform,'')))='expedia' OR LOWER(TRIM(COALESCE(oa.ota_name,''))) LIKE '%expedia%')
        ORDER BY oa.id_ota_account LIMIT 1;
        SET v_source_name = 'Expedia';
      ELSE
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source, v_source_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_id_company
          AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
          AND LOWER(TRIM(COALESCE(rsc.source_name,''))) COLLATE utf8mb4_unicode_ci =
              LOWER(TRIM(COALESCE(v_origin_raw,''))) COLLATE utf8mb4_unicode_ci
        ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END, rsc.id_reservation_source
        LIMIT 1;
      END IF;

      /* Fallback: si no hay OTA/source configurada, no bloquear la reserva. */
      IF (v_id_reservation_source IS NULL OR v_id_reservation_source <= 0) THEN
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source, v_source_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_id_company
          AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
          AND LOWER(TRIM(COALESCE(rsc.source_name,''))) COLLATE utf8mb4_unicode_ci IN (
            LOWER(TRIM(COALESCE(v_source_name,''))) COLLATE utf8mb4_unicode_ci,
            LOWER(TRIM(COALESCE(v_origin_raw,''))) COLLATE utf8mb4_unicode_ci
          )
        ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END, rsc.id_reservation_source
        LIMIT 1;
      END IF;

      IF v_source_name IS NULL OR v_source_name = '' THEN
        SET v_source_name = COALESCE(NULLIF(TRIM(v_origin_raw), ''), 'Directo');
      END IF;

      SELECT COUNT(*) INTO v_overlap_cnt
      FROM reservation r
      WHERE r.id_room = v_id_room
        AND r.deleted_at IS NULL
        AND COALESCE(r.is_active,1)=1
        AND COALESCE(LOWER(TRIM(r.status)), 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
        AND NOT (r.check_out_date <= v_check_in OR r.check_in_date >= v_check_out);
      IF v_overlap_cnt > 0 THEN
        SET v_reason = 'empalme con reservacion existente';
        LEAVE row_proc;
      END IF;

      SELECT COUNT(*) INTO v_block_overlap_cnt
      FROM room_block rb
      WHERE rb.id_room = v_id_room
        AND rb.deleted_at IS NULL
        AND rb.is_active = 1
        AND rb.start_date < v_check_out
        AND rb.end_date > v_check_in;
      IF v_block_overlap_cnt > 0 THEN
        SET v_reason = 'empalme con bloqueo de habitacion';
        LEAVE row_proc;
      END IF;

      SET v_note_text = CONCAT(
        'Import masivo (sin folio). Monto reportado: ',
        COALESCE(CASE WHEN v_amount_decimal IS NULL THEN NULL ELSE FORMAT(v_amount_decimal, 2) END, 'N/D'),
        ' MXN. Origen: ',
        v_source_name
      );

      SET v_code = CONCAT('IMP-', DATE_FORMAT(NOW(), '%y%m%d'), '-', LPAD(v_id_import, 6, '0'), '-', UPPER(SUBSTRING(REPLACE(UUID(), '-', ''), 1, 4)));

      INSERT INTO reservation (
        id_user, id_guest, id_room, id_property, id_category, code, status,
        source, id_ota_account, id_reservation_source,
        check_in_date, check_out_date,
        adults, children, currency,
        total_price_cents, balance_due_cents, notes_internal,
        is_active, created_at, created_by, updated_at
      ) VALUES (
        v_id_user, v_id_guest, v_id_room, v_id_property, v_id_category, v_code, 'confirmado',
        v_source_name, v_id_ota_account, v_id_reservation_source,
        v_check_in, v_check_out,
        1, 0, 'MXN',
        0, 0, v_note_text,
        1, NOW(), v_id_user, NOW()
      );
      SET v_new_reservation_id = LAST_INSERT_ID();

      INSERT INTO reservation_note (
        id_reservation, note_type, note_text, is_active, created_at, created_by, updated_at
      ) VALUES (
        v_new_reservation_id, 'internal', v_note_text, 1, NOW(), v_id_user, NOW()
      );
    END row_proc;

    IF v_sql_error = 1 THEN
      SET v_status = 'error';
      SET v_reason = CONCAT('SQL ERROR: ', COALESCE(v_sql_message, 'error'));
    ELSEIF v_reason IS NOT NULL AND v_reason <> '' THEN
      SET v_status = 'skipped';
    ELSE
      SET v_status = 'inserted';
    END IF;

    INSERT INTO tmp_reservation_import_log (
      id_import, result_status, reason, id_reservation, reservation_code, created_at
    ) VALUES (
      v_id_import, v_status, v_reason, v_new_reservation_id, v_code, NOW()
    );
  END LOOP;
  CLOSE cur;

  SELECT result_status, COUNT(*) AS total_rows
  FROM tmp_reservation_import_log
  GROUP BY result_status;

  SELECT
    l.id_import, i.id_property, i.room_name, i.guest_name, i.amount_raw, i.check_in_raw, i.check_out_raw, i.origin_raw,
    l.result_status, l.reason, l.id_reservation, l.reservation_code, l.created_at
  FROM tmp_reservation_import_log l
  JOIN tmp_reservation_import_input i ON i.id_import = l.id_import
  ORDER BY l.id_import;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_import_reservations_quick_mass_by_room_id` ()   BEGIN
  DECLARE done INT DEFAULT 0;

  DECLARE v_id_import BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_guest_name VARCHAR(255);
  DECLARE v_amount_raw VARCHAR(64);
  DECLARE v_check_in_raw VARCHAR(20);
  DECLARE v_check_out_raw VARCHAR(20);
  DECLARE v_origin_raw VARCHAR(120);

  DECLARE v_id_company BIGINT;
  DECLARE v_id_user BIGINT;
  DECLARE v_room_id_db BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_amount_clean VARCHAR(64);
  DECLARE v_total_override_cents INT;
  DECLARE v_source_input VARCHAR(120);
  DECLARE v_origin_norm VARCHAR(160);
  DECLARE v_source_norm VARCHAR(160);
  DECLARE v_id_ota_account BIGINT;
  DECLARE v_ota_name VARCHAR(150);
  DECLARE v_ota_platform VARCHAR(32);
  DECLARE v_id_reservation_source_match BIGINT;
  DECLARE v_source_related_name VARCHAR(120);
  DECLARE v_mapas_source_id BIGINT;
  DECLARE v_overlap_cnt INT DEFAULT 0;
  DECLARE v_block_overlap_cnt INT DEFAULT 0;
  DECLARE v_new_guest_id BIGINT;
  DECLARE v_note_text TEXT;
  DECLARE v_new_reservation_id BIGINT;
  DECLARE v_new_reservation_code VARCHAR(120);
  DECLARE v_reason VARCHAR(500);
  DECLARE v_status VARCHAR(16);
  DECLARE v_rows_input INT DEFAULT 0;
  DECLARE v_sql_error TINYINT DEFAULT 0;
  DECLARE v_sql_message TEXT DEFAULT '';

  DECLARE cur CURSOR FOR
    SELECT
      id_import,
      id_property,
      id_room,
      TRIM(COALESCE(guest_name, '')),
      TRIM(COALESCE(amount_raw, '')),
      TRIM(COALESCE(check_in_raw, '')),
      TRIM(COALESCE(check_out_raw, '')),
      TRIM(COALESCE(origin_raw, ''))
    FROM tmp_reservation_import_input
    ORDER BY id_import;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
  DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
  BEGIN
    SET v_sql_error = 1;
    GET DIAGNOSTICS CONDITION 1 v_sql_message = MESSAGE_TEXT;
  END;

  TRUNCATE TABLE tmp_reservation_import_log;

  SELECT COUNT(*) INTO v_rows_input
  FROM tmp_reservation_import_input;

  IF v_rows_input = 0 THEN
    SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'tmp_reservation_import_input esta vacia.';
  END IF;

  OPEN cur;
  read_loop: LOOP
    SET done = 0;
    FETCH cur
      INTO v_id_import, v_id_property, v_id_room, v_guest_name, v_amount_raw, v_check_in_raw, v_check_out_raw, v_origin_raw;
    IF done = 1 THEN
      LEAVE read_loop;
    END IF;

    SET v_sql_error = 0;
    SET v_sql_message = '';
    SET v_reason = NULL;
    SET v_status = 'inserted';
    SET v_id_company = NULL;
    SET v_id_user = NULL;
    SET v_room_id_db = NULL;
    SET v_id_category = NULL;
    SET v_check_in = NULL;
    SET v_check_out = NULL;
    SET v_amount_clean = NULL;
    SET v_total_override_cents = NULL;
    SET v_source_input = NULL;
    SET v_origin_norm = NULL;
    SET v_source_norm = NULL;
    SET v_id_ota_account = NULL;
    SET v_ota_name = NULL;
    SET v_ota_platform = NULL;
    SET v_id_reservation_source_match = NULL;
    SET v_source_related_name = NULL;
    SET v_mapas_source_id = NULL;
    SET v_overlap_cnt = 0;
    SET v_block_overlap_cnt = 0;
    SET v_new_guest_id = NULL;
    SET v_note_text = NULL;
    SET v_new_reservation_id = NULL;
    SET v_new_reservation_code = NULL;

    row_proc: BEGIN
      SET v_check_in = STR_TO_DATE(v_check_in_raw, '%Y-%m-%d');
      SET v_check_out = STR_TO_DATE(v_check_out_raw, '%Y-%m-%d');
      IF v_check_in IS NULL OR v_check_out IS NULL OR v_check_out <= v_check_in THEN
        SET v_reason = CONCAT('fechas invalidas: ', v_check_in_raw, ' -> ', v_check_out_raw);
        LEAVE row_proc;
      END IF;

      IF v_guest_name IS NULL OR v_guest_name = '' THEN
        SET v_reason = 'guest_name vacio';
        LEAVE row_proc;
      END IF;

      SELECT p.id_company
        INTO v_id_company
      FROM property p
      WHERE p.id_property = v_id_property
        AND p.deleted_at IS NULL
      LIMIT 1;

      IF v_id_company IS NULL OR v_id_company <= 0 THEN
        SET v_reason = CONCAT('propiedad no valida: ', COALESCE(v_id_property, 0));
        LEAVE row_proc;
      END IF;

      SELECT r.id_room, r.id_category
        INTO v_room_id_db, v_id_category
      FROM room r
      WHERE r.id_room = v_id_room
        AND r.id_property = v_id_property
        AND r.deleted_at IS NULL
        AND COALESCE(r.is_active, 1) = 1
      LIMIT 1;

      IF v_room_id_db IS NULL OR v_room_id_db <= 0 THEN
        SELECT r.id_room, r.id_category
          INTO v_room_id_db, v_id_category
        FROM room r
        WHERE r.id_property = v_id_property
          AND r.deleted_at IS NULL
          AND COALESCE(r.is_active, 1) = 1
          AND UPPER(TRIM(COALESCE(r.code, ''))) = UPPER(TRIM(CAST(v_id_room AS CHAR)))
        LIMIT 1;
      END IF;

      IF v_room_id_db IS NULL OR v_room_id_db <= 0 THEN
        SET v_reason = CONCAT('cuarto no valido para propiedad (id/code): ', COALESCE(v_id_room, 0));
        LEAVE row_proc;
      END IF;

      SELECT u.id_user
        INTO v_id_user
      FROM app_user u
      WHERE u.id_company = v_id_company
        AND u.deleted_at IS NULL
        AND COALESCE(u.is_active, 1) = 1
      ORDER BY COALESCE(u.is_owner, 0) DESC, u.id_user
      LIMIT 1;

      IF v_id_user IS NULL THEN
        SELECT u.id_user
          INTO v_id_user
        FROM app_user u
        WHERE u.deleted_at IS NULL
          AND COALESCE(u.is_active, 1) = 1
        ORDER BY u.id_user
        LIMIT 1;
      END IF;

      IF v_id_user IS NULL OR v_id_user <= 0 THEN
        SET v_reason = 'sin usuario activo para crear reservation/guest';
        LEAVE row_proc;
      END IF;

      SET v_amount_clean = REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(v_amount_raw, '')), '$', ''), ',', ''), 'MXN', ''), 'mxn', ''), ' ', '');
      IF v_amount_clean REGEXP '^-?[0-9]+(\\.[0-9]+)?$' THEN
        SET v_total_override_cents = CAST(ROUND(CAST(v_amount_clean AS DECIMAL(12,2)) * 100, 0) AS SIGNED);
      ELSE
        SET v_total_override_cents = NULL;
      END IF;

      SET v_origin_norm = LOWER(
        REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(v_origin_raw, '')), '&', ''), ' ', ''), '.', ''), '-', '')
      );

      SET v_source_input = 'Mapas';
      SET v_id_ota_account = NULL;
      SET v_ota_name = NULL;
      SET v_ota_platform = NULL;
      SET v_id_reservation_source_match = NULL;
      SET v_source_related_name = NULL;

      SELECT oa.id_ota_account, oa.ota_name, oa.platform
        INTO v_id_ota_account, v_ota_name, v_ota_platform
      FROM ota_account oa
      WHERE oa.id_company = v_id_company
        AND oa.deleted_at IS NULL
        AND oa.is_active = 1
        AND (
          TRIM(COALESCE(oa.ota_name, '')) COLLATE utf8mb4_unicode_ci =
            TRIM(COALESCE(v_origin_raw, '')) COLLATE utf8mb4_unicode_ci
          OR LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(oa.ota_name, '')), '&', ''), ' ', ''), '.', ''), '-', '')) = v_origin_norm
        )
      ORDER BY CASE WHEN oa.id_property = v_id_property THEN 0 ELSE 1 END, oa.id_ota_account
      LIMIT 1;

      IF v_id_ota_account IS NOT NULL AND v_id_ota_account > 0 THEN
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source_match, v_source_related_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_id_company
          AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
          AND (
            TRIM(COALESCE(rsc.source_name, '')) COLLATE utf8mb4_unicode_ci =
              TRIM(COALESCE(v_ota_name, '')) COLLATE utf8mb4_unicode_ci
            OR LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(rsc.source_name, '')), '&', ''), ' ', ''), '.', ''), '-', '')) =
               LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(v_ota_name, '')), '&', ''), ' ', ''), '.', ''), '-', ''))
          )
        ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END, rsc.id_reservation_source
        LIMIT 1;

        IF v_id_reservation_source_match IS NULL OR v_id_reservation_source_match <= 0 THEN
          SET v_source_norm = LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(v_ota_platform, '')), '&', ''), ' ', ''), '.', ''), '-', ''));
          SELECT rsc.id_reservation_source, rsc.source_name
            INTO v_id_reservation_source_match, v_source_related_name
          FROM reservation_source_catalog rsc
          WHERE rsc.id_company = v_id_company
            AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
            AND rsc.deleted_at IS NULL
            AND rsc.is_active = 1
            AND LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(rsc.source_name, '')), '&', ''), ' ', ''), '.', ''), '-', '')) = v_source_norm
          ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END, rsc.id_reservation_source
          LIMIT 1;
        END IF;

        SET v_source_input = COALESCE(NULLIF(TRIM(v_source_related_name), ''), NULLIF(TRIM(v_ota_name), ''), 'Mapas');
      ELSE
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source_match, v_source_related_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_id_company
          AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
          AND (
            TRIM(COALESCE(rsc.source_name, '')) COLLATE utf8mb4_unicode_ci =
              TRIM(COALESCE(v_origin_raw, '')) COLLATE utf8mb4_unicode_ci
            OR LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(rsc.source_name, '')), '&', ''), ' ', ''), '.', ''), '-', '')) = v_origin_norm
          )
        ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END, rsc.id_reservation_source
        LIMIT 1;

        IF v_id_reservation_source_match IS NOT NULL AND v_id_reservation_source_match > 0 THEN
          SET v_source_input = v_source_related_name;
        ELSE
          SELECT rsc.id_reservation_source, rsc.source_name
            INTO v_mapas_source_id, v_source_related_name
          FROM reservation_source_catalog rsc
          WHERE rsc.id_company = v_id_company
            AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
            AND rsc.deleted_at IS NULL
            AND rsc.is_active = 1
            AND LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(rsc.source_name, '')), '&', ''), ' ', ''), '.', ''), '-', '')) = 'mapas'
          ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END, rsc.id_reservation_source
          LIMIT 1;

          SET v_id_reservation_source_match = v_mapas_source_id;
          SET v_source_input = COALESCE(NULLIF(TRIM(v_source_related_name), ''), 'Mapas');
        END IF;
      END IF;

      SELECT COUNT(*)
        INTO v_overlap_cnt
      FROM reservation r
      WHERE r.id_room = v_room_id_db
        AND r.deleted_at IS NULL
        AND COALESCE(r.is_active, 1) = 1
        AND COALESCE(LOWER(TRIM(r.status)), 'confirmado') NOT IN ('cancelled', 'canceled', 'cancelado', 'cancelada')
        AND NOT (r.check_out_date <= v_check_in OR r.check_in_date >= v_check_out);

      IF v_overlap_cnt > 0 THEN
        SET v_reason = 'empalme con reservacion existente';
        LEAVE row_proc;
      END IF;

      SELECT COUNT(*)
        INTO v_block_overlap_cnt
      FROM room_block rb
      WHERE rb.id_room = v_room_id_db
        AND rb.deleted_at IS NULL
        AND rb.is_active = 1
        AND rb.start_date < v_check_out
        AND rb.end_date > v_check_in;

      IF v_block_overlap_cnt > 0 THEN
        SET v_reason = 'empalme con bloqueo de cuarto';
        LEAVE row_proc;
      END IF;

      SET v_note_text = CONCAT(
        'Monto capturado: ',
        COALESCE(NULLIF(TRIM(v_amount_raw), ''), 'N/D')
      );

      INSERT INTO guest (
        id_user,
        names,
        language,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        v_id_user,
        v_guest_name,
        'es',
        1,
        NOW(),
        v_id_user,
        NOW()
      );

      SET v_new_guest_id = LAST_INSERT_ID();

      SET v_new_reservation_code = CONCAT(
        'IMP-',
        DATE_FORMAT(NOW(), '%y%m%d'),
        '-',
        LPAD(v_id_import, 6, '0'),
        '-',
        UPPER(SUBSTRING(REPLACE(UUID(), '-', ''), 1, 4))
      );

      INSERT INTO reservation (
        id_user,
        id_guest,
        id_room,
        id_property,
        id_category,
        code,
        status,
        source,
        id_ota_account,
        id_reservation_source,
        check_in_date,
        check_out_date,
        adults,
        children,
        currency,
        total_price_cents,
        balance_due_cents,
        notes_internal,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        v_id_user,
        v_new_guest_id,
        v_room_id_db,
        v_id_property,
        v_id_category,
        v_new_reservation_code,
        'apartado',
        v_source_input,
        v_id_ota_account,
        v_id_reservation_source_match,
        v_check_in,
        v_check_out,
        1,
        0,
        'MXN',
        0,
        0,
        v_note_text,
        1,
        NOW(),
        v_id_user,
        NOW()
      );

      SET v_new_reservation_id = LAST_INSERT_ID();

      IF v_new_reservation_id IS NULL OR v_new_reservation_id <= 0 THEN
        SET v_reason = 'no se pudo insertar reservation';
        LEAVE row_proc;
      END IF;

      INSERT INTO reservation_note (
        id_reservation,
        note_type,
        note_text,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        v_new_reservation_id,
        'internal',
        v_note_text,
        1,
        NOW(),
        v_id_user,
        NOW()
      );
    END row_proc;

    IF v_sql_error = 1 THEN
      SET v_status = 'error';
      SET v_reason = CONCAT('SQL ERROR: ', COALESCE(v_sql_message, 'error'));
    ELSEIF v_reason IS NOT NULL AND v_reason <> '' THEN
      SET v_status = 'skipped';
    ELSE
      SET v_status = 'inserted';
    END IF;

    INSERT INTO tmp_reservation_import_log (
      id_import,
      result_status,
      reason,
      id_property,
      id_room,
      resolved_room_id,
      guest_name,
      check_in_date,
      check_out_date,
      origin_raw,
      source_used,
      id_ota_account,
      id_reservation_source,
      total_override_cents,
      id_reservation,
      reservation_code,
      created_at
    ) VALUES (
      v_id_import,
      v_status,
      v_reason,
      v_id_property,
      v_id_room,
      v_room_id_db,
      v_guest_name,
      v_check_in,
      v_check_out,
      v_origin_raw,
      v_source_input,
      v_id_ota_account,
      v_id_reservation_source_match,
      v_total_override_cents,
      v_new_reservation_id,
      v_new_reservation_code,
      NOW()
    );
  END LOOP;
  CLOSE cur;

  SELECT result_status, COUNT(*) AS total_rows
  FROM tmp_reservation_import_log
  GROUP BY result_status
  ORDER BY result_status;

  SELECT
    l.id_import,
    l.result_status,
    l.reason,
    l.id_property,
    l.id_room,
    l.guest_name,
    l.check_in_date,
    l.check_out_date,
    l.origin_raw,
    l.source_used,
    l.id_ota_account,
    l.id_reservation_source,
    l.total_override_cents,
    l.id_reservation,
    l.reservation_code
  FROM tmp_reservation_import_log l
  WHERE l.result_status <> 'inserted'
  ORDER BY l.id_import;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_income_catalog_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_show_inactive` TINYINT, IN `p_id_income_catalog` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    ic.id_line_item_catalog AS id_income_catalog,
    ic.id_property,
    p.code AS property_code,
    p.name AS property_name,
    ic.id_sale_item_catalog,
    sic.item_name AS sale_item_name,
    cat.category_name AS sale_item_category,
    ic.id_tax_rule,
    tr.name AS tax_rule_name,
    parent_map.parent_item_ids,
    ic.obligation_name AS income_name,
    ic.description,
    ic.is_percent,
    ic.percent_value,
    ic.default_amount_cents,
    ic.is_active,
    CASE
      WHEN ic.id_sale_item_catalog IS NOT NULL THEN 'sale_item'
      WHEN ic.id_tax_rule IS NOT NULL THEN 'tax_rule'
      ELSE 'manual'
    END AS source_type
  FROM line_item_catalog ic
  LEFT JOIN property p ON p.id_property = ic.id_property
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = ic.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = ic.id_tax_rule
   AND tr.catalog_type = 'tax_rule'
  LEFT JOIN (
    SELECT
      lcp.id_sale_item_catalog,
      GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids
    FROM line_item_catalog_parent lcp
    WHERE lcp.deleted_at IS NULL
      AND lcp.is_active = 1
    GROUP BY lcp.id_sale_item_catalog
  ) parent_map ON parent_map.id_sale_item_catalog = ic.id_line_item_catalog
  WHERE ic.catalog_type = 'income'
    AND ic.id_company = v_company_id
    AND ic.deleted_at IS NULL
    AND (p_show_inactive IS NOT NULL AND p_show_inactive <> 0 OR ic.is_active = 1)
    AND (v_property_id IS NULL OR ic.id_property IS NULL OR ic.id_property = v_property_id)
  ORDER BY ic.obligation_name;

  IF p_id_income_catalog IS NULL OR p_id_income_catalog = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_income_catalog,
      CAST(NULL AS SIGNED) AS id_property,
      CAST(NULL AS CHAR) AS property_code,
      CAST(NULL AS CHAR) AS property_name,
      CAST(NULL AS SIGNED) AS id_sale_item_catalog,
      CAST(NULL AS CHAR) AS sale_item_name,
      CAST(NULL AS CHAR) AS sale_item_category,
      CAST(NULL AS SIGNED) AS id_tax_rule,
      CAST(NULL AS CHAR) AS tax_rule_name,
      CAST(NULL AS CHAR) AS parent_item_ids,
      CAST(NULL AS CHAR) AS income_name,
      CAST(NULL AS CHAR) AS description,
      CAST(NULL AS SIGNED) AS is_percent,
      CAST(NULL AS DECIMAL(9,4)) AS percent_value,
      CAST(NULL AS SIGNED) AS default_amount_cents,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS CHAR) AS source_type
    LIMIT 0;
  ELSE
    SELECT
      ic.id_line_item_catalog AS id_income_catalog,
      ic.id_property,
      p.code AS property_code,
      p.name AS property_name,
      ic.id_sale_item_catalog,
      sic.item_name AS sale_item_name,
      cat.category_name AS sale_item_category,
      ic.id_tax_rule,
      tr.name AS tax_rule_name,
      parent_map.parent_item_ids,
      ic.obligation_name AS income_name,
      ic.description,
      ic.is_percent,
      ic.percent_value,
      ic.default_amount_cents,
      ic.is_active,
      CASE
        WHEN ic.id_sale_item_catalog IS NOT NULL THEN 'sale_item'
        WHEN ic.id_tax_rule IS NOT NULL THEN 'tax_rule'
        ELSE 'manual'
      END AS source_type
    FROM line_item_catalog ic
    LEFT JOIN property p ON p.id_property = ic.id_property
    LEFT JOIN line_item_catalog sic
      ON sic.id_line_item_catalog = ic.id_sale_item_catalog
     AND sic.catalog_type = 'sale_item'
    LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
    LEFT JOIN line_item_catalog tr
      ON tr.id_line_item_catalog = ic.id_tax_rule
     AND tr.catalog_type = 'tax_rule'
    LEFT JOIN (
      SELECT
        lcp.id_sale_item_catalog,
        GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids
      FROM line_item_catalog_parent lcp
      WHERE lcp.deleted_at IS NULL
        AND lcp.is_active = 1
      GROUP BY lcp.id_sale_item_catalog
    ) parent_map ON parent_map.id_sale_item_catalog = ic.id_line_item_catalog
    WHERE ic.id_line_item_catalog = p_id_income_catalog
      AND ic.catalog_type = 'income'
      AND ic.id_company = v_company_id
    LIMIT 1;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_income_catalog_upsert` (IN `p_action` VARCHAR(16), IN `p_id_income_catalog` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_id_sale_item_catalog` BIGINT, IN `p_id_tax_rule` BIGINT, IN `p_parent_ids` TEXT, IN `p_income_name` VARCHAR(255), IN `p_description` TEXT, IN `p_is_percent` TINYINT, IN `p_percent_value` DECIMAL(9,4), IN `p_default_amount_cents` INT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_sale_item_catalog_id BIGINT;
  DECLARE v_tax_rule_id BIGINT;
  DECLARE v_catalog_property_id BIGINT;
  DECLARE v_existing_id BIGINT;
  DECLARE v_action VARCHAR(16);
  DECLARE v_parent_ids TEXT;

  SET v_action = COALESCE(NULLIF(p_action,''),'create');
  IF v_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for income catalog';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_parent_ids = NULLIF(TRIM(p_parent_ids), '');

  IF v_parent_ids IS NULL THEN
    IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog <> 0
       AND p_id_tax_rule IS NOT NULL AND p_id_tax_rule <> 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Catalog must target sale_item or tax_rule, not both';
    END IF;
  END IF;

  IF v_parent_ids IS NOT NULL THEN
    SELECT
      MIN(CASE WHEN parent.catalog_type = 'sale_item' THEN parent.id_line_item_catalog END),
      MIN(CASE WHEN parent.catalog_type = 'tax_rule' THEN parent.id_line_item_catalog END)
      INTO v_sale_item_catalog_id, v_tax_rule_id
    FROM line_item_catalog parent
    LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = parent.id_category
    WHERE parent.deleted_at IS NULL
      AND FIND_IN_SET(parent.id_line_item_catalog, v_parent_ids)
      AND (
        (parent.catalog_type = 'sale_item' AND cat.id_company = v_company_id AND cat.deleted_at IS NULL)
        OR (parent.catalog_type = 'tax_rule' AND parent.id_company = v_company_id)
      )
      AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id);
    IF v_sale_item_catalog_id IS NULL AND v_tax_rule_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Parent catalog items not found';
    END IF;
  ELSE
    IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog <> 0 THEN
      SELECT lic.id_line_item_catalog, cat.id_property
        INTO v_sale_item_catalog_id, v_catalog_property_id
      FROM line_item_catalog lic
      JOIN sale_item_category cat ON cat.id_sale_item_category = lic.id_category
      WHERE lic.id_line_item_catalog = p_id_sale_item_catalog
        AND lic.catalog_type = 'sale_item'
        AND lic.deleted_at IS NULL
        AND cat.deleted_at IS NULL
        AND cat.id_company = v_company_id
      LIMIT 1;
      IF v_sale_item_catalog_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Sale item catalog not found';
      END IF;
      IF v_property_id IS NOT NULL
         AND v_catalog_property_id IS NOT NULL
         AND v_catalog_property_id <> v_property_id THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Catalog property mismatch';
      END IF;
    ELSE
      SET v_sale_item_catalog_id = NULL;
    END IF;

    IF p_id_tax_rule IS NOT NULL AND p_id_tax_rule <> 0 THEN
      SELECT id_line_item_catalog INTO v_tax_rule_id
      FROM line_item_catalog
      WHERE id_line_item_catalog = p_id_tax_rule
        AND catalog_type = 'tax_rule'
        AND id_company = v_company_id
        AND deleted_at IS NULL
      LIMIT 1;
      IF v_tax_rule_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Tax rule not found';
      END IF;
    ELSE
      SET v_tax_rule_id = NULL;
    END IF;
  END IF;

  IF v_action = 'create' THEN
    IF p_income_name IS NULL OR p_income_name = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Income name is required';
    END IF;
    INSERT INTO line_item_catalog (
      catalog_type,
      id_company,
      id_property,
      id_sale_item_catalog,
      id_tax_rule,
      obligation_name,
      description,
      is_percent,
      percent_value,
      default_amount_cents,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      'income',
      v_company_id,
      v_property_id,
      v_sale_item_catalog_id,
      v_tax_rule_id,
      p_income_name,
      p_description,
      COALESCE(p_is_percent,0),
      COALESCE(p_percent_value,0),
      COALESCE(p_default_amount_cents,0),
      COALESCE(p_is_active,1),
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET v_existing_id = LAST_INSERT_ID();
    IF v_parent_ids IS NOT NULL THEN
      UPDATE line_item_catalog_parent
         SET is_active = 0,
             deleted_at = NOW(),
             updated_at = NOW()
       WHERE id_sale_item_catalog = v_existing_id;
      INSERT INTO line_item_catalog_parent (
        id_sale_item_catalog,
        id_parent_sale_item_catalog,
        is_active,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_existing_id,
        parent.id_line_item_catalog,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      FROM line_item_catalog parent
      LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = parent.id_category
      WHERE parent.deleted_at IS NULL
        AND FIND_IN_SET(parent.id_line_item_catalog, v_parent_ids)
        AND (
          (parent.catalog_type = 'sale_item' AND cat.id_company = v_company_id AND cat.deleted_at IS NULL)
          OR (parent.catalog_type = 'tax_rule' AND parent.id_company = v_company_id)
        )
        AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
    CALL sp_income_sync_for_catalog(v_existing_id, p_actor_user_id);
    SELECT
      id_line_item_catalog AS id_income_catalog,
      id_company,
      id_property,
      id_sale_item_catalog,
      id_tax_rule,
      obligation_name AS income_name,
      description,
      is_percent,
      percent_value,
      default_amount_cents,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_existing_id;
    LEAVE proc;
  END IF;

  IF p_id_income_catalog IS NULL OR p_id_income_catalog = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Income catalog id is required';
  END IF;

  SELECT id_line_item_catalog INTO v_existing_id
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_income_catalog
    AND catalog_type = 'income'
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;
  IF v_existing_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Income catalog not found';
  END IF;

  IF v_action = 'delete' THEN
    UPDATE line_item_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item_catalog = v_existing_id;
    CALL sp_income_sync_for_catalog(v_existing_id, p_actor_user_id);
    SELECT
      id_line_item_catalog AS id_income_catalog,
      id_company,
      id_property,
      id_sale_item_catalog,
      id_tax_rule,
      obligation_name AS income_name,
      description,
      is_percent,
      percent_value,
      default_amount_cents,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_existing_id;
    LEAVE proc;
  END IF;

  UPDATE line_item_catalog
     SET id_property = v_property_id,
         id_sale_item_catalog = v_sale_item_catalog_id,
         id_tax_rule = v_tax_rule_id,
         obligation_name = COALESCE(p_income_name, obligation_name),
         description = p_description,
         is_percent = COALESCE(p_is_percent, is_percent),
         percent_value = COALESCE(p_percent_value, percent_value),
         default_amount_cents = COALESCE(p_default_amount_cents, default_amount_cents),
         is_active = COALESCE(p_is_active, is_active),
         updated_at = NOW()
   WHERE id_line_item_catalog = v_existing_id;

  IF v_parent_ids IS NOT NULL THEN
    UPDATE line_item_catalog_parent
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_sale_item_catalog = v_existing_id;
    IF v_parent_ids <> '' THEN
      INSERT INTO line_item_catalog_parent (
        id_sale_item_catalog,
        id_parent_sale_item_catalog,
        is_active,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_existing_id,
        parent.id_line_item_catalog,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      FROM line_item_catalog parent
      LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = parent.id_category
      WHERE parent.deleted_at IS NULL
        AND FIND_IN_SET(parent.id_line_item_catalog, v_parent_ids)
        AND (
          (parent.catalog_type = 'sale_item' AND cat.id_company = v_company_id AND cat.deleted_at IS NULL)
          OR (parent.catalog_type = 'tax_rule' AND parent.id_company = v_company_id)
        )
        AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  CALL sp_income_sync_for_catalog(v_existing_id, p_actor_user_id);
  SELECT
    id_line_item_catalog AS id_income_catalog,
    id_company,
    id_property,
    id_sale_item_catalog,
    id_tax_rule,
    obligation_name AS income_name,
    description,
    is_percent,
    percent_value,
    default_amount_cents,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item_catalog
  WHERE id_line_item_catalog = v_existing_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_income_report_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE, IN `p_status` VARCHAR(32), IN `p_type` VARCHAR(32), IN `p_catalog_id` BIGINT, IN `p_min_amount_cents` INT, IN `p_max_amount_cents` INT, IN `p_search` TEXT, IN `p_show_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_search TEXT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  DROP TEMPORARY TABLE IF EXISTS tmp_incomes;
  CREATE TEMPORARY TABLE tmp_incomes AS
  SELECT
    oi.id_line_item AS id_income_item,
    oc.id_line_item_catalog AS id_income_catalog,
    COALESCE(oi.obligation_name, oc.obligation_name) AS income_name,
    oc.description AS income_description,
    oc.is_percent,
    oc.percent_value,
    oc.default_amount_cents,
    oc.id_sale_item_catalog,
    oc.id_tax_rule,
    oi.id_reservation,
    oi.id_sale_item,
    oi.id_tax_item,
    oi.amount_cents,
    oi.paid_cents,
    GREATEST(oi.amount_cents - oi.paid_cents, 0) AS pending_cents,
    CASE
      WHEN oi.amount_cents <= oi.paid_cents THEN 'pagado'
      WHEN oi.paid_cents > 0 THEN 'parcial'
      ELSE 'pendiente'
    END AS status,
    CASE
      WHEN oi.id_sale_item IS NOT NULL THEN 'sale_item'
      WHEN oi.id_tax_item IS NOT NULL THEN 'tax_rule'
      ELSE 'manual'
    END AS source_type,
    oi.currency,
    oi.notes,
    oi.created_at,
    r.code AS reservation_code,
    CONCAT_WS(' ', COALESCE(g.names,''), COALESCE(g.last_name,'')) AS guest_name,
    g.email AS guest_email,
    g.phone AS guest_phone,
    p.code AS property_code,
    p.name AS property_name,
    sic.item_name AS sale_item_name,
    cat.category_name AS sale_item_category,
    tr.name AS tax_rule_name,
    oi.is_active,
    oi.deleted_at
  FROM line_item oi
  LEFT JOIN line_item_catalog oc
    ON oc.id_line_item_catalog = oi.id_obligation_catalog
   AND oc.catalog_type = 'income'
  LEFT JOIN reservation r ON r.id_reservation = oi.id_reservation
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  LEFT JOIN property p ON p.id_property = COALESCE(r.id_property, oc.id_property)
  LEFT JOIN line_item si
    ON si.id_line_item = oi.id_sale_item
   AND si.item_type = 'sale_item'
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = si.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN line_item ti
    ON ti.id_line_item = oi.id_tax_item
   AND ti.item_type = 'tax_item'
  LEFT JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = ti.id_tax_rule
   AND tr.catalog_type = 'tax_rule'
  WHERE (
      (oc.id_company = v_company_id AND oc.deleted_at IS NULL)
      OR (oc.id_company IS NULL AND r.id_reservation IS NOT NULL AND p.id_company = v_company_id)
    )
    AND (r.id_reservation IS NULL OR r.deleted_at IS NULL)
    AND oi.item_type = 'income'
    AND (v_property_id IS NULL OR COALESCE(r.id_property, oc.id_property) = v_property_id)
    AND (p_from IS NULL OR DATE(oi.created_at) >= p_from)
    AND (p_to IS NULL OR DATE(oi.created_at) <= p_to)
    AND (p_catalog_id IS NULL OR p_catalog_id = 0 OR oc.id_line_item_catalog = p_catalog_id)
    AND (
      p_min_amount_cents IS NULL
      OR p_min_amount_cents <= 0
      OR oi.amount_cents >= p_min_amount_cents
    )
    AND (
      p_max_amount_cents IS NULL
      OR p_max_amount_cents <= 0
      OR oi.amount_cents <= p_max_amount_cents
    )
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR (oi.deleted_at IS NULL AND oi.is_active = 1)
    )
    AND (
      v_search IS NULL
      OR COALESCE(oi.obligation_name, oc.obligation_name) LIKE CONCAT('%', v_search, '%')
      OR oc.description LIKE CONCAT('%', v_search, '%')
      OR r.code LIKE CONCAT('%', v_search, '%')
      OR g.names LIKE CONCAT('%', v_search, '%')
      OR g.last_name LIKE CONCAT('%', v_search, '%')
      OR g.email LIKE CONCAT('%', v_search, '%')
      OR g.phone LIKE CONCAT('%', v_search, '%')
      OR oi.notes LIKE CONCAT('%', v_search, '%')
      OR sic.item_name LIKE CONCAT('%', v_search, '%')
      OR tr.name LIKE CONCAT('%', v_search, '%')
    );

  SELECT
    id_income_item,
    id_income_catalog,
    income_name,
    income_description,
    source_type,
    amount_cents,
    paid_cents,
    pending_cents,
    status,
    currency,
    notes,
    created_at,
    reservation_code,
    guest_name,
    guest_email,
    guest_phone,
    property_code,
    property_name,
    sale_item_name,
    sale_item_category,
    tax_rule_name
  FROM tmp_incomes
  WHERE (p_status IS NULL OR p_status = '' OR status = p_status)
    AND (p_type IS NULL OR p_type = '' OR source_type = p_type)
  ORDER BY created_at DESC, id_income_item DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_income_sync_for_catalog` (IN `p_id_income_catalog` BIGINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_sale_item_catalog_id BIGINT;
  DECLARE v_tax_rule_id BIGINT;
  DECLARE v_income_name VARCHAR(255);
  DECLARE v_is_percent TINYINT DEFAULT 0;
  DECLARE v_percent_value DECIMAL(9,4) DEFAULT 0;
  DECLARE v_default_amount INT DEFAULT 0;
  DECLARE v_is_active TINYINT DEFAULT 0;
  DECLARE v_target_sale_item_id BIGINT;
  DECLARE v_target_tax_item_id BIGINT;
  DECLARE v_has_sale_parent INT DEFAULT 0;
  DECLARE v_has_tax_parent INT DEFAULT 0;

  IF p_id_income_catalog IS NULL OR p_id_income_catalog = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'income catalog id is required';
  END IF;

  SELECT id_company,
         id_property,
         id_sale_item_catalog,
         id_tax_rule,
         obligation_name,
         is_percent,
         percent_value,
         default_amount_cents,
         is_active
    INTO v_company_id,
         v_property_id,
         v_sale_item_catalog_id,
         v_tax_rule_id,
         v_income_name,
         v_is_percent,
         v_percent_value,
         v_default_amount,
         v_is_active
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_income_catalog
    AND catalog_type = 'income'
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'income catalog not found';
  END IF;

  IF v_is_active = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND id_obligation_catalog = p_id_income_catalog
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  SELECT COUNT(*)
    INTO v_has_sale_parent
  FROM line_item_catalog_parent lcp
  JOIN line_item_catalog parent
    ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
   AND parent.catalog_type = 'sale_item'
   AND parent.deleted_at IS NULL
   AND parent.is_active = 1
  WHERE lcp.id_sale_item_catalog = p_id_income_catalog
    AND lcp.deleted_at IS NULL
    AND lcp.is_active = 1
    AND parent.id_company = v_company_id
    AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id);

  SELECT COUNT(*)
    INTO v_has_tax_parent
  FROM line_item_catalog_parent lcp
  JOIN line_item_catalog parent
    ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
   AND parent.catalog_type = 'tax_rule'
   AND parent.deleted_at IS NULL
   AND parent.is_active = 1
  WHERE lcp.id_sale_item_catalog = p_id_income_catalog
    AND lcp.deleted_at IS NULL
    AND lcp.is_active = 1
    AND parent.id_company = v_company_id;

  IF v_has_sale_parent > 0 THEN
    DROP TEMPORARY TABLE IF EXISTS tmp_income_sale_items;
    CREATE TEMPORARY TABLE tmp_income_sale_items (
      id_sale_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_income_sale_items (id_sale_item)
    SELECT si.id_line_item
    FROM line_item si
    JOIN reservation r ON r.id_reservation = si.id_reservation
    JOIN property p ON p.id_property = r.id_property
    WHERE si.item_type = 'sale_item'
      AND si.id_sale_item_catalog IN (
          SELECT parent.id_line_item_catalog
          FROM line_item_catalog_parent lcp
          JOIN line_item_catalog parent
            ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
           AND parent.catalog_type = 'sale_item'
           AND parent.deleted_at IS NULL
           AND parent.is_active = 1
          WHERE lcp.id_sale_item_catalog = p_id_income_catalog
            AND lcp.deleted_at IS NULL
            AND lcp.is_active = 1
            AND parent.id_company = v_company_id
            AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id)
      )
      AND si.deleted_at IS NULL
      AND si.is_active = 1
      AND r.deleted_at IS NULL
      AND p.deleted_at IS NULL
      AND p.id_company = v_company_id
      AND (v_property_id IS NULL OR r.id_property = v_property_id);

    WHILE (SELECT COUNT(*) FROM tmp_income_sale_items) > 0 DO
      SELECT id_sale_item
        INTO v_target_sale_item_id
      FROM tmp_income_sale_items
      LIMIT 1;

      DELETE FROM tmp_income_sale_items WHERE id_sale_item = v_target_sale_item_id;

      CALL sp_income_sync_for_sale_item(v_target_sale_item_id, p_actor_user_id);
    END WHILE;
  ELSE
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND id_sale_item IS NOT NULL
       AND id_obligation_catalog = p_id_income_catalog
       AND deleted_at IS NULL;
  END IF;

  UPDATE line_item ii
  LEFT JOIN line_item si
    ON si.id_line_item = ii.id_sale_item
   AND si.item_type = 'sale_item'
   AND si.deleted_at IS NULL
   AND si.is_active = 1
  LEFT JOIN reservation r
    ON r.id_reservation = si.id_reservation
   AND r.deleted_at IS NULL
  LEFT JOIN property p
    ON p.id_property = r.id_property
   AND p.deleted_at IS NULL
  SET ii.is_active = 0,
      ii.deleted_at = NOW(),
      ii.updated_at = NOW()
  WHERE ii.item_type = 'income'
    AND ii.id_obligation_catalog = p_id_income_catalog
    AND ii.id_sale_item IS NOT NULL
    AND ii.deleted_at IS NULL
    AND (si.id_line_item IS NULL
         OR r.id_reservation IS NULL
         OR p.id_company <> v_company_id
         OR (v_property_id IS NOT NULL AND r.id_property <> v_property_id));

  IF v_has_tax_parent > 0 THEN
    DROP TEMPORARY TABLE IF EXISTS tmp_income_tax_items;
    CREATE TEMPORARY TABLE tmp_income_tax_items (
      id_tax_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_income_tax_items (id_tax_item)
    SELECT ti.id_line_item
    FROM line_item ti
    JOIN line_item si
      ON si.id_line_item = ti.id_sale_item
     AND si.item_type = 'sale_item'
    JOIN reservation r ON r.id_reservation = si.id_reservation
    JOIN property p ON p.id_property = r.id_property
    WHERE ti.item_type = 'tax_item'
      AND ti.id_tax_rule IN (
          SELECT parent.id_line_item_catalog
          FROM line_item_catalog_parent lcp
          JOIN line_item_catalog parent
            ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
           AND parent.catalog_type = 'tax_rule'
           AND parent.deleted_at IS NULL
           AND parent.is_active = 1
          WHERE lcp.id_sale_item_catalog = p_id_income_catalog
            AND lcp.deleted_at IS NULL
            AND lcp.is_active = 1
            AND parent.id_company = v_company_id
      )
      AND ti.deleted_at IS NULL
      AND ti.is_active = 1
      AND si.deleted_at IS NULL
      AND si.is_active = 1
      AND r.deleted_at IS NULL
      AND p.deleted_at IS NULL
      AND p.id_company = v_company_id
      AND (v_property_id IS NULL OR r.id_property = v_property_id);

    WHILE (SELECT COUNT(*) FROM tmp_income_tax_items) > 0 DO
      SELECT id_tax_item
        INTO v_target_tax_item_id
      FROM tmp_income_tax_items
      LIMIT 1;

      DELETE FROM tmp_income_tax_items WHERE id_tax_item = v_target_tax_item_id;

      CALL sp_income_sync_for_tax_item(v_target_tax_item_id, p_actor_user_id);
    END WHILE;
  ELSE
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND id_tax_item IS NOT NULL
       AND id_obligation_catalog = p_id_income_catalog
       AND deleted_at IS NULL;
  END IF;

  UPDATE line_item ii
  LEFT JOIN line_item ti
    ON ti.id_line_item = ii.id_tax_item
   AND ti.item_type = 'tax_item'
  LEFT JOIN line_item si
    ON si.id_line_item = ti.id_sale_item
   AND si.item_type = 'sale_item'
   AND si.deleted_at IS NULL
   AND si.is_active = 1
  LEFT JOIN reservation r
    ON r.id_reservation = si.id_reservation
   AND r.deleted_at IS NULL
  LEFT JOIN property p
    ON p.id_property = r.id_property
   AND p.deleted_at IS NULL
  SET ii.is_active = 0,
      ii.deleted_at = NOW(),
      ii.updated_at = NOW()
  WHERE ii.item_type = 'income'
    AND ii.id_obligation_catalog = p_id_income_catalog
    AND ii.id_tax_item IS NOT NULL
    AND ii.deleted_at IS NULL
    AND (ti.id_line_item IS NULL
         OR ti.deleted_at IS NOT NULL
         OR ti.is_active = 0
         OR si.id_line_item IS NULL
         OR r.id_reservation IS NULL
         OR p.id_company <> v_company_id
         OR (v_property_id IS NOT NULL AND r.id_property <> v_property_id));
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_income_sync_for_sale_item` (IN `p_id_sale_item` BIGINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_reservation_id BIGINT;
  DECLARE v_folio_id BIGINT;
  DECLARE v_sale_item_catalog_id BIGINT;
  DECLARE v_amount_cents INT DEFAULT 0;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_is_active TINYINT DEFAULT 0;
  DECLARE v_deleted_at DATETIME;
  DECLARE v_tax_item_id BIGINT;
  DECLARE v_base_amount_cents INT DEFAULT 0;
  DECLARE v_income_catalog_id BIGINT;
  DECLARE v_income_name VARCHAR(255);
  DECLARE v_income_is_percent TINYINT DEFAULT 0;
  DECLARE v_income_percent DECIMAL(9,4) DEFAULT 0;
  DECLARE v_income_default INT DEFAULT 0;
  DECLARE v_income_amount INT DEFAULT 0;
  DECLARE v_calc_count INT DEFAULT 0;
  DECLARE v_calc_adjust INT DEFAULT 0;
  DECLARE v_calc_component_id BIGINT;
  DECLARE v_calc_is_positive TINYINT;
  DECLARE v_calc_component_sum INT DEFAULT 0;
  DECLARE v_calc_component_type VARCHAR(16);
  DECLARE v_calc_parent_id BIGINT;
  DECLARE v_calc_component_item_id BIGINT;
  DECLARE done INT DEFAULT 0;

  DECLARE tax_cur CURSOR FOR
    SELECT id_line_item
    FROM line_item
    WHERE item_type = 'tax_item'
      AND id_sale_item = p_id_sale_item
      AND deleted_at IS NULL
      AND is_active = 1;
  DECLARE income_cur CURSOR FOR
    SELECT lic.id_line_item_catalog,
           lic.obligation_name,
           lic.is_percent,
           lic.percent_value,
           lic.default_amount_cents
    FROM line_item_catalog lic
    JOIN line_item_catalog_parent lcp
      ON lcp.id_sale_item_catalog = lic.id_line_item_catalog
     AND lcp.id_parent_sale_item_catalog = v_sale_item_catalog_id
     AND lcp.deleted_at IS NULL
     AND lcp.is_active = 1
    WHERE lic.catalog_type = 'income'
      AND lic.id_company = v_company_id
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND (lic.id_property IS NULL OR lic.id_property = v_property_id);
  DECLARE calc_cur CURSOR FOR
    SELECT id_component_line_item_catalog,
           is_positive
    FROM line_item_catalog_calc
    WHERE id_line_item_catalog = v_income_catalog_id
      AND id_parent_line_item_catalog = v_sale_item_catalog_id
      AND deleted_at IS NULL
      AND is_active = 1;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  IF p_id_sale_item IS NULL OR p_id_sale_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item id is required';
  END IF;

  SELECT
    si.id_sale_item_catalog,
    si.id_folio,
    si.amount_cents,
    si.is_active,
    si.deleted_at,
    r.id_reservation,
    r.id_property,
    p.id_company,
    COALESCE(si.currency, 'MXN')
  INTO v_sale_item_catalog_id,
       v_folio_id,
       v_amount_cents,
       v_is_active,
       v_deleted_at,
       v_reservation_id,
       v_property_id,
       v_company_id,
       v_currency
  FROM line_item si
  JOIN folio f ON f.id_folio = si.id_folio
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  WHERE si.id_line_item = p_id_sale_item
    AND si.item_type = 'sale_item'
    AND f.deleted_at IS NULL
    AND r.deleted_at IS NULL
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item not found';
  END IF;

  IF v_deleted_at IS NOT NULL OR v_is_active = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND (id_sale_item = p_id_sale_item
        OR id_tax_item IN (
          SELECT id_line_item
          FROM line_item
          WHERE item_type = 'tax_item'
            AND id_sale_item = p_id_sale_item
        ))
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  IF (SELECT COUNT(*)
        FROM line_item_catalog_parent lcp
        JOIN line_item_catalog ic
          ON ic.id_line_item_catalog = lcp.id_sale_item_catalog
         AND ic.catalog_type = 'income'
       WHERE lcp.id_parent_sale_item_catalog = v_sale_item_catalog_id
         AND lcp.deleted_at IS NULL
         AND lcp.is_active = 1
         AND ic.id_company = v_company_id
         AND ic.deleted_at IS NULL
         AND ic.is_active = 1
         AND (ic.id_property IS NULL OR ic.id_property = v_property_id)) = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND id_sale_item = p_id_sale_item
       AND deleted_at IS NULL;
  ELSE
    SET v_base_amount_cents = v_amount_cents;

    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_queue;
    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_all;
    CREATE TEMPORARY TABLE tmp_calc_parent_queue (
      id_sale_item BIGINT PRIMARY KEY
    );
    CREATE TEMPORARY TABLE tmp_calc_parent_all (
      id_sale_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
    VALUES (p_id_sale_item);
    INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
    VALUES (p_id_sale_item);

    parent_calc_loop:WHILE (SELECT COUNT(*) FROM tmp_calc_parent_queue) > 0 DO
      SELECT id_sale_item
        INTO v_calc_parent_id
      FROM tmp_calc_parent_queue
      LIMIT 1;

      DELETE FROM tmp_calc_parent_queue WHERE id_sale_item = v_calc_parent_id;

      INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;

      INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;
    END WHILE;

    SET done = 0;
    OPEN income_cur;
    income_loop: LOOP
      FETCH income_cur
        INTO v_income_catalog_id,
             v_income_name,
             v_income_is_percent,
             v_income_percent,
             v_income_default;
      IF done = 1 THEN
        LEAVE income_loop;
      END IF;

      SELECT COUNT(*)
        INTO v_calc_count
      FROM line_item_catalog_calc lcc
      WHERE lcc.id_line_item_catalog = v_income_catalog_id
        AND lcc.id_parent_line_item_catalog = v_sale_item_catalog_id
        AND lcc.deleted_at IS NULL
        AND lcc.is_active = 1;

      SET v_calc_adjust = 0;
      IF v_calc_count > 0 THEN
        SET done = 0;
        OPEN calc_cur;
        calc_loop: LOOP
          FETCH calc_cur INTO v_calc_component_id, v_calc_is_positive;
          IF done = 1 THEN
            LEAVE calc_loop;
          END IF;

          SELECT catalog_type
            INTO v_calc_component_type
          FROM line_item_catalog
          WHERE id_line_item_catalog = v_calc_component_id
          LIMIT 1;

          SET v_calc_component_sum = 0;

          IF v_calc_component_type = 'sale_item' THEN
            DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_queue;
            DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_all;
            CREATE TEMPORARY TABLE tmp_calc_comp_queue (
              id_sale_item BIGINT PRIMARY KEY
            );
            CREATE TEMPORARY TABLE tmp_calc_comp_all (
              id_sale_item BIGINT PRIMARY KEY
            );

            INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
            SELECT li.id_line_item
            FROM line_item li
            JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
            WHERE li.item_type = 'sale_item'
              AND li.id_sale_item_catalog = v_calc_component_id
              AND li.deleted_at IS NULL
              AND li.is_active = 1;

            INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
            SELECT id_sale_item FROM tmp_calc_comp_queue;

            comp_calc_loop: WHILE (SELECT COUNT(*) FROM tmp_calc_comp_queue) > 0 DO
              SELECT id_sale_item
                INTO v_calc_component_item_id
              FROM tmp_calc_comp_queue
              LIMIT 1;

              DELETE FROM tmp_calc_comp_queue WHERE id_sale_item = v_calc_component_item_id;

              INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
              SELECT li.id_line_item
              FROM line_item li
              JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
              WHERE li.item_type = 'sale_item'
                AND li.id_parent_sale_item = v_calc_component_item_id
                AND li.deleted_at IS NULL
                AND li.is_active = 1;

              INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
              SELECT li.id_line_item
              FROM line_item li
              JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
              WHERE li.item_type = 'sale_item'
                AND li.id_parent_sale_item = v_calc_component_item_id
                AND li.deleted_at IS NULL
                AND li.is_active = 1;
            END WHILE;

          SELECT COALESCE(SUM(li.amount_cents),0)
            INTO v_calc_component_sum
          FROM line_item li
          WHERE li.item_type = 'sale_item'
            AND li.id_line_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
          SELECT v_calc_component_sum + COALESCE(SUM(ti.amount_cents),0)
            INTO v_calc_component_sum
          FROM line_item ti
          WHERE ti.item_type = 'tax_item'
            AND ti.deleted_at IS NULL
            AND ti.is_active = 1
            AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
          ELSEIF v_calc_component_type = 'tax_rule' THEN
            SELECT COALESCE(SUM(ti.amount_cents),0)
              INTO v_calc_component_sum
            FROM line_item ti
            WHERE ti.item_type = 'tax_item'
              AND ti.id_tax_rule = v_calc_component_id
              AND ti.deleted_at IS NULL
              AND ti.is_active = 1
              AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all);
          ELSE
            SELECT COALESCE(SUM(li.amount_cents),0)
              INTO v_calc_component_sum
            FROM line_item li
            WHERE li.id_line_item_catalog = v_calc_component_id
              AND li.deleted_at IS NULL
              AND li.is_active = 1
              AND (
                (li.item_type IN ('obligation','income') AND li.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all))
                OR (li.item_type = 'obligation' AND li.id_tax_item IN (
                    SELECT id_line_item
                    FROM line_item
                    WHERE item_type = 'tax_item'
                      AND id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all)
                      AND deleted_at IS NULL
                      AND is_active = 1
                ))
              );
          END IF;

          IF v_calc_is_positive = 1 THEN
            SET v_calc_adjust = v_calc_adjust + v_calc_component_sum;
          ELSE
            SET v_calc_adjust = v_calc_adjust - v_calc_component_sum;
          END IF;
        END LOOP;
        CLOSE calc_cur;
        SET done = 0;
      END IF;

      IF v_calc_count > 0 THEN
        IF v_income_is_percent = 1 THEN
          SET v_income_amount = ROUND((v_base_amount_cents + v_calc_adjust) * (v_income_percent / 100));
        ELSE
          SET v_income_amount = v_base_amount_cents + v_calc_adjust + COALESCE(v_income_default,0);
        END IF;
      ELSE
        IF v_income_is_percent = 1 THEN
          SET v_income_amount = ROUND(v_base_amount_cents * (v_income_percent / 100));
        ELSE
          SET v_income_amount = COALESCE(v_income_default,0);
        END IF;
      END IF;

      IF v_income_amount IS NULL OR v_income_amount = 0 THEN
        ITERATE income_loop;
      END IF;

      INSERT INTO line_item (
        item_type,
        id_line_item_catalog,
        id_obligation_catalog,
        obligation_name,
        id_reservation,
        id_sale_item,
        id_tax_item,
        amount_cents,
        paid_cents,
        currency,
        notes,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        'income',
        v_income_catalog_id,
        v_income_catalog_id,
        COALESCE(v_income_name, ''),
        v_reservation_id,
        p_id_sale_item,
        NULL,
        v_income_amount,
        0,
        v_currency,
        NULL,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      )
      ON DUPLICATE KEY UPDATE
        id_reservation = VALUES(id_reservation),
        obligation_name = VALUES(obligation_name),
        amount_cents = VALUES(amount_cents),
        currency = VALUES(currency),
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END LOOP;
    CLOSE income_cur;
    SET done = 0;
  END IF;

  UPDATE line_item ii
  LEFT JOIN line_item si
    ON si.id_line_item = ii.id_sale_item
   AND si.item_type = 'sale_item'
   AND si.deleted_at IS NULL
   AND si.is_active = 1
  LEFT JOIN reservation r
    ON r.id_reservation = si.id_reservation
   AND r.deleted_at IS NULL
  LEFT JOIN property p
    ON p.id_property = r.id_property
   AND p.deleted_at IS NULL
  SET ii.is_active = 0,
      ii.deleted_at = NOW(),
      ii.updated_at = NOW()
  WHERE ii.item_type = 'income'
    AND ii.id_sale_item = p_id_sale_item
    AND ii.deleted_at IS NULL
    AND (si.id_line_item IS NULL
         OR r.id_reservation IS NULL
         OR p.id_company <> v_company_id
         OR (v_property_id IS NOT NULL AND r.id_property <> v_property_id));

  SET done = 0;
  OPEN tax_cur;
  tax_loop: LOOP
    FETCH tax_cur INTO v_tax_item_id;
    IF done = 1 THEN
      LEAVE tax_loop;
    END IF;
    CALL sp_income_sync_for_tax_item(v_tax_item_id, p_actor_user_id);
  END LOOP;
  CLOSE tax_cur;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_income_sync_for_tax_item` (IN `p_id_tax_item` BIGINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_reservation_id BIGINT;
  DECLARE v_tax_rule_id BIGINT;
  DECLARE v_sale_item_id BIGINT;
  DECLARE v_amount_cents INT DEFAULT 0;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_is_active TINYINT DEFAULT 0;
  DECLARE v_deleted_at DATETIME;
  DECLARE v_preferred_catalog_id BIGINT;
  DECLARE v_income_name VARCHAR(255);
  DECLARE v_income_is_percent TINYINT DEFAULT 0;
  DECLARE v_income_percent DECIMAL(9,4) DEFAULT 0;
  DECLARE v_income_default INT DEFAULT 0;
  DECLARE v_income_amount INT DEFAULT 0;
  DECLARE v_calc_count INT DEFAULT 0;
  DECLARE v_calc_adjust INT DEFAULT 0;
  DECLARE v_calc_component_id BIGINT;
  DECLARE v_calc_is_positive TINYINT;
  DECLARE v_calc_component_sum INT DEFAULT 0;
  DECLARE v_calc_component_type VARCHAR(16);
  DECLARE v_calc_parent_id BIGINT;
  DECLARE v_calc_component_item_id BIGINT;
  DECLARE done INT DEFAULT 0;

  DECLARE calc_cur CURSOR FOR
    SELECT id_component_line_item_catalog,
           is_positive
    FROM line_item_catalog_calc
    WHERE id_line_item_catalog = v_preferred_catalog_id
      AND id_parent_line_item_catalog = v_tax_rule_id
      AND deleted_at IS NULL
      AND is_active = 1;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  IF p_id_tax_item IS NULL OR p_id_tax_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_item id is required';
  END IF;

  SELECT
    ti.id_tax_rule,
    ti.amount_cents,
    ti.is_active,
    ti.deleted_at,
    r.id_reservation,
    r.id_property,
    p.id_company,
    COALESCE(si.currency, 'MXN'),
    ti.id_sale_item
  INTO v_tax_rule_id,
       v_amount_cents,
       v_is_active,
       v_deleted_at,
       v_reservation_id,
       v_property_id,
       v_company_id,
       v_currency,
       v_sale_item_id
  FROM line_item ti
  JOIN line_item si
    ON si.id_line_item = ti.id_sale_item
   AND si.item_type = 'sale_item'
  JOIN folio f ON f.id_folio = si.id_folio
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  WHERE ti.id_line_item = p_id_tax_item
    AND ti.item_type = 'tax_item'
    AND f.deleted_at IS NULL
    AND r.deleted_at IS NULL
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_item not found';
  END IF;

  IF v_deleted_at IS NOT NULL OR v_is_active = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND id_tax_item = p_id_tax_item
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  SELECT ic.id_line_item_catalog
    INTO v_preferred_catalog_id
  FROM line_item_catalog ic
  JOIN line_item_catalog_parent lcp
    ON lcp.id_sale_item_catalog = ic.id_line_item_catalog
   AND lcp.id_parent_sale_item_catalog = v_tax_rule_id
   AND lcp.deleted_at IS NULL
   AND lcp.is_active = 1
  WHERE ic.catalog_type = 'income'
    AND ic.id_company = v_company_id
    AND ic.deleted_at IS NULL
    AND ic.is_active = 1
    AND (ic.id_property IS NULL OR ic.id_property = v_property_id)
  ORDER BY (ic.id_property IS NULL) ASC, ic.id_property DESC, ic.id_line_item_catalog DESC
  LIMIT 1;

  IF v_preferred_catalog_id IS NULL THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'income'
       AND id_tax_item = p_id_tax_item
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  SELECT obligation_name,
         is_percent,
         percent_value,
         default_amount_cents
    INTO v_income_name,
         v_income_is_percent,
         v_income_percent,
         v_income_default
  FROM line_item_catalog
  WHERE id_line_item_catalog = v_preferred_catalog_id
  LIMIT 1;

  SELECT COUNT(*)
    INTO v_calc_count
  FROM line_item_catalog_calc lcc
  WHERE lcc.id_line_item_catalog = v_preferred_catalog_id
    AND lcc.id_parent_line_item_catalog = v_tax_rule_id
    AND lcc.deleted_at IS NULL
    AND lcc.is_active = 1;

  SET v_calc_adjust = 0;
  IF v_calc_count > 0 AND v_sale_item_id IS NOT NULL AND v_sale_item_id <> 0 THEN
    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_queue;
    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_all;
    CREATE TEMPORARY TABLE tmp_calc_parent_queue (
      id_sale_item BIGINT PRIMARY KEY
    );
    CREATE TEMPORARY TABLE tmp_calc_parent_all (
      id_sale_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
    VALUES (v_sale_item_id);
    INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
    VALUES (v_sale_item_id);

    parent_calc_loop:WHILE (SELECT COUNT(*) FROM tmp_calc_parent_queue) > 0 DO
      SELECT id_sale_item
        INTO v_calc_parent_id
      FROM tmp_calc_parent_queue
      LIMIT 1;

      DELETE FROM tmp_calc_parent_queue WHERE id_sale_item = v_calc_parent_id;

      INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;

      INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;
    END WHILE;

    SET done = 0;
    OPEN calc_cur;
    calc_loop: LOOP
      FETCH calc_cur INTO v_calc_component_id, v_calc_is_positive;
      IF done = 1 THEN
        LEAVE calc_loop;
      END IF;

      SELECT catalog_type
        INTO v_calc_component_type
      FROM line_item_catalog
      WHERE id_line_item_catalog = v_calc_component_id
      LIMIT 1;

      SET v_calc_component_sum = 0;

      IF v_calc_component_type = 'sale_item' THEN
        DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_queue;
        DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_all;
        CREATE TEMPORARY TABLE tmp_calc_comp_queue (
          id_sale_item BIGINT PRIMARY KEY
        );
        CREATE TEMPORARY TABLE tmp_calc_comp_all (
          id_sale_item BIGINT PRIMARY KEY
        );

        INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
        SELECT li.id_line_item
        FROM line_item li
        JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
        WHERE li.item_type = 'sale_item'
          AND li.id_sale_item_catalog = v_calc_component_id
          AND li.deleted_at IS NULL
          AND li.is_active = 1;

        INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
        SELECT id_sale_item FROM tmp_calc_comp_queue;

        comp_calc_loop: WHILE (SELECT COUNT(*) FROM tmp_calc_comp_queue) > 0 DO
          SELECT id_sale_item
            INTO v_calc_component_item_id
          FROM tmp_calc_comp_queue
          LIMIT 1;

          DELETE FROM tmp_calc_comp_queue WHERE id_sale_item = v_calc_component_item_id;

          INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
          SELECT li.id_line_item
          FROM line_item li
          JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
          WHERE li.item_type = 'sale_item'
            AND li.id_parent_sale_item = v_calc_component_item_id
            AND li.deleted_at IS NULL
            AND li.is_active = 1;

          INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
          SELECT li.id_line_item
          FROM line_item li
          JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
          WHERE li.item_type = 'sale_item'
            AND li.id_parent_sale_item = v_calc_component_item_id
            AND li.deleted_at IS NULL
            AND li.is_active = 1;
        END WHILE;

        SELECT COALESCE(SUM(li.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item li
        WHERE li.item_type = 'sale_item'
          AND li.id_line_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
      ELSEIF v_calc_component_type = 'tax_rule' THEN
        SELECT COALESCE(SUM(ti.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item ti
        WHERE ti.item_type = 'tax_item'
          AND ti.id_tax_rule = v_calc_component_id
          AND ti.deleted_at IS NULL
          AND ti.is_active = 1
          AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all);
      ELSE
        SELECT COALESCE(SUM(li.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item li
        WHERE li.id_line_item_catalog = v_calc_component_id
          AND li.deleted_at IS NULL
          AND li.is_active = 1
          AND (
            (li.item_type IN ('obligation','income') AND li.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all))
            OR (li.item_type = 'obligation' AND li.id_tax_item IN (
                SELECT id_line_item
                FROM line_item
                WHERE item_type = 'tax_item'
                  AND id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all)
                  AND deleted_at IS NULL
                  AND is_active = 1
            ))
          );
      END IF;

      IF v_calc_is_positive = 1 THEN
        SET v_calc_adjust = v_calc_adjust + v_calc_component_sum;
      ELSE
        SET v_calc_adjust = v_calc_adjust - v_calc_component_sum;
      END IF;
    END LOOP;
    CLOSE calc_cur;
    SET done = 0;
  END IF;

  IF v_calc_count > 0 THEN
    IF v_income_is_percent = 1 THEN
      SET v_income_amount = ROUND((v_amount_cents + v_calc_adjust) * (v_income_percent / 100));
    ELSE
      SET v_income_amount = v_amount_cents + v_calc_adjust + COALESCE(v_income_default,0);
    END IF;
  ELSE
    IF v_income_is_percent = 1 THEN
      SET v_income_amount = ROUND(v_amount_cents * (v_income_percent / 100));
    ELSE
      SET v_income_amount = COALESCE(v_income_default,0);
    END IF;
  END IF;

  INSERT INTO line_item (
    item_type,
    id_line_item_catalog,
    id_obligation_catalog,
    obligation_name,
    id_reservation,
    id_sale_item,
    id_tax_item,
    amount_cents,
    paid_cents,
    currency,
    notes,
    is_active,
    created_at,
    created_by,
    updated_at
  ) VALUES (
    'income',
    v_preferred_catalog_id,
    v_preferred_catalog_id,
    v_income_name,
    v_reservation_id,
    NULL,
    p_id_tax_item,
    v_income_amount,
    0,
    v_currency,
    NULL,
    1,
    NOW(),
    p_actor_user_id,
    NOW()
  )
  ON DUPLICATE KEY UPDATE
    id_reservation = VALUES(id_reservation),
    obligation_name = VALUES(obligation_name),
    amount_cents = VALUES(amount_cents),
    currency = VALUES(currency),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_line_item_payment_meta_upsert` (IN `p_id_line_item` BIGINT, IN `p_method` VARCHAR(120), IN `p_reference` VARCHAR(255), IN `p_status` VARCHAR(32), IN `p_service_date` DATE, IN `p_updated_by` BIGINT)   BEGIN
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  IF p_id_line_item IS NULL OR p_id_line_item <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line_item id is required';
  END IF;

  SELECT c.code, p.code
    INTO v_company_code, v_property_code
  FROM line_item li
  JOIN folio f ON f.id_folio = li.id_folio
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  JOIN company c ON c.id_company = p.id_company
  WHERE li.id_line_item = p_id_line_item
    AND li.deleted_at IS NULL
  LIMIT 1;

  IF v_company_code IS NULL OR v_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment line item not found';
  END IF;

  CALL sp_authz_assert(
    v_company_code,
    p_updated_by,
    'payments.edit',
    v_property_code,
    NULL
  );

  UPDATE line_item
     SET method = CASE
                    WHEN p_method IS NULL OR TRIM(p_method) = '' THEN method
                    ELSE p_method
                  END,
         reference = CASE
                       WHEN p_reference IS NULL THEN reference
                       ELSE p_reference
                     END,
         status = CASE
                    WHEN p_status IS NULL OR TRIM(p_status) = '' THEN status
                    ELSE p_status
                  END,
         service_date = COALESCE(p_service_date, service_date),
         updated_at = NOW()
   WHERE id_line_item = p_id_line_item
     AND item_type = 'payment'
     AND deleted_at IS NULL;

  SELECT
    id_line_item,
    item_type,
    id_folio,
    id_line_item_catalog,
    item_name,
    method,
    reference,
    status,
    service_date,
    updated_at
  FROM line_item
  WHERE id_line_item = p_id_line_item;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_line_item_percent_derived_upsert` (IN `p_id_folio` BIGINT, IN `p_id_reservation` BIGINT, IN `p_parent_catalog_id` BIGINT, IN `p_service_date` DATE, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_queue_parent_catalog_id BIGINT;
  DECLARE v_queue_depth INT DEFAULT 0;
  DECLARE v_parent_sale_item_id BIGINT;
  DECLARE v_parent_amount_cents INT DEFAULT 0;
  DECLARE v_parent_catalog_type VARCHAR(32);
  DECLARE v_parent_item_type VARCHAR(32) DEFAULT 'sale_item';
  DECLARE v_child_catalog_id BIGINT;
  DECLARE v_child_catalog_type VARCHAR(32);
  DECLARE v_child_allow_negative TINYINT DEFAULT 0;
  DECLARE v_percent_value DECIMAL(9,4);
  DECLARE v_component_cents INT DEFAULT 0;
  DECLARE v_base_cents INT DEFAULT 0;
  DECLARE v_child_amount_cents INT DEFAULT 0;
  DECLARE v_existing_child_sale_item_id BIGINT DEFAULT 0;
  DECLARE v_loop_guard INT DEFAULT 0;
  DECLARE v_pass INT DEFAULT 0;
  DECLARE v_derived_desc TEXT;
  DECLARE v_parent_item_name VARCHAR(255);
  DECLARE v_child_item_name VARCHAR(255);
  DECLARE v_child_item_type VARCHAR(32) DEFAULT 'sale_item';
  DECLARE v_folio_currency VARCHAR(10) DEFAULT 'MXN';
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  IF p_id_folio IS NULL OR p_id_folio <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio id is required';
  END IF;
  IF p_parent_catalog_id IS NULL OR p_parent_catalog_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'parent catalog id is required';
  END IF;

  SELECT f.currency
    INTO v_folio_currency
  FROM folio f
  WHERE f.id_folio = p_id_folio
    AND f.deleted_at IS NULL
  LIMIT 1;

  SET v_folio_currency = COALESCE(NULLIF(TRIM(v_folio_currency), ''), 'MXN');

  SELECT c.code, p.code
    INTO v_company_code, v_property_code
  FROM folio f
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  JOIN company c ON c.id_company = p.id_company
  WHERE f.id_folio = p_id_folio
    AND f.deleted_at IS NULL
  LIMIT 1;

  CALL sp_authz_assert(
    v_company_code,
    p_created_by,
    'reservations.post_charge',
    v_property_code,
    NULL
  );

  DROP TEMPORARY TABLE IF EXISTS tmp_lipdu_queue;
  CREATE TEMPORARY TABLE tmp_lipdu_queue (
    parent_catalog_id BIGINT PRIMARY KEY,
    depth INT NOT NULL DEFAULT 0,
    processed TINYINT NOT NULL DEFAULT 0
  ) ENGINE=MEMORY;

  DROP TEMPORARY TABLE IF EXISTS tmp_lipdu_children;
  CREATE TEMPORARY TABLE tmp_lipdu_children (
    child_catalog_id BIGINT PRIMARY KEY,
    child_item_name VARCHAR(255),
    child_catalog_type VARCHAR(32),
    child_allow_negative TINYINT NOT NULL DEFAULT 0,
    percent_value DECIMAL(9,4),
    processed TINYINT NOT NULL DEFAULT 0
  ) ENGINE=MEMORY;

  SET v_pass = 1;
  pass_loop: LOOP
    IF v_pass > 3 THEN
      LEAVE pass_loop;
    END IF;

    TRUNCATE TABLE tmp_lipdu_queue;
    INSERT IGNORE INTO tmp_lipdu_queue (parent_catalog_id, depth, processed)
    VALUES (p_parent_catalog_id, 0, 0);

    SET v_loop_guard = 0;

    queue_loop: LOOP
      SET v_loop_guard = v_loop_guard + 1;
      IF v_loop_guard > 1000 THEN
        LEAVE queue_loop;
      END IF;

    SET v_queue_parent_catalog_id = NULL;
    SET v_queue_depth = 0;

    SELECT q.parent_catalog_id, q.depth
      INTO v_queue_parent_catalog_id, v_queue_depth
    FROM tmp_lipdu_queue q
    WHERE q.processed = 0
    ORDER BY q.depth, q.parent_catalog_id
    LIMIT 1;

      IF v_queue_parent_catalog_id IS NULL THEN
        LEAVE queue_loop;
      END IF;

      UPDATE tmp_lipdu_queue
         SET processed = 1
       WHERE parent_catalog_id = v_queue_parent_catalog_id;

      IF v_queue_depth >= 25 THEN
        ITERATE queue_loop;
      END IF;

      SET v_parent_catalog_type = NULL;
      SELECT lic.catalog_type, lic.item_name
        INTO v_parent_catalog_type, v_parent_item_name
      FROM line_item_catalog lic
      WHERE lic.id_line_item_catalog = v_queue_parent_catalog_id
        AND lic.deleted_at IS NULL
      LIMIT 1;

      SET v_parent_item_type = CASE LOWER(TRIM(COALESCE(v_parent_catalog_type, 'sale_item')))
      WHEN 'sale_item' THEN 'sale_item'
      WHEN 'tax_rule' THEN 'tax_item'
      WHEN 'tax_item' THEN 'tax_item'
      WHEN 'tax' THEN 'tax_item'
      WHEN 'impuesto' THEN 'tax_item'
      WHEN 'impuestos' THEN 'tax_item'
      WHEN 'payment' THEN 'payment'
      WHEN 'pago' THEN 'payment'
      WHEN 'obligation' THEN 'obligation'
      WHEN 'obligacion' THEN 'obligation'
      WHEN 'obligación' THEN 'obligation'
      WHEN 'income' THEN 'income'
      WHEN 'ingreso' THEN 'income'
      ELSE 'sale_item'
    END;

      SET v_parent_sale_item_id = NULL;
      SET v_parent_amount_cents = 0;

      SELECT li.id_line_item, li.amount_cents
        INTO v_parent_sale_item_id, v_parent_amount_cents
      FROM line_item li
      WHERE li.id_folio = p_id_folio
        AND li.item_type = v_parent_item_type
        AND li.id_line_item_catalog = v_queue_parent_catalog_id
        AND li.deleted_at IS NULL
        AND li.is_active = 1
        AND (li.service_date <=> p_service_date)
      ORDER BY li.id_line_item DESC
      LIMIT 1;

      IF v_parent_sale_item_id IS NULL OR v_parent_sale_item_id <= 0 THEN
        SELECT li.id_line_item, li.amount_cents
          INTO v_parent_sale_item_id, v_parent_amount_cents
        FROM line_item li
        WHERE li.id_folio = p_id_folio
          AND li.id_line_item_catalog = v_queue_parent_catalog_id
          AND li.deleted_at IS NULL
          AND li.is_active = 1
          AND (li.service_date <=> p_service_date)
        ORDER BY li.id_line_item DESC
        LIMIT 1;
      END IF;

      IF v_parent_sale_item_id IS NULL OR v_parent_sale_item_id <= 0 THEN
        ITERATE queue_loop;
      END IF;

      /* Parent base stays as direct line item amount to avoid circular growth. */
      SET v_parent_amount_cents = COALESCE(v_parent_amount_cents, 0);

      TRUNCATE TABLE tmp_lipdu_children;

      INSERT IGNORE INTO tmp_lipdu_children (child_catalog_id, child_item_name, child_catalog_type, child_allow_negative, percent_value, processed)
      SELECT
        child.id_line_item_catalog,
        child.item_name,
        child.catalog_type,
        COALESCE(child.allow_negative, 0),
        COALESCE(lcp.percent_value, 0),
        0
      FROM line_item_catalog_parent lcp
      JOIN line_item_catalog child
        ON child.id_line_item_catalog = lcp.id_sale_item_catalog
       AND child.deleted_at IS NULL
       AND child.is_active = 1
       AND child.catalog_type IN ('sale_item','tax_rule','payment','obligation','income')
      WHERE lcp.id_parent_sale_item_catalog = v_queue_parent_catalog_id
        AND lcp.id_sale_item_catalog <> v_queue_parent_catalog_id
        AND lcp.deleted_at IS NULL
        AND lcp.is_active = 1
        AND lcp.percent_value IS NOT NULL;

      child_loop: LOOP
      SET v_child_catalog_id = NULL;
      SET v_child_item_name = NULL;
      SET v_child_catalog_type = NULL;
      SET v_child_allow_negative = 0;
      SET v_percent_value = 0;

      SELECT c.child_catalog_id, c.child_item_name, c.child_catalog_type, c.child_allow_negative, c.percent_value
        INTO v_child_catalog_id, v_child_item_name, v_child_catalog_type, v_child_allow_negative, v_percent_value
      FROM tmp_lipdu_children c
      WHERE c.processed = 0
      ORDER BY c.child_catalog_id
      LIMIT 1;

      SET v_child_item_type = CASE LOWER(TRIM(COALESCE(v_child_catalog_type, 'sale_item')))
        WHEN 'sale_item' THEN 'sale_item'
        WHEN 'tax_rule' THEN 'tax_item'
        WHEN 'tax_item' THEN 'tax_item'
        WHEN 'tax' THEN 'tax_item'
        WHEN 'impuesto' THEN 'tax_item'
        WHEN 'impuestos' THEN 'tax_item'
        WHEN 'payment' THEN 'payment'
        WHEN 'pago' THEN 'payment'
        WHEN 'obligation' THEN 'obligation'
        WHEN 'obligacion' THEN 'obligation'
        WHEN 'obligación' THEN 'obligation'
        WHEN 'income' THEN 'income'
        WHEN 'ingreso' THEN 'income'
        ELSE 'sale_item'
      END;

      IF v_child_catalog_id IS NULL THEN
        LEAVE child_loop;
      END IF;

      UPDATE tmp_lipdu_children
         SET processed = 1
       WHERE child_catalog_id = v_child_catalog_id;

      /* Advanced components: pick one best line per component catalog for this relation. */
      WITH RECURSIVE component_roots AS (
        SELECT
          picked.root_id,
          picked.root_sign
        FROM (
          SELECT
            (
              SELECT li_pick.id_line_item
              FROM line_item li_pick
              JOIN line_item_catalog comp_cat_pick
                ON comp_cat_pick.id_line_item_catalog = lcc.id_component_line_item_catalog
               AND comp_cat_pick.deleted_at IS NULL
              JOIN line_item_catalog parent_cat_pick
                ON parent_cat_pick.id_line_item_catalog = v_queue_parent_catalog_id
               AND parent_cat_pick.deleted_at IS NULL
              WHERE li_pick.id_folio = p_id_folio
                AND li_pick.id_line_item_catalog = lcc.id_component_line_item_catalog
                AND li_pick.deleted_at IS NULL
                AND li_pick.is_active = 1
              ORDER BY
                CASE
                  WHEN COALESCE(li_pick.description, '') = CONCAT(
                    COALESCE(comp_cat_pick.item_name, ''),
                    ' / ',
                    COALESCE(parent_cat_pick.item_name, '')
                  ) THEN 0
                  WHEN COALESCE(li_pick.description, '') = CONCAT('[AUTO-DERIVED parent_line_item=', v_parent_sale_item_id, ']') THEN 1
                  WHEN (li_pick.service_date <=> p_service_date) THEN 2
                  WHEN p_service_date IS NOT NULL AND li_pick.service_date IS NULL THEN 3
                  ELSE 4
                END,
                li_pick.id_line_item DESC
              LIMIT 1
            ) AS root_id,
            CASE WHEN COALESCE(lcc.is_positive, 1) = 1 THEN 1 ELSE -1 END AS root_sign
          FROM line_item_catalog_calc lcc
          WHERE lcc.id_line_item_catalog = v_child_catalog_id
            AND lcc.id_parent_line_item_catalog = v_queue_parent_catalog_id
            AND lcc.id_component_line_item_catalog <> v_child_catalog_id
            AND lcc.deleted_at IS NULL
            AND lcc.is_active = 1
        ) picked
        WHERE picked.root_id IS NOT NULL
      ),
      component_tree AS (
        SELECT
          cr.root_id,
          cr.root_sign,
          li.id_line_item,
          li.id_line_item_catalog,
          COALESCE(li.amount_cents, 0) AS amount_cents,
          0 AS depth,
          CAST(li.id_line_item AS CHAR(2000)) AS path
        FROM component_roots cr
        JOIN line_item li
          ON li.id_line_item = cr.root_id
        UNION ALL
        SELECT
          ct.root_id,
          ct.root_sign,
          ch.id_line_item,
          ch.id_line_item_catalog,
          COALESCE(ch.amount_cents, 0) AS amount_cents,
          ct.depth + 1 AS depth,
          CONCAT(ct.path, ',', ch.id_line_item) AS path
        FROM component_tree ct
        JOIN line_item_catalog_parent lcp
          ON lcp.id_parent_sale_item_catalog = ct.id_line_item_catalog
         AND lcp.deleted_at IS NULL
         AND lcp.is_active = 1
         AND COALESCE(lcp.add_to_father_total, 0) = 1
        JOIN line_item_catalog child_cat
          ON child_cat.id_line_item_catalog = lcp.id_sale_item_catalog
         AND child_cat.deleted_at IS NULL
         AND child_cat.is_active = 1
        JOIN line_item_catalog parent_cat
          ON parent_cat.id_line_item_catalog = ct.id_line_item_catalog
         AND parent_cat.deleted_at IS NULL
        JOIN line_item ch
          ON ch.id_folio = p_id_folio
         AND ch.id_line_item_catalog = lcp.id_sale_item_catalog
         AND ch.id_line_item_catalog <> v_child_catalog_id
         AND ch.deleted_at IS NULL
         AND ch.is_active = 1
         AND (ch.service_date <=> p_service_date)
         AND (
           COALESCE(ch.description, '') = CONCAT(COALESCE(child_cat.item_name, ''), ' / ', COALESCE(parent_cat.item_name, ''))
           OR COALESCE(ch.description, '') = CONCAT('[AUTO-DERIVED parent_line_item=', ct.id_line_item, ']')
         )
        WHERE ct.depth < 25
          AND FIND_IN_SET(CAST(ch.id_line_item AS CHAR), ct.path) = 0
      )
      SELECT COALESCE(SUM(x.root_sign * x.root_total), 0)
        INTO v_component_cents
      FROM (
        SELECT
          ct.root_id,
          ct.root_sign,
          COALESCE(SUM(ct.amount_cents), 0) AS root_total
        FROM component_tree ct
        GROUP BY ct.root_id, ct.root_sign
      ) x;

      SET v_base_cents = COALESCE(v_parent_amount_cents, 0) + COALESCE(v_component_cents, 0);
      SET v_child_amount_cents = ROUND(v_base_cents * (COALESCE(v_percent_value, 0) / 100));
      SET v_derived_desc = CONCAT(
        COALESCE(NULLIF(TRIM(v_child_item_name), ''), CONCAT('Catalog#', v_child_catalog_id)),
        ' / ',
        COALESCE(NULLIF(TRIM(v_parent_item_name), ''), CONCAT('Catalog#', v_queue_parent_catalog_id))
      );

      SET v_existing_child_sale_item_id = 0;
      SELECT li.id_line_item
        INTO v_existing_child_sale_item_id
      FROM line_item li
      WHERE li.id_folio = p_id_folio
        AND li.id_line_item_catalog = v_child_catalog_id
        AND li.deleted_at IS NULL
        AND li.is_active = 1
        AND (li.service_date <=> p_service_date)
        AND (
          COALESCE(li.description, '') = COALESCE(v_derived_desc, '')
          OR COALESCE(li.description, '') = CONCAT('[AUTO-DERIVED parent_line_item=', v_parent_sale_item_id, ']')
          OR (
            (COALESCE(li.description, '') = '' OR INSTR(COALESCE(li.description, ''), ' / ') = 0)
            AND (
              SELECT COUNT(*)
              FROM line_item_catalog_parent lcp_cnt
              WHERE lcp_cnt.id_sale_item_catalog = li.id_line_item_catalog
                AND lcp_cnt.deleted_at IS NULL
                AND lcp_cnt.is_active = 1
            ) = 1
          )
        )
      ORDER BY li.id_line_item DESC
      LIMIT 1;

      IF COALESCE(v_child_amount_cents, 0) <= 0
         AND COALESCE(v_child_allow_negative, 0) = 0 THEN
        IF v_existing_child_sale_item_id IS NOT NULL AND v_existing_child_sale_item_id > 0 THEN
          UPDATE line_item
             SET is_active = 0,
                 status = 'void',
                 deleted_at = NOW(),
                 updated_at = NOW()
           WHERE id_line_item = v_existing_child_sale_item_id
             AND deleted_at IS NULL;

          UPDATE line_item_hierarchy
             SET is_active = 0,
                 deleted_at = NOW(),
                 updated_at = NOW(),
                 updated_by = p_created_by
           WHERE id_line_item_child = v_existing_child_sale_item_id
             AND deleted_at IS NULL
             AND is_active = 1;
        END IF;
        ITERATE child_loop;
      END IF;

      IF v_existing_child_sale_item_id IS NULL OR v_existing_child_sale_item_id <= 0 THEN
        INSERT INTO line_item (
          item_type,
          id_user,
          id_folio,
          id_line_item_catalog,
          item_name,
          description,
          service_date,
          quantity,
          unit_price_cents,
          amount_cents,
          currency,
          method,
          discount_amount_cents,
          revenue_account_code,
          status,
          external_ref,
          is_active,
          created_at,
          created_by,
          updated_at
        ) VALUES (
          v_child_item_type,
          p_created_by,
          p_id_folio,
          v_child_catalog_id,
          v_child_item_name,
          v_derived_desc,
          p_service_date,
          1,
          v_child_amount_cents,
          v_child_amount_cents,
          v_folio_currency,
          CASE WHEN v_child_item_type = 'payment' THEN v_child_item_name ELSE NULL END,
          0,
          NULL,
          'posted',
          NULL,
          1,
          NOW(),
          p_created_by,
          NOW()
        );
        SET v_existing_child_sale_item_id = LAST_INSERT_ID();
      ELSE
        UPDATE line_item
           SET item_type = v_child_item_type,
               item_name = COALESCE(v_child_item_name, item_name),
               description = v_derived_desc,
               service_date = p_service_date,
               quantity = 1,
               unit_price_cents = v_child_amount_cents,
               amount_cents = v_child_amount_cents,
               currency = v_folio_currency,
               method = CASE
                 WHEN v_child_item_type = 'payment' THEN COALESCE(v_child_item_name, method)
                 ELSE method
               END,
               discount_amount_cents = 0,
               status = 'posted',
               is_active = 1,
               deleted_at = NULL,
               updated_at = NOW()
         WHERE id_line_item = v_existing_child_sale_item_id;
      END IF;

      INSERT INTO line_item_hierarchy (
        id_line_item_child,
        id_line_item_parent,
        relation_kind,
        is_active,
        deleted_at,
        created_by,
        updated_by
      ) VALUES (
        v_existing_child_sale_item_id,
        v_parent_sale_item_id,
        'derived_percent',
        1,
        NULL,
        p_created_by,
        p_created_by
      )
      ON DUPLICATE KEY UPDATE
        id_line_item_parent = VALUES(id_line_item_parent),
        relation_kind = VALUES(relation_kind),
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW(),
        updated_by = VALUES(updated_by);

      INSERT IGNORE INTO tmp_lipdu_queue (parent_catalog_id, depth, processed)
      VALUES (v_child_catalog_id, v_queue_depth + 1, 0);
      END LOOP;
    END LOOP;

    SET v_pass = v_pass + 1;
  END LOOP;

  DROP TEMPORARY TABLE IF EXISTS tmp_lipdu_children;
  DROP TEMPORARY TABLE IF EXISTS tmp_lipdu_queue;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_line_item_type_upsert` (IN `p_action` VARCHAR(16), IN `p_id_line_item` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_item_type` VARCHAR(32), IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_id_folio BIGINT;
  DECLARE v_catalog_type VARCHAR(32);
  DECLARE v_expected_catalog_type VARCHAR(32);

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'update';
  END IF;
  IF p_action <> 'update' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;
  IF p_id_line_item IS NULL OR p_id_line_item <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line item id is required';
  END IF;
  IF p_item_type NOT IN ('sale_item','tax_item','payment','obligation','income') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid line item type';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT li.id_folio, lic.catalog_type
    INTO v_id_folio, v_catalog_type
  FROM line_item li
  JOIN folio f ON f.id_folio = li.id_folio
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  LEFT JOIN line_item_catalog lic ON lic.id_line_item_catalog = li.id_line_item_catalog
  WHERE li.id_line_item = p_id_line_item
    AND li.deleted_at IS NULL
    AND p.id_company = v_company_id
  LIMIT 1;

  IF v_id_folio IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line item not found';
  END IF;

  SET v_expected_catalog_type = CASE p_item_type
    WHEN 'sale_item' THEN 'sale_item'
    WHEN 'tax_item' THEN 'tax_rule'
    WHEN 'payment' THEN 'payment'
    WHEN 'obligation' THEN 'obligation'
    WHEN 'income' THEN 'income'
    ELSE ''
  END;

  IF v_catalog_type IS NOT NULL AND v_catalog_type <> '' AND v_expected_catalog_type <> '' AND v_catalog_type <> v_expected_catalog_type THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line item type does not match catalog type';
  END IF;

  UPDATE line_item
     SET item_type = p_item_type,
         updated_at = NOW()
   WHERE id_line_item = p_id_line_item
     AND deleted_at IS NULL;

  CALL sp_folio_recalc(v_id_folio);

  SELECT
    id_line_item,
    id_folio,
    item_type,
    updated_at
  FROM line_item
  WHERE id_line_item = p_id_line_item;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_list_reservations_by_company` (IN `p_company_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE)   BEGIN
  DECLARE v_id_company BIGINT;
  DECLARE v_from DATE;
  DECLARE v_to DATE;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_id_company
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_id_company IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_from = COALESCE(p_from, DATE_SUB(CURDATE(), INTERVAL 30 DAY));
  SET v_to = COALESCE(p_to, DATE_ADD(CURDATE(), INTERVAL 180 DAY));

  SELECT
    ev.id_reservation,
    ev.reservation_code,
    ev.status,
    ev.source,
    ev.id_ota_account,
    oa.ota_name,
    oa.platform AS ota_platform,
    ev.id_reservation_source,
    COALESCE(rsc.source_name, '') AS reservation_source_name,
    ev.check_in_date,
    ev.check_out_date,
    ev.adults,
    ev.children,
    ev.currency,
    ev.total_price_cents,
    ev.balance_due_cents,
    g.email AS guest_email,
    g.names AS guest_names,
    g.last_name AS guest_last_name,
    rm.code AS room_code,
    rm.name AS room_name,
    pr.code AS property_code,
    pr.name AS property_name,
    ev.created_at,
    ev.updated_at
  FROM (
    SELECT
      r.id_reservation,
      r.code AS reservation_code,
      r.status,
      r.source,
      r.id_ota_account,
      r.id_reservation_source,
      r.check_in_date,
      r.check_out_date,
      r.adults,
      r.children,
      r.currency,
      r.total_price_cents,
      r.balance_due_cents,
      r.id_guest,
      r.id_room,
      r.id_property,
      r.created_at,
      r.updated_at
    FROM reservation r
    JOIN property p ON p.id_property = r.id_property
    WHERE p.id_company = v_id_company
      AND r.deleted_at IS NULL
      AND r.check_in_date >= v_from
      AND r.check_in_date <= v_to

    UNION ALL

    SELECT
      -rb.id_room_block AS id_reservation,
      rb.code AS reservation_code,
      'blocked' AS status,
      'block' AS source,
      NULL AS id_ota_account,
      NULL AS id_reservation_source,
      rb.start_date AS check_in_date,
      rb.end_date AS check_out_date,
      0 AS adults,
      0 AS children,
      'MXN' AS currency,
      0 AS total_price_cents,
      0 AS balance_due_cents,
      NULL AS id_guest,
      rb.id_room,
      rb.id_property,
      rb.created_at,
      rb.updated_at
    FROM room_block rb
    JOIN property p2 ON p2.id_property = rb.id_property
    WHERE p2.id_company = v_id_company
      AND rb.deleted_at IS NULL
      AND rb.is_active = 1
      AND rb.start_date >= v_from
      AND rb.start_date <= v_to
  ) AS ev
  LEFT JOIN guest g ON g.id_guest = ev.id_guest
  LEFT JOIN room rm ON rm.id_room = ev.id_room
  LEFT JOIN ota_account oa
    ON oa.id_ota_account = ev.id_ota_account
   AND oa.deleted_at IS NULL
   AND oa.is_active = 1
  LEFT JOIN reservation_source_catalog rsc
    ON rsc.id_reservation_source = ev.id_reservation_source
  JOIN property pr ON pr.id_property = ev.id_property
  ORDER BY ev.check_in_date DESC, ev.id_reservation DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_list_reservations_by_property` (IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE)   BEGIN
