    ev.created_at,
    ev.updated_at
  FROM (
    SELECT
      r.id_reservation,
      r.code AS reservation_code,
      r.status,
      r.source,
      r.id_ota_account,
      r.id_reservation_source,
      r.check_in_date,
      r.check_out_date,
      r.adults,
      r.children,
      r.currency,
      r.total_price_cents,
      r.balance_due_cents,
      r.id_guest,
      r.id_room,
      r.id_property,
      r.created_at,
      r.updated_at
    FROM reservation r
    WHERE r.id_property = v_id_property
      AND r.deleted_at IS NULL
      AND r.check_in_date >= v_from
      AND r.check_in_date <= v_to

    UNION ALL

    SELECT
      -rb.id_room_block AS id_reservation,
      rb.code AS reservation_code,
      'blocked' AS status,
      'block' AS source,
      NULL AS id_ota_account,
      NULL AS id_reservation_source,
      rb.start_date AS check_in_date,
      rb.end_date AS check_out_date,
      0 AS adults,
      0 AS children,
      'MXN' AS currency,
      0 AS total_price_cents,
      0 AS balance_due_cents,
      NULL AS id_guest,
      rb.id_room,
      rb.id_property,
      rb.created_at,
      rb.updated_at
    FROM room_block rb
    WHERE rb.id_property = v_id_property
      AND rb.deleted_at IS NULL
      AND rb.is_active = 1
      AND rb.start_date >= v_from
      AND rb.start_date <= v_to
  ) AS ev
  LEFT JOIN guest g ON g.id_guest = ev.id_guest
  LEFT JOIN room rm ON rm.id_room = ev.id_room
  LEFT JOIN ota_account oa
    ON oa.id_ota_account = ev.id_ota_account
   AND oa.deleted_at IS NULL
   AND oa.is_active = 1
  LEFT JOIN reservation_source_catalog rsc
    ON rsc.id_reservation_source = ev.id_reservation_source
  JOIN property pr ON pr.id_property = ev.id_property
  ORDER BY ev.check_in_date DESC, ev.id_reservation DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_list_room_blocks` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_from DATE;
  DECLARE v_to DATE;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_from = COALESCE(p_from, DATE_SUB(CURDATE(), INTERVAL 30 DAY));
  SET v_to = COALESCE(p_to, DATE_ADD(CURDATE(), INTERVAL 365 DAY));
  IF v_to < v_from THEN
    SET v_to = DATE_ADD(v_from, INTERVAL 1 DAY);
  END IF;

  SELECT
    rb.id_room_block,
    rb.code,
    rb.description,
    rb.start_date,
    rb.end_date,
    rb.is_active,
    rb.created_at,
    rb.updated_at,
    rm.id_room,
    rm.code AS room_code,
    rm.name AS room_name,
    pr.id_property,
    pr.code AS property_code,
    pr.name AS property_name,
    rb.id_user
  FROM room_block rb
  JOIN room rm ON rm.id_room = rb.id_room
  JOIN property pr ON pr.id_property = rb.id_property
  WHERE pr.id_company = v_company_id
    AND rb.deleted_at IS NULL
    AND rb.is_active = 1
    AND (v_property_id IS NULL OR rb.id_property = v_property_id)
    AND rb.start_date < v_to
    AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > v_from
  ORDER BY rb.start_date DESC, rb.id_room_block DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_load_reservation_import_input_from_tsv` (IN `p_raw` LONGTEXT)   BEGIN
  DECLARE v_text LONGTEXT;
  DECLARE v_line LONGTEXT;
  DECLARE v_pos INT DEFAULT 0;
  DECLARE v_f1 VARCHAR(64);
  DECLARE v_f2 VARCHAR(64);
  DECLARE v_f3 VARCHAR(255);
  DECLARE v_f4 VARCHAR(64);
  DECLARE v_f5 VARCHAR(20);
  DECLARE v_f6 VARCHAR(20);
  DECLARE v_f7 VARCHAR(120);

  TRUNCATE TABLE tmp_reservation_import_input;

  SET v_text = REPLACE(REPLACE(COALESCE(p_raw, ''), '\r\n', '\n'), '\r', '\n');

  parse_loop: LOOP
    IF v_text IS NULL OR v_text = '' THEN
      LEAVE parse_loop;
    END IF;

    SET v_pos = LOCATE('\n', v_text);
    IF v_pos = 0 THEN
      SET v_line = v_text;
      SET v_text = '';
    ELSE
      SET v_line = SUBSTRING(v_text, 1, v_pos - 1);
      SET v_text = SUBSTRING(v_text, v_pos + 1);
    END IF;

    SET v_line = TRIM(COALESCE(v_line, ''));
    IF v_line = '' THEN
      ITERATE parse_loop;
    END IF;

    SET v_f1 = TRIM(SUBSTRING_INDEX(v_line, '\t', 1));
    SET v_f2 = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(v_line, '\t', 2), '\t', -1));
    SET v_f3 = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(v_line, '\t', 3), '\t', -1));
    SET v_f4 = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(v_line, '\t', 4), '\t', -1));
    SET v_f5 = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(v_line, '\t', 5), '\t', -1));
    SET v_f6 = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(v_line, '\t', 6), '\t', -1));
    SET v_f7 = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(v_line, '\t', 7), '\t', -1));

    IF v_f1 REGEXP '^[0-9]+$'
       AND v_f2 REGEXP '^[0-9]+$'
       AND v_f3 <> ''
       AND v_f5 <> ''
       AND v_f6 <> ''
       AND v_f7 <> '' THEN
      INSERT INTO tmp_reservation_import_input (
        id_property,
        id_room,
        guest_name,
        amount_raw,
        check_in_raw,
        check_out_raw,
        origin_raw
      ) VALUES (
        CAST(v_f1 AS UNSIGNED),
        CAST(v_f2 AS UNSIGNED),
        v_f3,
        NULLIF(v_f4, ''),
        v_f5,
        v_f6,
        v_f7
      );
    END IF;
  END LOOP;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_message_template_upsert` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_template_code` VARCHAR(100), IN `p_title` VARCHAR(255), IN `p_body` TEXT, IN `p_category` VARCHAR(64), IN `p_sort_order` INT, IN `p_channel` VARCHAR(32), IN `p_is_trackable` TINYINT, IN `p_is_required` TINYINT, IN `p_id_sale_item_catalog` BIGINT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT, IN `p_id_message_template` BIGINT)   proc:BEGIN
  DECLARE v_id_company BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_id_template BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_category VARCHAR(64) DEFAULT 'general';
  DECLARE v_channel VARCHAR(32) DEFAULT 'whatsapp';
  DECLARE v_is_trackable TINYINT DEFAULT 0;
  DECLARE v_is_required TINYINT DEFAULT 0;
  DECLARE v_sale_item_catalog BIGINT DEFAULT NULL;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_actor_user_id IS NULL OR p_actor_user_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Actor user id is required';
  END IF;
  IF p_template_code IS NULL OR TRIM(p_template_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Template code is required';
  END IF;
  IF p_title IS NULL OR TRIM(p_title) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Template title is required';
  END IF;
  IF p_body IS NULL OR TRIM(p_body) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Template body is required';
  END IF;

  SELECT id_company
    INTO v_id_company
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_company IS NULL OR v_id_company <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_id_property = NULL;
  SET v_property_code = NULLIF(TRIM(COALESCE(p_property_code, '')), '');
  IF v_property_code IS NOT NULL THEN
    SELECT id_property, code
      INTO v_id_property, v_property_code
    FROM property
    WHERE code = v_property_code
      AND id_company = v_id_company
      AND deleted_at IS NULL
    LIMIT 1;

    IF v_id_property IS NULL OR v_id_property <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
    END IF;
  END IF;

  CALL sp_authz_assert(
    p_company_code,
    p_actor_user_id,
    'messages.template_edit',
    v_property_code,
    NULL
  );

  SET v_category = LOWER(TRIM(COALESCE(NULLIF(p_category, ''), 'general')));
  SET v_channel = LOWER(TRIM(COALESCE(NULLIF(p_channel, ''), 'whatsapp')));
  SET v_is_trackable = CASE WHEN COALESCE(p_is_trackable, 0) = 1 OR COALESCE(p_is_required, 0) = 1 THEN 1 ELSE 0 END;
  SET v_is_required = CASE WHEN COALESCE(p_is_required, 0) = 1 THEN 1 ELSE 0 END;
  IF v_channel = '' THEN
    SET v_channel = 'whatsapp';
  END IF;

  SET v_sale_item_catalog = NULL;
  IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog > 0 THEN
    SELECT lic.id_line_item_catalog
      INTO v_sale_item_catalog
    FROM line_item_catalog lic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
     AND cat.id_company = v_id_company
     AND cat.deleted_at IS NULL
     AND cat.is_active = 1
    WHERE lic.id_line_item_catalog = p_id_sale_item_catalog
      AND lic.catalog_type = 'sale_item'
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND (
        v_id_property IS NULL
        OR cat.id_property IS NULL
        OR cat.id_property = v_id_property
      )
    LIMIT 1;

    IF v_sale_item_catalog IS NULL OR v_sale_item_catalog <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid sale item catalog for template';
    END IF;
  END IF;

  SET v_id_template = NULL;
  IF p_id_message_template IS NOT NULL AND p_id_message_template > 0 THEN
    SELECT id_message_template
      INTO v_id_template
    FROM message_template
    WHERE id_message_template = p_id_message_template
      AND id_company = v_id_company
      AND deleted_at IS NULL
    LIMIT 1;
  ELSE
    SELECT id_message_template
      INTO v_id_template
    FROM message_template
    WHERE id_company = v_id_company
      AND code = TRIM(p_template_code)
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF v_id_template IS NULL OR v_id_template <= 0 THEN
    INSERT INTO message_template (
      id_company,
      id_property,
      code,
      title,
      body,
      category,
      sort_order,
      channel,
      is_trackable,
      is_required,
      id_sale_item_catalog,
      is_active,
      created_at,
      updated_at
    ) VALUES (
      v_id_company,
      v_id_property,
      TRIM(p_template_code),
      TRIM(p_title),
      p_body,
      v_category,
      COALESCE(p_sort_order, 0),
      v_channel,
      v_is_trackable,
      v_is_required,
      v_sale_item_catalog,
      COALESCE(p_is_active, 1),
      v_now,
      v_now
    );
    SET v_id_template = LAST_INSERT_ID();
  ELSE
    UPDATE message_template
    SET
      id_property = v_id_property,
      code = TRIM(p_template_code),
      title = TRIM(p_title),
      body = p_body,
      category = v_category,
      sort_order = COALESCE(p_sort_order, 0),
      channel = v_channel,
      is_trackable = v_is_trackable,
      is_required = v_is_required,
      id_sale_item_catalog = v_sale_item_catalog,
      is_active = COALESCE(p_is_active, is_active),
      updated_at = v_now
    WHERE id_message_template = v_id_template;
  END IF;

  SELECT
    mt.id_message_template,
    mt.id_company,
    mt.id_property,
    mt.code AS template_code,
    mt.title,
    mt.body,
    mt.category,
    mt.sort_order,
    mt.channel,
    mt.is_trackable,
    mt.is_required,
    mt.id_sale_item_catalog,
    mt.is_active
  FROM message_template mt
  WHERE mt.id_message_template = v_id_template
    AND mt.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_catalog_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_show_inactive` TINYINT, IN `p_id_obligation_catalog` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    oc.id_line_item_catalog AS id_obligation_catalog,
    oc.id_property,
    p.code AS property_code,
    p.name AS property_name,
    oc.id_sale_item_catalog,
    sic.item_name AS sale_item_name,
    cat.category_name AS sale_item_category,
    oc.id_tax_rule,
    tr.name AS tax_rule_name,
    parent_map.parent_item_ids,
    oc.obligation_name,
    oc.description,
    oc.is_percent,
    oc.percent_value,
    oc.default_amount_cents,
    oc.is_active,
    CASE
      WHEN oc.id_sale_item_catalog IS NOT NULL THEN 'sale_item'
      WHEN oc.id_tax_rule IS NOT NULL THEN 'tax_rule'
      ELSE 'manual'
    END AS source_type
  FROM line_item_catalog oc
  LEFT JOIN property p ON p.id_property = oc.id_property
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = oc.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = oc.id_tax_rule
   AND tr.catalog_type = 'tax_rule'
  LEFT JOIN (
    SELECT
      lcp.id_sale_item_catalog,
      GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids
    FROM line_item_catalog_parent lcp
    WHERE lcp.deleted_at IS NULL
      AND lcp.is_active = 1
    GROUP BY lcp.id_sale_item_catalog
  ) parent_map ON parent_map.id_sale_item_catalog = oc.id_line_item_catalog
  WHERE oc.catalog_type = 'obligation'
    AND oc.id_company = v_company_id
    AND oc.deleted_at IS NULL
    AND (p_show_inactive IS NOT NULL AND p_show_inactive <> 0 OR oc.is_active = 1)
    AND (v_property_id IS NULL OR oc.id_property IS NULL OR oc.id_property = v_property_id)
  ORDER BY oc.obligation_name;

  IF p_id_obligation_catalog IS NULL OR p_id_obligation_catalog = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_obligation_catalog,
      CAST(NULL AS SIGNED) AS id_property,
      CAST(NULL AS CHAR) AS property_code,
      CAST(NULL AS CHAR) AS property_name,
      CAST(NULL AS SIGNED) AS id_sale_item_catalog,
      CAST(NULL AS CHAR) AS sale_item_name,
      CAST(NULL AS CHAR) AS sale_item_category,
      CAST(NULL AS SIGNED) AS id_tax_rule,
      CAST(NULL AS CHAR) AS tax_rule_name,
      CAST(NULL AS CHAR) AS parent_item_ids,
      CAST(NULL AS CHAR) AS obligation_name,
      CAST(NULL AS CHAR) AS description,
      CAST(NULL AS SIGNED) AS is_percent,
      CAST(NULL AS DECIMAL(9,4)) AS percent_value,
      CAST(NULL AS SIGNED) AS default_amount_cents,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS CHAR) AS source_type
    LIMIT 0;
  ELSE
    SELECT
      oc.id_line_item_catalog AS id_obligation_catalog,
      oc.id_property,
      p.code AS property_code,
      p.name AS property_name,
      oc.id_sale_item_catalog,
      sic.item_name AS sale_item_name,
      cat.category_name AS sale_item_category,
      oc.id_tax_rule,
      tr.name AS tax_rule_name,
      parent_map.parent_item_ids,
      oc.obligation_name,
      oc.description,
      oc.is_percent,
      oc.percent_value,
      oc.default_amount_cents,
      oc.is_active,
      CASE
        WHEN oc.id_sale_item_catalog IS NOT NULL THEN 'sale_item'
        WHEN oc.id_tax_rule IS NOT NULL THEN 'tax_rule'
        ELSE 'manual'
      END AS source_type
    FROM line_item_catalog oc
    LEFT JOIN property p ON p.id_property = oc.id_property
    LEFT JOIN line_item_catalog sic
      ON sic.id_line_item_catalog = oc.id_sale_item_catalog
     AND sic.catalog_type = 'sale_item'
    LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
    LEFT JOIN line_item_catalog tr
      ON tr.id_line_item_catalog = oc.id_tax_rule
     AND tr.catalog_type = 'tax_rule'
    LEFT JOIN (
      SELECT
        lcp.id_sale_item_catalog,
        GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids
      FROM line_item_catalog_parent lcp
      WHERE lcp.deleted_at IS NULL
        AND lcp.is_active = 1
      GROUP BY lcp.id_sale_item_catalog
    ) parent_map ON parent_map.id_sale_item_catalog = oc.id_line_item_catalog
    WHERE oc.id_line_item_catalog = p_id_obligation_catalog
      AND oc.catalog_type = 'obligation'
      AND oc.id_company = v_company_id
    LIMIT 1;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_catalog_upsert` (IN `p_action` VARCHAR(16), IN `p_id_obligation_catalog` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_id_sale_item_catalog` BIGINT, IN `p_id_tax_rule` BIGINT, IN `p_parent_ids` TEXT, IN `p_obligation_name` VARCHAR(255), IN `p_description` TEXT, IN `p_is_percent` TINYINT, IN `p_percent_value` DECIMAL(9,4), IN `p_default_amount_cents` INT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_sale_item_catalog_id BIGINT;
  DECLARE v_tax_rule_id BIGINT;
  DECLARE v_catalog_property_id BIGINT;
  DECLARE v_existing_id BIGINT;
  DECLARE v_action VARCHAR(16);
  DECLARE v_parent_ids TEXT;

  SET v_action = COALESCE(NULLIF(p_action,''),'create');
  IF v_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for obligation catalog';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_parent_ids = NULLIF(TRIM(p_parent_ids), '');

  IF v_parent_ids IS NULL THEN
    IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog <> 0
       AND p_id_tax_rule IS NOT NULL AND p_id_tax_rule <> 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Catalog must target sale_item or tax_rule, not both';
    END IF;
  END IF;

  IF v_parent_ids IS NOT NULL THEN
    SELECT
      MIN(CASE WHEN parent.catalog_type = 'sale_item' THEN parent.id_line_item_catalog END),
      MIN(CASE WHEN parent.catalog_type = 'tax_rule' THEN parent.id_line_item_catalog END)
      INTO v_sale_item_catalog_id, v_tax_rule_id
    FROM line_item_catalog parent
    LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = parent.id_category
    WHERE parent.deleted_at IS NULL
      AND FIND_IN_SET(parent.id_line_item_catalog, v_parent_ids)
      AND (
        (parent.catalog_type = 'sale_item' AND cat.id_company = v_company_id AND cat.deleted_at IS NULL)
        OR (parent.catalog_type = 'tax_rule' AND parent.id_company = v_company_id)
      )
      AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id);
    IF v_sale_item_catalog_id IS NULL AND v_tax_rule_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Parent catalog items not found';
    END IF;
  ELSE
    IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog <> 0 THEN
      SELECT lic.id_line_item_catalog, cat.id_property
        INTO v_sale_item_catalog_id, v_catalog_property_id
      FROM line_item_catalog lic
      JOIN sale_item_category cat ON cat.id_sale_item_category = lic.id_category
      WHERE lic.id_line_item_catalog = p_id_sale_item_catalog
        AND lic.catalog_type = 'sale_item'
        AND lic.deleted_at IS NULL
        AND cat.deleted_at IS NULL
        AND cat.id_company = v_company_id
      LIMIT 1;
      IF v_sale_item_catalog_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Sale item catalog not found';
      END IF;
      IF v_property_id IS NOT NULL
         AND v_catalog_property_id IS NOT NULL
         AND v_catalog_property_id <> v_property_id THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Catalog property mismatch';
      END IF;
    ELSE
      SET v_sale_item_catalog_id = NULL;
    END IF;

    IF p_id_tax_rule IS NOT NULL AND p_id_tax_rule <> 0 THEN
      SELECT id_line_item_catalog INTO v_tax_rule_id
      FROM line_item_catalog
      WHERE id_line_item_catalog = p_id_tax_rule
        AND catalog_type = 'tax_rule'
        AND id_company = v_company_id
        AND deleted_at IS NULL
      LIMIT 1;
      IF v_tax_rule_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Tax rule not found';
      END IF;
    ELSE
      SET v_tax_rule_id = NULL;
    END IF;
  END IF;

  IF v_action = 'create' THEN
    IF p_obligation_name IS NULL OR p_obligation_name = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Obligation name is required';
    END IF;
    INSERT INTO line_item_catalog (
      catalog_type,
      id_company,
      id_property,
      id_sale_item_catalog,
      id_tax_rule,
      obligation_name,
      description,
      is_percent,
      percent_value,
      default_amount_cents,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      'obligation',
      v_company_id,
      v_property_id,
      v_sale_item_catalog_id,
      v_tax_rule_id,
      p_obligation_name,
      p_description,
      COALESCE(p_is_percent,0),
      COALESCE(p_percent_value,0),
      COALESCE(p_default_amount_cents,0),
      COALESCE(p_is_active,1),
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET v_existing_id = LAST_INSERT_ID();
    IF v_parent_ids IS NOT NULL THEN
      UPDATE line_item_catalog_parent
         SET is_active = 0,
             deleted_at = NOW(),
             updated_at = NOW()
       WHERE id_sale_item_catalog = v_existing_id;
      INSERT INTO line_item_catalog_parent (
        id_sale_item_catalog,
        id_parent_sale_item_catalog,
        is_active,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_existing_id,
        parent.id_line_item_catalog,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      FROM line_item_catalog parent
      LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = parent.id_category
      WHERE parent.deleted_at IS NULL
        AND FIND_IN_SET(parent.id_line_item_catalog, v_parent_ids)
        AND (
          (parent.catalog_type = 'sale_item' AND cat.id_company = v_company_id AND cat.deleted_at IS NULL)
          OR (parent.catalog_type = 'tax_rule' AND parent.id_company = v_company_id)
        )
        AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
    CALL sp_obligation_sync_for_catalog(v_existing_id, p_actor_user_id);
    SELECT
      id_line_item_catalog AS id_obligation_catalog,
      id_company,
      id_property,
      id_sale_item_catalog,
      id_tax_rule,
      obligation_name,
      description,
      is_percent,
      percent_value,
      default_amount_cents,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_existing_id;
    LEAVE proc;
  END IF;

  IF p_id_obligation_catalog IS NULL OR p_id_obligation_catalog = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Obligation catalog id is required';
  END IF;

  SELECT id_line_item_catalog INTO v_existing_id
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_obligation_catalog
    AND catalog_type = 'obligation'
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;
  IF v_existing_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Obligation catalog not found';
  END IF;

  IF v_action = 'delete' THEN
    UPDATE line_item_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item_catalog = v_existing_id;
    CALL sp_obligation_sync_for_catalog(v_existing_id, p_actor_user_id);
    SELECT
      id_line_item_catalog AS id_obligation_catalog,
      id_company,
      id_property,
      id_sale_item_catalog,
      id_tax_rule,
      obligation_name,
      description,
      is_percent,
      percent_value,
      default_amount_cents,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_existing_id;
    LEAVE proc;
  END IF;

  UPDATE line_item_catalog
     SET id_property = v_property_id,
         id_sale_item_catalog = v_sale_item_catalog_id,
         id_tax_rule = v_tax_rule_id,
         obligation_name = COALESCE(p_obligation_name, obligation_name),
         description = p_description,
         is_percent = COALESCE(p_is_percent, is_percent),
         percent_value = COALESCE(p_percent_value, percent_value),
         default_amount_cents = COALESCE(p_default_amount_cents, default_amount_cents),
         is_active = COALESCE(p_is_active, is_active),
         updated_at = NOW()
   WHERE id_line_item_catalog = v_existing_id;

  IF v_parent_ids IS NOT NULL THEN
    UPDATE line_item_catalog_parent
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_sale_item_catalog = v_existing_id;
    IF v_parent_ids <> '' THEN
      INSERT INTO line_item_catalog_parent (
        id_sale_item_catalog,
        id_parent_sale_item_catalog,
        is_active,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_existing_id,
        parent.id_line_item_catalog,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      FROM line_item_catalog parent
      LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = parent.id_category
      WHERE parent.deleted_at IS NULL
        AND FIND_IN_SET(parent.id_line_item_catalog, v_parent_ids)
        AND (
          (parent.catalog_type = 'sale_item' AND cat.id_company = v_company_id AND cat.deleted_at IS NULL)
          OR (parent.catalog_type = 'tax_rule' AND parent.id_company = v_company_id)
        )
        AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  CALL sp_obligation_sync_for_catalog(v_existing_id, p_actor_user_id);
  SELECT
    id_line_item_catalog AS id_obligation_catalog,
    id_company,
    id_property,
    id_sale_item_catalog,
    id_tax_rule,
    obligation_name,
    description,
    is_percent,
    percent_value,
    default_amount_cents,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item_catalog
  WHERE id_line_item_catalog = v_existing_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_date_from` DATE, IN `p_date_to` DATE, IN `p_search` VARCHAR(255), IN `p_payment_status` VARCHAR(16), IN `p_show_inactive` TINYINT, IN `p_id_reservation` BIGINT, IN `p_id_folio` BIGINT, IN `p_limit_rows` INT)   proc:BEGIN
  DECLARE v_company_id BIGINT DEFAULT 0;
  DECLARE v_payment_status VARCHAR(16) DEFAULT '';
  DECLARE v_limit_rows INT DEFAULT 500;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  SET v_payment_status = LOWER(TRIM(COALESCE(p_payment_status, '')));
  IF v_payment_status NOT IN ('', 'pending', 'partial', 'paid') THEN
    SET v_payment_status = '';
  END IF;

  SET v_limit_rows = COALESCE(p_limit_rows, 500);
  IF v_limit_rows <= 0 THEN
    SET v_limit_rows = 500;
  END IF;
  IF v_limit_rows > 5000 THEN
    SET v_limit_rows = 5000;
  END IF;

  WITH RECURSIVE obligation_base AS (
    SELECT
      li.id_line_item,
      li.id_folio,
      r.id_reservation,
      r.id_ota_account AS reservation_ota_account_id,
      li.id_line_item_catalog,
      prop.id_company AS company_id,
      prop.id_property AS property_id,
      prop.code AS property_code,
      prop.name AS property_name,
      r.code AS reservation_code,
      r.check_in_date,
      f.folio_name,
      f.status AS folio_status,
      TRIM(CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, ''))) AS guest_name,
      COALESCE(rm.code, '') AS room_code,
      COALESCE(li.item_name, lic.item_name, '') AS catalog_item_name,
      COALESCE(parent_cat.category_name, '') AS category_name,
      COALESCE(sub_cat.category_name, '') AS subcategory_name,
      COALESCE(li.description, '') AS description,
      COALESCE(li.reference, '') AS reference,
      COALESCE(li.method, '') AS method,
      COALESCE(li.service_date, DATE(li.created_at)) AS service_date,
      li.created_at,
      DATE(li.created_at) AS created_date,
      COALESCE(li.amount_cents, 0) AS amount_cents,
      COALESCE(li.paid_cents, 0) AS paid_cents,
      GREATEST(COALESCE(li.amount_cents, 0) - COALESCE(li.paid_cents, 0), 0) AS remaining_cents,
      COALESCE(li.currency, 'MXN') AS currency,
      COALESCE(li.status, '') AS status,
      CASE
        WHEN COALESCE(li.amount_cents, 0) <= 0 THEN 'paid'
        WHEN COALESCE(li.paid_cents, 0) <= 0 THEN 'pending'
        WHEN COALESCE(li.paid_cents, 0) >= COALESCE(li.amount_cents, 0) THEN 'paid'
        ELSE 'partial'
      END AS payment_status
    FROM line_item li
    JOIN folio f
      ON f.id_folio = li.id_folio
    JOIN reservation r
      ON r.id_reservation = f.id_reservation
    JOIN property prop
      ON prop.id_property = r.id_property
    LEFT JOIN guest g
      ON g.id_guest = r.id_guest
    LEFT JOIN room rm
      ON rm.id_room = r.id_room
    LEFT JOIN line_item_catalog lic
      ON lic.id_line_item_catalog = li.id_line_item_catalog
    LEFT JOIN sale_item_category sub_cat
      ON sub_cat.id_sale_item_category = lic.id_category
    LEFT JOIN sale_item_category parent_cat
      ON parent_cat.id_sale_item_category = sub_cat.id_parent_sale_item_category
    WHERE li.item_type = 'obligation'
      AND prop.id_company = v_company_id
      AND (
        p_property_code IS NULL
        OR TRIM(p_property_code) = ''
        OR prop.code = p_property_code
      )
      AND (
        p_id_reservation IS NULL
        OR p_id_reservation <= 0
        OR r.id_reservation = p_id_reservation
      )
      AND (
        p_id_folio IS NULL
        OR p_id_folio <= 0
        OR li.id_folio = p_id_folio
      )
      AND (
        p_show_inactive = 1
        OR (
          li.deleted_at IS NULL
          AND li.is_active = 1
          AND (li.status IS NULL OR li.status NOT IN ('void', 'canceled'))
          AND f.deleted_at IS NULL
          AND f.is_active = 1
          AND r.deleted_at IS NULL
        )
      )
      AND (
        p_date_from IS NULL
        OR COALESCE(li.service_date, DATE(li.created_at)) >= p_date_from
      )
      AND (
        p_date_to IS NULL
        OR COALESCE(li.service_date, DATE(li.created_at)) <= p_date_to
      )
      AND (
        p_search IS NULL
        OR TRIM(p_search) = ''
        OR r.code LIKE CONCAT('%', TRIM(p_search), '%')
        OR f.folio_name LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(g.names, '') LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(g.last_name, '') LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(g.email, '') LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(rm.code, '') LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(lic.item_name, '') LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(li.description, '') LIKE CONCAT('%', TRIM(p_search), '%')
        OR COALESCE(li.reference, '') LIKE CONCAT('%', TRIM(p_search), '%')
      )
  ),
  line_item_scope AS (
    SELECT DISTINCT
      li.id_line_item,
      li.id_folio,
      li.id_line_item_catalog,
      li.item_type,
      li.service_date,
      COALESCE(li.description, '') AS description
    FROM line_item li
    JOIN obligation_base ob
      ON ob.id_folio = li.id_folio
    WHERE (
      p_show_inactive = 1
      OR (
        li.deleted_at IS NULL
        AND li.is_active = 1
        AND (li.status IS NULL OR li.status NOT IN ('void', 'canceled'))
      )
    )
  ),
  line_item_hierarchy_rel AS (
    SELECT
      h.id_line_item_child AS child_line_item_id,
      h.id_line_item_parent AS parent_line_item_id,
      p.id_line_item_catalog AS parent_catalog_id,
      p.item_type AS parent_item_type
    FROM line_item_hierarchy h
    JOIN line_item_scope p
      ON p.id_line_item = h.id_line_item_parent
    WHERE h.deleted_at IS NULL
      AND h.is_active = 1
  ),
  line_item_ancestor AS (
    SELECT
      ob.id_line_item AS root_line_item_id,
      hr.parent_line_item_id AS ancestor_line_item_id,
      hr.parent_catalog_id AS ancestor_catalog_id,
      hr.parent_item_type AS ancestor_item_type,
      1 AS depth,
      CAST(CONCAT(ob.id_line_item, ',', hr.parent_line_item_id) AS CHAR(4000)) AS path
    FROM obligation_base ob
    JOIN line_item_hierarchy_rel hr
      ON hr.child_line_item_id = ob.id_line_item
    UNION ALL
    SELECT
      la.root_line_item_id,
      hr.parent_line_item_id,
      hr.parent_catalog_id,
      hr.parent_item_type,
      la.depth + 1 AS depth,
      CONCAT(la.path, ',', hr.parent_line_item_id) AS path
    FROM line_item_ancestor la
    JOIN line_item_hierarchy_rel hr
      ON hr.child_line_item_id = la.ancestor_line_item_id
    WHERE la.depth < 15
      AND FIND_IN_SET(CAST(hr.parent_line_item_id AS CHAR), la.path) = 0
  ),
  ota_candidates AS (
    SELECT
      la.root_line_item_id AS id_line_item,
      oa.id_ota_account,
      oa.ota_name,
      oa.platform AS ota_platform,
      oa.id_service_fee_payment_catalog,
      MIN(la.depth) AS min_depth,
      MIN(
        CASE
          WHEN ob.reservation_ota_account_id IS NOT NULL
               AND oa.id_ota_account = ob.reservation_ota_account_id
          THEN 0
          ELSE 1
        END
      ) AS match_priority
    FROM line_item_ancestor la
    JOIN obligation_base ob
      ON ob.id_line_item = la.root_line_item_id
    JOIN ota_account_lodging_catalog oalc
      ON oalc.id_line_item_catalog = la.ancestor_catalog_id
     AND oalc.deleted_at IS NULL
     AND oalc.is_active = 1
    JOIN ota_account oa
      ON oa.id_ota_account = oalc.id_ota_account
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
     AND oa.id_company = ob.company_id
     AND oa.id_property = ob.property_id
    GROUP BY
      la.root_line_item_id,
      oa.id_ota_account,
      oa.ota_name,
      oa.platform,
      oa.id_service_fee_payment_catalog
    UNION ALL
    SELECT
      ob.id_line_item,
      oa.id_ota_account,
      oa.ota_name,
      oa.platform AS ota_platform,
      oa.id_service_fee_payment_catalog,
      999 AS min_depth,
      0 AS match_priority
    FROM obligation_base ob
    JOIN ota_account oa
      ON oa.id_ota_account = ob.reservation_ota_account_id
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
     AND oa.id_company = ob.company_id
     AND oa.id_property = ob.property_id
  ),
  ota_best_priority AS (
    SELECT
      oc.id_line_item,
      MIN(oc.match_priority) AS best_priority
    FROM ota_candidates oc
    GROUP BY oc.id_line_item
  ),
  ota_best_depth AS (
    SELECT
      oc.id_line_item,
      MIN(oc.min_depth) AS best_depth
    FROM ota_candidates oc
    JOIN ota_best_priority bp
      ON bp.id_line_item = oc.id_line_item
     AND bp.best_priority = oc.match_priority
    GROUP BY oc.id_line_item
  ),
  ota_choice AS (
    SELECT
      oc.id_line_item,
      MIN(oc.id_ota_account) AS id_ota_account
    FROM ota_candidates oc
    JOIN ota_best_priority bp
      ON bp.id_line_item = oc.id_line_item
     AND bp.best_priority = oc.match_priority
    JOIN ota_best_depth bd
      ON bd.id_line_item = oc.id_line_item
     AND bd.best_depth = oc.min_depth
    GROUP BY oc.id_line_item
  ),
  ota_fee_catalog AS (
    SELECT
      ob.id_line_item,
      MIN(oa.id_ota_account) AS fee_ota_account_id
    FROM obligation_base ob
    JOIN ota_account oa
      ON oa.id_company = ob.company_id
     AND oa.id_property = ob.property_id
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
     AND oa.id_service_fee_payment_catalog = ob.id_line_item_catalog
    GROUP BY ob.id_line_item
  ),
  tax_candidates AS (
    SELECT
      la.root_line_item_id AS id_line_item,
      la.depth,
      NULLIF(TRIM(tax_lic.item_name), '') AS tax_parent_catalog_name
    FROM line_item_ancestor la
    JOIN line_item_catalog tax_lic
      ON tax_lic.id_line_item_catalog = la.ancestor_catalog_id
     AND tax_lic.deleted_at IS NULL
     AND tax_lic.is_active = 1
    WHERE LOWER(TRIM(COALESCE(la.ancestor_item_type, ''))) IN ('tax', 'tax_item')
  ),
  tax_best_depth AS (
    SELECT
      tc.id_line_item,
      MIN(tc.depth) AS best_depth
    FROM tax_candidates tc
    GROUP BY tc.id_line_item
  ),
  tax_parent AS (
    SELECT
      tc.id_line_item,
      1 AS has_tax_parent,
      COALESCE(MIN(tc.tax_parent_catalog_name), '') AS tax_parent_catalog_name
    FROM tax_candidates tc
    JOIN tax_best_depth td
      ON td.id_line_item = tc.id_line_item
     AND td.best_depth = tc.depth
    GROUP BY tc.id_line_item
  ),
  parent_name_candidates AS (
    SELECT
      la.root_line_item_id AS id_line_item,
      la.depth,
      NULLIF(TRIM(parent_lic.item_name), '') AS parent_catalog_name
    FROM line_item_ancestor la
    JOIN line_item_catalog parent_lic
      ON parent_lic.id_line_item_catalog = la.ancestor_catalog_id
     AND parent_lic.deleted_at IS NULL
     AND parent_lic.is_active = 1
    WHERE TRIM(COALESCE(parent_lic.item_name, '')) <> ''
  ),
  parent_name_depth AS (
    SELECT
      pnc.id_line_item,
      MIN(pnc.depth) AS best_depth
    FROM parent_name_candidates pnc
    GROUP BY pnc.id_line_item
  ),
  parent_name AS (
    SELECT
      pnc.id_line_item,
      COALESCE(MIN(pnc.parent_catalog_name), '') AS parent_catalog_name
    FROM parent_name_candidates pnc
    JOIN parent_name_depth pnd
      ON pnd.id_line_item = pnc.id_line_item
     AND pnd.best_depth = pnc.depth
    GROUP BY pnc.id_line_item
  )
  SELECT
    ob.id_line_item,
    ob.id_folio,
    ob.id_reservation,
    ob.id_line_item_catalog,
    ob.property_code,
    ob.property_name,
    ob.reservation_code,
    ob.check_in_date,
    ob.folio_name,
    ob.folio_status,
    ob.guest_name,
    ob.room_code,
    ob.catalog_item_name,
    ob.category_name,
    ob.subcategory_name,
    CASE
      WHEN COALESCE(tp.has_tax_parent, 0) = 1
           OR LOWER(TRIM(COALESCE(tp.tax_parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(pn.parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(ob.catalog_item_name, ''))) LIKE 'pago de impuestos%'
      THEN CONCAT(
        COALESCE(NULLIF(TRIM(ob.catalog_item_name), ''), CONCAT('Concepto #', COALESCE(ob.id_line_item_catalog, 0))),
        ' - ',
        COALESCE(NULLIF(TRIM(pn.parent_catalog_name), ''), NULLIF(TRIM(tp.tax_parent_catalog_name), ''), 'Impuesto')
      )
      WHEN (
        (oa.id_ota_account IS NOT NULL
         AND oa.id_service_fee_payment_catalog IS NOT NULL
         AND oa.id_service_fee_payment_catalog = ob.id_line_item_catalog)
        OR ofc.fee_ota_account_id IS NOT NULL
      )
      THEN CONCAT(
        COALESCE(NULLIF(TRIM(ob.catalog_item_name), ''), CONCAT('Concepto #', COALESCE(ob.id_line_item_catalog, 0))),
        ' - ',
        COALESCE(
          NULLIF(TRIM(res_oa.ota_name), ''),
          NULLIF(TRIM(oa.ota_name), ''),
          NULLIF(TRIM(oaf.ota_name), ''),
          'OTA'
        )
      )
      ELSE COALESCE(NULLIF(TRIM(ob.catalog_item_name), ''), CONCAT('Concepto #', COALESCE(ob.id_line_item_catalog, 0)))
    END AS concept_display_name,
    COALESCE(pn.parent_catalog_name, '') AS parent_concept_name,
    ob.description,
    ob.reference,
    ob.method,
    ob.service_date,
    ob.created_at,
    ob.created_date AS obligation_date,
    ob.amount_cents,
    ob.paid_cents,
    ob.remaining_cents,
    ob.currency,
    ob.status,
    ob.payment_status,
    CASE
      WHEN COALESCE(tp.has_tax_parent, 0) = 1
           OR LOWER(TRIM(COALESCE(tp.tax_parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(pn.parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(ob.catalog_item_name, ''))) LIKE 'pago de impuestos%'
      THEN 1
      ELSE 0
    END AS has_tax_parent_line_item_type,
    CASE
      WHEN COALESCE(tp.has_tax_parent, 0) = 1
           OR LOWER(TRIM(COALESCE(tp.tax_parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(pn.parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(ob.catalog_item_name, ''))) LIKE 'pago de impuestos%'
      THEN 'tax_payment'
      WHEN oa.id_ota_account IS NOT NULL
           AND oa.id_service_fee_payment_catalog IS NOT NULL
           AND oa.id_service_fee_payment_catalog = ob.id_line_item_catalog
      THEN 'ota_payment'
      WHEN ofc.fee_ota_account_id IS NOT NULL
      THEN 'ota_payment'
      ELSE 'property_payment'
    END AS obligation_type_key,
    CASE
      WHEN COALESCE(tp.has_tax_parent, 0) = 1
           OR LOWER(TRIM(COALESCE(tp.tax_parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(pn.parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(ob.catalog_item_name, ''))) LIKE 'pago de impuestos%'
      THEN 'Pago de impuesto'
      WHEN oa.id_ota_account IS NOT NULL
           AND oa.id_service_fee_payment_catalog IS NOT NULL
           AND oa.id_service_fee_payment_catalog = ob.id_line_item_catalog
      THEN 'Pago a OTA'
      WHEN ofc.fee_ota_account_id IS NOT NULL
      THEN 'Pago a OTA'
      ELSE 'Pago a propiedad'
    END AS obligation_type_label,
    CASE
      WHEN COALESCE(tp.has_tax_parent, 0) = 1
           OR LOWER(TRIM(COALESCE(tp.tax_parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(pn.parent_catalog_name, ''))) LIKE '%impuesto%'
           OR LOWER(TRIM(COALESCE(ob.catalog_item_name, ''))) LIKE 'pago de impuestos%'
      THEN COALESCE(
             NULLIF(TRIM(tp.tax_parent_catalog_name), ''),
             NULLIF(TRIM(pn.parent_catalog_name), ''),
             'Impuesto'
           )
      WHEN oa.id_ota_account IS NOT NULL
           AND oa.id_service_fee_payment_catalog IS NOT NULL
           AND oa.id_service_fee_payment_catalog = ob.id_line_item_catalog
      THEN COALESCE(NULLIF(TRIM(oa.ota_name), ''), NULLIF(TRIM(oaf.ota_name), ''), 'OTA')
      WHEN ofc.fee_ota_account_id IS NOT NULL
      THEN COALESCE(NULLIF(TRIM(oaf.ota_name), ''), NULLIF(TRIM(oa.ota_name), ''), 'OTA')
      ELSE COALESCE(NULLIF(TRIM(ob.property_name), ''), 'Propiedad')
    END AS obligation_target_name,
    COALESCE(tp.tax_parent_catalog_name, '') AS tax_parent_catalog_name,
    COALESCE(oa.id_ota_account, ofc.fee_ota_account_id, 0) AS resolved_ota_account_id,
    COALESCE(oa.ota_name, oaf.ota_name, '') AS ota_name,
    COALESCE(oa.ota_platform, oaf.ota_platform, '') AS ota_platform
  FROM obligation_base ob
  LEFT JOIN tax_parent tp
    ON tp.id_line_item = ob.id_line_item
  LEFT JOIN parent_name pn
    ON pn.id_line_item = ob.id_line_item
  LEFT JOIN ota_choice oc
    ON oc.id_line_item = ob.id_line_item
  LEFT JOIN ota_fee_catalog ofc
    ON ofc.id_line_item = ob.id_line_item
  LEFT JOIN ota_account res_oa
    ON res_oa.id_ota_account = ob.reservation_ota_account_id
   AND res_oa.deleted_at IS NULL
  LEFT JOIN (
    SELECT
      id_ota_account,
      ota_name,
      platform AS ota_platform,
      id_service_fee_payment_catalog
    FROM ota_account
    WHERE deleted_at IS NULL
      AND is_active = 1
  ) oa
    ON oa.id_ota_account = oc.id_ota_account
  LEFT JOIN (
    SELECT
      id_ota_account,
      ota_name,
      platform AS ota_platform
    FROM ota_account
    WHERE deleted_at IS NULL
      AND is_active = 1
  ) oaf
    ON oaf.id_ota_account = ofc.fee_ota_account_id
  WHERE (v_payment_status = '' OR ob.payment_status = v_payment_status)
  ORDER BY
    CASE ob.payment_status
      WHEN 'pending' THEN 1
      WHEN 'partial' THEN 2
      WHEN 'paid' THEN 3
      ELSE 4
    END,
    ob.created_at DESC,
    ob.id_line_item DESC
  LIMIT v_limit_rows;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_item_upsert` (IN `p_action` VARCHAR(16), IN `p_id_obligation_item` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_id_obligation_catalog` BIGINT, IN `p_id_reservation` BIGINT, IN `p_amount_cents` INT, IN `p_paid_cents` INT, IN `p_currency` VARCHAR(10), IN `p_notes` TEXT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_catalog_id BIGINT;
  DECLARE v_catalog_name VARCHAR(255);
  DECLARE v_is_manual TINYINT DEFAULT 0;
  DECLARE v_action VARCHAR(16);

  SET v_action = COALESCE(NULLIF(p_action,''),'create');
  IF v_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for obligation item';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF v_action = 'delete' THEN
    IF p_id_obligation_item IS NULL OR p_id_obligation_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation item id is required';
    END IF;
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item = p_id_obligation_item
       AND item_type = 'obligation';
    SELECT
      id_line_item AS id_obligation_item,
      id_obligation_catalog,
      obligation_name,
      id_reservation,
      id_sale_item,
      id_tax_item,
      amount_cents,
      paid_cents,
      currency,
      notes,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item
    WHERE id_line_item = p_id_obligation_item;
    LEAVE proc;
  END IF;

  IF p_id_obligation_catalog IS NULL OR p_id_obligation_catalog = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation catalog id is required';
  END IF;
  SELECT id_line_item_catalog,
         obligation_name,
         CASE
           WHEN id_sale_item_catalog IS NULL AND id_tax_rule IS NULL THEN 1
           ELSE 0
         END
    INTO v_catalog_id, v_catalog_name, v_is_manual
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_obligation_catalog
    AND catalog_type = 'obligation'
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;
  IF v_catalog_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation catalog not found';
  END IF;
  IF v_is_manual = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'manual obligations require a manual catalog';
  END IF;

  IF p_id_reservation IS NOT NULL AND p_id_reservation <> 0 THEN
    IF NOT EXISTS (
      SELECT 1
      FROM reservation r
      JOIN property p ON p.id_property = r.id_property
      WHERE r.id_reservation = p_id_reservation
        AND r.deleted_at IS NULL
        AND p.id_company = v_company_id
      LIMIT 1
    ) THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation not found for company';
    END IF;
  END IF;

  IF v_action = 'create' THEN
    INSERT INTO line_item (
      item_type,
      id_line_item_catalog,
      id_obligation_catalog,
      obligation_name,
      id_reservation,
      id_sale_item,
      id_tax_item,
      amount_cents,
      paid_cents,
      currency,
      notes,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      'obligation',
      v_catalog_id,
      v_catalog_id,
      COALESCE(v_catalog_name, ''),
      CASE WHEN p_id_reservation IS NULL OR p_id_reservation = 0 THEN NULL ELSE p_id_reservation END,
      NULL,
      NULL,
      COALESCE(p_amount_cents,0),
      COALESCE(p_paid_cents,0),
      COALESCE(NULLIF(p_currency,''), 'MXN'),
      p_notes,
      COALESCE(p_is_active,1),
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET p_id_obligation_item = LAST_INSERT_ID();
  ELSE
    IF p_id_obligation_item IS NULL OR p_id_obligation_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation item id is required';
    END IF;
    UPDATE line_item
       SET id_line_item_catalog = v_catalog_id,
           id_obligation_catalog = v_catalog_id,
           obligation_name = COALESCE(v_catalog_name, obligation_name),
           id_reservation = CASE WHEN p_id_reservation IS NULL OR p_id_reservation = 0 THEN NULL ELSE p_id_reservation END,
           amount_cents = COALESCE(p_amount_cents, amount_cents),
           paid_cents = LEAST(COALESCE(p_paid_cents, paid_cents), COALESCE(p_amount_cents, amount_cents)),
           currency = COALESCE(NULLIF(p_currency,''), currency),
           notes = p_notes,
           is_active = COALESCE(p_is_active, is_active),
           deleted_at = NULL,
           updated_at = NOW()
     WHERE id_line_item = p_id_obligation_item
       AND item_type = 'obligation';
  END IF;

  SELECT
    id_line_item AS id_obligation_item,
    id_obligation_catalog,
    obligation_name,
    id_reservation,
    id_sale_item,
    id_tax_item,
    amount_cents,
    paid_cents,
    currency,
    notes,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item
  WHERE id_line_item = p_id_obligation_item;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_paid_upsert` (IN `p_company_code` VARCHAR(100), IN `p_id_line_item` BIGINT, IN `p_mode` VARCHAR(16), IN `p_amount_cents` INT, IN `p_id_obligation_payment_method` BIGINT, IN `p_payment_notes` TEXT, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_line_company_id BIGINT;
  DECLARE v_id_folio BIGINT;
  DECLARE v_id_reservation BIGINT;
  DECLARE v_amount_cents INT DEFAULT 0;
  DECLARE v_paid_cents INT DEFAULT 0;
  DECLARE v_new_paid_cents INT DEFAULT 0;
  DECLARE v_applied_cents INT DEFAULT 0;
  DECLARE v_mode VARCHAR(16);
  DECLARE v_payment_method_id BIGINT DEFAULT 0;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;
  IF p_id_line_item IS NULL OR p_id_line_item <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line item id is required';
  END IF;
  IF p_id_obligation_payment_method IS NULL OR p_id_obligation_payment_method <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation payment method is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  SELECT
    p.id_company,
    li.id_folio,
    f.id_reservation,
    COALESCE(li.amount_cents, 0),
    COALESCE(li.paid_cents, 0)
    INTO v_line_company_id, v_id_folio, v_id_reservation, v_amount_cents, v_paid_cents
  FROM line_item li
  JOIN folio f
    ON f.id_folio = li.id_folio
   AND f.deleted_at IS NULL
   AND f.is_active = 1
  JOIN reservation r
    ON r.id_reservation = f.id_reservation
   AND r.deleted_at IS NULL
  JOIN property p
    ON p.id_property = r.id_property
   AND p.deleted_at IS NULL
  WHERE li.id_line_item = p_id_line_item
    AND li.item_type = 'obligation'
    AND li.deleted_at IS NULL
    AND li.is_active = 1
  LIMIT 1;

  IF v_id_folio IS NULL OR v_id_folio <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation line item not found';
  END IF;

  IF v_line_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line item does not belong to company';
  END IF;

  SELECT m.id_obligation_payment_method
    INTO v_payment_method_id
  FROM pms_settings_obligation_payment_method m
  WHERE m.id_obligation_payment_method = p_id_obligation_payment_method
    AND m.id_company = v_company_id
    AND m.deleted_at IS NULL
    AND m.is_active = 1
  LIMIT 1;

  IF v_payment_method_id IS NULL OR v_payment_method_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid obligation payment method';
  END IF;

  SET v_mode = LOWER(TRIM(COALESCE(p_mode, 'add')));
  IF v_mode NOT IN ('add', 'set') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid mode';
  END IF;

  SET p_amount_cents = COALESCE(p_amount_cents, 0);
  IF p_amount_cents < 0 THEN
    SET p_amount_cents = 0;
  END IF;

  IF v_mode = 'set' THEN
    SET v_new_paid_cents = p_amount_cents;
  ELSE
    SET v_new_paid_cents = COALESCE(v_paid_cents, 0) + p_amount_cents;
  END IF;

  IF v_new_paid_cents < 0 THEN
    SET v_new_paid_cents = 0;
  END IF;
  IF v_amount_cents >= 0 THEN
    SET v_new_paid_cents = LEAST(v_new_paid_cents, v_amount_cents);
  END IF;
  SET v_applied_cents = v_new_paid_cents - COALESCE(v_paid_cents, 0);

  UPDATE line_item
     SET paid_cents = v_new_paid_cents,
         updated_at = NOW()
   WHERE id_line_item = p_id_line_item
     AND deleted_at IS NULL
     AND is_active = 1;

  IF v_applied_cents <> 0 THEN
    INSERT INTO obligation_payment_log (
      id_company,
      id_line_item,
      id_folio,
      id_reservation,
      id_obligation_payment_method,
      payment_mode,
      amount_input_cents,
      amount_applied_cents,
      paid_before_cents,
      paid_after_cents,
      notes,
      created_by
    ) VALUES (
      v_company_id,
      p_id_line_item,
      v_id_folio,
      v_id_reservation,
      v_payment_method_id,
      v_mode,
      COALESCE(p_amount_cents, 0),
      v_applied_cents,
      COALESCE(v_paid_cents, 0),
      v_new_paid_cents,
      NULLIF(TRIM(COALESCE(p_payment_notes, '')), ''),
      p_created_by
    );
  END IF;

  CALL sp_folio_recalc(v_id_folio);

  SELECT
    li.id_line_item,
    li.id_folio,
    li.id_line_item_catalog,
    li.amount_cents,
    li.paid_cents,
    GREATEST(COALESCE(li.amount_cents, 0) - COALESCE(li.paid_cents, 0), 0) AS remaining_cents,
    CASE
      WHEN COALESCE(li.amount_cents, 0) <= 0 THEN 'paid'
      WHEN COALESCE(li.paid_cents, 0) <= 0 THEN 'pending'
      WHEN COALESCE(li.paid_cents, 0) >= COALESCE(li.amount_cents, 0) THEN 'paid'
      ELSE 'partial'
    END AS payment_status,
    li.updated_at
  FROM line_item li
  WHERE li.id_line_item = p_id_line_item
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_payment_upsert` (IN `p_action` VARCHAR(16), IN `p_id_obligation_payment` BIGINT, IN `p_id_obligation_item` BIGINT, IN `p_amount_cents` INT, IN `p_currency` VARCHAR(10), IN `p_method` VARCHAR(120), IN `p_reference` VARCHAR(255), IN `p_paid_at` DATETIME, IN `p_is_active` TINYINT, IN `p_company_code` VARCHAR(100), IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_obligation_item_id BIGINT;
  DECLARE v_obligation_amount INT DEFAULT 0;
  DECLARE v_obligation_currency VARCHAR(10);
  DECLARE v_paid_total INT DEFAULT 0;
  DECLARE v_item_company_id BIGINT;

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for obligation payment';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;
  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  IF p_id_obligation_item IS NULL OR p_id_obligation_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation item id is required';
  END IF;

  SELECT
    oi.id_line_item,
    oi.amount_cents,
    oi.currency,
    COALESCE(p.id_company, oc.id_company)
  INTO v_obligation_item_id,
       v_obligation_amount,
       v_obligation_currency,
       v_item_company_id
  FROM line_item oi
  LEFT JOIN reservation r ON r.id_reservation = oi.id_reservation
  LEFT JOIN property p ON p.id_property = r.id_property
  LEFT JOIN line_item_catalog oc
    ON oc.id_line_item_catalog = oi.id_obligation_catalog
   AND oc.catalog_type = 'obligation'
  WHERE oi.id_line_item = p_id_obligation_item
    AND oi.item_type = 'obligation'
    AND oi.deleted_at IS NULL
  LIMIT 1;

  IF v_obligation_item_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation item not found';
  END IF;
  IF v_item_company_id IS NULL OR v_item_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation item not found for company';
  END IF;

  IF p_action = 'delete' THEN
    IF p_id_obligation_payment IS NULL OR p_id_obligation_payment = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation payment id is required';
    END IF;
    UPDATE obligation_payment
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_obligation_payment = p_id_obligation_payment
       AND id_obligation_item = v_obligation_item_id
       AND deleted_at IS NULL;
  ELSE
    IF p_amount_cents IS NULL OR p_amount_cents <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment amount must be positive';
    END IF;
    IF p_action = 'create' THEN
      INSERT INTO obligation_payment (
        id_obligation_item,
        amount_cents,
        currency,
        method,
        reference,
        paid_at,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        v_obligation_item_id,
        p_amount_cents,
        COALESCE(NULLIF(p_currency,''), v_obligation_currency),
        NULLIF(p_method,''),
        NULLIF(p_reference,''),
        COALESCE(p_paid_at, NOW()),
        COALESCE(p_is_active,1),
        NOW(),
        p_actor_user_id,
        NOW()
      );
      SET p_id_obligation_payment = LAST_INSERT_ID();
    ELSE
      IF p_id_obligation_payment IS NULL OR p_id_obligation_payment = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation payment id is required';
      END IF;
      UPDATE obligation_payment
         SET amount_cents = COALESCE(p_amount_cents, amount_cents),
             currency = COALESCE(NULLIF(p_currency,''), currency),
             method = COALESCE(NULLIF(p_method,''), method),
             reference = COALESCE(NULLIF(p_reference,''), reference),
             paid_at = COALESCE(p_paid_at, paid_at),
             is_active = COALESCE(p_is_active, is_active),
             deleted_at = NULL,
             updated_at = NOW()
       WHERE id_obligation_payment = p_id_obligation_payment
         AND id_obligation_item = v_obligation_item_id;
    END IF;
  END IF;

  SELECT COALESCE(SUM(amount_cents),0)
    INTO v_paid_total
  FROM obligation_payment
  WHERE id_obligation_item = v_obligation_item_id
    AND deleted_at IS NULL
    AND is_active = 1;

  UPDATE line_item
     SET paid_cents = LEAST(v_paid_total, amount_cents),
         updated_at = NOW()
   WHERE id_line_item = v_obligation_item_id
     AND item_type = 'obligation';

  SELECT
    id_line_item AS id_obligation_item,
    id_obligation_catalog,
    obligation_name,
    amount_cents,
    paid_cents,
    currency,
    updated_at
  FROM line_item
  WHERE id_line_item = v_obligation_item_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_pending_dashboard` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_date` DATE, IN `p_status` VARCHAR(32), IN `p_show_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_target_date DATE;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_target_date = COALESCE(p_date, CURDATE());

  SELECT
    oi.id_line_item AS id_obligation_item,
    COALESCE(oi.obligation_name, oc.obligation_name) AS obligation_name,
    oi.amount_cents,
    oi.paid_cents,
    GREATEST(oi.amount_cents - oi.paid_cents, 0) AS pending_cents,
    CASE
      WHEN oi.amount_cents <= oi.paid_cents THEN 'pagado'
      WHEN oi.paid_cents > 0 THEN 'parcial'
      ELSE 'pendiente'
    END AS status,
    oi.currency,
    r.id_reservation,
    r.code AS reservation_code,
    CONCAT_WS(' ', COALESCE(g.names,''), COALESCE(g.last_name,'')) AS guest_name,
    p.code AS property_code,
    p.name AS property_name,
    sic.item_name AS sale_item_name,
    cat.category_name AS sale_item_category,
    tr.name AS tax_rule_name,
    COALESCE(si.service_date, tsi.service_date, DATE(oi.created_at)) AS obligation_date
  FROM line_item oi
  LEFT JOIN line_item_catalog oc
    ON oc.id_line_item_catalog = oi.id_obligation_catalog
   AND oc.catalog_type = 'obligation'
  LEFT JOIN reservation r ON r.id_reservation = oi.id_reservation
  LEFT JOIN property p ON p.id_property = r.id_property
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  LEFT JOIN line_item si
    ON si.id_line_item = oi.id_sale_item
   AND si.item_type = 'sale_item'
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = si.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN line_item ti
    ON ti.id_line_item = oi.id_tax_item
   AND ti.item_type = 'tax_item'
  LEFT JOIN line_item tsi
    ON tsi.id_line_item = ti.id_sale_item
   AND tsi.item_type = 'sale_item'
  LEFT JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = ti.id_tax_rule
   AND tr.catalog_type = 'tax_rule'
  WHERE (
      (oc.id_company = v_company_id AND oc.deleted_at IS NULL)
      OR (oc.id_company IS NULL AND r.id_reservation IS NOT NULL AND p.id_company = v_company_id)
    )
    AND oi.item_type = 'obligation'
    AND (r.id_reservation IS NULL OR r.deleted_at IS NULL)
    AND (v_property_id IS NULL OR r.id_property = v_property_id)
    AND (COALESCE(si.service_date, tsi.service_date, DATE(oi.created_at)) = v_target_date)
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR (oi.deleted_at IS NULL AND oi.is_active = 1)
    )
    AND (p_status IS NULL OR p_status = '' OR p_status = 'todas'
         OR (CASE
            WHEN oi.amount_cents <= oi.paid_cents THEN 'pagado'
            WHEN oi.paid_cents > 0 THEN 'parcial'
            ELSE 'pendiente'
          END) = p_status)
  ORDER BY pending_cents DESC, oi.amount_cents DESC, oi.id_line_item DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_report_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE, IN `p_status` VARCHAR(32), IN `p_type` VARCHAR(32), IN `p_catalog_id` BIGINT, IN `p_min_amount_cents` INT, IN `p_max_amount_cents` INT, IN `p_search` TEXT, IN `p_show_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_search TEXT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  DROP TEMPORARY TABLE IF EXISTS tmp_obligations;
  CREATE TEMPORARY TABLE tmp_obligations AS
  SELECT
    oi.id_line_item AS id_obligation_item,
    oc.id_line_item_catalog AS id_obligation_catalog,
    COALESCE(oi.obligation_name, oc.obligation_name) AS obligation_name,
    oc.description AS obligation_description,
    oc.is_percent,
    oc.percent_value,
    oc.default_amount_cents,
    oc.id_sale_item_catalog,
    oc.id_tax_rule,
    oi.id_reservation,
    oi.id_sale_item,
    oi.id_tax_item,
    oi.amount_cents,
    oi.paid_cents,
    GREATEST(oi.amount_cents - oi.paid_cents, 0) AS pending_cents,
    CASE
      WHEN oi.amount_cents <= oi.paid_cents THEN 'pagado'
      WHEN oi.paid_cents > 0 THEN 'parcial'
      ELSE 'pendiente'
    END AS status,
    CASE
      WHEN oi.id_sale_item IS NOT NULL THEN 'sale_item'
      WHEN oi.id_tax_item IS NOT NULL THEN 'tax_rule'
      ELSE 'manual'
    END AS source_type,
    oi.currency,
    oi.notes,
    oi.created_at,
    r.code AS reservation_code,
    CONCAT_WS(' ', COALESCE(g.names,''), COALESCE(g.last_name,'')) AS guest_name,
    g.email AS guest_email,
    g.phone AS guest_phone,
    p.code AS property_code,
    p.name AS property_name,
    sic.item_name AS sale_item_name,
    cat.category_name AS sale_item_category,
    tr.name AS tax_rule_name,
    oi.is_active,
    oi.deleted_at
  FROM line_item oi
  LEFT JOIN line_item_catalog oc
    ON oc.id_line_item_catalog = oi.id_obligation_catalog
   AND oc.catalog_type = 'obligation'
  LEFT JOIN reservation r ON r.id_reservation = oi.id_reservation
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  LEFT JOIN property p ON p.id_property = COALESCE(r.id_property, oc.id_property)
  LEFT JOIN line_item si
    ON si.id_line_item = oi.id_sale_item
   AND si.item_type = 'sale_item'
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = si.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN line_item ti
    ON ti.id_line_item = oi.id_tax_item
   AND ti.item_type = 'tax_item'
  LEFT JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = ti.id_tax_rule
   AND tr.catalog_type = 'tax_rule'
  WHERE (
      (oc.id_company = v_company_id AND oc.deleted_at IS NULL)
      OR (oc.id_company IS NULL AND r.id_reservation IS NOT NULL AND p.id_company = v_company_id)
    )
    AND (r.id_reservation IS NULL OR r.deleted_at IS NULL)
    AND oi.item_type = 'obligation'
    AND (v_property_id IS NULL OR COALESCE(r.id_property, oc.id_property) = v_property_id)
    AND (p_from IS NULL OR DATE(oi.created_at) >= p_from)
    AND (p_to IS NULL OR DATE(oi.created_at) <= p_to)
    AND (p_catalog_id IS NULL OR p_catalog_id = 0 OR oc.id_line_item_catalog = p_catalog_id)
    AND (
      p_min_amount_cents IS NULL
      OR p_min_amount_cents <= 0
      OR oi.amount_cents >= p_min_amount_cents
    )
    AND (
      p_max_amount_cents IS NULL
      OR p_max_amount_cents <= 0
      OR oi.amount_cents <= p_max_amount_cents
    )
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR (oi.deleted_at IS NULL AND oi.is_active = 1)
    )
    AND (
      v_search IS NULL
      OR COALESCE(oi.obligation_name, oc.obligation_name) LIKE CONCAT('%', v_search, '%')
      OR oc.description LIKE CONCAT('%', v_search, '%')
      OR r.code LIKE CONCAT('%', v_search, '%')
      OR g.names LIKE CONCAT('%', v_search, '%')
      OR g.last_name LIKE CONCAT('%', v_search, '%')
      OR g.email LIKE CONCAT('%', v_search, '%')
      OR g.phone LIKE CONCAT('%', v_search, '%')
      OR oi.notes LIKE CONCAT('%', v_search, '%')
      OR sic.item_name LIKE CONCAT('%', v_search, '%')
      OR tr.name LIKE CONCAT('%', v_search, '%')
    );

  SELECT
    id_obligation_item,
    id_obligation_catalog,
    obligation_name,
    obligation_description,
    source_type,
    amount_cents,
    paid_cents,
    pending_cents,
    status,
    currency,
    notes,
    created_at,
    reservation_code,
    guest_name,
    guest_email,
    guest_phone,
    property_code,
    property_name,
    sale_item_name,
    sale_item_category,
    tax_rule_name
  FROM tmp_obligations
  WHERE (p_status IS NULL OR p_status = '' OR status = p_status)
    AND (p_type IS NULL OR p_type = '' OR source_type = p_type)
  ORDER BY created_at DESC, id_obligation_item DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_sync_for_catalog` (IN `p_id_obligation_catalog` BIGINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_sale_item_catalog_id BIGINT;
  DECLARE v_obligation_name VARCHAR(255);
  DECLARE v_is_percent TINYINT DEFAULT 0;
  DECLARE v_percent_value DECIMAL(9,4) DEFAULT 0;
  DECLARE v_default_amount INT DEFAULT 0;
  DECLARE v_is_active TINYINT DEFAULT 0;
  DECLARE v_target_sale_item_id BIGINT;
  DECLARE v_has_sale_parent INT DEFAULT 0;

  IF p_id_obligation_catalog IS NULL OR p_id_obligation_catalog = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation catalog id is required';
  END IF;

  SELECT id_company,
         id_property,
         id_sale_item_catalog,
         obligation_name,
         is_percent,
         percent_value,
         default_amount_cents,
         is_active
    INTO v_company_id,
         v_property_id,
         v_sale_item_catalog_id,
         v_obligation_name,
         v_is_percent,
         v_percent_value,
         v_default_amount,
         v_is_active
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_obligation_catalog
    AND catalog_type = 'obligation'
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'obligation catalog not found';
  END IF;

  IF v_is_active = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'obligation'
       AND id_obligation_catalog = p_id_obligation_catalog
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  SELECT COUNT(*)
    INTO v_has_sale_parent
  FROM line_item_catalog_parent lcp
  JOIN line_item_catalog parent
    ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
   AND parent.catalog_type = 'sale_item'
   AND parent.deleted_at IS NULL
   AND parent.is_active = 1
  WHERE lcp.id_sale_item_catalog = p_id_obligation_catalog
    AND lcp.deleted_at IS NULL
    AND lcp.is_active = 1
    AND parent.id_company = v_company_id
    AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id);

  IF v_has_sale_parent > 0 THEN
    DROP TEMPORARY TABLE IF EXISTS tmp_obligation_sale_items;
    CREATE TEMPORARY TABLE tmp_obligation_sale_items (
      id_sale_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_obligation_sale_items (id_sale_item)
    SELECT si.id_line_item
    FROM line_item si
    JOIN reservation r ON r.id_reservation = si.id_reservation
    JOIN property p ON p.id_property = r.id_property
    WHERE si.item_type = 'sale_item'
      AND si.id_sale_item_catalog IN (
          SELECT parent.id_line_item_catalog
          FROM line_item_catalog_parent lcp
          JOIN line_item_catalog parent
            ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
           AND parent.catalog_type = 'sale_item'
           AND parent.deleted_at IS NULL
           AND parent.is_active = 1
          WHERE lcp.id_sale_item_catalog = p_id_obligation_catalog
            AND lcp.deleted_at IS NULL
            AND lcp.is_active = 1
            AND parent.id_company = v_company_id
            AND (v_property_id IS NULL OR parent.id_property IS NULL OR parent.id_property = v_property_id)
      )
      AND si.deleted_at IS NULL
      AND si.is_active = 1
      AND r.deleted_at IS NULL
      AND p.deleted_at IS NULL
      AND p.id_company = v_company_id
      AND (v_property_id IS NULL OR r.id_property = v_property_id);

    WHILE (SELECT COUNT(*) FROM tmp_obligation_sale_items) > 0 DO
      SELECT id_sale_item
        INTO v_target_sale_item_id
      FROM tmp_obligation_sale_items
      LIMIT 1;

      DELETE FROM tmp_obligation_sale_items WHERE id_sale_item = v_target_sale_item_id;

      CALL sp_obligation_sync_for_sale_item(v_target_sale_item_id, p_actor_user_id);
    END WHILE;
  ELSE
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'obligation'
       AND id_obligation_catalog = p_id_obligation_catalog
       AND id_sale_item IS NOT NULL
       AND deleted_at IS NULL;
  END IF;

  UPDATE line_item oi
  LEFT JOIN line_item si
    ON si.id_line_item = oi.id_sale_item
   AND si.item_type = 'sale_item'
   AND si.deleted_at IS NULL
   AND si.is_active = 1
  LEFT JOIN reservation r
    ON r.id_reservation = si.id_reservation
   AND r.deleted_at IS NULL
  LEFT JOIN property p
    ON p.id_property = r.id_property
   AND p.deleted_at IS NULL
  SET oi.is_active = 0,
      oi.deleted_at = NOW(),
      oi.updated_at = NOW()
  WHERE oi.item_type = 'obligation'
    AND oi.id_obligation_catalog = p_id_obligation_catalog
    AND oi.id_sale_item IS NOT NULL
    AND oi.deleted_at IS NULL
    AND (si.id_line_item IS NULL
         OR r.id_reservation IS NULL
         OR p.id_company <> v_company_id
         OR (v_property_id IS NOT NULL AND r.id_property <> v_property_id));

END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_sync_for_sale_item` (IN `p_id_sale_item` BIGINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_reservation_id BIGINT;
  DECLARE v_folio_id BIGINT;
  DECLARE v_sale_item_catalog_id BIGINT;
  DECLARE v_check_in_date DATE;
  DECLARE v_amount_cents INT DEFAULT 0;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_is_active TINYINT DEFAULT 0;
  DECLARE v_deleted_at DATETIME;
  DECLARE v_tax_item_id BIGINT;
  DECLARE v_base_amount_cents INT DEFAULT 0;
  DECLARE v_obligation_catalog_id BIGINT;
  DECLARE v_obligation_name VARCHAR(255);
  DECLARE v_obligation_is_percent TINYINT DEFAULT 0;
  DECLARE v_obligation_percent DECIMAL(9,4) DEFAULT 0;
  DECLARE v_obligation_default INT DEFAULT 0;
  DECLARE v_obligation_amount INT DEFAULT 0;
  DECLARE v_calc_count INT DEFAULT 0;
  DECLARE v_calc_adjust INT DEFAULT 0;
  DECLARE v_calc_component_id BIGINT;
  DECLARE v_calc_is_positive TINYINT;
  DECLARE v_calc_component_sum INT DEFAULT 0;
  DECLARE v_calc_component_type VARCHAR(16);
  DECLARE v_calc_parent_id BIGINT;
  DECLARE v_calc_component_item_id BIGINT;
  DECLARE done INT DEFAULT 0;

  DECLARE tax_cur CURSOR FOR
    SELECT id_line_item
    FROM line_item
    WHERE item_type = 'tax_item'
      AND id_sale_item = p_id_sale_item
      AND deleted_at IS NULL
      AND is_active = 1;
  DECLARE obligation_cur CURSOR FOR
    SELECT lic.id_line_item_catalog,
           lic.obligation_name,
           lic.is_percent,
           lic.percent_value,
           lic.default_amount_cents
    FROM line_item_catalog lic
    JOIN line_item_catalog_parent lcp
      ON lcp.id_sale_item_catalog = lic.id_line_item_catalog
     AND lcp.id_parent_sale_item_catalog = v_sale_item_catalog_id
     AND lcp.deleted_at IS NULL
     AND lcp.is_active = 1
    WHERE lic.catalog_type = 'obligation'
      AND lic.id_company = v_company_id
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND (lic.id_property IS NULL OR lic.id_property = v_property_id);
  DECLARE calc_cur CURSOR FOR
    SELECT id_component_line_item_catalog,
           is_positive
    FROM line_item_catalog_calc
    WHERE id_line_item_catalog = v_obligation_catalog_id
      AND id_parent_line_item_catalog = v_sale_item_catalog_id
      AND deleted_at IS NULL
      AND is_active = 1;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  IF p_id_sale_item IS NULL OR p_id_sale_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item id is required';
  END IF;

  SELECT
    si.id_sale_item_catalog,
    si.id_folio,
    si.amount_cents,
    si.is_active,
    si.deleted_at,
    r.id_reservation,
    r.id_property,
    r.check_in_date,
    p.id_company,
    COALESCE(si.currency, 'MXN')
  INTO v_sale_item_catalog_id,
       v_folio_id,
       v_amount_cents,
       v_is_active,
       v_deleted_at,
       v_reservation_id,
       v_property_id,
       v_check_in_date,
       v_company_id,
       v_currency
  FROM line_item si
  JOIN folio f ON f.id_folio = si.id_folio
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  WHERE si.id_line_item = p_id_sale_item
    AND si.item_type = 'sale_item'
    AND f.deleted_at IS NULL
    AND r.deleted_at IS NULL
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item not found';
  END IF;

  IF v_deleted_at IS NOT NULL OR v_is_active = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'obligation'
       AND (id_sale_item = p_id_sale_item
        OR id_tax_item IN (
          SELECT id_line_item
          FROM line_item
          WHERE item_type = 'tax_item'
            AND id_sale_item = p_id_sale_item
        ))
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  IF (SELECT COUNT(*)
        FROM line_item_catalog_parent lcp
        JOIN line_item_catalog oc
          ON oc.id_line_item_catalog = lcp.id_sale_item_catalog
         AND oc.catalog_type = 'obligation'
       WHERE lcp.id_parent_sale_item_catalog = v_sale_item_catalog_id
         AND lcp.deleted_at IS NULL
         AND lcp.is_active = 1
         AND oc.id_company = v_company_id
         AND oc.deleted_at IS NULL
         AND oc.is_active = 1
         AND (oc.id_property IS NULL OR oc.id_property = v_property_id)) = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'obligation'
       AND id_sale_item = p_id_sale_item
       AND deleted_at IS NULL;
  ELSE
    SET v_base_amount_cents = v_amount_cents;

    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_queue;
    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_all;
    CREATE TEMPORARY TABLE tmp_calc_parent_queue (
      id_sale_item BIGINT PRIMARY KEY
    );
    CREATE TEMPORARY TABLE tmp_calc_parent_all (
      id_sale_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
    VALUES (p_id_sale_item);
    INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
    VALUES (p_id_sale_item);

    parent_calc_loop:WHILE (SELECT COUNT(*) FROM tmp_calc_parent_queue) > 0 DO
      SELECT id_sale_item
        INTO v_calc_parent_id
      FROM tmp_calc_parent_queue
      LIMIT 1;

      DELETE FROM tmp_calc_parent_queue WHERE id_sale_item = v_calc_parent_id;

      INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;

      INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;
    END WHILE;

    SET done = 0;
    OPEN obligation_cur;
    obligation_loop:LOOP
      FETCH obligation_cur
        INTO v_obligation_catalog_id,
             v_obligation_name,
             v_obligation_is_percent,
             v_obligation_percent,
             v_obligation_default;
      IF done = 1 THEN
        LEAVE obligation_loop;
      END IF;

      SELECT COUNT(*)
        INTO v_calc_count
      FROM line_item_catalog_calc lcc
      WHERE lcc.id_line_item_catalog = v_obligation_catalog_id
        AND lcc.id_parent_line_item_catalog = v_sale_item_catalog_id
        AND lcc.deleted_at IS NULL
        AND lcc.is_active = 1;

      SET v_calc_adjust = 0;
      IF v_calc_count > 0 THEN
        SET done = 0;
        OPEN calc_cur;
        calc_loop: LOOP
          FETCH calc_cur INTO v_calc_component_id, v_calc_is_positive;
          IF done = 1 THEN
            LEAVE calc_loop;
          END IF;

          SELECT catalog_type
            INTO v_calc_component_type
          FROM line_item_catalog
          WHERE id_line_item_catalog = v_calc_component_id
          LIMIT 1;

          SET v_calc_component_sum = 0;

          IF v_calc_component_type = 'sale_item' THEN
            DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_queue;
            DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_all;
            CREATE TEMPORARY TABLE tmp_calc_comp_queue (
              id_sale_item BIGINT PRIMARY KEY
            );
            CREATE TEMPORARY TABLE tmp_calc_comp_all (
              id_sale_item BIGINT PRIMARY KEY
            );

            INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
            SELECT li.id_line_item
            FROM line_item li
            JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
            WHERE li.item_type = 'sale_item'
              AND li.id_sale_item_catalog = v_calc_component_id
              AND li.deleted_at IS NULL
              AND li.is_active = 1;

            INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
            SELECT id_sale_item FROM tmp_calc_comp_queue;

            comp_calc_loop: WHILE (SELECT COUNT(*) FROM tmp_calc_comp_queue) > 0 DO
              SELECT id_sale_item
                INTO v_calc_component_item_id
              FROM tmp_calc_comp_queue
              LIMIT 1;

              DELETE FROM tmp_calc_comp_queue WHERE id_sale_item = v_calc_component_item_id;

              INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
              SELECT li.id_line_item
              FROM line_item li
              JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
              WHERE li.item_type = 'sale_item'
                AND li.id_parent_sale_item = v_calc_component_item_id
                AND li.deleted_at IS NULL
                AND li.is_active = 1;

              INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
              SELECT li.id_line_item
              FROM line_item li
              JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
              WHERE li.item_type = 'sale_item'
                AND li.id_parent_sale_item = v_calc_component_item_id
                AND li.deleted_at IS NULL
                AND li.is_active = 1;
            END WHILE;

            SELECT COALESCE(SUM(li.amount_cents),0)
              INTO v_calc_component_sum
            FROM line_item li
            WHERE li.item_type = 'sale_item'
              AND li.id_line_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
            SELECT v_calc_component_sum + COALESCE(SUM(ti.amount_cents),0)
              INTO v_calc_component_sum
            FROM line_item ti
            WHERE ti.item_type = 'tax_item'
              AND ti.deleted_at IS NULL
              AND ti.is_active = 1
              AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
          ELSEIF v_calc_component_type = 'tax_rule' THEN
            SELECT COALESCE(SUM(ti.amount_cents),0)
              INTO v_calc_component_sum
            FROM line_item ti
            WHERE ti.item_type = 'tax_item'
              AND ti.id_tax_rule = v_calc_component_id
              AND ti.deleted_at IS NULL
              AND ti.is_active = 1
              AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all);
          ELSE
            SELECT COALESCE(SUM(li.amount_cents),0)
              INTO v_calc_component_sum
            FROM line_item li
            WHERE li.id_line_item_catalog = v_calc_component_id
              AND li.deleted_at IS NULL
              AND li.is_active = 1
              AND (
                (li.item_type IN ('obligation','income') AND li.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all))
                OR (li.item_type = 'obligation' AND li.id_tax_item IN (
                    SELECT id_line_item
                    FROM line_item
                    WHERE item_type = 'tax_item'
                      AND id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all)
                      AND deleted_at IS NULL
                      AND is_active = 1
                ))
              );
          END IF;

          IF v_calc_is_positive = 1 THEN
            SET v_calc_adjust = v_calc_adjust + v_calc_component_sum;
          ELSE
            SET v_calc_adjust = v_calc_adjust - v_calc_component_sum;
          END IF;
        END LOOP;
        CLOSE calc_cur;
        SET done = 0;
      END IF;

      IF v_calc_count > 0 THEN
        IF v_obligation_is_percent = 1 THEN
          SET v_obligation_amount = ROUND((v_base_amount_cents + v_calc_adjust) * (v_obligation_percent / 100));
        ELSE
          SET v_obligation_amount = v_base_amount_cents + v_calc_adjust + COALESCE(v_obligation_default,0);
        END IF;
      ELSE
        IF v_obligation_is_percent = 1 THEN
          SET v_obligation_amount = ROUND(v_base_amount_cents * (v_obligation_percent / 100));
        ELSE
          SET v_obligation_amount = COALESCE(v_obligation_default,0);
        END IF;
      END IF;

      INSERT INTO line_item (
        item_type,
        id_line_item_catalog,
        id_obligation_catalog,
        obligation_name,
        id_reservation,
        id_sale_item,
        id_tax_item,
        service_date,
        amount_cents,
        paid_cents,
        currency,
        notes,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        'obligation',
        v_obligation_catalog_id,
        v_obligation_catalog_id,
        v_obligation_name,
        v_reservation_id,
        p_id_sale_item,
        NULL,
        v_check_in_date,
        v_obligation_amount,
        0,
        v_currency,
        NULL,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      )
      ON DUPLICATE KEY UPDATE
        id_reservation = VALUES(id_reservation),
        obligation_name = VALUES(obligation_name),
        amount_cents = VALUES(amount_cents),
        currency = VALUES(currency),
        service_date = VALUES(service_date),
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW(),
        paid_cents = LEAST(paid_cents, VALUES(amount_cents));
    END LOOP;
    CLOSE obligation_cur;
    SET done = 0;
  END IF;

  UPDATE line_item oi
  LEFT JOIN line_item_catalog oc
    ON oc.id_line_item_catalog = oi.id_obligation_catalog
   AND oc.catalog_type = 'obligation'
  SET oi.is_active = 0,
      oi.deleted_at = NOW(),
      oi.updated_at = NOW()
  WHERE oi.item_type = 'obligation'
    AND oi.id_sale_item = p_id_sale_item
    AND oi.deleted_at IS NULL
    AND (oc.id_line_item_catalog IS NULL
         OR oc.deleted_at IS NOT NULL
         OR oc.is_active = 0
         OR oc.id_company <> v_company_id
         OR (oc.id_property IS NOT NULL AND oc.id_property <> v_property_id)
         OR NOT EXISTS (
            SELECT 1
              FROM line_item_catalog_parent lcp
             WHERE lcp.id_sale_item_catalog = oc.id_line_item_catalog
               AND lcp.id_parent_sale_item_catalog = v_sale_item_catalog_id
               AND lcp.deleted_at IS NULL
               AND lcp.is_active = 1
         ));

END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_obligation_sync_for_tax_item` (IN `p_id_tax_item` BIGINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_reservation_id BIGINT;
  DECLARE v_tax_rule_id BIGINT;
  DECLARE v_sale_item_id BIGINT;
  DECLARE v_check_in_date DATE;
  DECLARE v_amount_cents INT DEFAULT 0;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_is_active TINYINT DEFAULT 0;
  DECLARE v_deleted_at DATETIME;
  DECLARE v_preferred_catalog_id BIGINT;
  DECLARE v_obligation_name VARCHAR(255);
  DECLARE v_obligation_is_percent TINYINT DEFAULT 0;
  DECLARE v_obligation_percent DECIMAL(9,4) DEFAULT 0;
  DECLARE v_obligation_default INT DEFAULT 0;
  DECLARE v_obligation_amount INT DEFAULT 0;
  DECLARE v_calc_count INT DEFAULT 0;
  DECLARE v_calc_adjust INT DEFAULT 0;
  DECLARE v_calc_component_id BIGINT;
  DECLARE v_calc_is_positive TINYINT;
  DECLARE v_calc_component_sum INT DEFAULT 0;
  DECLARE v_calc_component_type VARCHAR(16);
  DECLARE v_calc_parent_id BIGINT;
  DECLARE v_calc_component_item_id BIGINT;
  DECLARE done INT DEFAULT 0;

  DECLARE calc_cur CURSOR FOR
    SELECT id_component_line_item_catalog,
           is_positive
    FROM line_item_catalog_calc
    WHERE id_line_item_catalog = v_preferred_catalog_id
      AND id_parent_line_item_catalog = v_tax_rule_id
      AND deleted_at IS NULL
      AND is_active = 1;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  IF p_id_tax_item IS NULL OR p_id_tax_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_item id is required';
  END IF;

  SELECT
    ti.id_tax_rule,
    ti.amount_cents,
    ti.is_active,
    ti.deleted_at,
    r.id_reservation,
    r.id_property,
    r.check_in_date,
    p.id_company,
    COALESCE(si.currency, 'MXN'),
    ti.id_sale_item
  INTO v_tax_rule_id,
       v_amount_cents,
       v_is_active,
       v_deleted_at,
       v_reservation_id,
       v_property_id,
       v_check_in_date,
       v_company_id,
       v_currency,
       v_sale_item_id
  FROM line_item ti
  JOIN line_item si
    ON si.id_line_item = ti.id_sale_item
   AND si.item_type = 'sale_item'
  JOIN folio f ON f.id_folio = si.id_folio
  JOIN reservation r ON r.id_reservation = f.id_reservation
  JOIN property p ON p.id_property = r.id_property
  WHERE ti.id_line_item = p_id_tax_item
    AND ti.item_type = 'tax_item'
    AND f.deleted_at IS NULL
    AND r.deleted_at IS NULL
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_item not found';
  END IF;

  IF v_deleted_at IS NOT NULL OR v_is_active = 0 THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'obligation'
       AND id_tax_item = p_id_tax_item
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  SELECT oc.id_line_item_catalog
    INTO v_preferred_catalog_id
  FROM line_item_catalog oc
  JOIN line_item_catalog_parent lcp
    ON lcp.id_sale_item_catalog = oc.id_line_item_catalog
   AND lcp.id_parent_sale_item_catalog = v_tax_rule_id
   AND lcp.deleted_at IS NULL
   AND lcp.is_active = 1
  WHERE oc.catalog_type = 'obligation'
    AND oc.id_company = v_company_id
    AND oc.deleted_at IS NULL
    AND oc.is_active = 1
    AND (oc.id_property IS NULL OR oc.id_property = v_property_id)
  ORDER BY (oc.id_property IS NULL) ASC, oc.id_property DESC, oc.id_line_item_catalog DESC
  LIMIT 1;

  IF v_preferred_catalog_id IS NULL THEN
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE item_type = 'obligation'
       AND id_tax_item = p_id_tax_item
       AND deleted_at IS NULL;
    LEAVE proc;
  END IF;

  SELECT obligation_name,
         is_percent,
         percent_value,
         default_amount_cents
    INTO v_obligation_name,
         v_obligation_is_percent,
         v_obligation_percent,
         v_obligation_default
  FROM line_item_catalog
  WHERE id_line_item_catalog = v_preferred_catalog_id
  LIMIT 1;

  SELECT COUNT(*)
    INTO v_calc_count
  FROM line_item_catalog_calc lcc
  WHERE lcc.id_line_item_catalog = v_preferred_catalog_id
    AND lcc.id_parent_line_item_catalog = v_tax_rule_id
    AND lcc.deleted_at IS NULL
    AND lcc.is_active = 1;

  SET v_calc_adjust = 0;
  IF v_calc_count > 0 AND v_sale_item_id IS NOT NULL AND v_sale_item_id <> 0 THEN
    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_queue;
    DROP TEMPORARY TABLE IF EXISTS tmp_calc_parent_all;
    CREATE TEMPORARY TABLE tmp_calc_parent_queue (
      id_sale_item BIGINT PRIMARY KEY
    );
    CREATE TEMPORARY TABLE tmp_calc_parent_all (
      id_sale_item BIGINT PRIMARY KEY
    );

    INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
    VALUES (v_sale_item_id);
    INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
    VALUES (v_sale_item_id);

    parent_calc_loop:WHILE (SELECT COUNT(*) FROM tmp_calc_parent_queue) > 0 DO
      SELECT id_sale_item
        INTO v_calc_parent_id
      FROM tmp_calc_parent_queue
      LIMIT 1;

      DELETE FROM tmp_calc_parent_queue WHERE id_sale_item = v_calc_parent_id;

      INSERT IGNORE INTO tmp_calc_parent_queue (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;

      INSERT IGNORE INTO tmp_calc_parent_all (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE item_type = 'sale_item'
        AND id_parent_sale_item = v_calc_parent_id
        AND deleted_at IS NULL
        AND is_active = 1;
    END WHILE;

    SET done = 0;
    OPEN calc_cur;
    calc_loop: LOOP
      FETCH calc_cur INTO v_calc_component_id, v_calc_is_positive;
      IF done = 1 THEN
        LEAVE calc_loop;
      END IF;

      SELECT catalog_type
        INTO v_calc_component_type
      FROM line_item_catalog
      WHERE id_line_item_catalog = v_calc_component_id
      LIMIT 1;

      SET v_calc_component_sum = 0;

      IF v_calc_component_type = 'sale_item' THEN
        DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_queue;
        DROP TEMPORARY TABLE IF EXISTS tmp_calc_comp_all;
        CREATE TEMPORARY TABLE tmp_calc_comp_queue (
          id_sale_item BIGINT PRIMARY KEY
        );
        CREATE TEMPORARY TABLE tmp_calc_comp_all (
          id_sale_item BIGINT PRIMARY KEY
        );

        INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
        SELECT li.id_line_item
        FROM line_item li
        JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
        WHERE li.item_type = 'sale_item'
          AND li.id_sale_item_catalog = v_calc_component_id
          AND li.deleted_at IS NULL
          AND li.is_active = 1;

        INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
        SELECT id_sale_item FROM tmp_calc_comp_queue;

        comp_calc_loop: WHILE (SELECT COUNT(*) FROM tmp_calc_comp_queue) > 0 DO
          SELECT id_sale_item
            INTO v_calc_component_item_id
          FROM tmp_calc_comp_queue
          LIMIT 1;

          DELETE FROM tmp_calc_comp_queue WHERE id_sale_item = v_calc_component_item_id;

          INSERT IGNORE INTO tmp_calc_comp_queue (id_sale_item)
          SELECT li.id_line_item
          FROM line_item li
          JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
          WHERE li.item_type = 'sale_item'
            AND li.id_parent_sale_item = v_calc_component_item_id
            AND li.deleted_at IS NULL
            AND li.is_active = 1;

          INSERT IGNORE INTO tmp_calc_comp_all (id_sale_item)
          SELECT li.id_line_item
          FROM line_item li
          JOIN tmp_calc_parent_all tp ON tp.id_sale_item = li.id_line_item
          WHERE li.item_type = 'sale_item'
            AND li.id_parent_sale_item = v_calc_component_item_id
            AND li.deleted_at IS NULL
            AND li.is_active = 1;
        END WHILE;

        SELECT COALESCE(SUM(li.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item li
        WHERE li.item_type = 'sale_item'
          AND li.id_line_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
        SELECT v_calc_component_sum + COALESCE(SUM(ti.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item ti
        WHERE ti.item_type = 'tax_item'
          AND ti.deleted_at IS NULL
          AND ti.is_active = 1
          AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_comp_all);
      ELSEIF v_calc_component_type = 'tax_rule' THEN
        SELECT COALESCE(SUM(ti.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item ti
        WHERE ti.item_type = 'tax_item'
          AND ti.id_tax_rule = v_calc_component_id
          AND ti.deleted_at IS NULL
          AND ti.is_active = 1
          AND ti.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all);
      ELSE
        SELECT COALESCE(SUM(li.amount_cents),0)
          INTO v_calc_component_sum
        FROM line_item li
        WHERE li.id_line_item_catalog = v_calc_component_id
          AND li.deleted_at IS NULL
          AND li.is_active = 1
          AND (
            (li.item_type IN ('obligation','income') AND li.id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all))
            OR (li.item_type = 'obligation' AND li.id_tax_item IN (
                SELECT id_line_item
                FROM line_item
                WHERE item_type = 'tax_item'
                  AND id_sale_item IN (SELECT id_sale_item FROM tmp_calc_parent_all)
                  AND deleted_at IS NULL
                  AND is_active = 1
            ))
          );
      END IF;

      IF v_calc_is_positive = 1 THEN
        SET v_calc_adjust = v_calc_adjust + v_calc_component_sum;
      ELSE
        SET v_calc_adjust = v_calc_adjust - v_calc_component_sum;
      END IF;
    END LOOP;
    CLOSE calc_cur;
    SET done = 0;
  END IF;

  IF v_calc_count > 0 THEN
    IF v_obligation_is_percent = 1 THEN
      SET v_obligation_amount = ROUND((v_amount_cents + v_calc_adjust) * (v_obligation_percent / 100));
    ELSE
      SET v_obligation_amount = v_amount_cents + v_calc_adjust + COALESCE(v_obligation_default,0);
    END IF;
  ELSE
    IF v_obligation_is_percent = 1 THEN
      SET v_obligation_amount = ROUND(v_amount_cents * (v_obligation_percent / 100));
    ELSE
      SET v_obligation_amount = COALESCE(v_obligation_default,0);
    END IF;
  END IF;

  INSERT INTO line_item (
    item_type,
    id_line_item_catalog,
    id_obligation_catalog,
    obligation_name,
    id_reservation,
    id_sale_item,
    id_tax_item,
    service_date,
    amount_cents,
    paid_cents,
    currency,
    notes,
    is_active,
    created_at,
    created_by,
    updated_at
  ) VALUES (
    'obligation',
    v_preferred_catalog_id,
    v_preferred_catalog_id,
    v_obligation_name,
    v_reservation_id,
    NULL,
    p_id_tax_item,
    v_check_in_date,
    v_obligation_amount,
    0,
    v_currency,
    NULL,
    1,
    NOW(),
    p_actor_user_id,
    NOW()
  )
  ON DUPLICATE KEY UPDATE
    id_reservation = VALUES(id_reservation),
    obligation_name = VALUES(obligation_name),
    amount_cents = VALUES(amount_cents),
    currency = VALUES(currency),
    service_date = VALUES(service_date),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW(),
    paid_cents = LEAST(paid_cents, VALUES(amount_cents));

  UPDATE line_item oi
  LEFT JOIN line_item_catalog oc
    ON oc.id_line_item_catalog = oi.id_obligation_catalog
   AND oc.catalog_type = 'obligation'
  SET oi.is_active = 0,
      oi.deleted_at = NOW(),
      oi.updated_at = NOW()
  WHERE oi.item_type = 'obligation'
    AND oi.id_tax_item = p_id_tax_item
    AND oi.deleted_at IS NULL
    AND (oc.id_line_item_catalog IS NULL
         OR oc.deleted_at IS NOT NULL
         OR oc.is_active = 0
         OR oc.id_company <> v_company_id
         OR (oc.id_property IS NOT NULL AND oc.id_property <> v_property_id)
         OR NOT EXISTS (
            SELECT 1
              FROM line_item_catalog_parent lcp
             WHERE lcp.id_sale_item_catalog = oc.id_line_item_catalog
               AND lcp.id_parent_sale_item_catalog = v_tax_rule_id
               AND lcp.deleted_at IS NULL
               AND lcp.is_active = 1
         )
         OR oc.id_line_item_catalog <> v_preferred_catalog_id);
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_account_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_include_inactive` TINYINT, IN `p_id_ota_account` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND TRIM(p_property_code) <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;

    IF v_property_id IS NULL OR v_property_id <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    oa.id_ota_account,
    oa.id_company,
    oa.id_property,
    p.code AS property_code,
    p.name AS property_name,
    oa.platform,
    oa.ota_name,
    oa.external_code,
    oa.contact_email,
    oa.timezone,
    oa.notes,
    oa.id_service_fee_payment_catalog,
    COALESCE(sfp.item_name, '') AS service_fee_payment_catalog_name,
    oa.is_active,
    oa.deleted_at,
    oa.created_at,
    oa.updated_at,
    COALESCE(SUM(
      CASE
        WHEN oalc.deleted_at IS NULL AND oalc.is_active = 1 THEN 1
        ELSE 0
      END
    ), 0) AS lodging_catalog_count
  FROM ota_account oa
  JOIN property p
    ON p.id_property = oa.id_property
   AND p.deleted_at IS NULL
  LEFT JOIN ota_account_lodging_catalog oalc
    ON oalc.id_ota_account = oa.id_ota_account
  LEFT JOIN line_item_catalog sfp
    ON sfp.id_line_item_catalog = oa.id_service_fee_payment_catalog
   AND sfp.deleted_at IS NULL
  WHERE oa.id_company = v_company_id
    AND (v_property_id IS NULL OR oa.id_property = v_property_id)
    AND (p_id_ota_account IS NULL OR p_id_ota_account <= 0 OR oa.id_ota_account = p_id_ota_account)
    AND (
      COALESCE(p_include_inactive, 0) <> 0
      OR (oa.deleted_at IS NULL AND oa.is_active = 1)
    )
  GROUP BY
    oa.id_ota_account,
    oa.id_company,
    oa.id_property,
    p.code,
    p.name,
    oa.platform,
    oa.ota_name,
    oa.external_code,
    oa.contact_email,
    oa.timezone,
    oa.notes,
    oa.id_service_fee_payment_catalog,
    sfp.item_name,
    oa.is_active,
    oa.deleted_at,
    oa.created_at,
    oa.updated_at
  ORDER BY p.code, oa.platform, oa.ota_name, oa.id_ota_account;

  SELECT
    oa.id_ota_account,
    oa.id_property,
    p.code AS property_code,
    oalc.id_line_item_catalog,
    lic.item_name,
    cat.category_name,
    oalc.sort_order
  FROM ota_account oa
  JOIN property p
    ON p.id_property = oa.id_property
   AND p.deleted_at IS NULL
  JOIN ota_account_lodging_catalog oalc
    ON oalc.id_ota_account = oa.id_ota_account
   AND oalc.deleted_at IS NULL
   AND oalc.is_active = 1
  JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = oalc.id_line_item_catalog
   AND lic.deleted_at IS NULL
  LEFT JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
  WHERE oa.id_company = v_company_id
    AND (v_property_id IS NULL OR oa.id_property = v_property_id)
    AND (p_id_ota_account IS NULL OR p_id_ota_account <= 0 OR oa.id_ota_account = p_id_ota_account)
    AND (
      COALESCE(p_include_inactive, 0) <> 0
      OR (oa.deleted_at IS NULL AND oa.is_active = 1)
    )
  ORDER BY p.code, oa.ota_name, oalc.sort_order, cat.category_name, lic.item_name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_account_info_catalog_sync` (IN `p_company_code` VARCHAR(100), IN `p_id_ota_account` BIGINT, IN `p_catalog_ids_csv` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_ota_company_id BIGINT;
  DECLARE v_csv TEXT;
  DECLARE v_token VARCHAR(64);
  DECLARE v_id BIGINT;
  DECLARE v_pos INT;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;
  IF p_id_ota_account IS NULL OR p_id_ota_account <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account id is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  SELECT id_company
    INTO v_ota_company_id
  FROM ota_account
  WHERE id_ota_account = p_id_ota_account
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_ota_company_id IS NULL OR v_ota_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account not found';
  END IF;
  IF v_ota_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account does not belong to company';
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_ota_info_catalog_ids;
  CREATE TEMPORARY TABLE tmp_ota_info_catalog_ids (
    id_line_item_catalog BIGINT PRIMARY KEY
  ) ENGINE=MEMORY;

  SET v_csv = REPLACE(TRIM(COALESCE(p_catalog_ids_csv, '')), ' ', '');
  SET v_csv = TRIM(BOTH ',' FROM v_csv);

  parse_loop: WHILE v_csv IS NOT NULL AND v_csv <> '' DO
    SET v_pos = INSTR(v_csv, ',');
    IF v_pos > 0 THEN
      SET v_token = SUBSTRING(v_csv, 1, v_pos - 1);
      SET v_csv = SUBSTRING(v_csv, v_pos + 1);
    ELSE
      SET v_token = v_csv;
      SET v_csv = '';
    END IF;

    SET v_id = CAST(TRIM(v_token) AS UNSIGNED);
    IF v_id IS NOT NULL AND v_id > 0 THEN
      INSERT IGNORE INTO tmp_ota_info_catalog_ids (id_line_item_catalog)
      VALUES (v_id);
    END IF;
  END WHILE parse_loop;

  UPDATE ota_account_info_catalog
     SET is_active = 0,
         deleted_at = NOW(),
         updated_at = NOW()
   WHERE id_ota_account = p_id_ota_account
     AND deleted_at IS NULL
     AND id_line_item_catalog NOT IN (
       SELECT id_line_item_catalog FROM tmp_ota_info_catalog_ids
     );

  UPDATE ota_account_info_catalog oaic
  JOIN tmp_ota_info_catalog_ids t
    ON t.id_line_item_catalog = oaic.id_line_item_catalog
   SET oaic.is_active = 1,
       oaic.deleted_at = NULL,
       oaic.updated_at = NOW()
 WHERE oaic.id_ota_account = p_id_ota_account;

  INSERT INTO ota_account_info_catalog (
    id_ota_account,
    id_line_item_catalog,
    sort_order,
    is_active,
    deleted_at
  )
  SELECT
    p_id_ota_account,
    t.id_line_item_catalog,
    0,
    1,
    NULL
  FROM tmp_ota_info_catalog_ids t
  JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = t.id_line_item_catalog
   AND lic.deleted_at IS NULL
   AND lic.is_active = 1
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.deleted_at IS NULL
   AND cat.is_active = 1
   AND cat.id_company = v_company_id
  LEFT JOIN ota_account_info_catalog existing
    ON existing.id_ota_account = p_id_ota_account
   AND existing.id_line_item_catalog = t.id_line_item_catalog
  WHERE existing.id_ota_account_info_catalog IS NULL;

  SELECT
    oaic.id_ota_account_info_catalog,
    oaic.id_ota_account,
    oaic.id_line_item_catalog,
    lic.item_name,
    lic.catalog_type,
    cat.category_name,
    oaic.sort_order,
    oaic.is_active,
    oaic.deleted_at
  FROM ota_account_info_catalog oaic
  JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = oaic.id_line_item_catalog
  LEFT JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
  WHERE oaic.id_ota_account = p_id_ota_account
    AND oaic.deleted_at IS NULL
    AND oaic.is_active = 1
  ORDER BY oaic.sort_order, lic.item_name, oaic.id_line_item_catalog;

  DROP TEMPORARY TABLE IF EXISTS tmp_ota_info_catalog_ids;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_account_lodging_sync` (IN `p_company_code` VARCHAR(100), IN `p_id_ota_account` BIGINT, IN `p_catalog_ids_csv` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_ota_company_id BIGINT;
  DECLARE v_csv TEXT;
  DECLARE v_token VARCHAR(64);
  DECLARE v_id BIGINT;
  DECLARE v_pos INT;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;
  IF p_id_ota_account IS NULL OR p_id_ota_account <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account id is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  SELECT id_company
    INTO v_ota_company_id
  FROM ota_account
  WHERE id_ota_account = p_id_ota_account
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_ota_company_id IS NULL OR v_ota_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account not found';
  END IF;
  IF v_ota_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account does not belong to company';
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_ota_catalog_ids;
  CREATE TEMPORARY TABLE tmp_ota_catalog_ids (
    id_line_item_catalog BIGINT PRIMARY KEY
  ) ENGINE=MEMORY;

  SET v_csv = REPLACE(TRIM(COALESCE(p_catalog_ids_csv, '')), ' ', '');
  SET v_csv = TRIM(BOTH ',' FROM v_csv);

  parse_loop: WHILE v_csv IS NOT NULL AND v_csv <> '' DO
    SET v_pos = INSTR(v_csv, ',');
    IF v_pos > 0 THEN
      SET v_token = SUBSTRING(v_csv, 1, v_pos - 1);
      SET v_csv = SUBSTRING(v_csv, v_pos + 1);
    ELSE
      SET v_token = v_csv;
      SET v_csv = '';
    END IF;

    SET v_id = CAST(TRIM(v_token) AS UNSIGNED);
    IF v_id IS NOT NULL AND v_id > 0 THEN
      INSERT IGNORE INTO tmp_ota_catalog_ids (id_line_item_catalog)
      VALUES (v_id);
    END IF;
  END WHILE parse_loop;

  UPDATE ota_account_lodging_catalog
     SET is_active = 0,
         deleted_at = NOW(),
         updated_at = NOW()
   WHERE id_ota_account = p_id_ota_account
     AND deleted_at IS NULL
     AND id_line_item_catalog NOT IN (
       SELECT id_line_item_catalog FROM tmp_ota_catalog_ids
     );

  UPDATE ota_account_lodging_catalog oalc
  JOIN tmp_ota_catalog_ids t
    ON t.id_line_item_catalog = oalc.id_line_item_catalog
   SET oalc.is_active = 1,
       oalc.deleted_at = NULL,
       oalc.updated_at = NOW()
 WHERE oalc.id_ota_account = p_id_ota_account;

  INSERT INTO ota_account_lodging_catalog (
    id_ota_account,
    id_line_item_catalog,
    sort_order,
    is_active,
    deleted_at
  )
  SELECT
    p_id_ota_account,
    t.id_line_item_catalog,
    0,
    1,
    NULL
  FROM tmp_ota_catalog_ids t
  JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = t.id_line_item_catalog
   AND lic.deleted_at IS NULL
   AND lic.is_active = 1
   AND lic.catalog_type = 'sale_item'
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.deleted_at IS NULL
   AND cat.is_active = 1
   AND cat.id_company = v_company_id
  LEFT JOIN ota_account_lodging_catalog existing
    ON existing.id_ota_account = p_id_ota_account
   AND existing.id_line_item_catalog = t.id_line_item_catalog
  WHERE existing.id_ota_account_lodging_catalog IS NULL;

  SELECT
    oalc.id_ota_account_lodging_catalog,
    oalc.id_ota_account,
    oalc.id_line_item_catalog,
    lic.item_name,
    cat.category_name,
    oalc.sort_order,
    oalc.is_active,
    oalc.deleted_at
  FROM ota_account_lodging_catalog oalc
  JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = oalc.id_line_item_catalog
  LEFT JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
  WHERE oalc.id_ota_account = p_id_ota_account
    AND oalc.deleted_at IS NULL
    AND oalc.is_active = 1
  ORDER BY oalc.sort_order, lic.item_name, oalc.id_line_item_catalog;

  DROP TEMPORARY TABLE IF EXISTS tmp_ota_catalog_ids;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_account_upsert` (IN `p_mode` VARCHAR(16), IN `p_id_ota_account` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_platform` VARCHAR(32), IN `p_ota_name` VARCHAR(150), IN `p_external_code` VARCHAR(120), IN `p_contact_email` VARCHAR(190), IN `p_timezone` VARCHAR(64), IN `p_notes` TEXT, IN `p_id_service_fee_payment_catalog` BIGINT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_mode VARCHAR(16);
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_effective_id BIGINT;
  DECLARE v_platform VARCHAR(32);
  DECLARE v_ota_name VARCHAR(150);
  DECLARE v_timezone VARCHAR(64);
  DECLARE v_current_company_id BIGINT;
  DECLARE v_service_fee_payment_catalog BIGINT DEFAULT NULL;

  SET v_mode = LOWER(TRIM(COALESCE(p_mode, '')));
  IF v_mode NOT IN ('create', 'update', 'delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid mode';
  END IF;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  SET v_effective_id = COALESCE(p_id_ota_account, 0);

  IF v_mode IN ('update', 'delete') THEN
    IF v_effective_id <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account id is required';
    END IF;

    SELECT id_company
      INTO v_current_company_id
    FROM ota_account
    WHERE id_ota_account = v_effective_id
      AND deleted_at IS NULL
    LIMIT 1;

    IF v_current_company_id IS NULL OR v_current_company_id <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account not found';
    END IF;

    IF v_current_company_id <> v_company_id THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ota account does not belong to company';
    END IF;
  END IF;

  IF v_mode = 'delete' THEN
    UPDATE ota_account
       SET is_active = 0,
           deleted_at = NOW(),
           updated_by = p_actor_user_id,
           updated_at = NOW()
     WHERE id_ota_account = v_effective_id
       AND deleted_at IS NULL;

    UPDATE ota_account_lodging_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_ota_account = v_effective_id
       AND deleted_at IS NULL;

    UPDATE ota_account_info_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_ota_account = v_effective_id
       AND deleted_at IS NULL;

    SELECT
      oa.id_ota_account,
      oa.id_company,
      oa.id_property,
      p.code AS property_code,
      oa.platform,
      oa.ota_name,
      oa.external_code,
      oa.contact_email,
      oa.timezone,
      oa.notes,
      oa.id_service_fee_payment_catalog,
      COALESCE(sfp.item_name, '') AS service_fee_payment_catalog_name,
      oa.is_active,
      oa.deleted_at,
      oa.created_at,
      oa.updated_at
    FROM ota_account oa
    JOIN property p ON p.id_property = oa.id_property
    LEFT JOIN line_item_catalog sfp
      ON sfp.id_line_item_catalog = oa.id_service_fee_payment_catalog
    WHERE oa.id_ota_account = v_effective_id
    LIMIT 1;
    LEAVE proc;
  END IF;

  IF p_property_code IS NULL OR TRIM(p_property_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'property code is required';
  END IF;

  SELECT id_property
    INTO v_property_id
  FROM property
  WHERE code = p_property_code
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_property_id IS NULL OR v_property_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown property';
  END IF;

  SET v_service_fee_payment_catalog = NULL;
  IF p_id_service_fee_payment_catalog IS NOT NULL
     AND p_id_service_fee_payment_catalog > 0 THEN
    SELECT lic.id_line_item_catalog
      INTO v_service_fee_payment_catalog
    FROM line_item_catalog lic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
     AND cat.id_company = v_company_id
     AND cat.deleted_at IS NULL
     AND cat.is_active = 1
    WHERE lic.id_line_item_catalog = p_id_service_fee_payment_catalog
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND lic.catalog_type = 'obligation'
    LIMIT 1;

    IF v_service_fee_payment_catalog IS NULL OR v_service_fee_payment_catalog <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid service fee obligation catalog';
    END IF;
  END IF;

  SET v_platform = LOWER(TRIM(COALESCE(p_platform, 'other')));
  IF v_platform IN ('abb') THEN
    SET v_platform = 'airbnb';
  END IF;
  IF v_platform NOT IN ('airbnb', 'booking', 'expedia', 'other') THEN
    SET v_platform = 'other';
  END IF;

  SET v_ota_name = TRIM(COALESCE(p_ota_name, ''));
  IF v_ota_name = '' THEN
    SET v_ota_name = CASE v_platform
      WHEN 'airbnb' THEN 'Airbnb'
      WHEN 'booking' THEN 'Booking'
      WHEN 'expedia' THEN 'Expedia'
      ELSE 'Directo/Otro'
    END;
  END IF;

  SET v_timezone = TRIM(COALESCE(p_timezone, ''));
  IF v_timezone = '' THEN
    SET v_timezone = 'America/Mexico_City';
  END IF;

  IF v_mode = 'create' THEN
    INSERT INTO ota_account (
      id_company,
      id_property,
      platform,
      ota_name,
      external_code,
      contact_email,
      timezone,
      notes,
      id_service_fee_payment_catalog,
      is_active,
      deleted_at,
      created_by,
      updated_by
    ) VALUES (
      v_company_id,
      v_property_id,
      v_platform,
      v_ota_name,
      NULLIF(TRIM(p_external_code), ''),
      NULLIF(TRIM(p_contact_email), ''),
      v_timezone,
      NULLIF(TRIM(p_notes), ''),
      v_service_fee_payment_catalog,
      CASE WHEN COALESCE(p_is_active, 1) <> 0 THEN 1 ELSE 0 END,
      NULL,
      p_actor_user_id,
      p_actor_user_id
    );
    SET v_effective_id = LAST_INSERT_ID();
  ELSE
    UPDATE ota_account
       SET id_property = v_property_id,
           platform = v_platform,
           ota_name = v_ota_name,
           external_code = NULLIF(TRIM(p_external_code), ''),
           contact_email = NULLIF(TRIM(p_contact_email), ''),
           timezone = v_timezone,
           notes = NULLIF(TRIM(p_notes), ''),
           id_service_fee_payment_catalog = v_service_fee_payment_catalog,
           is_active = CASE WHEN COALESCE(p_is_active, 1) <> 0 THEN 1 ELSE 0 END,
           deleted_at = CASE WHEN COALESCE(p_is_active, 1) <> 0 THEN NULL ELSE deleted_at END,
           updated_by = p_actor_user_id,
           updated_at = NOW()
     WHERE id_ota_account = v_effective_id;
  END IF;

  SELECT
    oa.id_ota_account,
    oa.id_company,
    oa.id_property,
    p.code AS property_code,
    oa.platform,
    oa.ota_name,
    oa.external_code,
    oa.contact_email,
    oa.timezone,
    oa.notes,
    oa.id_service_fee_payment_catalog,
    COALESCE(sfp.item_name, '') AS service_fee_payment_catalog_name,
    oa.is_active,
    oa.deleted_at,
    oa.created_at,
    oa.updated_at
  FROM ota_account oa
  JOIN property p ON p.id_property = oa.id_property
  LEFT JOIN line_item_catalog sfp
    ON sfp.id_line_item_catalog = oa.id_service_fee_payment_catalog
  WHERE oa.id_ota_account = v_effective_id
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_ical_feed_lodging_data` (IN `p_company_code` VARCHAR(100), IN `p_id_ota_ical_feed` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT DEFAULT 0;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_id_ota_ical_feed IS NULL OR p_id_ota_ical_feed <= 0 THEN
    SELECT
      flc.id_ota_ical_feed,
      flc.id_line_item_catalog
    FROM ota_ical_feed_lodging_catalog flc
    JOIN ota_ical_feed f
      ON f.id_ota_ical_feed = flc.id_ota_ical_feed
     AND f.id_company = v_company_id
     AND f.deleted_at IS NULL
    WHERE flc.deleted_at IS NULL
      AND flc.is_active = 1
    ORDER BY flc.id_ota_ical_feed, flc.sort_order, flc.id_line_item_catalog;
  ELSE
    SELECT
      flc.id_ota_ical_feed,
      flc.id_line_item_catalog
    FROM ota_ical_feed_lodging_catalog flc
    JOIN ota_ical_feed f
      ON f.id_ota_ical_feed = flc.id_ota_ical_feed
     AND f.id_company = v_company_id
     AND f.deleted_at IS NULL
    WHERE flc.id_ota_ical_feed = p_id_ota_ical_feed
      AND flc.deleted_at IS NULL
      AND flc.is_active = 1
    ORDER BY flc.sort_order, flc.id_line_item_catalog;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_ical_feed_lodging_upsert` (IN `p_company_code` VARCHAR(100), IN `p_id_ota_ical_feed` BIGINT, IN `p_lodging_catalog_ids` TEXT, IN `p_updated_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT DEFAULT 0;
  DECLARE v_id_property BIGINT DEFAULT 0;
  DECLARE v_csv TEXT;
  DECLARE v_token VARCHAR(64);
  DECLARE v_catalog_id BIGINT;
  DECLARE v_sort INT DEFAULT 0;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_id_ota_ical_feed IS NULL OR p_id_ota_ical_feed <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Feed id is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT f.id_property
    INTO v_id_property
  FROM ota_ical_feed f
  WHERE f.id_ota_ical_feed = p_id_ota_ical_feed
    AND f.id_company = v_company_id
    AND f.deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL OR v_id_property <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Feed not found for company';
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_ota_lodging_ids;
  CREATE TEMPORARY TABLE tmp_ota_lodging_ids (
    id_line_item_catalog BIGINT PRIMARY KEY,
    sort_order INT NOT NULL DEFAULT 0
  ) ENGINE=MEMORY;

  SET v_csv = TRIM(COALESCE(p_lodging_catalog_ids, ''));
  WHILE v_csv <> '' DO
    SET v_token = TRIM(SUBSTRING_INDEX(v_csv, ',', 1));
    SET v_csv = IF(INSTR(v_csv, ',') > 0, SUBSTRING(v_csv, INSTR(v_csv, ',') + 1), '');
    SET v_catalog_id = CAST(v_token AS UNSIGNED);
    IF v_catalog_id IS NOT NULL AND v_catalog_id > 0 THEN
      INSERT INTO tmp_ota_lodging_ids (id_line_item_catalog, sort_order)
      VALUES (v_catalog_id, v_sort)
      ON DUPLICATE KEY UPDATE sort_order = LEAST(sort_order, VALUES(sort_order));
      SET v_sort = v_sort + 1;
    END IF;
  END WHILE;

  DELETE t
  FROM tmp_ota_lodging_ids t
  LEFT JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = t.id_line_item_catalog
   AND lic.catalog_type = 'sale_item'
   AND lic.deleted_at IS NULL
   AND lic.is_active = 1
  LEFT JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.id_company = v_company_id
   AND cat.deleted_at IS NULL
   AND cat.is_active = 1
   AND (cat.id_property = v_id_property OR cat.id_property IS NULL)
  WHERE lic.id_line_item_catalog IS NULL
     OR cat.id_sale_item_category IS NULL;

  UPDATE ota_ical_feed_lodging_catalog
     SET is_active = 0,
         deleted_at = NOW(),
         updated_at = NOW()
   WHERE id_ota_ical_feed = p_id_ota_ical_feed
     AND deleted_at IS NULL;

  INSERT INTO ota_ical_feed_lodging_catalog (
    id_ota_ical_feed,
    id_line_item_catalog,
    sort_order,
    is_active,
    deleted_at,
    created_at,
    updated_at
  )
  SELECT
    p_id_ota_ical_feed,
    t.id_line_item_catalog,
    t.sort_order,
    1,
    NULL,
    NOW(),
    NOW()
  FROM tmp_ota_lodging_ids t
  ON DUPLICATE KEY UPDATE
    sort_order = VALUES(sort_order),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  DROP TEMPORARY TABLE IF EXISTS tmp_ota_lodging_ids;

  SELECT
    flc.id_ota_ical_feed,
    flc.id_line_item_catalog
  FROM ota_ical_feed_lodging_catalog flc
  WHERE flc.id_ota_ical_feed = p_id_ota_ical_feed
    AND flc.is_active = 1
    AND flc.deleted_at IS NULL
  ORDER BY flc.sort_order, flc.id_line_item_catalog;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_ota_ical_lodging_catalog_data` (IN `p_company_code` VARCHAR(100), IN `p_id_property` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT DEFAULT 0;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT
    lic.id_line_item_catalog,
    lic.item_name,
    COALESCE(cat.category_name, '') AS category_name,
    lic.default_unit_price_cents
  FROM line_item_catalog lic
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.id_company = v_company_id
   AND cat.deleted_at IS NULL
   AND cat.is_active = 1
  WHERE lic.deleted_at IS NULL
    AND lic.is_active = 1
    AND lic.catalog_type = 'sale_item'
    AND (
      p_id_property IS NULL
      OR p_id_property <= 0
      OR cat.id_property = p_id_property
      OR cat.id_property IS NULL
    )
  ORDER BY category_name, lic.item_name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_payment_catalog_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_show_inactive` TINYINT, IN `p_id_payment_catalog` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    lic.id_line_item_catalog AS id_payment_catalog,
    lic.id_company,
    lic.id_property,
    prop.code AS property_code,
    prop.name AS property_name,
    lic.name,
    lic.description,
    lic.is_active,
    lic.deleted_at,
    lic.created_at,
    lic.created_by,
    lic.updated_at,
    taxmap.tax_rule_ids
  FROM line_item_catalog lic
  LEFT JOIN property prop ON prop.id_property = lic.id_property
  LEFT JOIN (
    SELECT sctr.id_sale_item_catalog,
           GROUP_CONCAT(DISTINCT sctr.id_tax_rule ORDER BY sctr.id_tax_rule) AS tax_rule_ids
    FROM sale_item_catalog_tax_rule sctr
    WHERE sctr.deleted_at IS NULL
      AND sctr.is_active = 1
    GROUP BY sctr.id_sale_item_catalog
  ) taxmap ON taxmap.id_sale_item_catalog = lic.id_line_item_catalog
  WHERE lic.catalog_type = 'payment'
    AND lic.id_company = v_company_id
    AND (p_id_payment_catalog IS NULL OR p_id_payment_catalog = 0 OR lic.id_line_item_catalog = p_id_payment_catalog)
    AND (v_property_id IS NULL OR lic.id_property IS NULL OR lic.id_property = v_property_id)
    AND (p_show_inactive = 1 OR lic.is_active = 1)
  ORDER BY lic.name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_payment_catalog_upsert` (IN `p_action` VARCHAR(16), IN `p_id_payment_catalog` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_name` VARCHAR(255), IN `p_description` TEXT, IN `p_tax_rule_ids` TEXT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_action VARCHAR(16);
  DECLARE v_existing_id BIGINT;

  SET v_action = COALESCE(NULLIF(p_action,''),'create');
  IF v_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for payment catalog';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  IF v_action = 'create' THEN
    IF p_name IS NULL OR p_name = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Payment name is required';
    END IF;
    INSERT INTO line_item_catalog (
      catalog_type,
      id_company,
      id_property,
      name,
      description,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      'payment',
      v_company_id,
      v_property_id,
      p_name,
      p_description,
      COALESCE(p_is_active,1),
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET v_existing_id = LAST_INSERT_ID();

    SELECT
      id_line_item_catalog AS id_payment_catalog,
      id_company,
      id_property,
      name,
      description,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_existing_id;
    LEAVE proc;
  END IF;

  IF p_id_payment_catalog IS NULL OR p_id_payment_catalog = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Payment catalog id is required';
  END IF;

  SELECT id_line_item_catalog INTO v_existing_id
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_payment_catalog
    AND catalog_type = 'payment'
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;
  IF v_existing_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Payment catalog not found';
  END IF;

  IF v_action = 'delete' THEN
    UPDATE line_item_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item_catalog = v_existing_id;
    SELECT
      id_line_item_catalog AS id_payment_catalog,
      id_company,
      id_property,
      name,
      description,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_existing_id;
    LEAVE proc;
  END IF;

  UPDATE line_item_catalog
     SET id_property = v_property_id,
         name = COALESCE(NULLIF(p_name,''), name),
         description = COALESCE(p_description, description),
         is_active = COALESCE(p_is_active, is_active),
         updated_at = NOW()
   WHERE id_line_item_catalog = v_existing_id;

  SELECT
    id_line_item_catalog AS id_payment_catalog,
    id_company,
    id_property,
    name,
    description,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item_catalog
  WHERE id_line_item_catalog = v_existing_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_payment_upsert` (IN `p_action` VARCHAR(16), IN `p_id_payment` BIGINT, IN `p_id_folio` BIGINT, IN `p_id_payment_catalog` BIGINT, IN `p_amount_cents` INT, IN `p_service_date` DATE, IN `p_reference` VARCHAR(255), IN `p_status` VARCHAR(32), IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_id_folio BIGINT;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_amount INT;
  DECLARE v_refunded INT DEFAULT 0;
  DECLARE v_payment_catalog_id BIGINT;
  DECLARE v_payment_name VARCHAR(255);
  DECLARE v_reservation_id BIGINT;

  DECLARE v_queue_id INT;
  DECLARE v_parent_sale_item_id BIGINT;
  DECLARE v_parent_catalog_id BIGINT;
  DECLARE v_parent_qty DECIMAL(18,6);
  DECLARE v_parent_unit_price INT;
  DECLARE v_parent_service_date DATE;

  DECLARE v_child_catalog_id BIGINT;
  DECLARE v_child_catalog_type VARCHAR(32);
  DECLARE v_child_item_type VARCHAR(16);
  DECLARE v_child_is_percent TINYINT;
  DECLARE v_child_percent DECIMAL(9,4);
  DECLARE v_child_default INT;
  DECLARE v_child_name VARCHAR(255);
  DECLARE v_child_obligation_name VARCHAR(255);
  DECLARE v_child_unit_price INT;
  DECLARE v_child_amount INT;
  DECLARE v_child_sale_item_id BIGINT;
  DECLARE done INT DEFAULT 0;

  DECLARE child_cur CURSOR FOR
    SELECT
      lic.id_line_item_catalog,
      lic.catalog_type,
      lic.is_percent,
      lic.percent_value,
      COALESCE(lic.default_unit_price_cents, lic.default_amount_cents, 0) AS default_amount_cents,
      COALESCE(lic.item_name, lic.name, lic.obligation_name) AS item_name,
      lic.obligation_name
    FROM line_item_catalog_parent lcp
    JOIN line_item_catalog lic
      ON lic.id_line_item_catalog = lcp.id_sale_item_catalog
    WHERE lcp.id_parent_sale_item_catalog = v_parent_catalog_id
      AND lcp.deleted_at IS NULL
      AND lcp.is_active = 1
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;

  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for payment';
  END IF;

  IF p_action IN ('create','update') THEN
    IF p_id_folio IS NULL OR p_id_folio = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio id is required';
    END IF;

    SELECT id_folio, currency INTO v_id_folio, v_currency
    FROM folio
    WHERE id_folio = p_id_folio AND deleted_at IS NULL
    LIMIT 1;

    IF v_id_folio IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio not found';
    END IF;

    SET v_amount = COALESCE(p_amount_cents,0);
    IF v_amount <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment amount must be positive';
    END IF;

    SET v_payment_catalog_id = NULL;
    SET v_payment_name = NULL;
    IF p_id_payment_catalog IS NOT NULL AND p_id_payment_catalog <> 0 THEN
      SELECT id_line_item_catalog, name
        INTO v_payment_catalog_id, v_payment_name
      FROM line_item_catalog
      WHERE id_line_item_catalog = p_id_payment_catalog
        AND catalog_type = 'payment'
        AND deleted_at IS NULL
        AND is_active = 1
      LIMIT 1;
      IF v_payment_catalog_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment catalog not found';
      END IF;
    ELSEIF p_action = 'create' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment catalog is required';
    END IF;

    IF p_action = 'create' THEN
      INSERT INTO line_item (
        item_type,
        id_folio,
        id_user,
        id_line_item_catalog,
        method,
        amount_cents,
        currency,
        fx_rate,
        reference,
        service_date,
        authorized_at,
        captured_at,
        refunded_total_cents,
        status,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        'payment',
        v_id_folio,
        p_created_by,
        v_payment_catalog_id,
        COALESCE(v_payment_name, NULL),
        v_amount,
        v_currency,
        NULL,
        NULLIF(p_reference,''),
        COALESCE(p_service_date, CURDATE()),
        NOW(),
        NOW(),
        0,
        COALESCE(NULLIF(p_status,''), 'captured'),
        1,
        NULL,
        NOW(),
        p_created_by,
        NOW()
      );
      SET p_id_payment = LAST_INSERT_ID();
    ELSE
      SELECT COALESCE(refunded_total_cents,0) INTO v_refunded
      FROM line_item
      WHERE id_line_item = p_id_payment
        AND item_type = 'payment'
      LIMIT 1;
      IF v_amount < v_refunded THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'amount is below refunded total';
      END IF;
      UPDATE line_item
         SET id_line_item_catalog = COALESCE(v_payment_catalog_id, id_line_item_catalog),
             method = COALESCE(v_payment_name, method),
             amount_cents = v_amount,
             reference = COALESCE(NULLIF(p_reference,''), reference),
             service_date = COALESCE(p_service_date, service_date),
             status = COALESCE(NULLIF(p_status,''), status),
             updated_at = NOW()
       WHERE id_line_item = p_id_payment
         AND item_type = 'payment';
    END IF;

    SELECT f.id_reservation INTO v_reservation_id
    FROM folio f
    WHERE f.id_folio = v_id_folio
    LIMIT 1;

    /* eliminar derivados actuales del pago */
    DROP TEMPORARY TABLE IF EXISTS tmp_payment_desc_queue;
    CREATE TEMPORARY TABLE tmp_payment_desc_queue (
      id_sale_item BIGINT PRIMARY KEY
    );
    INSERT IGNORE INTO tmp_payment_desc_queue (id_sale_item) VALUES (p_id_payment);

    payment_desc_loop:WHILE (SELECT COUNT(*) FROM tmp_payment_desc_queue) > 0 DO
      SELECT id_sale_item
        INTO v_parent_sale_item_id
      FROM tmp_payment_desc_queue
      LIMIT 1;

      DELETE FROM tmp_payment_desc_queue WHERE id_sale_item = v_parent_sale_item_id;

      INSERT IGNORE INTO tmp_payment_desc_queue (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE id_parent_sale_item = v_parent_sale_item_id
        AND deleted_at IS NULL;

      UPDATE line_item
         SET is_active = 0,
             deleted_at = NOW(),
             updated_at = NOW()
       WHERE id_parent_sale_item = v_parent_sale_item_id
         AND deleted_at IS NULL;
    END WHILE;

    /* crear derivados desde el catalogo de pago */
    IF v_payment_catalog_id IS NOT NULL AND v_payment_catalog_id <> 0 THEN
      DROP TEMPORARY TABLE IF EXISTS tmp_child_queue;
      CREATE TEMPORARY TABLE tmp_child_queue (
        id_queue INT NOT NULL AUTO_INCREMENT PRIMARY KEY,
        id_parent_sale_item BIGINT NOT NULL,
        id_parent_catalog BIGINT NOT NULL,
        qty DECIMAL(18,6) NOT NULL,
        unit_price INT NOT NULL,
        service_date DATE NULL
      );

      INSERT INTO tmp_child_queue (
        id_parent_sale_item,
        id_parent_catalog,
        qty,
        unit_price,
        service_date
      ) VALUES (
        p_id_payment,
        v_payment_catalog_id,
        1,
        v_amount,
        COALESCE(p_service_date, CURDATE())
      );

      child_queue: WHILE (SELECT COUNT(*) FROM tmp_child_queue) > 0 DO
        SELECT id_queue, id_parent_sale_item, id_parent_catalog, qty, unit_price, service_date
          INTO v_queue_id, v_parent_sale_item_id, v_parent_catalog_id, v_parent_qty, v_parent_unit_price, v_parent_service_date
        FROM tmp_child_queue
        ORDER BY id_queue
        LIMIT 1;

        DELETE FROM tmp_child_queue WHERE id_queue = v_queue_id;

        SET done = 0;
        OPEN child_cur;
        read_loop: LOOP
          FETCH child_cur
            INTO v_child_catalog_id,
                 v_child_catalog_type,
                 v_child_is_percent,
                 v_child_percent,
                 v_child_default,
                 v_child_name,
                 v_child_obligation_name;
          IF done = 1 THEN
            LEAVE read_loop;
          END IF;

          SET v_child_item_type = CASE v_child_catalog_type
            WHEN 'tax_rule' THEN 'tax_item'
            WHEN 'payment' THEN 'payment'
            WHEN 'obligation' THEN 'obligation'
            WHEN 'income' THEN 'income'
            ELSE 'sale_item'
          END;
          IF v_child_catalog_type = 'tax_rule' THEN
            SET v_child_is_percent = 1;
          END IF;

          IF v_child_is_percent = 1 THEN
            SET v_child_unit_price = ROUND(v_parent_unit_price * (v_child_percent / 100));
          ELSE
            SET v_child_unit_price = COALESCE(v_child_default,0);
          END IF;

          SET v_child_amount = v_parent_qty * v_child_unit_price;

          INSERT INTO line_item (
            item_type,
            id_user,
            id_folio,
            id_reservation,
            id_line_item_catalog,
            id_sale_item_catalog,
            id_parent_sale_item,
            id_obligation_catalog,
            id_tax_rule,
            id_sale_item,
            obligation_name,
            description,
            service_date,
            quantity,
            unit_price_cents,
            amount_cents,
            currency,
            discount_amount_cents,
            revenue_account,
            status,
            external_ref,
            method,
            is_active,
            created_at,
            created_by,
            updated_at
          ) VALUES (
            v_child_item_type,
            p_created_by,
            v_id_folio,
            v_reservation_id,
            v_child_catalog_id,
            CASE WHEN v_child_item_type = 'sale_item' THEN v_child_catalog_id ELSE NULL END,
            v_parent_sale_item_id,
            CASE WHEN v_child_item_type IN ('obligation','income') THEN v_child_catalog_id ELSE NULL END,
            CASE WHEN v_child_item_type = 'tax_item' THEN v_child_catalog_id ELSE NULL END,
            CASE WHEN v_child_item_type IN ('obligation','income','tax_item') THEN v_parent_sale_item_id ELSE NULL END,
            CASE WHEN v_child_item_type IN ('obligation','income') THEN COALESCE(v_child_obligation_name, v_child_name, '') ELSE '' END,
            NULL,
            v_parent_service_date,
            v_parent_qty,
            v_child_unit_price,
            v_child_amount,
            v_currency,
            0,
            NULL,
            COALESCE(NULLIF(p_status,''),'posted'),
            NULL,
            CASE WHEN v_child_item_type = 'payment' THEN v_child_name ELSE NULL END,
            1,
            NOW(),
            p_created_by,
            NOW()
          );
          SET v_child_sale_item_id = LAST_INSERT_ID();

          INSERT INTO tmp_child_queue (
            id_parent_sale_item,
            id_parent_catalog,
            qty,
            unit_price,
            service_date
          ) VALUES (
            v_child_sale_item_id,
            v_child_catalog_id,
            v_parent_qty,
            v_child_unit_price,
            v_parent_service_date
          );
        END LOOP;
        CLOSE child_cur;
      END WHILE;
    END IF;

    CALL sp_folio_recalc(v_id_folio);
    SELECT
      id_line_item AS id_payment,
      id_folio,
      id_user,
      method,
      amount_cents,
      currency,
      fx_rate,
      reference,
      service_date,
      authorized_at,
      captured_at,
      refunded_total_cents,
      status,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item
    WHERE id_line_item = p_id_payment;
    LEAVE proc;
  END IF;

  /* delete */
  IF p_action = 'delete' THEN
    IF p_id_payment IS NULL OR p_id_payment = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment id is required';
    END IF;
    SELECT id_folio INTO v_id_folio
    FROM line_item
    WHERE id_line_item = p_id_payment
      AND item_type = 'payment'
    LIMIT 1;
    UPDATE line_item
       SET is_active = 0,
           status = 'void',
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item = p_id_payment
       AND item_type = 'payment';
    /* eliminar derivados del pago */
    DROP TEMPORARY TABLE IF EXISTS tmp_payment_desc_queue;
    CREATE TEMPORARY TABLE tmp_payment_desc_queue (
      id_sale_item BIGINT PRIMARY KEY
    );
    INSERT IGNORE INTO tmp_payment_desc_queue (id_sale_item) VALUES (p_id_payment);

    payment_desc_delete:WHILE (SELECT COUNT(*) FROM tmp_payment_desc_queue) > 0 DO
      SELECT id_sale_item
        INTO v_parent_sale_item_id
      FROM tmp_payment_desc_queue
      LIMIT 1;

      DELETE FROM tmp_payment_desc_queue WHERE id_sale_item = v_parent_sale_item_id;

      INSERT IGNORE INTO tmp_payment_desc_queue (id_sale_item)
      SELECT id_line_item
      FROM line_item
      WHERE id_parent_sale_item = v_parent_sale_item_id
        AND deleted_at IS NULL;

      UPDATE line_item
         SET is_active = 0,
             deleted_at = NOW(),
             updated_at = NOW()
       WHERE id_parent_sale_item = v_parent_sale_item_id
        AND deleted_at IS NULL;
    END WHILE;
    IF v_id_folio IS NOT NULL THEN
      CALL sp_folio_recalc(v_id_folio);
    END IF;
    SELECT
      id_line_item AS id_payment,
      id_folio,
      id_user,
      method,
      amount_cents,
      currency,
      fx_rate,
      reference,
      service_date,
      authorized_at,
      captured_at,
      refunded_total_cents,
      status,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item
    WHERE id_line_item = p_id_payment;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_pms_settings_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100))   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_has_service_table TINYINT DEFAULT 0;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
    INTO v_has_service_table
  FROM information_schema.TABLES
  WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = 'pms_settings_service_catalog';

  SELECT
    v_company_id AS id_company,
    v_property_id AS id_property,
    IFNULL((
      SELECT GROUP_CONCAT(DISTINCT l.id_sale_item_catalog ORDER BY l.id_sale_item_catalog)
      FROM pms_settings_lodging_catalog l
      WHERE l.id_company = v_company_id
        AND ((v_property_id IS NULL AND l.id_property IS NULL) OR l.id_property = v_property_id)
        AND l.deleted_at IS NULL
        AND l.is_active = 1
    ), '') AS lodging_catalog_ids,
    IFNULL((
      SELECT GROUP_CONCAT(DISTINCT i.id_sale_item_catalog ORDER BY i.id_sale_item_catalog)
      FROM pms_settings_interest_catalog i
      WHERE i.id_company = v_company_id
        AND ((v_property_id IS NULL AND i.id_property IS NULL) OR i.id_property = v_property_id)
        AND i.deleted_at IS NULL
        AND i.is_active = 1
    ), '') AS interest_catalog_ids,
    IFNULL((
      SELECT GROUP_CONCAT(DISTINCT p.id_sale_item_catalog ORDER BY p.id_sale_item_catalog)
      FROM pms_settings_payment_catalog p
      WHERE p.id_company = v_company_id
        AND ((v_property_id IS NULL AND p.id_property IS NULL) OR p.id_property = v_property_id)
        AND p.deleted_at IS NULL
        AND p.is_active = 1
    ), '') AS payment_catalog_ids,
    CASE
      WHEN v_has_service_table = 1 THEN IFNULL((
        SELECT GROUP_CONCAT(DISTINCT s.id_sale_item_catalog ORDER BY s.id_sale_item_catalog)
        FROM pms_settings_service_catalog s
        WHERE s.id_company = v_company_id
          AND ((v_property_id IS NULL AND s.id_property IS NULL) OR s.id_property = v_property_id)
          AND s.deleted_at IS NULL
          AND s.is_active = 1
      ), '')
      ELSE ''
    END AS service_catalog_ids;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_pms_settings_payment_method_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_include_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT DEFAULT 0;
  DECLARE v_property_id BIGINT DEFAULT NULL;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company code';
  END IF;

  IF p_property_code IS NOT NULL AND TRIM(p_property_code) <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE id_company = v_company_id
      AND code = p_property_code
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  SELECT
    pm.id_payment_method,
    pm.id_company,
    c.code AS company_code,
    pm.id_property,
    p.code AS property_code,
    pm.method_name,
    pm.is_active,
    pm.deleted_at,
    pm.created_at,
    pm.created_by,
    pm.updated_at
  FROM pms_settings_payment_method pm
  JOIN company c ON c.id_company = pm.id_company
  LEFT JOIN property p ON p.id_property = pm.id_property
  WHERE pm.id_company = v_company_id
    AND (
      v_property_id IS NULL
      OR pm.id_property IS NULL
      OR pm.id_property = v_property_id
    )
    AND (
      COALESCE(p_include_inactive, 0) = 1
      OR (pm.deleted_at IS NULL AND pm.is_active = 1)
    )
  ORDER BY
    CASE WHEN pm.id_property IS NULL THEN 0 ELSE 1 END,
    pm.method_name,
    pm.id_payment_method;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_pms_settings_payment_method_upsert` (IN `p_action` VARCHAR(16), IN `p_id_payment_method` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_method_name` VARCHAR(120), IN `p_is_active` TINYINT, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT DEFAULT 0;
  DECLARE v_property_id BIGINT DEFAULT NULL;
  DECLARE v_id_payment_method BIGINT DEFAULT 0;

  IF p_action IS NULL OR TRIM(p_action) = '' THEN
    SET p_action = 'create';
  END IF;

  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action';
  END IF;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company code';
  END IF;

  IF p_property_code IS NOT NULL AND TRIM(p_property_code) <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE id_company = v_company_id
      AND code = p_property_code
      AND deleted_at IS NULL
    LIMIT 1;
  ELSE
    SET v_property_id = NULL;
  END IF;

  IF p_action = 'create' THEN
    IF p_method_name IS NULL OR TRIM(p_method_name) = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'method name is required';
    END IF;

    SELECT pm.id_payment_method
      INTO v_id_payment_method
    FROM pms_settings_payment_method pm
    WHERE pm.id_company = v_company_id
      AND (
        (pm.id_property IS NULL AND v_property_id IS NULL)
        OR pm.id_property = v_property_id
      )
      AND LOWER(TRIM(pm.method_name)) = LOWER(TRIM(p_method_name))
    ORDER BY pm.id_payment_method DESC
    LIMIT 1;

    IF v_id_payment_method IS NULL OR v_id_payment_method <= 0 THEN
      INSERT INTO pms_settings_payment_method (
        id_company,
        id_property,
        method_name,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        v_company_id,
        v_property_id,
        TRIM(p_method_name),
        COALESCE(p_is_active, 1),
        NULL,
        NOW(),
        p_created_by,
        NOW()
      );
      SET v_id_payment_method = LAST_INSERT_ID();
    ELSE
      UPDATE pms_settings_payment_method
         SET method_name = TRIM(p_method_name),
             is_active = COALESCE(p_is_active, 1),
             deleted_at = NULL,
             updated_at = NOW()
       WHERE id_payment_method = v_id_payment_method;
    END IF;

    SELECT
      id_payment_method,
      id_company,
      id_property,
      method_name,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM pms_settings_payment_method
    WHERE id_payment_method = v_id_payment_method;
    LEAVE proc;
  END IF;

  IF p_id_payment_method IS NULL OR p_id_payment_method <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'id_payment_method is required';
  END IF;

  SELECT pm.id_payment_method
    INTO v_id_payment_method
  FROM pms_settings_payment_method pm
  WHERE pm.id_payment_method = p_id_payment_method
    AND pm.id_company = v_company_id
  LIMIT 1;

  IF v_id_payment_method IS NULL OR v_id_payment_method <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment method not found';
  END IF;

  IF p_action = 'delete' THEN
    UPDATE pms_settings_payment_method
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_payment_method = v_id_payment_method;
  ELSE
    UPDATE pms_settings_payment_method
       SET method_name = CASE
             WHEN p_method_name IS NULL OR TRIM(p_method_name) = '' THEN method_name
             ELSE TRIM(p_method_name)
           END,
           is_active = COALESCE(p_is_active, is_active),
           deleted_at = NULL,
           updated_at = NOW()
     WHERE id_payment_method = v_id_payment_method;
  END IF;

  SELECT
    id_payment_method,
    id_company,
    id_property,
    method_name,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM pms_settings_payment_method
  WHERE id_payment_method = v_id_payment_method;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_pms_settings_upsert` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_lodging_catalog_ids` TEXT, IN `p_interest_catalog_ids` TEXT, IN `p_payment_catalog_ids` TEXT, IN `p_service_catalog_ids` TEXT, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_has_service_table TINYINT DEFAULT 0;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
    INTO v_has_service_table
  FROM information_schema.TABLES
  WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = 'pms_settings_service_catalog';

  IF p_lodging_catalog_ids IS NOT NULL THEN
    UPDATE pms_settings_lodging_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_company = v_company_id
       AND ((v_property_id IS NULL AND id_property IS NULL) OR id_property = v_property_id)
       AND deleted_at IS NULL;

    IF p_lodging_catalog_ids <> '' THEN
      INSERT INTO pms_settings_lodging_catalog (
        id_company,
        id_property,
        id_sale_item_catalog,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_company_id,
        v_property_id,
        sic.id_line_item_catalog,
        1,
        NULL,
        NOW(),
        p_created_by,
        NOW()
      FROM line_item_catalog sic
      JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
      WHERE cat.id_company = v_company_id
        AND cat.deleted_at IS NULL
        AND cat.is_active = 1
        AND sic.catalog_type = 'sale_item'
        AND sic.deleted_at IS NULL
        AND sic.is_active = 1
        AND (v_property_id IS NULL OR cat.id_property IS NULL OR cat.id_property = v_property_id)
        AND FIND_IN_SET(sic.id_line_item_catalog, p_lodging_catalog_ids)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  IF p_interest_catalog_ids IS NOT NULL THEN
    UPDATE pms_settings_interest_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_company = v_company_id
       AND ((v_property_id IS NULL AND id_property IS NULL) OR id_property = v_property_id)
       AND deleted_at IS NULL;

    IF p_interest_catalog_ids <> '' THEN
      INSERT INTO pms_settings_interest_catalog (
        id_company,
        id_property,
        id_sale_item_catalog,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_company_id,
        v_property_id,
        sic.id_line_item_catalog,
        1,
        NULL,
        NOW(),
        p_created_by,
        NOW()
      FROM line_item_catalog sic
      JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
      WHERE cat.id_company = v_company_id
        AND cat.deleted_at IS NULL
        AND cat.is_active = 1
        AND sic.catalog_type = 'sale_item'
        AND sic.deleted_at IS NULL
        AND sic.is_active = 1
        AND (v_property_id IS NULL OR cat.id_property IS NULL OR cat.id_property = v_property_id)
        AND FIND_IN_SET(sic.id_line_item_catalog, p_interest_catalog_ids)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  IF p_payment_catalog_ids IS NOT NULL THEN
    UPDATE pms_settings_payment_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_company = v_company_id
       AND ((v_property_id IS NULL AND id_property IS NULL) OR id_property = v_property_id)
       AND deleted_at IS NULL;

    IF p_payment_catalog_ids <> '' THEN
      INSERT INTO pms_settings_payment_catalog (
        id_company,
        id_property,
        id_sale_item_catalog,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_company_id,
        v_property_id,
        sic.id_line_item_catalog,
        1,
        NULL,
        NOW(),
        p_created_by,
        NOW()
      FROM line_item_catalog sic
      JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
      WHERE cat.id_company = v_company_id
        AND cat.deleted_at IS NULL
        AND cat.is_active = 1
        AND sic.catalog_type = 'payment'
        AND sic.deleted_at IS NULL
        AND sic.is_active = 1
        AND (v_property_id IS NULL OR cat.id_property IS NULL OR cat.id_property = v_property_id)
        AND FIND_IN_SET(sic.id_line_item_catalog, p_payment_catalog_ids)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  IF p_service_catalog_ids IS NOT NULL THEN
    IF v_has_service_table = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Missing table pms_settings_service_catalog. Run catalog table migration first.';
    END IF;

    UPDATE pms_settings_service_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_company = v_company_id
       AND ((v_property_id IS NULL AND id_property IS NULL) OR id_property = v_property_id)
       AND deleted_at IS NULL;

    IF p_service_catalog_ids <> '' THEN
      INSERT INTO pms_settings_service_catalog (
        id_company,
        id_property,
        id_sale_item_catalog,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_company_id,
        v_property_id,
        sic.id_line_item_catalog,
        1,
        NULL,
        NOW(),
        p_created_by,
        NOW()
      FROM line_item_catalog sic
      JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
      WHERE cat.id_company = v_company_id
        AND cat.deleted_at IS NULL
        AND cat.is_active = 1
        AND sic.catalog_type = 'sale_item'
        AND sic.deleted_at IS NULL
        AND sic.is_active = 1
        AND (v_property_id IS NULL OR cat.id_property IS NULL OR cat.id_property = v_property_id)
        AND FIND_IN_SET(sic.id_line_item_catalog, p_service_catalog_ids)
      ON DUPLICATE KEY UPDATE
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  SELECT
    v_company_id AS id_company,
    v_property_id AS id_property,
    IFNULL((
      SELECT GROUP_CONCAT(DISTINCT l.id_sale_item_catalog ORDER BY l.id_sale_item_catalog)
      FROM pms_settings_lodging_catalog l
      WHERE l.id_company = v_company_id
        AND ((v_property_id IS NULL AND l.id_property IS NULL) OR l.id_property = v_property_id)
        AND l.deleted_at IS NULL
        AND l.is_active = 1
    ), '') AS lodging_catalog_ids,
    IFNULL((
      SELECT GROUP_CONCAT(DISTINCT i.id_sale_item_catalog ORDER BY i.id_sale_item_catalog)
      FROM pms_settings_interest_catalog i
      WHERE i.id_company = v_company_id
        AND ((v_property_id IS NULL AND i.id_property IS NULL) OR i.id_property = v_property_id)
        AND i.deleted_at IS NULL
        AND i.is_active = 1
    ), '') AS interest_catalog_ids,
    IFNULL((
      SELECT GROUP_CONCAT(DISTINCT p.id_sale_item_catalog ORDER BY p.id_sale_item_catalog)
      FROM pms_settings_payment_catalog p
      WHERE p.id_company = v_company_id
        AND ((v_property_id IS NULL AND p.id_property IS NULL) OR p.id_property = v_property_id)
        AND p.deleted_at IS NULL
        AND p.is_active = 1
    ), '') AS payment_catalog_ids,
    CASE
      WHEN v_has_service_table = 1 THEN IFNULL((
        SELECT GROUP_CONCAT(DISTINCT s.id_sale_item_catalog ORDER BY s.id_sale_item_catalog)
        FROM pms_settings_service_catalog s
        WHERE s.id_company = v_company_id
          AND ((v_property_id IS NULL AND s.id_property IS NULL) OR s.id_property = v_property_id)
          AND s.deleted_at IS NULL
          AND s.is_active = 1
      ), '')
      ELSE ''
    END AS service_catalog_ids;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_pms_theme_data` (IN `p_company_code` VARCHAR(100))   BEGIN
  DECLARE v_company_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT
    v_company_id AS id_company,
    COALESCE(pct.theme_code, 'default') AS theme_code
  FROM pms_company_theme pct
  WHERE pct.id_company = v_company_id
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_pms_theme_upsert` (IN `p_company_code` VARCHAR(100), IN `p_theme_code` VARCHAR(32), IN `p_actor_user_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_theme_code VARCHAR(32);

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SET v_theme_code = LOWER(TRIM(COALESCE(p_theme_code, 'default')));
  IF v_theme_code NOT IN ('default','ocean') THEN
    SET v_theme_code = 'default';
  END IF;

  INSERT INTO pms_company_theme (
    id_company,
    theme_code,
    created_at,
    updated_at
  ) VALUES (
    v_company_id,
    v_theme_code,
    NOW(),
    NOW()
  )
  ON DUPLICATE KEY UPDATE
    theme_code = VALUES(theme_code),
    updated_at = NOW();

  SELECT v_company_id AS id_company, v_theme_code AS theme_code;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_portal_activity_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_search` VARCHAR(255), IN `p_only_active` TINYINT, IN `p_activity_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_search VARCHAR(255);

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  /* Result set 1: list of activities */
  SELECT
    act.id_activity,
    act.code AS activity_code,
    act.name AS activity_name,
    act.type,
    act.duration_minutes,
    act.base_price_cents,
    act.currency,
    act.capacity_default,
    act.location,
    act.is_active,
    act.id_sale_item_catalog,
    sic.item_name AS sale_item_name,
    cat.category_name AS sale_item_category,
    pr.code AS property_code,
    pr.name AS property_name
  FROM activity act
  LEFT JOIN property pr ON pr.id_property = act.id_property
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = act.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
    AND cat.id_company = act.id_company
    AND cat.deleted_at IS NULL
  WHERE act.id_company = v_company_id
    AND act.deleted_at IS NULL
    AND (p_only_active IS NULL OR p_only_active = 0 OR act.is_active = 1)
    AND (v_property_id IS NULL OR act.id_property = v_property_id)
    AND (
      v_search IS NULL OR
      act.code LIKE CONCAT('%', v_search, '%') OR
      act.name LIKE CONCAT('%', v_search, '%') OR
      act.type LIKE CONCAT('%', v_search, '%')
    )
  ORDER BY act.name
  LIMIT 500;

  /* Result set 2: activity detail */
  IF p_activity_id IS NULL OR p_activity_id = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_activity,
      CAST(NULL AS CHAR) AS activity_code,
      CAST(NULL AS CHAR) AS activity_name,
      CAST(NULL AS CHAR) AS type,
      CAST(NULL AS CHAR) AS description,
      CAST(NULL AS SIGNED) AS duration_minutes,
      CAST(NULL AS SIGNED) AS base_price_cents,
      CAST(NULL AS CHAR) AS currency,
      CAST(NULL AS SIGNED) AS capacity_default,
      CAST(NULL AS CHAR) AS location,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS SIGNED) AS id_sale_item_catalog,
      CAST(NULL AS CHAR) AS sale_item_name,
      CAST(NULL AS CHAR) AS sale_item_category,
      CAST(NULL AS CHAR) AS property_code
    LIMIT 0;
  ELSE
    SELECT
      act.id_activity,
      act.code AS activity_code,
      act.name AS activity_name,
      act.type,
      act.description,
      act.duration_minutes,
      act.base_price_cents,
      act.currency,
      act.capacity_default,
      act.location,
      act.is_active,
      act.id_sale_item_catalog,
      sic.item_name AS sale_item_name,
      cat.category_name AS sale_item_category,
      pr.code AS property_code,
      pr.name AS property_name
    FROM activity act
    LEFT JOIN property pr ON pr.id_property = act.id_property
    LEFT JOIN line_item_catalog sic
      ON sic.id_line_item_catalog = act.id_sale_item_catalog
     AND sic.catalog_type = 'sale_item'
    LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
      AND cat.id_company = act.id_company
      AND cat.deleted_at IS NULL
    WHERE act.id_activity = p_activity_id
      AND act.id_company = v_company_id
      AND act.deleted_at IS NULL
    LIMIT 1;
  END IF;

  /* Result set 3: recent bookings for the activity */
  SELECT
    ab.id_booking,
    ab.scheduled_at,
    ab.status,
    ab.num_adults,
    ab.num_children,
    ab.price_cents,
    ab.currency,
    COALESCE(g.names, g0.names) AS guest_names,
    COALESCE(g.last_name, g0.last_name) AS guest_last_name,
    COALESCE(g.email, g0.email) AS guest_email,
    COALESCE(r.code, r0.code) AS reservation_code,
    COALESCE(linked.first_reservation_id, ab.id_reservation) AS id_reservation,
    COALESCE(linked.linked_reservation_count, CASE WHEN ab.id_reservation IS NULL THEN 0 ELSE 1 END) AS linked_reservation_count,
    COALESCE(linked.linked_reservation_ids_csv, CASE WHEN ab.id_reservation IS NULL THEN '' ELSE CAST(ab.id_reservation AS CHAR) END) AS linked_reservation_ids_csv,
    COALESCE(linked.linked_reservation_codes, COALESCE(r0.code, '')) AS linked_reservation_codes,
    COALESCE(linked.linked_guest_names, NULLIF(TRIM(CONCAT_WS(' ', COALESCE(g0.names, ''), COALESCE(g0.last_name, ''))), '')) AS linked_guest_names
  FROM activity_booking ab
  LEFT JOIN reservation r0 ON r0.id_reservation = ab.id_reservation
  LEFT JOIN guest g0 ON g0.id_guest = r0.id_guest
  LEFT JOIN (
    SELECT
      x.id_booking,
      MIN(x.id_reservation) AS first_reservation_id,
      COUNT(DISTINCT x.id_reservation) AS linked_reservation_count,
      GROUP_CONCAT(DISTINCT CAST(x.id_reservation AS CHAR) ORDER BY x.id_reservation SEPARATOR ',') AS linked_reservation_ids_csv,
      GROUP_CONCAT(DISTINCT COALESCE(r.code, '') ORDER BY r.code SEPARATOR ' | ') AS linked_reservation_codes,
      GROUP_CONCAT(
        DISTINCT NULLIF(TRIM(CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, ''))), '')
        ORDER BY r.code
        SEPARATOR ' | '
      ) AS linked_guest_names
    FROM (
      SELECT abr.id_booking, abr.id_reservation
      FROM activity_booking_reservation abr
      WHERE abr.deleted_at IS NULL
        AND COALESCE(abr.is_active, 1) = 1

      UNION ALL

      SELECT b2.id_booking, b2.id_reservation
      FROM activity_booking b2
      WHERE b2.id_reservation IS NOT NULL
        AND NOT EXISTS (
          SELECT 1
          FROM activity_booking_reservation abr2
          WHERE abr2.id_booking = b2.id_booking
            AND abr2.deleted_at IS NULL
            AND COALESCE(abr2.is_active, 1) = 1
        )
    ) x
    JOIN reservation r
      ON r.id_reservation = x.id_reservation
     AND r.deleted_at IS NULL
    LEFT JOIN guest g ON g.id_guest = r.id_guest
    GROUP BY x.id_booking
  ) linked ON linked.id_booking = ab.id_booking
  LEFT JOIN reservation r ON r.id_reservation = linked.first_reservation_id
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  WHERE ab.id_activity = p_activity_id
    AND ab.deleted_at IS NULL
  ORDER BY ab.scheduled_at DESC
  LIMIT 200;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_portal_app_user_data` (IN `p_company_code` VARCHAR(100), IN `p_search` VARCHAR(255), IN `p_property_code` VARCHAR(100), IN `p_only_active` TINYINT, IN `p_user_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_search VARCHAR(255);

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  /* Result set 1: list of users with aggregates */
  SELECT
    au.id_user,
    au.email,
    au.names,
    au.last_name,
    au.display_name,
    au.phone,
    au.is_owner,
    au.is_active,
    au.last_login_at,
    COUNT(DISTINCT up.id_property) AS property_count,
    GROUP_CONCAT(DISTINCT pr.code ORDER BY pr.code SEPARATOR ', ') AS property_codes,
    GROUP_CONCAT(DISTINCT rl.name ORDER BY rl.name SEPARATOR ', ') AS role_names
  FROM app_user au
  LEFT JOIN user_property up
    ON up.id_user = au.id_user
   AND up.deleted_at IS NULL
  LEFT JOIN property pr
    ON pr.id_property = up.id_property
   AND pr.id_company = v_company_id
   AND pr.deleted_at IS NULL
  LEFT JOIN user_role ur
    ON ur.id_user = au.id_user
   AND ur.deleted_at IS NULL
  LEFT JOIN role rl
    ON rl.id_role = ur.id_role
   AND rl.deleted_at IS NULL
   AND rl.is_active = 1
  LEFT JOIN property rlpr
    ON rlpr.id_property = rl.id_property
  WHERE au.id_company = v_company_id
    AND au.deleted_at IS NULL
    AND (p_only_active IS NULL OR p_only_active = 0 OR au.is_active = 1)
    AND (
      v_search IS NULL OR
      au.email LIKE CONCAT('%', v_search, '%') OR
      au.names LIKE CONCAT('%', v_search, '%') OR
      au.last_name LIKE CONCAT('%', v_search, '%') OR
      au.display_name LIKE CONCAT('%', v_search, '%') OR
      au.full_name LIKE CONCAT('%', v_search, '%')
    )
    AND (
      p_property_code IS NULL OR p_property_code = '' OR EXISTS (
        SELECT 1
        FROM user_property up2
        JOIN property pr2 ON pr2.id_property = up2.id_property
        WHERE up2.id_user = au.id_user
          AND up2.deleted_at IS NULL
          AND pr2.id_company = v_company_id
          AND pr2.deleted_at IS NULL
          AND pr2.code = p_property_code
      )
    )
    AND (
      rl.id_role IS NULL
      OR rl.id_property IS NULL
      OR (
        rlpr.id_company = v_company_id
        AND rlpr.deleted_at IS NULL
      )
    )
  GROUP BY
    au.id_user,
    au.email,
    au.names,
    au.last_name,
    au.display_name,
    au.phone,
    au.is_owner,
    au.is_active,
    au.last_login_at
  ORDER BY au.names, au.email;

  /* Result set 2: selected user detail */
  IF p_user_id IS NULL OR p_user_id = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_user,
      CAST(NULL AS CHAR) AS email,
      CAST(NULL AS CHAR) AS names,
      CAST(NULL AS CHAR) AS last_name,
      CAST(NULL AS CHAR) AS maiden_name,
      CAST(NULL AS CHAR) AS display_name,
      CAST(NULL AS CHAR) AS phone,
      CAST(NULL AS CHAR) AS locale,
      CAST(NULL AS CHAR) AS timezone,
      CAST(NULL AS SIGNED) AS is_owner,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS CHAR) AS notes
    LIMIT 0;
  ELSE
    SELECT
      au.id_user,
      au.email,
      au.names,
      au.last_name,
      au.maiden_name,
      au.display_name,
      au.phone,
      au.locale,
      au.timezone,
      au.is_owner,
      au.is_active,
      au.notes
    FROM app_user au
    WHERE au.id_user = p_user_id
      AND au.id_company = v_company_id
      AND au.deleted_at IS NULL
    LIMIT 1;
  END IF;

  /* Result set 3: properties of the company with assignment flag */
  SELECT
    pr.id_property,
    pr.code        AS property_code,
    pr.name        AS property_name,
    IF(up.id_user IS NULL, 0, 1) AS is_assigned
  FROM property pr
  LEFT JOIN user_property up
    ON up.id_property = pr.id_property
   AND up.deleted_at IS NULL
   AND up.id_user = p_user_id
  WHERE pr.id_company = v_company_id
    AND pr.deleted_at IS NULL
    AND pr.is_active = 1
  ORDER BY pr.name;

  /* Result set 4: global + property roles with assignment flag */
  SELECT
    rl.id_role,
    rl.name,
    rl.description,
    CASE WHEN rl.id_property IS NULL THEN '*' ELSE pr.code END AS property_code,
    CASE WHEN rl.id_property IS NULL THEN 'Global' ELSE pr.name END AS property_name,
    IF(ur.id_user_role IS NULL, 0, 1) AS is_assigned
  FROM role rl
  LEFT JOIN property pr
    ON pr.id_property = rl.id_property
  LEFT JOIN user_role ur
    ON ur.id_role = rl.id_role
   AND ur.deleted_at IS NULL
   AND ur.id_user = p_user_id
  WHERE rl.deleted_at IS NULL
    AND rl.is_active = 1
    AND (
      rl.id_property IS NULL
      OR (
        pr.id_company = v_company_id
        AND pr.deleted_at IS NULL
      )
    )
  ORDER BY
    CASE WHEN rl.id_property IS NULL THEN 0 ELSE 1 END,
    pr.name,
    rl.name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_portal_guest_data` (IN `p_company_code` VARCHAR(100), IN `p_search` VARCHAR(255), IN `p_only_active` TINYINT, IN `p_guest_id` BIGINT, IN `p_actor_user_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_search VARCHAR(255);
  DECLARE v_actor_user_id BIGINT DEFAULT 0;
  DECLARE v_actor_is_owner TINYINT DEFAULT 0;
  DECLARE v_scope_by_property TINYINT DEFAULT 0;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_actor_user_id = COALESCE(p_actor_user_id, 0);
  IF v_actor_user_id > 0 THEN
    SELECT COALESCE(au.is_owner, 0)
      INTO v_actor_is_owner
    FROM app_user au
    WHERE au.id_user = v_actor_user_id
      AND au.id_company = v_company_id
      AND au.deleted_at IS NULL
      AND COALESCE(au.is_active, 1) = 1
    LIMIT 1;

    IF v_actor_is_owner IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid actor user for company';
    END IF;

    IF v_actor_is_owner <> 1 THEN
      SET v_scope_by_property = 1;
    END IF;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  /* Result set 1: guests linked to the company */
  SELECT
    g.id_guest,
    g.email,
    g.names,
    g.last_name,
    g.maiden_name,
    g.full_name,
    g.phone,
    g.is_active,
    COUNT(DISTINCT CASE
      WHEN pr.id_company = v_company_id
           AND (
             v_scope_by_property = 0 OR EXISTS (
               SELECT 1
               FROM user_property up_cnt
               WHERE up_cnt.id_user = v_actor_user_id
                 AND up_cnt.id_property = pr.id_property
                 AND up_cnt.deleted_at IS NULL
                 AND COALESCE(up_cnt.is_active, 1) = 1
             )
           )
      THEN r.id_reservation END) AS reservation_count,
    MIN(CASE
      WHEN pr.id_company = v_company_id
           AND (
             v_scope_by_property = 0 OR EXISTS (
               SELECT 1
               FROM user_property up_min
               WHERE up_min.id_user = v_actor_user_id
                 AND up_min.id_property = pr.id_property
                 AND up_min.deleted_at IS NULL
                 AND COALESCE(up_min.is_active, 1) = 1
             )
           )
      THEN r.check_in_date END) AS first_check_in,
    MAX(CASE
      WHEN pr.id_company = v_company_id
           AND (
             v_scope_by_property = 0 OR EXISTS (
               SELECT 1
               FROM user_property up_max
               WHERE up_max.id_user = v_actor_user_id
                 AND up_max.id_property = pr.id_property
                 AND up_max.deleted_at IS NULL
                 AND COALESCE(up_max.is_active, 1) = 1
             )
           )
      THEN r.check_out_date END) AS last_check_out
  FROM guest g
  LEFT JOIN reservation r
    ON r.id_guest = g.id_guest
   AND r.deleted_at IS NULL
  LEFT JOIN property pr
    ON pr.id_property = r.id_property
  LEFT JOIN app_user au
    ON au.id_user = g.created_by
  WHERE g.deleted_at IS NULL
    AND (
      (
        v_scope_by_property = 1
        AND pr.id_company = v_company_id
        AND EXISTS (
          SELECT 1
          FROM user_property up
          WHERE up.id_user = v_actor_user_id
            AND up.id_property = pr.id_property
            AND up.deleted_at IS NULL
            AND COALESCE(up.is_active, 1) = 1
        )
      )
      OR
      (
        v_scope_by_property = 0
        AND (
          (pr.id_property IS NOT NULL AND pr.id_company = v_company_id) OR
          (au.id_user IS NOT NULL AND au.id_company = v_company_id)
        )
      )
    )
    AND (p_only_active IS NULL OR p_only_active = 0 OR g.is_active = 1)
    AND (
      v_search IS NULL OR
      g.email LIKE CONCAT('%', v_search, '%') OR
      g.names LIKE CONCAT('%', v_search, '%') OR
      g.last_name LIKE CONCAT('%', v_search, '%') OR
      g.maiden_name LIKE CONCAT('%', v_search, '%') OR
      g.full_name LIKE CONCAT('%', v_search, '%') OR
      g.phone LIKE CONCAT('%', v_search, '%')
    )
  GROUP BY
    g.id_guest,
    g.email,
    g.names,
    g.last_name,
    g.maiden_name,
    g.full_name,
    g.phone,
    g.is_active
  ORDER BY g.names, g.last_name, g.maiden_name, g.email;

  /* Result set 2: guest detail */
  IF p_guest_id IS NULL OR p_guest_id = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_guest,
      CAST(NULL AS CHAR) AS email,
      CAST(NULL AS CHAR) AS names,
      CAST(NULL AS CHAR) AS last_name,
      CAST(NULL AS CHAR) AS maiden_name,
      CAST(NULL AS CHAR) AS phone,
      CAST(NULL AS CHAR) AS nationality,
      CAST(NULL AS CHAR) AS country,
      CAST(NULL AS CHAR) AS language,
      CAST(NULL AS CHAR) AS notes_internal,
      CAST(NULL AS CHAR) AS notes_guest,
      CAST(NULL AS SIGNED) AS is_active
    LIMIT 0;
  ELSE
    SELECT
      g.id_guest,
      g.email,
      g.names,
      g.last_name,
      g.maiden_name,
      g.phone,
      g.nationality,
      g.country,
      g.language,
      g.marketing_opt_in,
      g.blacklisted,
      g.blacklist_reason,
      g.notes_internal,
      g.notes_guest,
      g.is_active
    FROM guest g
    LEFT JOIN reservation r ON r.id_guest = g.id_guest AND r.deleted_at IS NULL
    LEFT JOIN property pr ON pr.id_property = r.id_property
    LEFT JOIN app_user au ON au.id_user = g.created_by
    WHERE g.id_guest = p_guest_id
      AND g.deleted_at IS NULL
      AND (
        (
          v_scope_by_property = 0
          AND (
            (pr.id_company = v_company_id) OR
            (pr.id_company IS NULL AND au.id_company = v_company_id)
          )
        )
        OR
        (
          v_scope_by_property = 1
          AND EXISTS (
            SELECT 1
            FROM reservation rs
            JOIN property prs ON prs.id_property = rs.id_property
            JOIN user_property up
              ON up.id_property = prs.id_property
             AND up.id_user = v_actor_user_id
             AND up.deleted_at IS NULL
             AND COALESCE(up.is_active, 1) = 1
            WHERE rs.id_guest = g.id_guest
              AND rs.deleted_at IS NULL
              AND prs.id_company = v_company_id
          )
        )
      )
    LIMIT 1;
  END IF;

  /* Result set 3: reservations for guest belonging to the company */
  SELECT
    r.id_reservation,
    r.code AS reservation_code,
    r.status,
    r.source,
    r.check_in_date,
    r.check_out_date,
    r.adults,
    r.children,
    r.total_price_cents,
    r.balance_due_cents,
    pr.code AS property_code,
    pr.name AS property_name,
    rm.code AS room_code,
    rc.name AS category_name
  FROM reservation r
  JOIN property pr ON pr.id_property = r.id_property
  LEFT JOIN room rm ON rm.id_room = r.id_room
  LEFT JOIN roomcategory rc ON rc.id_category = r.id_category
  WHERE r.id_guest = p_guest_id
    AND pr.id_company = v_company_id
    AND r.deleted_at IS NULL
    AND (
      v_scope_by_property = 0 OR EXISTS (
        SELECT 1
        FROM user_property up
        WHERE up.id_user = v_actor_user_id
          AND up.id_property = pr.id_property
          AND up.deleted_at IS NULL
          AND COALESCE(up.is_active, 1) = 1
      )
    )
  ORDER BY r.check_in_date DESC, r.id_reservation DESC
  LIMIT 500;

  /* Result set 4: activity bookings for guest */
  SELECT
    ab.id_booking,
    ab.scheduled_at,
    ab.status,
    ab.num_adults,
    ab.num_children,
    ab.price_cents,
    ab.currency,
    act.code AS activity_code,
    act.name AS activity_name,
    pr.code AS property_code,
    pr.name AS property_name
  FROM activity_booking ab
  JOIN activity act ON act.id_activity = ab.id_activity
  JOIN (
    SELECT abr.id_booking, abr.id_reservation
    FROM activity_booking_reservation abr
    WHERE abr.deleted_at IS NULL
      AND COALESCE(abr.is_active, 1) = 1

    UNION ALL

    SELECT b2.id_booking, b2.id_reservation
    FROM activity_booking b2
    WHERE b2.id_reservation IS NOT NULL
      AND NOT EXISTS (
        SELECT 1
        FROM activity_booking_reservation abr2
        WHERE abr2.id_booking = b2.id_booking
          AND abr2.deleted_at IS NULL
          AND COALESCE(abr2.is_active, 1) = 1
      )
  ) abr_link ON abr_link.id_booking = ab.id_booking
  JOIN reservation r ON r.id_reservation = abr_link.id_reservation
  JOIN property pr_res ON pr_res.id_property = r.id_property
  LEFT JOIN property pr ON pr.id_property = act.id_property
  WHERE r.id_guest = p_guest_id
    AND ab.deleted_at IS NULL
    AND pr_res.id_company = v_company_id
    AND (
      v_scope_by_property = 0 OR EXISTS (
        SELECT 1
        FROM user_property up
        WHERE up.id_user = v_actor_user_id
          AND up.id_property = pr_res.id_property
          AND up.deleted_at IS NULL
          AND COALESCE(up.is_active, 1) = 1
      )
    )
    AND (
      pr.id_property IS NULL OR pr.id_company = v_company_id
    )
  ORDER BY ab.scheduled_at DESC
  LIMIT 500;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_portal_property_data` (IN `p_company_code` VARCHAR(100), IN `p_search` VARCHAR(255), IN `p_only_active` TINYINT, IN `p_property_code` VARCHAR(100))   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_search VARCHAR(255);
  DECLARE v_has_category_calendar_display TINYINT DEFAULT 0;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');
  SELECT CASE WHEN EXISTS (
    SELECT 1
    FROM information_schema.TABLES
    WHERE TABLE_SCHEMA = DATABASE()
      AND TABLE_NAME = 'category_calendar_amenity_display'
  ) THEN 1 ELSE 0 END
    INTO v_has_category_calendar_display;

  /* Result set 1: property list with aggregates */
  SELECT
    p.id_property,
    p.code AS property_code,
    p.name AS property_name,
    COALESCE(NULLIF(TRIM(p.color_hex), ''), '') AS color_hex,
    p.city,
    p.state,
    p.country,
    p.currency,
    p.check_out_time,
    p.order_index AS property_order_index,
    p.is_active,
    COUNT(DISTINCT rm.id_room) AS room_count,
    COUNT(DISTINCT rc.id_category) AS category_count,
    COUNT(DISTINCT rp.id_rateplan) AS rateplan_count
  FROM property p
  LEFT JOIN room rm
    ON rm.id_property = p.id_property
   AND rm.deleted_at IS NULL
  LEFT JOIN roomcategory rc
    ON rc.id_property = p.id_property
   AND rc.deleted_at IS NULL
  LEFT JOIN rateplan rp
    ON rp.id_property = p.id_property
   AND rp.deleted_at IS NULL
  WHERE p.id_company = v_company_id
    AND p.deleted_at IS NULL
    AND (p_only_active IS NULL OR p_only_active = 0 OR p.is_active = 1)
    AND (
      v_search IS NULL OR
      p.code LIKE CONCAT('%', v_search, '%') OR
      p.name LIKE CONCAT('%', v_search, '%') OR
      p.city LIKE CONCAT('%', v_search, '%') OR
      p.state LIKE CONCAT('%', v_search, '%')
    )
  GROUP BY
    p.id_property,
    p.code,
    p.name,
    p.color_hex,
    p.city,
    p.state,
    p.country,
    p.currency,
    p.order_index,
    p.is_active
  ORDER BY p.order_index, p.name;

  /* Result set 2: property detail */
  IF v_property_id IS NULL THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_property,
      CAST(NULL AS CHAR)   AS property_code,
      CAST(NULL AS CHAR)   AS property_name,
      CAST(NULL AS CHAR)   AS color_hex,
      CAST(NULL AS CHAR)   AS description,
      CAST(NULL AS CHAR)   AS email,
      CAST(NULL AS CHAR)   AS phone,
      CAST(NULL AS CHAR)   AS website,
      CAST(NULL AS CHAR)   AS address_line1,
      CAST(NULL AS CHAR)   AS address_line2,
      CAST(NULL AS CHAR)   AS city,
      CAST(NULL AS CHAR)   AS state,
      CAST(NULL AS CHAR)   AS postal_code,
      CAST(NULL AS CHAR)   AS country,
      CAST(NULL AS CHAR)   AS timezone,
      CAST(NULL AS CHAR)   AS currency,
      CAST(NULL AS DATETIME) AS check_out_time,
      CAST(NULL AS SIGNED) AS order_index,
      CAST(NULL AS SIGNED) AS id_owner_payment_obligation_catalog,
      CAST(NULL AS CHAR)   AS owner_payment_obligation_catalog_name,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS CHAR)   AS notes,
      CAST(NULL AS SIGNED) AS has_wifi,
      CAST(NULL AS SIGNED) AS has_parking,
      CAST(NULL AS SIGNED) AS has_shared_kitchen,
      CAST(NULL AS SIGNED) AS has_dining_area,
      CAST(NULL AS SIGNED) AS has_cleaning_service,
      CAST(NULL AS SIGNED) AS has_shared_laundry,
      CAST(NULL AS SIGNED) AS has_purified_water,
      CAST(NULL AS SIGNED) AS has_security_24h,
      CAST(NULL AS SIGNED) AS has_self_checkin,
      CAST(NULL AS SIGNED) AS has_pool,
      CAST(NULL AS SIGNED) AS has_jacuzzi,
      CAST(NULL AS SIGNED) AS has_garden_patio,
      CAST(NULL AS SIGNED) AS has_terrace_rooftop,
      CAST(NULL AS SIGNED) AS has_hammocks_loungers,
      CAST(NULL AS SIGNED) AS has_bbq_area,
      CAST(NULL AS SIGNED) AS has_beach_access,
      CAST(NULL AS SIGNED) AS has_panoramic_views,
      CAST(NULL AS SIGNED) AS has_outdoor_lounge,
      CAST(NULL AS SIGNED) AS offers_airport_transfers,
      CAST(NULL AS SIGNED) AS offers_tours_activities,
      CAST(NULL AS SIGNED) AS has_breakfast_available,
      CAST(NULL AS SIGNED) AS offers_bike_rental,
      CAST(NULL AS SIGNED) AS has_luggage_storage,
      CAST(NULL AS SIGNED) AS is_pet_friendly,
      CAST(NULL AS SIGNED) AS has_accessible_spaces,
      CAST(NULL AS SIGNED) AS amenities_is_active
    LIMIT 0;
  ELSE
    SELECT
      p.id_property,
      p.code AS property_code,
      p.name AS property_name,
      COALESCE(NULLIF(TRIM(p.color_hex), ''), '') AS color_hex,
      p.description,
      p.email,
      p.phone,
      p.website,
      p.address_line1,
      p.address_line2,
      p.city,
      p.state,
      p.postal_code,
      p.country,
      p.timezone,
      p.currency,
      p.check_out_time,
      p.order_index,
      p.id_owner_payment_obligation_catalog,
      COALESCE(owner_lic.item_name, '') AS owner_payment_obligation_catalog_name,
      p.is_active,
      p.notes,
      COALESCE(pa.has_wifi, 0) AS has_wifi,
      COALESCE(pa.has_parking, 0) AS has_parking,
      COALESCE(pa.has_shared_kitchen, 0) AS has_shared_kitchen,
      COALESCE(pa.has_dining_area, 0) AS has_dining_area,
      COALESCE(pa.has_cleaning_service, 0) AS has_cleaning_service,
      COALESCE(pa.has_shared_laundry, 0) AS has_shared_laundry,
      COALESCE(pa.has_purified_water, 0) AS has_purified_water,
      COALESCE(pa.has_security_24h, 0) AS has_security_24h,
      COALESCE(pa.has_self_checkin, 0) AS has_self_checkin,
      COALESCE(pa.has_pool, 0) AS has_pool,
      COALESCE(pa.has_jacuzzi, 0) AS has_jacuzzi,
      COALESCE(pa.has_garden_patio, 0) AS has_garden_patio,
      COALESCE(pa.has_terrace_rooftop, 0) AS has_terrace_rooftop,
      COALESCE(pa.has_hammocks_loungers, 0) AS has_hammocks_loungers,
      COALESCE(pa.has_bbq_area, 0) AS has_bbq_area,
      COALESCE(pa.has_beach_access, 0) AS has_beach_access,
      COALESCE(pa.has_panoramic_views, 0) AS has_panoramic_views,
      COALESCE(pa.has_outdoor_lounge, 0) AS has_outdoor_lounge,
      COALESCE(pa.offers_airport_transfers, 0) AS offers_airport_transfers,
      COALESCE(pa.offers_tours_activities, 0) AS offers_tours_activities,
      COALESCE(pa.has_breakfast_available, 0) AS has_breakfast_available,
      COALESCE(pa.offers_bike_rental, 0) AS offers_bike_rental,
      COALESCE(pa.has_luggage_storage, 0) AS has_luggage_storage,
      COALESCE(pa.is_pet_friendly, 0) AS is_pet_friendly,
      COALESCE(pa.has_accessible_spaces, 0) AS has_accessible_spaces,
      COALESCE(pa.is_active, 1) AS amenities_is_active
    FROM property p
    LEFT JOIN property_amenities pa
      ON pa.id_property = p.id_property
     AND pa.deleted_at IS NULL
     AND pa.is_active = 1
    LEFT JOIN line_item_catalog owner_lic
      ON owner_lic.id_line_item_catalog = p.id_owner_payment_obligation_catalog
     AND owner_lic.deleted_at IS NULL
    WHERE p.id_property = v_property_id
      AND p.id_company = v_company_id
      AND p.deleted_at IS NULL
    LIMIT 1;
  END IF;

  /* Result set 3: rate plans for selected property */
  SELECT
    rp.id_rateplan,
    rp.code AS rateplan_code,
    rp.name AS rateplan_name,
    rp.currency,
    rp.refundable,
    rp.min_stay_default,
    rp.max_stay_default,
    rp.effective_from,
    rp.effective_to,
    rp.is_active
  FROM rateplan rp
  WHERE rp.id_property = v_property_id
    AND rp.deleted_at IS NULL
  ORDER BY rp.name
  LIMIT 500;

  /* Result set 4: room categories */
  IF v_has_category_calendar_display = 1 THEN
    SELECT
      rc.id_category,
      rc.code AS category_code,
      rc.name AS category_name,
      rc.description,
      rc.base_occupancy,
      rc.max_occupancy,
      rc.order_index,
      rc.default_base_price_cents,
      rc.min_price_cents,
      rc.image_url,
      rc.color_hex,
      rc.is_active,
      rp.code AS rateplan_code,
      rp.name AS rateplan_name,
      COALESCE(ca.has_air_conditioning,0) AS has_air_conditioning,
      COALESCE(ca.has_fan,0) AS has_fan,
      COALESCE(ca.has_tv,0) AS has_tv,
      COALESCE(ca.has_private_wifi,0) AS has_private_wifi,
      COALESCE(ca.has_minibar,0) AS has_minibar,
      COALESCE(ca.has_safe_box,0) AS has_safe_box,
      COALESCE(ca.has_workspace,0) AS has_workspace,
      COALESCE(ca.includes_bedding_towels,0) AS includes_bedding_towels,
      COALESCE(ca.has_iron_board,0) AS has_iron_board,
      COALESCE(ca.has_closet_rack,0) AS has_closet_rack,
      COALESCE(ca.has_private_balcony_terrace,0) AS has_private_balcony_terrace,
      COALESCE(ca.has_view,0) AS has_view,
      COALESCE(ca.has_private_entrance,0) AS has_private_entrance,
      COALESCE(ca.has_hot_water,0) AS has_hot_water,
      COALESCE(ca.includes_toiletries,0) AS includes_toiletries,
      COALESCE(ca.has_hairdryer,0) AS has_hairdryer,
      COALESCE(ca.includes_clean_towels,0) AS includes_clean_towels,
      COALESCE(ca.has_coffee_tea_kettle,0) AS has_coffee_tea_kettle,
      COALESCE(ca.has_basic_utensils,0) AS has_basic_utensils,
      COALESCE(ca.has_basic_food_items,0) AS has_basic_food_items,
      COALESCE(ca.is_private,0) AS is_private,
      COALESCE(ca.is_shared,0) AS is_shared,
      COALESCE(ca.has_shared_bathroom,0) AS has_shared_bathroom,
      COALESCE(ca.has_private_bathroom,0) AS has_private_bathroom,
      COALESCE(ca.is_active,1) AS amenities_is_active,
      COALESCE(cad.calendar_amenities_csv, '') AS calendar_amenities_csv
    FROM roomcategory rc
    LEFT JOIN rateplan rp ON rp.id_rateplan = rc.id_rateplan
    LEFT JOIN category_amenities ca ON ca.id_category = rc.id_category AND ca.deleted_at IS NULL
    LEFT JOIN (
      SELECT
        t.id_category,
        GROUP_CONCAT(t.amenity_key ORDER BY t.display_order, t.id_category_calendar_amenity_display SEPARATOR ',') AS calendar_amenities_csv
      FROM category_calendar_amenity_display t
      WHERE t.is_active = 1
      GROUP BY t.id_category
    ) cad ON cad.id_category = rc.id_category
    WHERE rc.id_property = v_property_id
      AND rc.deleted_at IS NULL
    ORDER BY rc.order_index, rc.name
    LIMIT 500;
  ELSE
    SELECT
      rc.id_category,
      rc.code AS category_code,
      rc.name AS category_name,
      rc.description,
      rc.base_occupancy,
      rc.max_occupancy,
      rc.order_index,
      rc.default_base_price_cents,
      rc.min_price_cents,
      rc.image_url,
      rc.color_hex,
      rc.is_active,
      rp.code AS rateplan_code,
      rp.name AS rateplan_name,
      COALESCE(ca.has_air_conditioning,0) AS has_air_conditioning,
      COALESCE(ca.has_fan,0) AS has_fan,
      COALESCE(ca.has_tv,0) AS has_tv,
      COALESCE(ca.has_private_wifi,0) AS has_private_wifi,
      COALESCE(ca.has_minibar,0) AS has_minibar,
      COALESCE(ca.has_safe_box,0) AS has_safe_box,
      COALESCE(ca.has_workspace,0) AS has_workspace,
      COALESCE(ca.includes_bedding_towels,0) AS includes_bedding_towels,
      COALESCE(ca.has_iron_board,0) AS has_iron_board,
      COALESCE(ca.has_closet_rack,0) AS has_closet_rack,
      COALESCE(ca.has_private_balcony_terrace,0) AS has_private_balcony_terrace,
      COALESCE(ca.has_view,0) AS has_view,
      COALESCE(ca.has_private_entrance,0) AS has_private_entrance,
      COALESCE(ca.has_hot_water,0) AS has_hot_water,
      COALESCE(ca.includes_toiletries,0) AS includes_toiletries,
      COALESCE(ca.has_hairdryer,0) AS has_hairdryer,
      COALESCE(ca.includes_clean_towels,0) AS includes_clean_towels,
      COALESCE(ca.has_coffee_tea_kettle,0) AS has_coffee_tea_kettle,
      COALESCE(ca.has_basic_utensils,0) AS has_basic_utensils,
      COALESCE(ca.has_basic_food_items,0) AS has_basic_food_items,
      COALESCE(ca.is_private,0) AS is_private,
      COALESCE(ca.is_shared,0) AS is_shared,
      COALESCE(ca.has_shared_bathroom,0) AS has_shared_bathroom,
      COALESCE(ca.has_private_bathroom,0) AS has_private_bathroom,
      COALESCE(ca.is_active,1) AS amenities_is_active,
      '' AS calendar_amenities_csv
    FROM roomcategory rc
    LEFT JOIN rateplan rp ON rp.id_rateplan = rc.id_rateplan
    LEFT JOIN category_amenities ca ON ca.id_category = rc.id_category AND ca.deleted_at IS NULL
    WHERE rc.id_property = v_property_id
      AND rc.deleted_at IS NULL
    ORDER BY rc.order_index, rc.name
    LIMIT 500;
  END IF;

  /* Result set 5: rooms */
  SELECT
    rm.id_room,
    rm.code AS room_code,
    rm.name AS room_name,
    rm.status,
    rm.housekeeping_status,
    rm.capacity_total,
    rm.max_adults,
    rm.max_children,
    rm.floor,
    rm.building,
    rm.order_index,
    rm.is_active,
    rc.code AS category_code,
    rc.name AS category_name,
    rp.code AS rateplan_code,
    rp.name AS rateplan_name
  FROM room rm
  LEFT JOIN roomcategory rc ON rc.id_category = rm.id_category
  LEFT JOIN rateplan rp ON rp.id_rateplan = rm.id_rateplan
  WHERE rm.id_property = v_property_id
    AND rm.deleted_at IS NULL
  ORDER BY rm.order_index, rm.code
  LIMIT 1000;

  /* Result set 6: bed configurations for categories */
  SELECT
    bc.id_bed_config,
    bc.id_category,
    bc.bed_type,
    bc.bed_count,
    bc.is_active
  FROM category_bed_config bc
  JOIN roomcategory rc ON rc.id_category = bc.id_category
  WHERE rc.id_property = v_property_id
    AND bc.deleted_at IS NULL
  ORDER BY rc.code, bc.id_bed_config;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_portal_reservation_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_status` VARCHAR(32), IN `p_from` DATE, IN `p_to` DATE, IN `p_reservation_id` BIGINT, IN `p_actor_user_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_status_filter VARCHAR(32);
  DECLARE v_from DATE;
  DECLARE v_to DATE;
  DECLARE v_rate_col VARCHAR(32) DEFAULT 'percent_value';
  DECLARE v_sql_tax_items LONGTEXT;
  DECLARE v_actor_user_id BIGINT DEFAULT 0;
  DECLARE v_actor_is_owner TINYINT DEFAULT 0;
  DECLARE v_scope_by_property TINYINT DEFAULT 0;
  DECLARE v_target_reservation_id BIGINT DEFAULT NULL;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_actor_user_id = COALESCE(p_actor_user_id, 0);
  IF v_actor_user_id > 0 THEN
    SELECT COALESCE(au.is_owner, 0)
      INTO v_actor_is_owner
    FROM app_user au
    WHERE au.id_user = v_actor_user_id
      AND au.id_company = v_company_id
      AND au.deleted_at IS NULL
      AND COALESCE(au.is_active, 1) = 1
    LIMIT 1;

    IF v_actor_is_owner IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid actor user for company';
    END IF;

    IF v_actor_is_owner <> 1 THEN
      SET v_scope_by_property = 1;
    END IF;
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_status_filter = NULLIF(TRIM(p_status), '');
  SET v_from = COALESCE(p_from, DATE_SUB(CURDATE(), INTERVAL 30 DAY));
  SET v_to = COALESCE(p_to, DATE_ADD(CURDATE(), INTERVAL 180 DAY));
  IF v_to < v_from THEN
    SET v_to = DATE_ADD(v_from, INTERVAL 1 DAY);
  END IF;

  SET v_rate_col = 'percent_value';

  IF p_reservation_id IS NOT NULL AND p_reservation_id > 0 THEN
    SELECT r.id_reservation
      INTO v_target_reservation_id
    FROM reservation r
    JOIN property pr ON pr.id_property = r.id_property
    WHERE r.id_reservation = p_reservation_id
      AND pr.id_company = v_company_id
      AND r.deleted_at IS NULL
      AND (
        v_scope_by_property = 0 OR EXISTS (
          SELECT 1
          FROM user_property up
          WHERE up.id_user = v_actor_user_id
            AND up.id_property = r.id_property
            AND up.deleted_at IS NULL
            AND COALESCE(up.is_active, 1) = 1
        )
      )
    LIMIT 1;
  ELSE
    SET v_target_reservation_id = NULL;
  END IF;

  /* Result set 1: reservation list */
  SELECT
    r.id_reservation,
    r.code AS reservation_code,
    r.status,
    r.source,
    r.id_ota_account,
    r.id_reservation_source,
    COALESCE(rsc.source_name, '') AS reservation_source_name,
    oa.ota_name,
    oa.platform AS ota_platform,
    r.check_in_date,
    r.check_out_date,
    r.adults,
    r.children,
    COALESCE(fsum.total_cents, r.total_price_cents, 0) AS total_price_cents,
    COALESCE(fsum.balance_cents, r.balance_due_cents, 0) AS balance_due_cents,
    g.names AS guest_names,
    g.last_name AS guest_last_name,
    g.email AS guest_email,
    pr.code AS property_code,
    pr.name AS property_name,
    rm.code AS room_code
  FROM reservation r
  JOIN property pr ON pr.id_property = r.id_property
  LEFT JOIN room rm ON rm.id_room = r.id_room
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  LEFT JOIN ota_account oa
    ON oa.id_ota_account = r.id_ota_account
   AND oa.deleted_at IS NULL
   AND oa.is_active = 1
  LEFT JOIN reservation_source_catalog rsc
    ON rsc.id_reservation_source = r.id_reservation_source
  LEFT JOIN (
    SELECT
      f.id_reservation,
      SUM(f.total_cents) AS total_cents,
      SUM(f.balance_cents) AS balance_cents
    FROM folio f
    WHERE f.deleted_at IS NULL
      AND COALESCE(f.is_active, 1) = 1
    GROUP BY f.id_reservation
  ) fsum ON fsum.id_reservation = r.id_reservation
  WHERE pr.id_company = v_company_id
    AND r.deleted_at IS NULL
    AND r.check_in_date >= v_from
    AND r.check_in_date <= v_to
    AND (v_property_id IS NULL OR r.id_property = v_property_id)
    AND (
      v_scope_by_property = 0 OR EXISTS (
        SELECT 1
        FROM user_property up
        WHERE up.id_user = v_actor_user_id
          AND up.id_property = r.id_property
          AND up.deleted_at IS NULL
          AND COALESCE(up.is_active, 1) = 1
      )
    )
    AND (v_status_filter IS NULL OR r.status = v_status_filter)
  ORDER BY r.check_in_date DESC, r.id_reservation DESC
  LIMIT 500;

  /* Result set 2: reservation detail */
  IF v_target_reservation_id IS NULL OR v_target_reservation_id = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_reservation,
      CAST(NULL AS CHAR) AS reservation_code,
      CAST(NULL AS CHAR) AS status,
      CAST(NULL AS CHAR) AS source,
      CAST(NULL AS SIGNED) AS id_ota_account,
      CAST(NULL AS SIGNED) AS id_reservation_source,
      CAST(NULL AS CHAR) AS reservation_source_name,
      CAST(NULL AS CHAR) AS ota_name,
      CAST(NULL AS CHAR) AS ota_platform,
      CAST(NULL AS DATE) AS check_in_date,
      CAST(NULL AS DATE) AS check_out_date,
      CAST(NULL AS SIGNED) AS adults,
      CAST(NULL AS SIGNED) AS children,
      CAST(NULL AS SIGNED) AS infants,
      CAST(NULL AS SIGNED) AS id_guest,
      CAST(NULL AS CHAR) AS currency,
      CAST(NULL AS CHAR) AS notes_guest,
      CAST(NULL AS CHAR) AS notes_internal,
      CAST(NULL AS SIGNED) AS total_price_cents,
      CAST(NULL AS SIGNED) AS balance_due_cents,
      CAST(NULL AS CHAR) AS property_code,
      CAST(NULL AS CHAR) AS property_name,
      CAST(NULL AS CHAR) AS room_code,
      CAST(NULL AS CHAR) AS category_name,
      CAST(NULL AS CHAR) AS rateplan_name,
      CAST(NULL AS CHAR) AS guest_names,
      CAST(NULL AS CHAR) AS guest_last_name,
      CAST(NULL AS CHAR) AS guest_email,
      CAST(NULL AS CHAR) AS guest_phone
    LIMIT 0;
  ELSE
    SELECT
      r.id_reservation,
      r.code AS reservation_code,
      r.status,
      r.source,
      r.id_ota_account,
      r.id_reservation_source,
      COALESCE(rsc.source_name, '') AS reservation_source_name,
      oa.ota_name,
      oa.platform AS ota_platform,
      r.channel_ref,
      r.check_in_date,
      r.check_out_date,
      r.adults,
      r.children,
      r.infants,
      r.id_guest,
      r.currency,
      r.notes_guest,
      r.notes_internal,
      COALESCE(fsum.total_cents, r.total_price_cents, 0) AS total_price_cents,
      COALESCE(fsum.balance_cents, r.balance_due_cents, 0) AS balance_due_cents,
      pr.code AS property_code,
      pr.name AS property_name,
      rm.code AS room_code,
      rc.name AS category_name,
      rp.name AS rateplan_name,
      g.names AS guest_names,
      g.last_name AS guest_last_name,
      g.email AS guest_email,
      g.phone AS guest_phone
    FROM reservation r
    JOIN property pr ON pr.id_property = r.id_property
    LEFT JOIN room rm ON rm.id_room = r.id_room
    LEFT JOIN roomcategory rc ON rc.id_category = r.id_category
    LEFT JOIN rateplan rp ON rp.id_rateplan = r.id_rateplan
    LEFT JOIN guest g ON g.id_guest = r.id_guest
    LEFT JOIN ota_account oa
      ON oa.id_ota_account = r.id_ota_account
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
    LEFT JOIN reservation_source_catalog rsc
      ON rsc.id_reservation_source = r.id_reservation_source
    LEFT JOIN (
      SELECT
        f.id_reservation,
        SUM(f.total_cents) AS total_cents,
        SUM(f.balance_cents) AS balance_cents
      FROM folio f
      WHERE f.deleted_at IS NULL
        AND COALESCE(f.is_active, 1) = 1
      GROUP BY f.id_reservation
    ) fsum ON fsum.id_reservation = r.id_reservation
    WHERE r.id_reservation = v_target_reservation_id
      AND pr.id_company = v_company_id
      AND r.deleted_at IS NULL
    LIMIT 1;
  END IF;

  /* Result set 3: folios + totales */
  SELECT
    f.id_folio,
    f.folio_name,
    f.status,
    f.currency,
    f.total_cents,
    f.balance_cents,
    f.due_date,
    f.bill_to_type,
    f.bill_to_id,
    f.notes,
    f.created_at,
    COALESCE(pay.payments_cents,0) AS payments_cents,
    COALESCE(ref.refunds_cents,0) AS refunds_cents
  FROM folio f
  LEFT JOIN (
    SELECT li.id_folio, SUM(li.amount_cents) AS payments_cents
    FROM line_item li
    LEFT JOIN line_item_catalog lic
      ON lic.id_line_item_catalog = li.id_line_item_catalog
    WHERE li.item_type = 'payment'
      AND li.deleted_at IS NULL
      AND li.is_active = 1
      AND (li.status IS NULL OR li.status NOT IN ('void','canceled'))
      AND (
        li.id_line_item_catalog IS NULL
        OR COALESCE(lic.show_in_folio, 1) = 1
      )
    GROUP BY li.id_folio
  ) pay ON pay.id_folio = f.id_folio
  LEFT JOIN (
    SELECT p.id_folio, SUM(r.amount_cents) AS refunds_cents
    FROM refund r
    JOIN line_item p
      ON p.id_line_item = r.id_payment
     AND p.item_type = 'payment'
    LEFT JOIN line_item_catalog lic
      ON lic.id_line_item_catalog = p.id_line_item_catalog
    WHERE r.deleted_at IS NULL AND r.is_active = 1
      AND (
        p.id_line_item_catalog IS NULL
        OR COALESCE(lic.show_in_folio, 1) = 1
      )
    GROUP BY p.id_folio
  ) ref ON ref.id_folio = f.id_folio
  WHERE f.id_reservation = v_target_reservation_id
    AND f.deleted_at IS NULL
  ORDER BY f.created_at;

  /* Result set 4: sale items por folio/reserva (compat layer with new line_item schema) */
  SELECT
    si.id_line_item AS id_sale_item,
    rel.id_parent_sale_item AS id_parent_sale_item,
    si.id_line_item_catalog AS id_sale_item_catalog,
    si.item_type,
    rel.parent_sale_item_catalog_id AS parent_sale_item_catalog_id,
    COALESCE(rel.add_to_father_total, 0) AS add_to_father_total,
    rel.show_in_folio_relation AS show_in_folio_relation,
    COALESCE(
      CASE
        WHEN rel.parent_sale_item_catalog_id IS NOT NULL THEN rel.show_in_folio_relation
        ELSE NULL
      END,
      sic.show_in_folio,
      1
    ) AS show_in_folio_effective,
    si.id_folio,
    f.folio_name,
    cat.category_name AS subcategory_name,
    COALESCE(si.item_name, sic.item_name) AS item_name,
    si.description,
    si.service_date,
    si.quantity,
    si.unit_price_cents,
    si.discount_amount_cents,
    COALESCE(tax.tax_amount_cents,0) AS tax_amount_cents,
    si.amount_cents,
    si.currency,
    si.status,
    si.created_at
  FROM line_item si
  JOIN folio f ON f.id_folio = si.id_folio
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = si.id_line_item_catalog
  LEFT JOIN (
    SELECT
      c.id_line_item AS child_sale_item_id,
      COALESCE(
        MIN(
          CASE
            WHEN COALESCE(c.description,'') = CONCAT(COALESCE(cc.item_name,''), ' / ', COALESCE(pc.item_name,''))
            THEN p.id_line_item
            ELSE NULL
          END
        ),
        MIN(p.id_line_item)
      ) AS id_parent_sale_item,
      COALESCE(
        MIN(
          CASE
            WHEN COALESCE(c.description,'') = CONCAT(COALESCE(cc.item_name,''), ' / ', COALESCE(pc.item_name,''))
            THEN p.id_line_item_catalog
            ELSE NULL
          END
        ),
        MIN(lcp.id_parent_sale_item_catalog)
      ) AS parent_sale_item_catalog_id,
      COALESCE(
        MIN(
          CASE
            WHEN COALESCE(c.description,'') = CONCAT(COALESCE(cc.item_name,''), ' / ', COALESCE(pc.item_name,''))
            THEN lcp.add_to_father_total
            ELSE NULL
          END
        ),
        MIN(lcp.add_to_father_total),
        0
      ) AS add_to_father_total,
      COALESCE(
        MIN(
          CASE
            WHEN COALESCE(c.description,'') = CONCAT(COALESCE(cc.item_name,''), ' / ', COALESCE(pc.item_name,''))
            THEN lcp.show_in_folio_relation
            ELSE NULL
          END
        ),
        MIN(lcp.show_in_folio_relation),
        NULL
      ) AS show_in_folio_relation
    FROM line_item c
    JOIN folio cf ON cf.id_folio = c.id_folio
    LEFT JOIN line_item_catalog cc
      ON cc.id_line_item_catalog = c.id_line_item_catalog
    JOIN line_item_catalog_parent lcp
      ON lcp.id_sale_item_catalog = c.id_line_item_catalog
     AND lcp.deleted_at IS NULL
     AND lcp.is_active = 1
    LEFT JOIN line_item_catalog pc
      ON pc.id_line_item_catalog = lcp.id_parent_sale_item_catalog
    JOIN line_item p
      ON p.id_folio = c.id_folio
     AND p.item_type IN ('sale_item','tax_item','payment','obligation','income')
     AND p.id_line_item_catalog = lcp.id_parent_sale_item_catalog
     AND p.deleted_at IS NULL
     AND p.is_active = 1
     AND p.id_line_item <> c.id_line_item
     AND (p.service_date <=> c.service_date)
    WHERE cf.id_reservation = v_target_reservation_id
      AND c.item_type IN ('sale_item','tax_item','obligation','income')
      AND c.deleted_at IS NULL
     AND c.is_active = 1
    GROUP BY c.id_line_item
  ) rel ON rel.child_sale_item_id = si.id_line_item
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN (
    SELECT
      s.id_line_item AS id_sale_item,
      COALESCE(SUM(t.amount_cents),0) AS tax_amount_cents
    FROM line_item s
    JOIN folio sf ON sf.id_folio = s.id_folio
    LEFT JOIN line_item_catalog_parent lcp
      ON lcp.id_parent_sale_item_catalog = s.id_line_item_catalog
     AND lcp.deleted_at IS NULL
     AND lcp.is_active = 1
    LEFT JOIN line_item t
      ON t.id_folio = s.id_folio
     AND t.item_type = 'tax_item'
     AND t.id_line_item_catalog = lcp.id_sale_item_catalog
     AND t.deleted_at IS NULL
     AND t.is_active = 1
     AND (t.service_date <=> s.service_date)
    WHERE sf.id_reservation = v_target_reservation_id
      AND s.item_type IN ('sale_item','tax_item','obligation','income')
      AND s.deleted_at IS NULL
      AND s.is_active = 1
    GROUP BY s.id_line_item
  ) tax ON tax.id_sale_item = si.id_line_item
  WHERE f.id_reservation = v_target_reservation_id
    AND si.item_type IN ('sale_item','tax_item','obligation','income')
    AND si.deleted_at IS NULL
    AND si.is_active = 1
    AND (
      sic.id_line_item_catalog IS NULL
      OR COALESCE(
        CASE
          WHEN rel.parent_sale_item_catalog_id IS NOT NULL THEN rel.show_in_folio_relation
          ELSE NULL
        END,
        sic.show_in_folio,
        1
      ) = 1
    )
    AND (
      NOT EXISTS (
        SELECT 1
        FROM line_item_catalog_parent lcp_rel
        WHERE lcp_rel.id_sale_item_catalog = si.id_line_item_catalog
          AND lcp_rel.deleted_at IS NULL
          AND lcp_rel.is_active = 1
      )
      OR EXISTS (
        SELECT 1
        FROM line_item_catalog_parent lcp_rel
        JOIN line_item p
          ON p.id_folio = si.id_folio
         AND p.id_line_item_catalog = lcp_rel.id_parent_sale_item_catalog
         AND p.deleted_at IS NULL
         AND p.is_active = 1
         AND (p.status IS NULL OR p.status NOT IN ('void','canceled'))
         AND (p.service_date <=> si.service_date)
        LEFT JOIN line_item_catalog plic
          ON plic.id_line_item_catalog = p.id_line_item_catalog
        WHERE lcp_rel.id_sale_item_catalog = si.id_line_item_catalog
          AND lcp_rel.deleted_at IS NULL
          AND lcp_rel.is_active = 1
          AND (
            COALESCE(si.description, '') = CONCAT(COALESCE(sic.item_name, ''), ' / ', COALESCE(plic.item_name, ''))
            OR (
              (COALESCE(si.description, '') = '' OR INSTR(COALESCE(si.description, ''), ' / ') = 0)
              AND (
                SELECT COUNT(*)
                FROM line_item_catalog_parent lcp_cnt
                WHERE lcp_cnt.id_sale_item_catalog = si.id_line_item_catalog
                  AND lcp_cnt.deleted_at IS NULL
                  AND lcp_cnt.is_active = 1
              ) = 1
            )
          )
          AND (
            COALESCE(lcp_rel.add_to_father_total, 1) = 0
            OR plic.id_line_item_catalog IS NULL
            OR (
              plic.deleted_at IS NULL
              AND plic.is_active = 1
              AND COALESCE(plic.show_in_folio, 1) = 1
            )
          )
      )
      OR EXISTS (
        SELECT 1
        FROM line_item_catalog_parent lcp_rel
        WHERE lcp_rel.id_sale_item_catalog = si.id_line_item_catalog
          AND lcp_rel.deleted_at IS NULL
          AND lcp_rel.is_active = 1
          AND COALESCE(lcp_rel.add_to_father_total, 1) = 0
      )
    )
  ORDER BY si.service_date, si.id_line_item;

  /* Result set 5 (legacy): no tax-specific dataset. Derivados now come from result set 4. */
  SELECT
    CAST(NULL AS SIGNED) AS id_tax_item,
    CAST(NULL AS SIGNED) AS id_sale_item,
    CAST(NULL AS SIGNED) AS id_tax_rule,
    CAST(NULL AS CHAR) AS tax_name,
    CAST(NULL AS DECIMAL(9,4)) AS rate_percent,
    CAST(NULL AS SIGNED) AS amount_cents,
    CAST(NULL AS DATETIME) AS created_at
  LIMIT 0;

  /* Result set 6: pagos */
  SELECT
    p.id_line_item AS id_payment,
    p.id_folio,
    f.folio_name,
    p.id_line_item_catalog AS id_payment_catalog,
    p.method,
    p.amount_cents,
    p.currency,
    p.reference,
    p.service_date,
    p.status,
    p.refunded_total_cents,
    p.created_at
  FROM line_item p
  JOIN folio f ON f.id_folio = p.id_folio
  LEFT JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = p.id_line_item_catalog
  WHERE f.id_reservation = v_target_reservation_id
    AND p.item_type = 'payment'
    AND p.deleted_at IS NULL
    AND (
      p.id_line_item_catalog IS NULL
      OR COALESCE(lic.show_in_folio, 1) = 1
    )
  ORDER BY p.created_at DESC;

  /* Result set 7: reembolsos */
  SELECT
    r.id_refund,
    r.id_payment,
    p.id_folio,
    f.folio_name,
    r.amount_cents,
    r.currency,
    r.reference,
    r.reason,
    r.refunded_at
  FROM refund r
  JOIN line_item p
    ON p.id_line_item = r.id_payment
   AND p.item_type = 'payment'
  LEFT JOIN line_item_catalog lic
    ON lic.id_line_item_catalog = p.id_line_item_catalog
  JOIN folio f ON f.id_folio = p.id_folio
  WHERE f.id_reservation = v_target_reservation_id
    AND r.deleted_at IS NULL
    AND (
      p.id_line_item_catalog IS NULL
      OR COALESCE(lic.show_in_folio, 1) = 1
    )
  ORDER BY r.refunded_at DESC, r.id_refund DESC;

  /* Result set 8: activity bookings for the reservation */
  SELECT
    ab.id_booking,
    ab.scheduled_at,
    ab.status,
    ab.num_adults,
    ab.num_children,
    ab.price_cents,
    ab.currency,
    act.code AS activity_code,
    act.name AS activity_name
  FROM activity_booking ab
  JOIN activity act ON act.id_activity = ab.id_activity
  JOIN (
    SELECT abr.id_booking, abr.id_reservation
    FROM activity_booking_reservation abr
    WHERE abr.deleted_at IS NULL
      AND COALESCE(abr.is_active, 1) = 1

    UNION ALL

    SELECT b2.id_booking, b2.id_reservation
    FROM activity_booking b2
    WHERE b2.id_reservation IS NOT NULL
      AND NOT EXISTS (
        SELECT 1
        FROM activity_booking_reservation abr2
        WHERE abr2.id_booking = b2.id_booking
          AND abr2.deleted_at IS NULL
          AND COALESCE(abr2.is_active, 1) = 1
      )
  ) abr_link ON abr_link.id_booking = ab.id_booking
  WHERE abr_link.id_reservation = v_target_reservation_id
    AND ab.deleted_at IS NULL
  ORDER BY ab.scheduled_at DESC
  LIMIT 200;

  /* Result set 9: conceptos de interes por reserva */
  SELECT
    ri.id_reservation,
    ri.id_sale_item_catalog,
    sic.item_name,
    cat.category_name,
    ri.created_at
  FROM reservation_interest ri
  JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = ri.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  WHERE ri.id_reservation = v_target_reservation_id
    AND ri.deleted_at IS NULL
    AND ri.is_active = 1
    AND cat.id_company = v_company_id
    AND cat.deleted_at IS NULL
  ORDER BY cat.category_name, sic.item_name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_property_room_calendar` (IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_days` INT)   BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_to DATE;
  DECLARE v_day_count INT;
  DECLARE v_index INT DEFAULT 0;
  DECLARE v_total_rooms INT DEFAULT 0;
  DECLARE v_has_category_calendar_display TINYINT DEFAULT 0;

  SET v_day_count = CASE
    WHEN p_days IS NULL OR p_days < 1 THEN 1
    WHEN p_days > 120 THEN 120
    ELSE p_days
  END;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SET v_to = DATE_ADD(p_from, INTERVAL v_day_count DAY);
  SELECT CASE WHEN EXISTS (
    SELECT 1
    FROM information_schema.TABLES
    WHERE TABLE_SCHEMA = DATABASE()
      AND TABLE_NAME = 'category_calendar_amenity_display'
  ) THEN 1 ELSE 0 END
    INTO v_has_category_calendar_display;

  SELECT COUNT(*)
    INTO v_total_rooms
  FROM room
  WHERE id_property = v_id_property
    AND is_active = 1
    AND deleted_at IS NULL;

  DROP TEMPORARY TABLE IF EXISTS tmp_calendar_days;
  CREATE TEMPORARY TABLE tmp_calendar_days (
    day_index INT PRIMARY KEY,
    calendar_date DATE NOT NULL
  ) ENGINE = MEMORY;

  day_loop: WHILE v_index < v_day_count DO
    INSERT INTO tmp_calendar_days (day_index, calendar_date)
    VALUES (v_index, DATE_ADD(p_from, INTERVAL v_index DAY));
    SET v_index = v_index + 1;
  END WHILE day_loop;

  DROP TEMPORARY TABLE IF EXISTS tmp_room_events;
  CREATE TEMPORARY TABLE tmp_room_events AS
  SELECT
    'reservation' AS event_type,
    r.id_reservation,
    NULL AS id_room_block,
    r.id_room,
    rm.id_property,
    COALESCE(r.id_category, rm.id_category) AS id_category,
    r.id_guest,
    r.id_user AS id_user,
    r.code,
    r.status,
    CASE
      WHEN COALESCE(r.id_ota_account, 0) > 0 THEN 'ota'
      ELSE COALESCE(NULLIF(TRIM(r.source), ''), COALESCE(rsc.source_name, 'Directo'))
    END AS source,
    r.id_ota_account,
    COALESCE(oa.ota_name, '') AS ota_name,
    COALESCE(oa.platform, '') AS ota_platform,
    r.id_reservation_source,
    COALESCE(rsc.source_name, '') AS reservation_source_name,
    r.check_in_date,
    r.check_out_date,
    r.check_out_date AS end_date_exclusive,
    r.adults,
    r.children,
    r.currency,
    CASE
      WHEN COALESCE(fsum.folio_count, 0) > 0 THEN COALESCE(fsum.total_cents, 0)
      ELSE 0
    END AS total_price_cents,
    CASE
      WHEN COALESCE(fsum.folio_count, 0) > 0 THEN COALESCE(fsum.balance_cents, 0)
      ELSE 0
    END AS balance_due_cents,
    COALESCE(fsum.folio_count, 0) AS folio_count,
    r.notes_guest AS notes_guest,
    (
      SELECT rn.note_text
      FROM reservation_note rn
      WHERE rn.id_reservation = r.id_reservation
        AND rn.deleted_at IS NULL
        AND COALESCE(rn.is_active, 1) = 1
      ORDER BY rn.created_at DESC, rn.id_reservation_note DESC
      LIMIT 1
    ) AS latest_note_text,
    r.notes_internal AS description
  FROM reservation r
  JOIN room rm ON rm.id_room = r.id_room
  LEFT JOIN ota_account oa
    ON oa.id_ota_account = r.id_ota_account
   AND oa.deleted_at IS NULL
   AND oa.is_active = 1
  LEFT JOIN reservation_source_catalog rsc
    ON rsc.id_reservation_source = r.id_reservation_source
  LEFT JOIN (
    SELECT
      f.id_reservation,
      SUM(CASE WHEN COALESCE(f.is_active, 1) = 1 THEN 1 ELSE 0 END) AS folio_count,
      SUM(CASE WHEN COALESCE(f.is_active, 1) = 1 THEN f.total_cents ELSE 0 END) AS total_cents,
      SUM(CASE WHEN COALESCE(f.is_active, 1) = 1 THEN f.balance_cents ELSE 0 END) AS balance_cents
    FROM folio f
    WHERE f.deleted_at IS NULL
    GROUP BY f.id_reservation
  ) fsum ON fsum.id_reservation = r.id_reservation
  WHERE rm.id_property = v_id_property
    AND r.deleted_at IS NULL
    AND COALESCE(r.status, 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
    AND r.check_in_date < v_to
    AND r.check_out_date > p_from
  UNION ALL
  SELECT
    'block' AS event_type,
    NULL AS id_reservation,
    rb.id_room_block,
    rb.id_room,
    rb.id_property,
    rm.id_category,
    NULL AS id_guest,
    rb.id_user AS id_user,
    rb.code,
    'blocked' AS status,
    'block'  AS source,
    NULL AS id_ota_account,
    '' AS ota_name,
    '' AS ota_platform,
    NULL AS id_reservation_source,
    '' AS reservation_source_name,
    rb.start_date AS check_in_date,
    rb.end_date   AS check_out_date,
    DATE_ADD(rb.end_date, INTERVAL 1 DAY) AS end_date_exclusive,
    0 AS adults,
    0 AS children,
    'MXN' AS currency,
    0 AS total_price_cents,
    0 AS balance_due_cents,
    0 AS folio_count,
    '' AS notes_guest,
    '' AS latest_note_text,
    rb.description AS description
  FROM room_block rb
  JOIN room rm ON rm.id_room = rb.id_room
  WHERE rb.id_property = v_id_property
    AND rb.deleted_at IS NULL
    AND rb.is_active = 1
    AND rb.start_date < v_to
    AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > p_from;

  /* Result set 1: room catalog for the property */
  IF v_has_category_calendar_display = 1 THEN
    SELECT
      r.id_room,
      r.code AS room_code,
      r.name AS room_name,
      NULL AS floor_label,
      rc.id_category,
      rc.code AS category_code,
      rc.name AS category_name,
      rc.order_index AS category_order_index,
      rc.max_occupancy,
      COALESCE(rc.color_hex, '') AS category_color,
      COALESCE(r.max_adults, rc.max_occupancy) AS room_max_adults,
      COALESCE(cad.calendar_amenities_csv, '') AS calendar_amenities_csv,
      r.order_index AS room_order_index
    FROM room r
    JOIN roomcategory rc ON rc.id_category = r.id_category
    LEFT JOIN (
      SELECT
        t.id_category,
        GROUP_CONCAT(t.amenity_key ORDER BY t.display_order, t.id_category_calendar_amenity_display SEPARATOR ',') AS calendar_amenities_csv
      FROM category_calendar_amenity_display t
      WHERE t.is_active = 1
      GROUP BY t.id_category
    ) cad ON cad.id_category = rc.id_category
    WHERE r.id_property = v_id_property
      AND r.is_active = 1
      AND r.deleted_at IS NULL
    ORDER BY rc.order_index, rc.name, r.order_index, r.code;
  ELSE
    SELECT
      r.id_room,
      r.code AS room_code,
      r.name AS room_name,
      NULL AS floor_label,
      rc.id_category,
      rc.code AS category_code,
      rc.name AS category_name,
      rc.order_index AS category_order_index,
      rc.max_occupancy,
      COALESCE(rc.color_hex, '') AS category_color,
      COALESCE(r.max_adults, rc.max_occupancy) AS room_max_adults,
      '' AS calendar_amenities_csv,
      r.order_index AS room_order_index
    FROM room r
    JOIN roomcategory rc ON rc.id_category = r.id_category
    WHERE r.id_property = v_id_property
      AND r.is_active = 1
      AND r.deleted_at IS NULL
    ORDER BY rc.order_index, rc.name, r.order_index, r.code;
  END IF;

  /* Result set 2: calendar days metadata */
  SELECT
    d.day_index,
    d.calendar_date,
    DATE_FORMAT(d.calendar_date, '%Y-%m-%d') AS date_key,
    DATE_FORMAT(d.calendar_date, '%a') AS day_short_name,
    DATE_FORMAT(d.calendar_date, '%W') AS day_name,
    DATE_FORMAT(d.calendar_date, '%d/%m') AS day_label,
    DAYOFWEEK(d.calendar_date) AS day_of_week,
    WEEKOFYEAR(d.calendar_date) AS iso_week,
    MONTH(d.calendar_date) AS month,
    YEAR(d.calendar_date) AS year,
    CASE WHEN d.calendar_date = CURDATE() THEN 1 ELSE 0 END AS is_today
  FROM tmp_calendar_days d
  ORDER BY d.day_index;

  /* Result set 3: reservations + blocks overlapping the range */
  SELECT
    CASE
      WHEN ev.event_type = 'block' THEN -ev.id_room_block
      ELSE ev.id_reservation
    END AS id_reservation,
    ev.id_room_block,
    ev.event_type,
    ev.code AS reservation_code,
    ev.status,
    ev.source,
    ev.id_ota_account,
    ev.ota_name,
    ev.ota_platform,
    ev.id_reservation_source,
    ev.reservation_source_name,
    ev.check_in_date,
    ev.check_out_date,
    GREATEST(0, DATEDIFF(GREATEST(ev.check_in_date, p_from), p_from)) AS range_start_offset,
    GREATEST(1,
      DATEDIFF(
        LEAST(ev.end_date_exclusive, v_to),
        GREATEST(ev.check_in_date, p_from)
      )
    ) AS range_nights,
    DATEDIFF(ev.end_date_exclusive, ev.check_in_date) AS total_nights,
    ev.adults,
    ev.children,
    ev.currency,
    ev.total_price_cents,
    ev.balance_due_cents,
    ev.folio_count,
    ev.notes_guest,
    ev.latest_note_text,
    ev.description,
    g.email AS guest_email,
    CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, '')) AS guest_full_name,
    g.names AS guest_names,
    g.last_name AS guest_last_name,
    ev.id_user,
    rm.id_room,
    rm.code AS room_code,
    rm.name AS room_name,
    rc.code AS category_code,
    rc.name AS category_name
  FROM tmp_room_events ev
  JOIN room rm ON rm.id_room = ev.id_room
  JOIN roomcategory rc ON rc.id_category = ev.id_category
  LEFT JOIN guest g ON g.id_guest = ev.id_guest
  WHERE ev.id_property = v_id_property
  ORDER BY rm.code, ev.check_in_date,
    CASE
      WHEN ev.event_type = 'block' THEN -ev.id_room_block
      ELSE ev.id_reservation
    END;

  /* Result set 4: daily occupancy summary (reservations + blocks) */
  SELECT
    d.day_index,
    d.calendar_date,
    DATE_FORMAT(d.calendar_date, '%Y-%m-%d') AS date_key,
    v_total_rooms AS total_rooms,
    COUNT(DISTINCT ev.id_room) AS occupied_rooms,
    SUM(
      CASE
        WHEN ev.id_room IS NOT NULL AND ev.event_type = 'reservation' AND ev.check_in_date = d.calendar_date THEN 1
        ELSE 0
      END
    ) AS arrivals,
    SUM(
      CASE
        WHEN ev.id_room IS NOT NULL AND ev.event_type = 'reservation' AND ev.check_out_date = d.calendar_date THEN 1
        ELSE 0
      END
    ) AS departures,
    CASE
      WHEN v_total_rooms = 0 THEN 0
      ELSE ROUND(COUNT(DISTINCT ev.id_room) / v_total_rooms * 100, 1)
    END AS occupancy_pct
  FROM tmp_calendar_days d
  LEFT JOIN tmp_room_events ev
    ON ev.check_in_date <= d.calendar_date
   AND ev.end_date_exclusive > d.calendar_date
  GROUP BY d.day_index, d.calendar_date
  ORDER BY d.day_index;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_property_upsert` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_name` VARCHAR(255), IN `p_color_hex` VARCHAR(16), IN `p_description` TEXT, IN `p_email` VARCHAR(255), IN `p_phone` VARCHAR(100), IN `p_website` VARCHAR(255), IN `p_address_line1` VARCHAR(255), IN `p_address_line2` VARCHAR(255), IN `p_city` VARCHAR(120), IN `p_state` VARCHAR(120), IN `p_postal_code` VARCHAR(30), IN `p_country` VARCHAR(120), IN `p_timezone` VARCHAR(64), IN `p_currency` VARCHAR(10), IN `p_check_out_time` VARCHAR(32), IN `p_order_index` INT, IN `p_is_active` TINYINT, IN `p_notes` TEXT, IN `p_has_wifi` TINYINT, IN `p_has_parking` TINYINT, IN `p_has_shared_kitchen` TINYINT, IN `p_has_dining_area` TINYINT, IN `p_has_cleaning_service` TINYINT, IN `p_has_shared_laundry` TINYINT, IN `p_has_purified_water` TINYINT, IN `p_has_security_24h` TINYINT, IN `p_has_self_checkin` TINYINT, IN `p_has_pool` TINYINT, IN `p_has_jacuzzi` TINYINT, IN `p_has_garden_patio` TINYINT, IN `p_has_terrace_rooftop` TINYINT, IN `p_has_hammocks_loungers` TINYINT, IN `p_has_bbq_area` TINYINT, IN `p_has_beach_access` TINYINT, IN `p_has_panoramic_views` TINYINT, IN `p_has_outdoor_lounge` TINYINT, IN `p_offers_airport_transfers` TINYINT, IN `p_offers_tours_activities` TINYINT, IN `p_has_breakfast_available` TINYINT, IN `p_offers_bike_rental` TINYINT, IN `p_has_luggage_storage` TINYINT, IN `p_is_pet_friendly` TINYINT, IN `p_has_accessible_spaces` TINYINT, IN `p_id_owner_payment_obligation_catalog` BIGINT, IN `p_amenities_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_id_property_amenities BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();
  DECLARE v_check_out_time_val DATETIME;
  DECLARE v_owner_payment_obligation_catalog BIGINT DEFAULT NULL;
  DECLARE v_color_hex VARCHAR(16) DEFAULT NULL;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_name IS NULL OR p_name = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property name is required';
  END IF;

  SET v_check_out_time_val = NULL;
  IF p_check_out_time IS NOT NULL AND TRIM(p_check_out_time) <> '' THEN
    SET v_check_out_time_val = STR_TO_DATE(CONCAT('1970-01-01 ', TIME(p_check_out_time)), '%Y-%m-%d %H:%i:%s');
  END IF;

  SET v_color_hex = NULL;
  IF p_color_hex IS NOT NULL AND TRIM(p_color_hex) <> '' THEN
    SET v_color_hex = UPPER(TRIM(p_color_hex));
    IF LEFT(v_color_hex, 1) <> '#' THEN
      SET v_color_hex = CONCAT('#', v_color_hex);
    END IF;
    IF v_color_hex NOT REGEXP '^#[0-9A-F]{6}$' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid property color';
    END IF;
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_owner_payment_obligation_catalog = NULL;
  IF p_id_owner_payment_obligation_catalog IS NOT NULL
     AND p_id_owner_payment_obligation_catalog > 0 THEN
    SELECT lic.id_line_item_catalog
      INTO v_owner_payment_obligation_catalog
    FROM line_item_catalog lic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
     AND cat.id_company = v_company_id
     AND cat.deleted_at IS NULL
     AND cat.is_active = 1
    WHERE lic.id_line_item_catalog = p_id_owner_payment_obligation_catalog
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND lic.catalog_type = 'obligation'
    LIMIT 1;

    IF v_owner_payment_obligation_catalog IS NULL
       OR v_owner_payment_obligation_catalog <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid owner payment obligation catalog';
    END IF;
  END IF;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    INSERT INTO property (
      id_company,
      code,
      name,
      color_hex,
      description,
      email,
      phone,
      website,
      address_line1,
      address_line2,
      city,
      state,
      postal_code,
      country,
      timezone,
      currency,
      check_out_time,
      order_index,
      id_owner_payment_obligation_catalog,
      is_active,
      notes,
      created_at,
      updated_at
    ) VALUES (
      v_company_id,
      p_property_code,
      p_name,
      v_color_hex,
      NULLIF(p_description, ''),
      NULLIF(p_email, ''),
      NULLIF(p_phone, ''),
      NULLIF(p_website, ''),
      NULLIF(p_address_line1, ''),
      NULLIF(p_address_line2, ''),
      NULLIF(p_city, ''),
      NULLIF(p_state, ''),
      NULLIF(p_postal_code, ''),
      NULLIF(p_country, ''),
      COALESCE(NULLIF(p_timezone, ''), 'America/Mexico_City'),
      COALESCE(NULLIF(p_currency, ''), 'MXN'),
      v_check_out_time_val,
      COALESCE(p_order_index, 0),
      v_owner_payment_obligation_catalog,
      COALESCE(p_is_active, 1),
      NULLIF(p_notes, ''),
      v_now,
      v_now
    );
    SET v_id_property = LAST_INSERT_ID();
  ELSE
    UPDATE property
    SET
      name = p_name,
      color_hex = v_color_hex,
      description = NULLIF(p_description, ''),
      email = NULLIF(p_email, ''),
      phone = NULLIF(p_phone, ''),
      website = NULLIF(p_website, ''),
      address_line1 = NULLIF(p_address_line1, ''),
      address_line2 = NULLIF(p_address_line2, ''),
      city = NULLIF(p_city, ''),
      state = NULLIF(p_state, ''),
      postal_code = NULLIF(p_postal_code, ''),
      country = NULLIF(p_country, ''),
      timezone = COALESCE(NULLIF(p_timezone, ''), timezone),
      currency = COALESCE(NULLIF(p_currency, ''), currency),
      check_out_time = v_check_out_time_val,
      order_index = COALESCE(p_order_index, order_index),
      id_owner_payment_obligation_catalog = v_owner_payment_obligation_catalog,
      is_active = COALESCE(p_is_active, is_active),
      notes = COALESCE(NULLIF(p_notes, ''), notes),
      updated_at = v_now
    WHERE id_property = v_id_property;
  END IF;

  /* Upsert amenities */
  SELECT id_property_amenities
    INTO v_id_property_amenities
  FROM property_amenities
  WHERE id_property = v_id_property
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property_amenities IS NULL THEN
    INSERT INTO property_amenities (
      id_property,
      has_wifi,
      has_parking,
      has_shared_kitchen,
      has_dining_area,
      has_cleaning_service,
      has_shared_laundry,
      has_purified_water,
      has_security_24h,
      has_self_checkin,
      has_pool,
      has_jacuzzi,
      has_garden_patio,
      has_terrace_rooftop,
      has_hammocks_loungers,
      has_bbq_area,
      has_beach_access,
      has_panoramic_views,
      has_outdoor_lounge,
      offers_airport_transfers,
      offers_tours_activities,
      has_breakfast_available,
      offers_bike_rental,
      has_luggage_storage,
      is_pet_friendly,
      has_accessible_spaces,
      is_active,
      created_by,
      created_at,
      updated_at
    ) VALUES (
      v_id_property,
      COALESCE(p_has_wifi, 0),
      COALESCE(p_has_parking, 0),
      COALESCE(p_has_shared_kitchen, 0),
      COALESCE(p_has_dining_area, 0),
      COALESCE(p_has_cleaning_service, 0),
      COALESCE(p_has_shared_laundry, 0),
      COALESCE(p_has_purified_water, 0),
      COALESCE(p_has_security_24h, 0),
      COALESCE(p_has_self_checkin, 0),
      COALESCE(p_has_pool, 0),
      COALESCE(p_has_jacuzzi, 0),
      COALESCE(p_has_garden_patio, 0),
      COALESCE(p_has_terrace_rooftop, 0),
      COALESCE(p_has_hammocks_loungers, 0),
      COALESCE(p_has_bbq_area, 0),
      COALESCE(p_has_beach_access, 0),
      COALESCE(p_has_panoramic_views, 0),
      COALESCE(p_has_outdoor_lounge, 0),
      COALESCE(p_offers_airport_transfers, 0),
      COALESCE(p_offers_tours_activities, 0),
      COALESCE(p_has_breakfast_available, 0),
      COALESCE(p_offers_bike_rental, 0),
      COALESCE(p_has_luggage_storage, 0),
      COALESCE(p_is_pet_friendly, 0),
      COALESCE(p_has_accessible_spaces, 0),
      COALESCE(p_amenities_is_active, 1),
      p_actor_user_id,
      v_now,
      v_now
    );
  ELSE
    UPDATE property_amenities
    SET
      has_wifi = COALESCE(p_has_wifi, has_wifi),
      has_parking = COALESCE(p_has_parking, has_parking),
      has_shared_kitchen = COALESCE(p_has_shared_kitchen, has_shared_kitchen),
      has_dining_area = COALESCE(p_has_dining_area, has_dining_area),
      has_cleaning_service = COALESCE(p_has_cleaning_service, has_cleaning_service),
      has_shared_laundry = COALESCE(p_has_shared_laundry, has_shared_laundry),
      has_purified_water = COALESCE(p_has_purified_water, has_purified_water),
      has_security_24h = COALESCE(p_has_security_24h, has_security_24h),
      has_self_checkin = COALESCE(p_has_self_checkin, has_self_checkin),
      has_pool = COALESCE(p_has_pool, has_pool),
      has_jacuzzi = COALESCE(p_has_jacuzzi, has_jacuzzi),
      has_garden_patio = COALESCE(p_has_garden_patio, has_garden_patio),
      has_terrace_rooftop = COALESCE(p_has_terrace_rooftop, has_terrace_rooftop),
      has_hammocks_loungers = COALESCE(p_has_hammocks_loungers, has_hammocks_loungers),
      has_bbq_area = COALESCE(p_has_bbq_area, has_bbq_area),
      has_beach_access = COALESCE(p_has_beach_access, has_beach_access),
      has_panoramic_views = COALESCE(p_has_panoramic_views, has_panoramic_views),
      has_outdoor_lounge = COALESCE(p_has_outdoor_lounge, has_outdoor_lounge),
      offers_airport_transfers = COALESCE(p_offers_airport_transfers, offers_airport_transfers),
      offers_tours_activities = COALESCE(p_offers_tours_activities, offers_tours_activities),
      has_breakfast_available = COALESCE(p_has_breakfast_available, has_breakfast_available),
      offers_bike_rental = COALESCE(p_offers_bike_rental, offers_bike_rental),
      has_luggage_storage = COALESCE(p_has_luggage_storage, has_luggage_storage),
      is_pet_friendly = COALESCE(p_is_pet_friendly, is_pet_friendly),
      has_accessible_spaces = COALESCE(p_has_accessible_spaces, has_accessible_spaces),
      is_active = COALESCE(p_amenities_is_active, is_active),
      updated_at = v_now,
      created_by = COALESCE(created_by, p_actor_user_id)
    WHERE id_property = v_id_property;
  END IF;

  SELECT
    p.id_property,
    p.code AS property_code,
    p.name AS property_name,
    p.description,
    p.email,
    p.phone,
    p.website,
    p.address_line1,
    p.address_line2,
    p.city,
    p.state,
    p.postal_code,
    p.country,
    p.timezone,
    p.currency,
    p.check_out_time,
    p.order_index,
    p.id_owner_payment_obligation_catalog,
    p.is_active,
    p.notes
  FROM property p
  WHERE p.id_property = v_id_property
    AND p.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_rateplan_calc_total` (IN `p_property_id` BIGINT, IN `p_rateplan_id` BIGINT, IN `p_room_id` BIGINT, IN `p_category_id` BIGINT, IN `p_check_in` DATE, IN `p_check_out` DATE, OUT `p_total_cents` INT, OUT `p_avg_nightly_cents` INT, OUT `p_breakdown_json` TEXT)   proc:BEGIN
  DECLARE v_id_category BIGINT;
  DECLARE v_base_cents INT DEFAULT 0;
  DECLARE v_min_cents INT DEFAULT 0;
  DECLARE v_day_count INT DEFAULT 0;
  DECLARE v_index INT DEFAULT 0;
  DECLARE v_total_rooms INT DEFAULT 0;
  DECLARE v_use_season TINYINT DEFAULT 1;
  DECLARE v_use_occupancy TINYINT DEFAULT 1;
  DECLARE v_base_adjust_pct DECIMAL(6,2) DEFAULT 0;
  DECLARE v_low_threshold DECIMAL(6,2) DEFAULT 40;
  DECLARE v_mid_low_threshold DECIMAL(6,2) DEFAULT 55;
  DECLARE v_mid_high_threshold DECIMAL(6,2) DEFAULT 70;
  DECLARE v_high_threshold DECIMAL(6,2) DEFAULT 80;
  DECLARE v_low_adjust_pct DECIMAL(6,2) DEFAULT -15;
  DECLARE v_mid_low_adjust_pct DECIMAL(6,2) DEFAULT -5;
  DECLARE v_mid_high_adjust_pct DECIMAL(6,2) DEFAULT 10;
  DECLARE v_high_adjust_pct DECIMAL(6,2) DEFAULT 20;
  DECLARE v_weekend_adjust_pct DECIMAL(6,2) DEFAULT 0;
  DECLARE v_max_discount_pct DECIMAL(6,2) DEFAULT 30;
  DECLARE v_max_markup_pct DECIMAL(6,2) DEFAULT 40;

  SET p_total_cents = 0;
  SET p_avg_nightly_cents = 0;
  SET p_breakdown_json = '[]';

  IF p_property_id IS NULL OR p_property_id = 0 THEN
    LEAVE proc;
  END IF;
  IF p_check_in IS NULL OR p_check_out IS NULL THEN
    LEAVE proc;
  END IF;

  SET v_day_count = DATEDIFF(p_check_out, p_check_in);
  IF v_day_count <= 0 THEN
    LEAVE proc;
  END IF;

  IF p_category_id IS NOT NULL AND p_category_id > 0 THEN
    SET v_id_category = p_category_id;
  ELSEIF p_room_id IS NOT NULL AND p_room_id > 0 THEN
    SELECT id_category
      INTO v_id_category
    FROM room
    WHERE id_room = p_room_id
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF v_id_category IS NULL THEN
    LEAVE proc;
  END IF;

  SELECT
    COALESCE(rc.default_base_price_cents,0),
    COALESCE(NULLIF(rc.min_price_cents,0), COALESCE(rc.default_base_price_cents,0))
    INTO v_base_cents, v_min_cents
  FROM roomcategory rc
  WHERE rc.id_category = v_id_category
    AND rc.deleted_at IS NULL
  LIMIT 1;

  IF p_rateplan_id IS NOT NULL AND p_rateplan_id > 0 THEN
    SELECT
      COALESCE(rpp.base_adjust_pct, 0),
      COALESCE(rpp.use_season, 1),
      COALESCE(rpp.use_occupancy, 1),
      COALESCE(rpp.occupancy_low_threshold, 40),
      COALESCE(rpp.occupancy_mid_low_threshold, 55),
      COALESCE(rpp.occupancy_mid_high_threshold, 70),
      COALESCE(rpp.occupancy_high_threshold, 80),
      COALESCE(rpp.low_occupancy_adjust_pct, -15),
      COALESCE(rpp.mid_low_occupancy_adjust_pct, -5),
      COALESCE(rpp.mid_high_occupancy_adjust_pct, 10),
      COALESCE(rpp.high_occupancy_adjust_pct, 20),
      COALESCE(rpp.weekend_adjust_pct, 0),
      COALESCE(rpp.max_discount_pct, 30),
      COALESCE(rpp.max_markup_pct, 40)
      INTO v_base_adjust_pct,
           v_use_season,
           v_use_occupancy,
           v_low_threshold,
           v_mid_low_threshold,
           v_mid_high_threshold,
           v_high_threshold,
           v_low_adjust_pct,
           v_mid_low_adjust_pct,
           v_mid_high_adjust_pct,
           v_high_adjust_pct,
           v_weekend_adjust_pct,
           v_max_discount_pct,
           v_max_markup_pct
    FROM rateplan_pricing rpp
    WHERE rpp.id_rateplan = p_rateplan_id
    LIMIT 1;
  END IF;

  SELECT COUNT(*)
    INTO v_total_rooms
  FROM room
  WHERE id_property = p_property_id
    AND is_active = 1
    AND deleted_at IS NULL;

  DROP TEMPORARY TABLE IF EXISTS tmp_rateplan_days;
  CREATE TEMPORARY TABLE tmp_rateplan_days (
    day_index INT PRIMARY KEY,
    calendar_date DATE NOT NULL
  ) ENGINE = MEMORY;

  rateplan_day_loop:WHILE v_index < v_day_count DO
    INSERT INTO tmp_rateplan_days (day_index, calendar_date)
    VALUES (v_index, DATE_ADD(p_check_in, INTERVAL v_index DAY));
    SET v_index = v_index + 1;
  END WHILE rateplan_day_loop;

  DROP TEMPORARY TABLE IF EXISTS tmp_rateplan_occupancy;
  CREATE TEMPORARY TABLE tmp_rateplan_occupancy AS
  SELECT
    d.calendar_date,
    COUNT(DISTINCT CASE
      WHEN res.id_reservation IS NOT NULL OR rb.id_room_block IS NOT NULL THEN r.id_room
    END) AS occupied_rooms
  FROM tmp_rateplan_days d
  JOIN room r
    ON r.id_property = p_property_id
   AND r.is_active = 1
   AND r.deleted_at IS NULL
  LEFT JOIN reservation res
    ON res.id_room = r.id_room
   AND res.deleted_at IS NULL
   AND COALESCE(res.status, 'confirmed') NOT IN ('cancelled','canceled','cancelado','cancelada')
   AND res.check_in_date <= d.calendar_date
   AND res.check_out_date > d.calendar_date
  LEFT JOIN room_block rb
    ON rb.id_room = r.id_room
   AND rb.deleted_at IS NULL
   AND rb.is_active = 1
   AND rb.start_date <= d.calendar_date
   AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > d.calendar_date
  GROUP BY d.calendar_date;

  DROP TEMPORARY TABLE IF EXISTS tmp_rateplan_calc;
  CREATE TEMPORARY TABLE tmp_rateplan_calc AS
  SELECT
    d.calendar_date,
    v_base_cents AS base_cents,
    v_min_cents AS min_cents,
    v_base_adjust_pct AS base_adjust_pct,
    CASE WHEN DAYOFWEEK(d.calendar_date) IN (1,7) THEN 1 ELSE 0 END AS is_weekend,
    IF(v_total_rooms = 0, 0,
      ROUND(COALESCE(o.occupied_rooms,0) / v_total_rooms * 100, 1)
    ) AS occupancy_pct,
    CASE
      WHEN v_use_occupancy = 0 OR v_total_rooms = 0 THEN 0
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) <= v_low_threshold THEN v_low_adjust_pct
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) <= v_mid_low_threshold THEN v_mid_low_adjust_pct
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) >= v_high_threshold THEN v_high_adjust_pct
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) >= v_mid_high_threshold THEN v_mid_high_adjust_pct
      ELSE 0
    END AS occupancy_adjust_pct,
    CASE
      WHEN v_use_season = 1 AND p_rateplan_id IS NOT NULL THEN COALESCE((
        SELECT rs.adjust_pct
        FROM rateplan_season rs
        WHERE rs.id_rateplan = p_rateplan_id
          AND rs.is_active = 1
          AND d.calendar_date BETWEEN rs.start_date AND rs.end_date
        ORDER BY rs.priority DESC, rs.adjust_pct DESC
        LIMIT 1
      ), 0)
      ELSE 0
    END AS season_adjust_pct,
    CASE
      WHEN p_rateplan_id IS NULL THEN NULL
      ELSE (
        SELECT ro.price_cents
        FROM rateplan_override ro
        WHERE ro.id_rateplan = p_rateplan_id
          AND ro.is_active = 1
          AND ro.override_date = d.calendar_date
          AND (
            (p_room_id IS NOT NULL AND ro.id_room = p_room_id)
            OR (p_room_id IS NULL AND v_id_category IS NOT NULL AND ro.id_category = v_id_category)
            OR (ro.id_room IS NULL AND ro.id_category IS NULL)
          )
        ORDER BY ro.id_room IS NOT NULL DESC, ro.id_category IS NOT NULL DESC, ro.id_rateplan_override DESC
        LIMIT 1
      )
    END AS override_price_cents,
    0 AS base_adjusted_cents,
    0 AS calc_cents,
    0 AS final_price_cents
  FROM tmp_rateplan_days d
  LEFT JOIN tmp_rateplan_occupancy o ON o.calendar_date = d.calendar_date;

  UPDATE tmp_rateplan_calc
  SET
    base_adjusted_cents = ROUND(base_cents * (1 + base_adjust_pct / 100)),
    calc_cents = ROUND(base_cents * (1 + base_adjust_pct / 100))
      + ROUND(ROUND(base_cents * (1 + base_adjust_pct / 100)) * (season_adjust_pct / 100))
      + ROUND(ROUND(base_cents * (1 + base_adjust_pct / 100)) * (occupancy_adjust_pct / 100))
      + ROUND(ROUND(base_cents * (1 + base_adjust_pct / 100)) * (CASE WHEN is_weekend = 1 THEN v_weekend_adjust_pct ELSE 0 END / 100));

  UPDATE tmp_rateplan_calc
  SET
    calc_cents = CASE
      WHEN v_max_discount_pct > 0 AND v_max_markup_pct > 0 THEN LEAST(
        ROUND(base_adjusted_cents * (1 + v_max_markup_pct / 100)),
        GREATEST(
          ROUND(base_adjusted_cents * (1 - v_max_discount_pct / 100)),
          calc_cents
        )
      )
      WHEN v_max_discount_pct > 0 THEN GREATEST(
        ROUND(base_adjusted_cents * (1 - v_max_discount_pct / 100)),
        calc_cents
      )
      WHEN v_max_markup_pct > 0 THEN LEAST(
        ROUND(base_adjusted_cents * (1 + v_max_markup_pct / 100)),
        calc_cents
      )
      ELSE calc_cents
    END,
    final_price_cents = CASE
      WHEN override_price_cents IS NOT NULL THEN override_price_cents
      ELSE GREATEST(calc_cents, min_cents)
    END;

  SELECT COALESCE(SUM(final_price_cents), 0)
    INTO p_total_cents
  FROM tmp_rateplan_calc;

  SET p_avg_nightly_cents = CASE
    WHEN v_day_count > 0 THEN CEILING(p_total_cents / v_day_count)
    ELSE 0
  END;

  SELECT CONCAT(
    '[',
    COALESCE(GROUP_CONCAT(
      CONCAT(
        '{"date":"', DATE_FORMAT(calendar_date, '%Y-%m-%d'),
        '","nightly_cents":', final_price_cents,
        '}'
      )
      ORDER BY calendar_date SEPARATOR ','
    ), ''),
    ']'
  )
    INTO p_breakdown_json
  FROM tmp_rateplan_calc;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_rateplan_calendar` (IN `p_property_code` VARCHAR(100), IN `p_rateplan_code` VARCHAR(100), IN `p_category_code` VARCHAR(100), IN `p_room_code` VARCHAR(100), IN `p_from` DATE, IN `p_days` INT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_base_cents INT DEFAULT 0;
  DECLARE v_min_cents INT DEFAULT 0;
  DECLARE v_day_count INT DEFAULT 0;
  DECLARE v_to DATE;
  DECLARE v_index INT DEFAULT 0;
  DECLARE v_total_rooms INT DEFAULT 0;
  DECLARE v_use_season TINYINT DEFAULT 1;
  DECLARE v_use_occupancy TINYINT DEFAULT 1;
  DECLARE v_base_adjust_pct DECIMAL(6,2) DEFAULT 0;
  DECLARE v_low_threshold DECIMAL(6,2) DEFAULT 40;
  DECLARE v_mid_low_threshold DECIMAL(6,2) DEFAULT 55;
  DECLARE v_mid_high_threshold DECIMAL(6,2) DEFAULT 70;
  DECLARE v_high_threshold DECIMAL(6,2) DEFAULT 80;
  DECLARE v_low_adjust_pct DECIMAL(6,2) DEFAULT -15;
  DECLARE v_mid_low_adjust_pct DECIMAL(6,2) DEFAULT -5;
  DECLARE v_mid_high_adjust_pct DECIMAL(6,2) DEFAULT 10;
  DECLARE v_high_adjust_pct DECIMAL(6,2) DEFAULT 20;
  DECLARE v_weekend_adjust_pct DECIMAL(6,2) DEFAULT 0;
  DECLARE v_max_discount_pct DECIMAL(6,2) DEFAULT 30;
  DECLARE v_max_markup_pct DECIMAL(6,2) DEFAULT 40;

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_from IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'From date is required';
  END IF;

  SET v_day_count = CASE
    WHEN p_days IS NULL OR p_days < 1 THEN 1
    WHEN p_days > 120 THEN 120
    ELSE p_days
  END;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SET v_id_room = NULL;
  SET v_id_category = NULL;
  SET v_id_rateplan = NULL;

  IF p_room_code IS NOT NULL AND p_room_code <> '' THEN
    SELECT r.id_room,
           r.id_category,
           COALESCE(rc.default_base_price_cents,0),
           COALESCE(NULLIF(rc.min_price_cents,0), COALESCE(rc.default_base_price_cents,0)),
           COALESCE(r.id_rateplan, rc.id_rateplan)
      INTO v_id_room, v_id_category, v_base_cents, v_min_cents, v_id_rateplan
    FROM room r
    JOIN roomcategory rc ON rc.id_category = r.id_category
    WHERE r.id_property = v_id_property
      AND r.code = p_room_code
      AND r.deleted_at IS NULL
    LIMIT 1;
  ELSEIF p_category_code IS NOT NULL AND p_category_code <> '' THEN
    SELECT rc.id_category,
           COALESCE(rc.default_base_price_cents,0),
           COALESCE(NULLIF(rc.min_price_cents,0), COALESCE(rc.default_base_price_cents,0)),
           rc.id_rateplan
      INTO v_id_category, v_base_cents, v_min_cents, v_id_rateplan
    FROM roomcategory rc
    WHERE rc.id_property = v_id_property
      AND rc.code = p_category_code
      AND rc.deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF v_id_category IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category or room is required';
  END IF;

  IF p_rateplan_code IS NOT NULL AND p_rateplan_code <> '' THEN
    SELECT id_rateplan
      INTO v_id_rateplan
    FROM rateplan
    WHERE id_property = v_id_property
      AND code = p_rateplan_code
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF v_id_rateplan IS NOT NULL THEN
    SELECT
      COALESCE(rpp.base_adjust_pct, 0),
      COALESCE(rpp.use_season, 1),
      COALESCE(rpp.use_occupancy, 1),
      COALESCE(rpp.occupancy_low_threshold, 40),
      COALESCE(rpp.occupancy_mid_low_threshold, 55),
      COALESCE(rpp.occupancy_mid_high_threshold, 70),
      COALESCE(rpp.occupancy_high_threshold, 80),
      COALESCE(rpp.low_occupancy_adjust_pct, -15),
      COALESCE(rpp.mid_low_occupancy_adjust_pct, -5),
      COALESCE(rpp.mid_high_occupancy_adjust_pct, 10),
      COALESCE(rpp.high_occupancy_adjust_pct, 20),
      COALESCE(rpp.weekend_adjust_pct, 0),
      COALESCE(rpp.max_discount_pct, 30),
      COALESCE(rpp.max_markup_pct, 40)
      INTO v_base_adjust_pct,
           v_use_season,
           v_use_occupancy,
           v_low_threshold,
           v_mid_low_threshold,
           v_mid_high_threshold,
           v_high_threshold,
           v_low_adjust_pct,
           v_mid_low_adjust_pct,
           v_mid_high_adjust_pct,
           v_high_adjust_pct,
           v_weekend_adjust_pct,
           v_max_discount_pct,
           v_max_markup_pct
    FROM rateplan_pricing rpp
    WHERE rpp.id_rateplan = v_id_rateplan
    LIMIT 1;
  END IF;

  SELECT COUNT(*)
    INTO v_total_rooms
  FROM room
  WHERE id_property = v_id_property
    AND is_active = 1
    AND deleted_at IS NULL;

  SET v_to = DATE_ADD(p_from, INTERVAL v_day_count DAY);

  DROP TEMPORARY TABLE IF EXISTS tmp_rateplan_days;
  CREATE TEMPORARY TABLE tmp_rateplan_days (
    day_index INT PRIMARY KEY,
    calendar_date DATE NOT NULL
  ) ENGINE = MEMORY;

  rateplan_day_loop:WHILE v_index < v_day_count DO
    INSERT INTO tmp_rateplan_days (day_index, calendar_date)
    VALUES (v_index, DATE_ADD(p_from, INTERVAL v_index DAY));
    SET v_index = v_index + 1;
  END WHILE rateplan_day_loop;

  DROP TEMPORARY TABLE IF EXISTS tmp_rateplan_occupancy;
  CREATE TEMPORARY TABLE tmp_rateplan_occupancy AS
  SELECT
    d.calendar_date,
    COUNT(DISTINCT CASE
      WHEN res.id_reservation IS NOT NULL OR rb.id_room_block IS NOT NULL THEN r.id_room
    END) AS occupied_rooms
  FROM tmp_rateplan_days d
  JOIN room r
    ON r.id_property = v_id_property
   AND r.is_active = 1
   AND r.deleted_at IS NULL
  LEFT JOIN reservation res
    ON res.id_room = r.id_room
   AND res.deleted_at IS NULL
   AND COALESCE(res.status, 'confirmed') NOT IN ('cancelled','canceled','cancelado','cancelada')
   AND res.check_in_date <= d.calendar_date
   AND res.check_out_date > d.calendar_date
  LEFT JOIN room_block rb
    ON rb.id_room = r.id_room
   AND rb.deleted_at IS NULL
   AND rb.is_active = 1
   AND rb.start_date <= d.calendar_date
   AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > d.calendar_date
  GROUP BY d.calendar_date;

  DROP TEMPORARY TABLE IF EXISTS tmp_rateplan_calc;
  CREATE TEMPORARY TABLE tmp_rateplan_calc AS
  SELECT
    d.day_index,
    d.calendar_date,
    v_base_cents AS base_cents,
    v_min_cents AS min_cents,
    v_base_adjust_pct AS base_adjust_pct,
    CASE WHEN DAYOFWEEK(d.calendar_date) IN (1,7) THEN 1 ELSE 0 END AS is_weekend,
    IF(v_total_rooms = 0, 0,
      ROUND(COALESCE(o.occupied_rooms,0) / v_total_rooms * 100, 1)
    ) AS occupancy_pct,
    CASE
      WHEN v_use_occupancy = 0 OR v_total_rooms = 0 THEN 0
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) <= v_low_threshold THEN v_low_adjust_pct
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) <= v_mid_low_threshold THEN v_mid_low_adjust_pct
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) >= v_high_threshold THEN v_high_adjust_pct
      WHEN (COALESCE(o.occupied_rooms,0) / NULLIF(v_total_rooms,0) * 100) >= v_mid_high_threshold THEN v_mid_high_adjust_pct
      ELSE 0
    END AS occupancy_adjust_pct,
    CASE
      WHEN v_use_season = 1 AND v_id_rateplan IS NOT NULL THEN COALESCE((
        SELECT rs.adjust_pct
        FROM rateplan_season rs
        WHERE rs.id_rateplan = v_id_rateplan
          AND rs.is_active = 1
          AND d.calendar_date BETWEEN rs.start_date AND rs.end_date
        ORDER BY rs.priority DESC, rs.adjust_pct DESC
        LIMIT 1
      ), 0)
      ELSE 0
    END AS season_adjust_pct,
    CASE
      WHEN v_id_rateplan IS NULL THEN NULL
      ELSE (
        SELECT ro.price_cents
        FROM rateplan_override ro
        WHERE ro.id_rateplan = v_id_rateplan
          AND ro.is_active = 1
          AND ro.override_date = d.calendar_date
          AND (
            (v_id_room IS NOT NULL AND ro.id_room = v_id_room)
            OR (v_id_room IS NULL AND v_id_category IS NOT NULL AND ro.id_category = v_id_category)
            OR (ro.id_room IS NULL AND ro.id_category IS NULL)
          )
        ORDER BY ro.id_room IS NOT NULL DESC, ro.id_category IS NOT NULL DESC, ro.id_rateplan_override DESC
        LIMIT 1
      )
    END AS override_price_cents,
    0 AS base_adjusted_cents,
    0 AS calc_cents,
    0 AS final_price_cents
  FROM tmp_rateplan_days d
  LEFT JOIN tmp_rateplan_occupancy o ON o.calendar_date = d.calendar_date;

  UPDATE tmp_rateplan_calc
  SET
    base_adjusted_cents = ROUND(base_cents * (1 + base_adjust_pct / 100)),
    calc_cents = ROUND(base_cents * (1 + base_adjust_pct / 100))
      + ROUND(ROUND(base_cents * (1 + base_adjust_pct / 100)) * (season_adjust_pct / 100))
      + ROUND(ROUND(base_cents * (1 + base_adjust_pct / 100)) * (occupancy_adjust_pct / 100))
      + ROUND(ROUND(base_cents * (1 + base_adjust_pct / 100)) * (CASE WHEN is_weekend = 1 THEN v_weekend_adjust_pct ELSE 0 END / 100));

  UPDATE tmp_rateplan_calc
  SET
    calc_cents = CASE
      WHEN v_max_discount_pct > 0 AND v_max_markup_pct > 0 THEN LEAST(
        ROUND(base_adjusted_cents * (1 + v_max_markup_pct / 100)),
        GREATEST(
          ROUND(base_adjusted_cents * (1 - v_max_discount_pct / 100)),
          calc_cents
        )
      )
      WHEN v_max_discount_pct > 0 THEN GREATEST(
        ROUND(base_adjusted_cents * (1 - v_max_discount_pct / 100)),
        calc_cents
      )
      WHEN v_max_markup_pct > 0 THEN LEAST(
        ROUND(base_adjusted_cents * (1 + v_max_markup_pct / 100)),
        calc_cents
      )
      ELSE calc_cents
    END,
    final_price_cents = CASE
      WHEN override_price_cents IS NOT NULL THEN override_price_cents
      ELSE GREATEST(calc_cents, min_cents)
    END;

  SELECT
    day_index,
    calendar_date,
    base_cents,
    min_cents,
    base_adjust_pct,
    base_adjusted_cents,
    season_adjust_pct,
    occupancy_pct,
    occupancy_adjust_pct,
    override_price_cents,
    final_price_cents
  FROM tmp_rateplan_calc
  ORDER BY day_index;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_rateplan_override_upsert` (IN `p_property_code` VARCHAR(100), IN `p_rateplan_code` VARCHAR(100), IN `p_id_rateplan_override` BIGINT, IN `p_id_category` BIGINT, IN `p_id_room` BIGINT, IN `p_override_date` DATE, IN `p_price_cents` INT, IN `p_notes` VARCHAR(255), IN `p_is_active` TINYINT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_id_override BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_rateplan_code IS NULL OR p_rateplan_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Rateplan code is required';
  END IF;
  IF p_override_date IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Override date is required';
  END IF;
  IF p_price_cents IS NULL OR p_price_cents <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Override price must be greater than zero';
  END IF;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SELECT id_rateplan
    INTO v_id_rateplan
  FROM rateplan
  WHERE id_property = v_id_property
    AND code = p_rateplan_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_rateplan IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown rateplan code for property';
  END IF;

  SET v_id_room = NULL;
  SET v_id_category = NULL;
  IF p_id_room IS NOT NULL AND p_id_room > 0 THEN
    SELECT r.id_room
      INTO v_id_room
    FROM room r
    WHERE r.id_room = p_id_room
      AND r.id_property = v_id_property
      AND r.deleted_at IS NULL
    LIMIT 1;
    IF v_id_room IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room not found for property';
    END IF;
  ELSEIF p_id_category IS NOT NULL AND p_id_category > 0 THEN
    SELECT rc.id_category
      INTO v_id_category
    FROM roomcategory rc
    WHERE rc.id_category = p_id_category
      AND rc.id_property = v_id_property
      AND rc.deleted_at IS NULL
    LIMIT 1;
    IF v_id_category IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category not found for property';
    END IF;
  END IF;

  SET v_id_override = NULL;
  IF p_id_rateplan_override IS NOT NULL AND p_id_rateplan_override > 0 THEN
    SELECT id_rateplan_override
      INTO v_id_override
    FROM rateplan_override
    WHERE id_rateplan_override = p_id_rateplan_override
      AND id_rateplan = v_id_rateplan
    LIMIT 1;
  END IF;

  IF v_id_override IS NULL THEN
    INSERT INTO rateplan_override (
      id_rateplan,
      id_category,
      id_room,
      override_date,
      price_cents,
      notes,
      is_active,
      created_at,
      updated_at
    ) VALUES (
      v_id_rateplan,
      v_id_category,
      v_id_room,
      p_override_date,
      p_price_cents,
      NULLIF(p_notes, ''),
      COALESCE(p_is_active, 1),
      v_now,
      v_now
    );
    SET v_id_override = LAST_INSERT_ID();
  ELSE
    UPDATE rateplan_override
    SET
      id_category = v_id_category,
      id_room = v_id_room,
      override_date = p_override_date,
      price_cents = p_price_cents,
      notes = NULLIF(p_notes, ''),
      is_active = COALESCE(p_is_active, is_active),
      updated_at = v_now
    WHERE id_rateplan_override = v_id_override;
  END IF;

  SELECT
    ro.id_rateplan_override,
    ro.id_rateplan,
    ro.id_category,
    ro.id_room,
    ro.override_date,
    ro.price_cents,
    ro.notes,
    ro.is_active
  FROM rateplan_override ro
  WHERE ro.id_rateplan_override = v_id_override
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_rateplan_pricing_upsert` (IN `p_property_code` VARCHAR(100), IN `p_rateplan_code` VARCHAR(100), IN `p_base_adjust_pct` DECIMAL(6,2), IN `p_use_season` TINYINT, IN `p_use_occupancy` TINYINT, IN `p_occupancy_low_threshold` DECIMAL(6,2), IN `p_occupancy_mid_low_threshold` DECIMAL(6,2), IN `p_occupancy_mid_high_threshold` DECIMAL(6,2), IN `p_occupancy_high_threshold` DECIMAL(6,2), IN `p_low_occupancy_adjust_pct` DECIMAL(6,2), IN `p_mid_low_occupancy_adjust_pct` DECIMAL(6,2), IN `p_mid_high_occupancy_adjust_pct` DECIMAL(6,2), IN `p_high_occupancy_adjust_pct` DECIMAL(6,2), IN `p_weekend_adjust_pct` DECIMAL(6,2), IN `p_max_discount_pct` DECIMAL(6,2), IN `p_max_markup_pct` DECIMAL(6,2), IN `p_is_active` TINYINT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_id_pricing BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_rateplan_code IS NULL OR p_rateplan_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Rateplan code is required';
  END IF;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SELECT id_rateplan
    INTO v_id_rateplan
  FROM rateplan
  WHERE id_property = v_id_property
    AND code = p_rateplan_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_rateplan IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown rateplan code for property';
  END IF;

  SELECT id_rateplan_pricing
    INTO v_id_pricing
  FROM rateplan_pricing
  WHERE id_rateplan = v_id_rateplan
  LIMIT 1;

  IF v_id_pricing IS NULL THEN
    INSERT INTO rateplan_pricing (
      id_rateplan,
      base_adjust_pct,
      use_season,
      use_occupancy,
      occupancy_low_threshold,
      occupancy_mid_low_threshold,
      occupancy_mid_high_threshold,
      occupancy_high_threshold,
      low_occupancy_adjust_pct,
      mid_low_occupancy_adjust_pct,
      mid_high_occupancy_adjust_pct,
      high_occupancy_adjust_pct,
      weekend_adjust_pct,
      max_discount_pct,
      max_markup_pct,
      is_active,
      created_at,
      updated_at
    ) VALUES (
      v_id_rateplan,
      COALESCE(p_base_adjust_pct, 0),
      COALESCE(p_use_season, 1),
      COALESCE(p_use_occupancy, 1),
      COALESCE(p_occupancy_low_threshold, 40),
      COALESCE(p_occupancy_mid_low_threshold, 55),
      COALESCE(p_occupancy_mid_high_threshold, 70),
      COALESCE(p_occupancy_high_threshold, 80),
      COALESCE(p_low_occupancy_adjust_pct, -15),
      COALESCE(p_mid_low_occupancy_adjust_pct, -5),
      COALESCE(p_mid_high_occupancy_adjust_pct, 10),
      COALESCE(p_high_occupancy_adjust_pct, 20),
      COALESCE(p_weekend_adjust_pct, 0),
      COALESCE(p_max_discount_pct, 30),
      COALESCE(p_max_markup_pct, 40),
      COALESCE(p_is_active, 1),
      v_now,
      v_now
    );
    SET v_id_pricing = LAST_INSERT_ID();
  ELSE
    UPDATE rateplan_pricing
    SET
      base_adjust_pct = COALESCE(p_base_adjust_pct, base_adjust_pct),
      use_season = COALESCE(p_use_season, use_season),
      use_occupancy = COALESCE(p_use_occupancy, use_occupancy),
      occupancy_low_threshold = COALESCE(p_occupancy_low_threshold, occupancy_low_threshold),
      occupancy_mid_low_threshold = COALESCE(p_occupancy_mid_low_threshold, occupancy_mid_low_threshold),
      occupancy_mid_high_threshold = COALESCE(p_occupancy_mid_high_threshold, occupancy_mid_high_threshold),
      occupancy_high_threshold = COALESCE(p_occupancy_high_threshold, occupancy_high_threshold),
      low_occupancy_adjust_pct = COALESCE(p_low_occupancy_adjust_pct, low_occupancy_adjust_pct),
      mid_low_occupancy_adjust_pct = COALESCE(p_mid_low_occupancy_adjust_pct, mid_low_occupancy_adjust_pct),
      mid_high_occupancy_adjust_pct = COALESCE(p_mid_high_occupancy_adjust_pct, mid_high_occupancy_adjust_pct),
      high_occupancy_adjust_pct = COALESCE(p_high_occupancy_adjust_pct, high_occupancy_adjust_pct),
      weekend_adjust_pct = COALESCE(p_weekend_adjust_pct, weekend_adjust_pct),
      max_discount_pct = COALESCE(p_max_discount_pct, max_discount_pct),
      max_markup_pct = COALESCE(p_max_markup_pct, max_markup_pct),
      is_active = COALESCE(p_is_active, is_active),
      updated_at = v_now
    WHERE id_rateplan_pricing = v_id_pricing;
  END IF;

  SELECT
    rpp.id_rateplan_pricing,
    rpp.id_rateplan,
    rpp.base_adjust_pct,
    rpp.use_season,
    rpp.use_occupancy,
    rpp.occupancy_low_threshold,
    rpp.occupancy_mid_low_threshold,
    rpp.occupancy_mid_high_threshold,
    rpp.occupancy_high_threshold,
    rpp.low_occupancy_adjust_pct,
    rpp.mid_low_occupancy_adjust_pct,
    rpp.mid_high_occupancy_adjust_pct,
    rpp.high_occupancy_adjust_pct,
    rpp.weekend_adjust_pct,
    rpp.max_discount_pct,
    rpp.max_markup_pct,
    rpp.is_active
  FROM rateplan_pricing rpp
  WHERE rpp.id_rateplan_pricing = v_id_pricing
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_rateplan_season_upsert` (IN `p_property_code` VARCHAR(100), IN `p_rateplan_code` VARCHAR(100), IN `p_id_rateplan_season` BIGINT, IN `p_season_name` VARCHAR(100), IN `p_start_date` DATE, IN `p_end_date` DATE, IN `p_adjust_pct` DECIMAL(6,2), IN `p_priority` INT, IN `p_is_active` TINYINT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_id_season BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_rateplan_code IS NULL OR p_rateplan_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Rateplan code is required';
  END IF;
  IF p_season_name IS NULL OR p_season_name = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Season name is required';
  END IF;
  IF p_start_date IS NULL OR p_end_date IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Season date range is required';
  END IF;
  IF p_start_date > p_end_date THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Season start date must be before end date';
  END IF;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SELECT id_rateplan
    INTO v_id_rateplan
  FROM rateplan
  WHERE id_property = v_id_property
    AND code = p_rateplan_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_rateplan IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown rateplan code for property';
  END IF;

  SET v_id_season = NULL;
  IF p_id_rateplan_season IS NOT NULL AND p_id_rateplan_season > 0 THEN
    SELECT id_rateplan_season
      INTO v_id_season
    FROM rateplan_season
    WHERE id_rateplan_season = p_id_rateplan_season
      AND id_rateplan = v_id_rateplan
    LIMIT 1;
  END IF;

  IF v_id_season IS NULL THEN
    INSERT INTO rateplan_season (
      id_rateplan,
      season_name,
      start_date,
      end_date,
      adjust_pct,
      priority,
      is_active,
      created_at,
      updated_at
    ) VALUES (
      v_id_rateplan,
      p_season_name,
      p_start_date,
      p_end_date,
      COALESCE(p_adjust_pct, 0),
      COALESCE(p_priority, 0),
      COALESCE(p_is_active, 1),
      v_now,
      v_now
    );
    SET v_id_season = LAST_INSERT_ID();
  ELSE
    UPDATE rateplan_season
    SET
      season_name = p_season_name,
      start_date = p_start_date,
      end_date = p_end_date,
      adjust_pct = COALESCE(p_adjust_pct, adjust_pct),
      priority = COALESCE(p_priority, priority),
      is_active = COALESCE(p_is_active, is_active),
      updated_at = v_now
    WHERE id_rateplan_season = v_id_season;
  END IF;

  SELECT
    rs.id_rateplan_season,
    rs.id_rateplan,
    rs.season_name,
    rs.start_date,
    rs.end_date,
    rs.adjust_pct,
    rs.priority,
    rs.is_active
  FROM rateplan_season rs
  WHERE rs.id_rateplan_season = v_id_season
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_rateplan_upsert` (IN `p_property_code` VARCHAR(100), IN `p_rateplan_code` VARCHAR(100), IN `p_name` VARCHAR(255), IN `p_description` TEXT, IN `p_currency` VARCHAR(10), IN `p_refundable` TINYINT, IN `p_min_stay` INT, IN `p_max_stay` INT, IN `p_effective_from` DATE, IN `p_effective_to` DATE, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_rateplan_code IS NULL OR p_rateplan_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Rate plan code is required';
  END IF;
  IF p_name IS NULL OR p_name = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Rate plan name is required';
  END IF;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SELECT id_rateplan
    INTO v_id_rateplan
  FROM rateplan
  WHERE id_property = v_id_property
    AND code = p_rateplan_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_rateplan IS NULL THEN
    INSERT INTO rateplan (
      id_property,
      code,
      name,
      description,
      currency,
      refundable,
      min_stay_default,
      max_stay_default,
      effective_from,
      effective_to,
      is_active,
      created_at,
      updated_at,
      created_by
    ) VALUES (
      v_id_property,
      p_rateplan_code,
      p_name,
      NULLIF(p_description, ''),
      COALESCE(NULLIF(p_currency, ''), 'MXN'),
      COALESCE(p_refundable, 1),
      p_min_stay,
      p_max_stay,
      COALESCE(p_effective_from, CURDATE()),
      p_effective_to,
      COALESCE(p_is_active, 1),
      v_now,
      v_now,
      p_actor_user_id
    );
    SET v_id_rateplan = LAST_INSERT_ID();
  ELSE
    UPDATE rateplan
    SET
      name = p_name,
      description = NULLIF(p_description, ''),
      currency = COALESCE(NULLIF(p_currency, ''), currency),
      refundable = COALESCE(p_refundable, refundable),
      min_stay_default = p_min_stay,
      max_stay_default = p_max_stay,
      effective_from = COALESCE(p_effective_from, effective_from),
      effective_to = p_effective_to,
      is_active = COALESCE(p_is_active, is_active),
      updated_at = v_now
    WHERE id_rateplan = v_id_rateplan;
  END IF;

  SELECT
    rp.id_rateplan,
    rp.id_property,
    rp.code AS rateplan_code,
    rp.name AS rateplan_name,
    rp.description,
    rp.currency,
    rp.refundable,
    rp.min_stay_default,
    rp.max_stay_default,
    rp.effective_from,
    rp.effective_to,
    rp.is_active
  FROM rateplan rp
  WHERE rp.id_rateplan = v_id_rateplan
    AND rp.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_refund_upsert` (IN `p_action` VARCHAR(16), IN `p_id_refund` BIGINT, IN `p_id_payment` BIGINT, IN `p_amount_cents` INT, IN `p_reason` TEXT, IN `p_reference` VARCHAR(255), IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_id_payment BIGINT;
  DECLARE v_id_folio BIGINT;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_available INT;
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;

  IF p_action NOT IN ('create','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for refund';
  END IF;

  IF p_action = 'create' THEN
    IF p_id_payment IS NULL OR p_id_payment = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment id is required';
    END IF;
    SELECT li.id_line_item,
           li.id_folio,
           li.currency,
           li.amount_cents - li.refunded_total_cents,
           c.code,
           p.code
      INTO v_id_payment,
           v_id_folio,
           v_currency,
           v_available,
           v_company_code,
           v_property_code
    FROM line_item li
    JOIN folio f ON f.id_folio = li.id_folio
    JOIN reservation rs ON rs.id_reservation = f.id_reservation
    JOIN property p ON p.id_property = rs.id_property
    JOIN company c ON c.id_company = p.id_company
    WHERE li.id_line_item = p_id_payment
      AND li.item_type = 'payment'
      AND li.deleted_at IS NULL
    LIMIT 1;
    IF v_id_payment IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'payment not found';
    END IF;
    IF p_amount_cents IS NULL OR p_amount_cents <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'refund amount must be positive';
    END IF;
    IF p_amount_cents > v_available THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'refund exceeds remaining amount';
    END IF;

    CALL sp_authz_assert(
      v_company_code,
      p_created_by,
      'reservations.refund',
      v_property_code,
      NULL
    );

    INSERT INTO refund (
      id_payment,
      id_user,
      amount_cents,
      currency,
      reference,
      reason,
      refunded_at,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_id_payment,
      p_created_by,
      p_amount_cents,
      v_currency,
      NULLIF(p_reference,''),
      p_reason,
      NOW(),
      1,
      NULL,
      NOW(),
      p_created_by,
      NOW()
    );
    SET p_id_refund = LAST_INSERT_ID();

    UPDATE line_item
       SET refunded_total_cents = refunded_total_cents + p_amount_cents,
           updated_at = NOW()
     WHERE id_line_item = v_id_payment
       AND item_type = 'payment';

    CALL sp_folio_recalc(v_id_folio);
    SELECT * FROM refund WHERE id_refund = p_id_refund;
    LEAVE proc;
  END IF;

  /* delete refund */
  IF p_action = 'delete' THEN
    IF p_id_refund IS NULL OR p_id_refund = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'refund id is required';
    END IF;
    SELECT r.id_payment, p.id_folio, c.code, pr.code
      INTO v_id_payment, v_id_folio, v_company_code, v_property_code
    FROM refund r
    JOIN line_item p
      ON p.id_line_item = r.id_payment
     AND p.item_type = 'payment'
    JOIN folio f
      ON f.id_folio = p.id_folio
    JOIN reservation rs
      ON rs.id_reservation = f.id_reservation
    JOIN property pr
      ON pr.id_property = rs.id_property
    JOIN company c
      ON c.id_company = pr.id_company
    WHERE r.id_refund = p_id_refund
    LIMIT 1;

    CALL sp_authz_assert(
      v_company_code,
      p_created_by,
      'reservations.refund',
      v_property_code,
      NULL
    );
    UPDATE refund
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_refund = p_id_refund;
    IF v_id_payment IS NOT NULL THEN
      UPDATE line_item
         SET refunded_total_cents = GREATEST(refunded_total_cents - COALESCE(p_amount_cents,0), 0),
             updated_at = NOW()
       WHERE id_line_item = v_id_payment
         AND item_type = 'payment';
    END IF;
    IF v_id_folio IS NOT NULL THEN
      CALL sp_folio_recalc(v_id_folio);
    END IF;
    SELECT * FROM refund WHERE id_refund = p_id_refund;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_catalog_options` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100))   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    sic.id_line_item_catalog,
    sic.catalog_type,
    sic.item_name,
    parent_map.percent_value AS rate_percent,
    cat.id_property AS category_property_id,
    cat.category_name AS subcategory_name,
    parent.category_name AS category_name
  FROM line_item_catalog sic
  LEFT JOIN (
    SELECT
      id_sale_item_catalog,
      MIN(percent_value) AS percent_value
    FROM line_item_catalog_parent
    WHERE deleted_at IS NULL
      AND is_active = 1
    GROUP BY id_sale_item_catalog
  ) parent_map
    ON parent_map.id_sale_item_catalog = sic.id_line_item_catalog
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = sic.id_category
   AND cat.id_company = v_company_id
   AND cat.deleted_at IS NULL
  LEFT JOIN sale_item_category parent
    ON parent.id_sale_item_category = cat.id_parent_sale_item_category
  LEFT JOIN property prop
    ON prop.id_property = cat.id_property
  WHERE sic.deleted_at IS NULL
    AND sic.is_active = 1
    AND sic.catalog_type IN ('sale_item','tax_rule')
    AND (
      v_property_id IS NULL
      OR cat.id_property IS NULL
      OR cat.id_property = v_property_id
      OR prop.code = p_property_code
    )
  ORDER BY category_name, subcategory_name, sic.item_name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_config_data` (IN `p_company_code` VARCHAR(100), IN `p_report_key` VARCHAR(64))   BEGIN
  DECLARE v_company_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_report_key IS NULL OR p_report_key = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report key is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT
    rc.id_report_config,
    rc.report_name,
    rc.report_type,
    rc.line_item_type_scope,
    rc.description,
    rc.column_order,
    rc.report_key,
    rc.is_active
  FROM report_config rc
  WHERE rc.id_company = v_company_id
    AND rc.report_key = p_report_key
    AND rc.deleted_at IS NULL
    AND rc.is_active = 1
  LIMIT 1;

  SELECT
    rcc.id_line_item_catalog AS id_sale_item_catalog,
    rcc.legacy_role AS role
  FROM report_config_column rcc
  JOIN report_config rc
    ON rc.id_report_config = rcc.id_report_config
  WHERE rc.id_company = v_company_id
    AND rc.report_key = p_report_key
    AND rc.deleted_at IS NULL
    AND rc.is_active = 1
    AND rcc.deleted_at IS NULL
    AND rcc.is_active = 1
    AND rcc.legacy_role IS NOT NULL
  ORDER BY rcc.order_index, rcc.id_report_config_column;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_config_upsert` (IN `p_company_code` VARCHAR(100), IN `p_report_key` VARCHAR(64), IN `p_report_name` VARCHAR(120), IN `p_column_order` TEXT, IN `p_lodging_ids` TEXT, IN `p_cleaning_id` BIGINT, IN `p_iva_id` BIGINT, IN `p_ish_id` BIGINT, IN `p_extra_ids` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_report_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_report_key IS NULL OR p_report_key = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report key is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT id_report_config INTO v_report_id
  FROM report_config
  WHERE id_company = v_company_id
    AND report_key = p_report_key
  LIMIT 1;

  IF v_report_id IS NULL OR v_report_id = 0 THEN
    INSERT INTO report_config (
      id_company,
      report_key,
      report_name,
      report_type,
      line_item_type_scope,
      description,
      column_order,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_company_id,
      p_report_key,
      COALESCE(NULLIF(p_report_name, ''), p_report_key),
      'reservation',
      NULL,
      NULL,
      p_column_order,
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET v_report_id = LAST_INSERT_ID();
  ELSE
    UPDATE report_config
       SET report_name = COALESCE(NULLIF(p_report_name, ''), report_name),
           report_type = COALESCE(NULLIF(report_type, ''), 'reservation'),
           column_order = p_column_order,
           is_active = 1,
           deleted_at = NULL,
           updated_at = NOW()
     WHERE id_report_config = v_report_id;
  END IF;

  UPDATE report_config_column
     SET is_active = 0,
         deleted_at = NOW(),
         updated_at = NOW()
   WHERE id_report_config = v_report_id
     AND legacy_role IS NOT NULL;

  IF p_lodging_ids IS NOT NULL AND p_lodging_ids <> '' THEN
    INSERT INTO report_config_column (
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      v_report_id,
      CONCAT('catalog_', lic.id_line_item_catalog, '_lodging'),
      'line_item_catalog',
      NULL,
      lic.id_line_item_catalog,
      lic.item_name,
      'lodging',
      'money',
      'sum',
      NULL,
      150,
      1,
      1,
      'eq',
      'lodging',
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM line_item_catalog lic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
     AND cat.deleted_at IS NULL
     AND cat.id_company = v_company_id
    WHERE lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND lic.catalog_type IN ('sale_item','tax_rule')
      AND FIND_IN_SET(lic.id_line_item_catalog, p_lodging_ids)
    ON DUPLICATE KEY UPDATE
      display_name = VALUES(display_name),
      display_category = VALUES(display_category),
      data_type = VALUES(data_type),
      aggregation = VALUES(aggregation),
      order_index = VALUES(order_index),
      is_visible = 1,
      is_filterable = 1,
      filter_operator_default = 'eq',
      legacy_role = 'lodging',
      is_active = 1,
      deleted_at = NULL,
      updated_at = NOW();
  END IF;

  IF p_cleaning_id IS NOT NULL AND p_cleaning_id > 0 THEN
    INSERT INTO report_config_column (
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      v_report_id,
      CONCAT('catalog_', lic.id_line_item_catalog, '_cleaning'),
      'line_item_catalog',
      NULL,
      lic.id_line_item_catalog,
      lic.item_name,
      'cleaning',
      'money',
      'sum',
      NULL,
      200,
      1,
      1,
      'eq',
      'cleaning',
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM line_item_catalog lic
    WHERE lic.id_line_item_catalog = p_cleaning_id
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
    ON DUPLICATE KEY UPDATE
      display_name = VALUES(display_name),
      display_category = VALUES(display_category),
      data_type = VALUES(data_type),
      aggregation = VALUES(aggregation),
      order_index = VALUES(order_index),
      is_visible = 1,
      is_filterable = 1,
      filter_operator_default = 'eq',
      legacy_role = 'cleaning',
      is_active = 1,
      deleted_at = NULL,
      updated_at = NOW();
  END IF;

  IF p_iva_id IS NOT NULL AND p_iva_id > 0 THEN
    INSERT INTO report_config_column (
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      v_report_id,
      CONCAT('catalog_', lic.id_line_item_catalog, '_iva'),
      'line_item_catalog',
      NULL,
      lic.id_line_item_catalog,
      lic.item_name,
      'iva',
      'money',
      'sum',
      NULL,
      250,
      1,
      1,
      'eq',
      'iva',
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM line_item_catalog lic
    WHERE lic.id_line_item_catalog = p_iva_id
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
    ON DUPLICATE KEY UPDATE
      display_name = VALUES(display_name),
      display_category = VALUES(display_category),
      data_type = VALUES(data_type),
      aggregation = VALUES(aggregation),
      order_index = VALUES(order_index),
      is_visible = 1,
      is_filterable = 1,
      filter_operator_default = 'eq',
      legacy_role = 'iva',
      is_active = 1,
      deleted_at = NULL,
      updated_at = NOW();
  END IF;

  IF p_ish_id IS NOT NULL AND p_ish_id > 0 THEN
    INSERT INTO report_config_column (
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      v_report_id,
      CONCAT('catalog_', lic.id_line_item_catalog, '_ish'),
      'line_item_catalog',
      NULL,
      lic.id_line_item_catalog,
      lic.item_name,
      'ish',
      'money',
      'sum',
      NULL,
      300,
      1,
      1,
      'eq',
      'ish',
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM line_item_catalog lic
    WHERE lic.id_line_item_catalog = p_ish_id
      AND lic.deleted_at IS NULL
      AND lic.is_active = 1
    ON DUPLICATE KEY UPDATE
      display_name = VALUES(display_name),
      display_category = VALUES(display_category),
      data_type = VALUES(data_type),
      aggregation = VALUES(aggregation),
      order_index = VALUES(order_index),
      is_visible = 1,
      is_filterable = 1,
      filter_operator_default = 'eq',
      legacy_role = 'ish',
      is_active = 1,
      deleted_at = NULL,
      updated_at = NOW();
  END IF;

  IF p_extra_ids IS NOT NULL AND p_extra_ids <> '' THEN
    INSERT INTO report_config_column (
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      v_report_id,
      CONCAT('catalog_', lic.id_line_item_catalog, '_extra'),
      'line_item_catalog',
      NULL,
      lic.id_line_item_catalog,
      lic.item_name,
      'extra',
      'money',
      'sum',
      NULL,
      400,
      1,
      1,
      'eq',
      'extra',
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM line_item_catalog lic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
     AND cat.deleted_at IS NULL
     AND cat.id_company = v_company_id
    WHERE lic.deleted_at IS NULL
      AND lic.is_active = 1
      AND lic.catalog_type IN ('sale_item','tax_rule')
      AND FIND_IN_SET(lic.id_line_item_catalog, p_extra_ids)
    ON DUPLICATE KEY UPDATE
      display_name = VALUES(display_name),
      display_category = VALUES(display_category),
      data_type = VALUES(data_type),
      aggregation = VALUES(aggregation),
      order_index = VALUES(order_index),
      is_visible = 1,
      is_filterable = 1,
      filter_operator_default = 'eq',
      legacy_role = 'extra',
      is_active = 1,
      deleted_at = NULL,
      updated_at = NOW();
  END IF;

  SELECT v_report_id AS id_report_config;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_definition_column_upsert` (IN `p_action` VARCHAR(16), IN `p_id_report_config_column` BIGINT, IN `p_id_report_config` BIGINT, IN `p_column_key` VARCHAR(160), IN `p_column_source` VARCHAR(32), IN `p_source_field_key` VARCHAR(120), IN `p_id_line_item_catalog` BIGINT, IN `p_display_name` VARCHAR(160), IN `p_display_category` VARCHAR(80), IN `p_data_type` VARCHAR(32), IN `p_aggregation` VARCHAR(32), IN `p_format_hint` VARCHAR(64), IN `p_order_index` INT, IN `p_is_visible` TINYINT, IN `p_is_filterable` TINYINT, IN `p_filter_operator_default` VARCHAR(32), IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_col_id BIGINT;
  DECLARE v_column_source VARCHAR(32);
  DECLARE v_report_type VARCHAR(32);
  DECLARE v_column_key VARCHAR(160);

  SET p_action = LOWER(TRIM(COALESCE(p_action, 'create')));
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_id_report_config IS NULL OR p_id_report_config <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'id_report_config is required';
  END IF;

  SELECT report_type
    INTO v_report_type
  FROM report_config
  WHERE id_report_config = p_id_report_config
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_report_type IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report not found';
  END IF;

  SET v_col_id = NULL;
  IF p_id_report_config_column IS NOT NULL AND p_id_report_config_column > 0 THEN
    SELECT id_report_config_column
      INTO v_col_id
    FROM report_config_column
    WHERE id_report_config_column = p_id_report_config_column
      AND id_report_config = p_id_report_config
    LIMIT 1;
  END IF;

  IF p_action = 'delete' THEN
    IF v_col_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Column not found';
    END IF;

    UPDATE report_config_column
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_report_config_column = v_col_id;

    SELECT
      id_report_config_column,
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM report_config_column
    WHERE id_report_config_column = v_col_id;

    LEAVE proc;
  END IF;

  SET v_column_source = LOWER(TRIM(COALESCE(p_column_source, 'field')));
  IF v_column_source NOT IN ('field','line_item_catalog') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported column_source';
  END IF;

  IF v_column_source = 'field' THEN
    IF p_source_field_key IS NULL OR TRIM(p_source_field_key) = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'source_field_key is required for field columns';
    END IF;

    IF NOT EXISTS (
      SELECT 1
      FROM report_field_catalog rfc
      WHERE rfc.report_type = v_report_type
        AND rfc.field_key = TRIM(p_source_field_key)
        AND rfc.is_active = 1
      LIMIT 1
    ) THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'source_field_key is not valid for report_type';
    END IF;
  ELSE
    IF p_id_line_item_catalog IS NULL OR p_id_line_item_catalog <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'id_line_item_catalog is required for line_item_catalog columns';
    END IF;

    IF NOT EXISTS (
      SELECT 1
      FROM line_item_catalog lic
      WHERE lic.id_line_item_catalog = p_id_line_item_catalog
        AND lic.deleted_at IS NULL
        AND lic.is_active = 1
      LIMIT 1
    ) THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'line_item_catalog not found';
    END IF;
  END IF;

  SET v_column_key = LOWER(TRIM(COALESCE(p_column_key, '')));
  IF v_column_key = '' THEN
    IF v_column_source = 'field' THEN
      SET v_column_key = LOWER(TRIM(p_source_field_key));
    ELSE
      SET v_column_key = CONCAT('catalog_', p_id_line_item_catalog);
    END IF;
  END IF;

  SET v_column_key = REPLACE(v_column_key, ' ', '_');
  SET v_column_key = REPLACE(v_column_key, '-', '_');
  SET v_column_key = REPLACE(v_column_key, '/', '_');
  WHILE INSTR(v_column_key, '__') > 0 DO
    SET v_column_key = REPLACE(v_column_key, '__', '_');
  END WHILE;

  IF v_col_id IS NULL THEN
    SELECT id_report_config_column
      INTO v_col_id
    FROM report_config_column
    WHERE id_report_config = p_id_report_config
      AND column_key = v_column_key
    LIMIT 1;
  END IF;

  IF v_col_id IS NULL OR v_col_id = 0 THEN
    INSERT INTO report_config_column (
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default,
      legacy_role,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      p_id_report_config,
      v_column_key,
      v_column_source,
      CASE WHEN v_column_source = 'field' THEN TRIM(p_source_field_key) ELSE NULL END,
      CASE WHEN v_column_source = 'line_item_catalog' THEN p_id_line_item_catalog ELSE NULL END,
      COALESCE(NULLIF(TRIM(p_display_name), ''), v_column_key),
      NULLIF(TRIM(COALESCE(p_display_category, '')), ''),
      COALESCE(NULLIF(TRIM(p_data_type), ''), CASE WHEN v_column_source = 'line_item_catalog' THEN 'money' ELSE 'text' END),
      COALESCE(NULLIF(TRIM(p_aggregation), ''), CASE WHEN v_column_source = 'line_item_catalog' THEN 'sum' ELSE 'none' END),
      NULLIF(TRIM(COALESCE(p_format_hint, '')), ''),
      CASE WHEN p_order_index IS NULL OR p_order_index < 1 THEN 1 ELSE p_order_index END,
      CASE WHEN COALESCE(p_is_visible, 1) = 0 THEN 0 ELSE 1 END,
      CASE WHEN COALESCE(p_is_filterable, 1) = 0 THEN 0 ELSE 1 END,
      NULLIF(TRIM(COALESCE(p_filter_operator_default, '')), ''),
      NULL,
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    );

    SET v_col_id = LAST_INSERT_ID();
  ELSE
    UPDATE report_config_column
       SET column_key = v_column_key,
           column_source = v_column_source,
           source_field_key = CASE WHEN v_column_source = 'field' THEN TRIM(p_source_field_key) ELSE NULL END,
           id_line_item_catalog = CASE WHEN v_column_source = 'line_item_catalog' THEN p_id_line_item_catalog ELSE NULL END,
           display_name = COALESCE(NULLIF(TRIM(p_display_name), ''), display_name),
           display_category = NULLIF(TRIM(COALESCE(p_display_category, display_category, '')), ''),
           data_type = COALESCE(NULLIF(TRIM(p_data_type), ''), data_type),
           aggregation = COALESCE(NULLIF(TRIM(p_aggregation), ''), aggregation),
           format_hint = NULLIF(TRIM(COALESCE(p_format_hint, format_hint, '')), ''),
           order_index = CASE WHEN p_order_index IS NULL OR p_order_index < 1 THEN order_index ELSE p_order_index END,
           is_visible = CASE WHEN COALESCE(p_is_visible, is_visible) = 0 THEN 0 ELSE 1 END,
           is_filterable = CASE WHEN COALESCE(p_is_filterable, is_filterable) = 0 THEN 0 ELSE 1 END,
           filter_operator_default = NULLIF(TRIM(COALESCE(p_filter_operator_default, filter_operator_default, '')), ''),
           is_active = 1,
           deleted_at = NULL,
           updated_at = NOW()
     WHERE id_report_config_column = v_col_id;
  END IF;

  SELECT
    id_report_config_column,
    id_report_config,
    column_key,
    column_source,
    source_field_key,
    id_line_item_catalog,
    display_name,
    display_category,
    data_type,
    aggregation,
    format_hint,
    order_index,
    is_visible,
    is_filterable,
    filter_operator_default,
    legacy_role,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM report_config_column
  WHERE id_report_config_column = v_col_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_definition_data` (IN `p_company_code` VARCHAR(100), IN `p_id_report_config` BIGINT, IN `p_report_key` VARCHAR(64), IN `p_include_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_report_id BIGINT;
  DECLARE v_include_inactive TINYINT DEFAULT 0;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SET v_include_inactive = CASE WHEN COALESCE(p_include_inactive, 0) = 0 THEN 0 ELSE 1 END;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT
    rc.id_report_config,
    rc.id_company,
    rc.report_key,
    rc.report_name,
    rc.report_type,
    rc.line_item_type_scope,
    rc.description,
    rc.column_order,
    rc.is_active,
    rc.deleted_at,
    rc.created_at,
    rc.created_by,
    rc.updated_at
  FROM report_config rc
  WHERE rc.id_company = v_company_id
    AND (v_include_inactive = 1 OR (rc.is_active = 1 AND rc.deleted_at IS NULL))
  ORDER BY rc.report_name, rc.id_report_config;

  SET v_report_id = NULL;

  IF p_id_report_config IS NOT NULL AND p_id_report_config > 0 THEN
    SELECT rc.id_report_config
      INTO v_report_id
    FROM report_config rc
    WHERE rc.id_report_config = p_id_report_config
      AND rc.id_company = v_company_id
      AND (v_include_inactive = 1 OR (rc.is_active = 1 AND rc.deleted_at IS NULL))
    LIMIT 1;
  ELSEIF p_report_key IS NOT NULL AND TRIM(p_report_key) <> '' THEN
    SELECT rc.id_report_config
      INTO v_report_id
    FROM report_config rc
    WHERE rc.id_company = v_company_id
      AND rc.report_key = TRIM(p_report_key)
      AND (v_include_inactive = 1 OR (rc.is_active = 1 AND rc.deleted_at IS NULL))
    LIMIT 1;
  END IF;

  SELECT
    rc.id_report_config,
    rc.id_company,
    rc.report_key,
    rc.report_name,
    rc.report_type,
    rc.line_item_type_scope,
    rc.description,
    rc.column_order,
    rc.is_active,
    rc.deleted_at,
    rc.created_at,
    rc.created_by,
    rc.updated_at
  FROM report_config rc
  WHERE rc.id_report_config = v_report_id
  LIMIT 1;

  SELECT
    rcc.id_report_config_column,
    rcc.id_report_config,
    rcc.column_key,
    rcc.column_source,
    rcc.source_field_key,
    rcc.id_line_item_catalog,
    rcc.display_name,
    rcc.display_category,
    rcc.data_type,
    rcc.aggregation,
    rcc.format_hint,
    rcc.order_index,
    rcc.is_visible,
    rcc.is_filterable,
    rcc.filter_operator_default,
    rcc.legacy_role,
    rcc.is_active,
    rcc.deleted_at,
    rcc.created_at,
    rcc.created_by,
    rcc.updated_at
  FROM report_config_column rcc
  WHERE rcc.id_report_config = v_report_id
    AND (v_include_inactive = 1 OR (rcc.is_active = 1 AND rcc.deleted_at IS NULL))
  ORDER BY rcc.order_index, rcc.id_report_config_column;

  SELECT
    rcf.id_report_config_filter,
    rcf.id_report_config,
    rcf.filter_key,
    rcf.operator_key,
    rcf.value_text,
    rcf.value_from_text,
    rcf.value_to_text,
    rcf.value_list_text,
    rcf.logic_join,
    rcf.order_index,
    rcf.is_active,
    rcf.created_at,
    rcf.created_by,
    rcf.updated_at
  FROM report_config_filter rcf
  WHERE rcf.id_report_config = v_report_id
    AND (v_include_inactive = 1 OR rcf.is_active = 1)
  ORDER BY rcf.order_index, rcf.id_report_config_filter;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_definition_filter_upsert` (IN `p_action` VARCHAR(16), IN `p_id_report_config_filter` BIGINT, IN `p_id_report_config` BIGINT, IN `p_filter_key` VARCHAR(160), IN `p_operator_key` VARCHAR(32), IN `p_value_text` TEXT, IN `p_value_from_text` VARCHAR(255), IN `p_value_to_text` VARCHAR(255), IN `p_value_list_text` TEXT, IN `p_logic_join` VARCHAR(8), IN `p_order_index` INT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_filter_id BIGINT;
  DECLARE v_report_type VARCHAR(32);
  DECLARE v_operator VARCHAR(32);
  DECLARE v_logic VARCHAR(8);

  SET p_action = LOWER(TRIM(COALESCE(p_action, 'create')));
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_id_report_config IS NULL OR p_id_report_config <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'id_report_config is required';
  END IF;

  SELECT report_type
    INTO v_report_type
  FROM report_config
  WHERE id_report_config = p_id_report_config
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_report_type IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report not found';
  END IF;

  SET v_filter_id = NULL;
  IF p_id_report_config_filter IS NOT NULL AND p_id_report_config_filter > 0 THEN
    SELECT id_report_config_filter
      INTO v_filter_id
    FROM report_config_filter
    WHERE id_report_config_filter = p_id_report_config_filter
      AND id_report_config = p_id_report_config
    LIMIT 1;
  END IF;

  IF p_action = 'delete' THEN
    IF v_filter_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Filter not found';
    END IF;

    UPDATE report_config_filter
       SET is_active = 0,
           updated_at = NOW()
     WHERE id_report_config_filter = v_filter_id;

    SELECT
      id_report_config_filter,
      id_report_config,
      filter_key,
      operator_key,
      value_text,
      value_from_text,
      value_to_text,
      value_list_text,
      logic_join,
      order_index,
      is_active,
      created_at,
      created_by,
      updated_at
    FROM report_config_filter
    WHERE id_report_config_filter = v_filter_id;

    LEAVE proc;
  END IF;

  IF p_filter_key IS NULL OR TRIM(p_filter_key) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'filter_key is required';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM report_config_column rcc
    WHERE rcc.id_report_config = p_id_report_config
      AND rcc.column_key = TRIM(p_filter_key)
      AND rcc.is_active = 1
      AND rcc.deleted_at IS NULL
    LIMIT 1
  ) AND NOT EXISTS (
    SELECT 1
    FROM report_field_catalog rfc
    WHERE rfc.report_type = v_report_type
      AND rfc.field_key = TRIM(p_filter_key)
      AND rfc.is_active = 1
    LIMIT 1
  ) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'filter_key is not valid for report';
  END IF;

  SET v_operator = LOWER(TRIM(COALESCE(p_operator_key, 'eq')));
  IF v_operator NOT IN ('eq','neq','gt','gte','lt','lte','contains','between','is_null','is_not_null','in') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported operator_key';
  END IF;

  SET v_logic = UPPER(TRIM(COALESCE(p_logic_join, 'AND')));
  IF v_logic NOT IN ('AND','OR') THEN
    SET v_logic = 'AND';
  END IF;

  IF v_filter_id IS NULL OR v_filter_id = 0 THEN
    INSERT INTO report_config_filter (
      id_report_config,
      filter_key,
      operator_key,
      value_text,
      value_from_text,
      value_to_text,
      value_list_text,
      logic_join,
      order_index,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      p_id_report_config,
      TRIM(p_filter_key),
      v_operator,
      p_value_text,
      p_value_from_text,
      p_value_to_text,
      p_value_list_text,
      v_logic,
      CASE WHEN p_order_index IS NULL OR p_order_index < 1 THEN 1 ELSE p_order_index END,
      CASE WHEN COALESCE(p_is_active, 1) = 0 THEN 0 ELSE 1 END,
      NOW(),
      p_actor_user_id,
      NOW()
    );

    SET v_filter_id = LAST_INSERT_ID();
  ELSE
    UPDATE report_config_filter
       SET filter_key = TRIM(p_filter_key),
           operator_key = v_operator,
           value_text = p_value_text,
           value_from_text = p_value_from_text,
           value_to_text = p_value_to_text,
           value_list_text = p_value_list_text,
           logic_join = v_logic,
           order_index = CASE WHEN p_order_index IS NULL OR p_order_index < 1 THEN order_index ELSE p_order_index END,
           is_active = CASE WHEN COALESCE(p_is_active, is_active) = 0 THEN 0 ELSE 1 END,
           updated_at = NOW()
     WHERE id_report_config_filter = v_filter_id;
  END IF;

  SELECT
    id_report_config_filter,
    id_report_config,
    filter_key,
    operator_key,
    value_text,
    value_from_text,
    value_to_text,
    value_list_text,
    logic_join,
    order_index,
    is_active,
    created_at,
    created_by,
    updated_at
  FROM report_config_filter
  WHERE id_report_config_filter = v_filter_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_definition_run_data` (IN `p_company_code` VARCHAR(100), IN `p_id_report_config` BIGINT, IN `p_from` DATE, IN `p_to` DATE, IN `p_limit` INT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_report_type VARCHAR(32);
  DECLARE v_line_item_scope VARCHAR(32);
  DECLARE v_limit INT DEFAULT 500;
  DECLARE v_select_list LONGTEXT;
  DECLARE v_where_clause LONGTEXT;
  DECLARE v_having_clause LONGTEXT;
  DECLARE v_sql LONGTEXT;
  DECLARE v_from_filter TEXT DEFAULT '';
  DECLARE v_to_filter TEXT DEFAULT '';

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_id_report_config IS NULL OR p_id_report_config <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'id_report_config is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT rc.report_type, COALESCE(rc.line_item_type_scope, 'all')
    INTO v_report_type, v_line_item_scope
  FROM report_config rc
  WHERE rc.id_report_config = p_id_report_config
    AND rc.id_company = v_company_id
    AND rc.deleted_at IS NULL
    AND rc.is_active = 1
  LIMIT 1;

  IF v_report_type IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report not found or inactive';
  END IF;

  SET v_limit = CASE
    WHEN p_limit IS NULL OR p_limit < 1 THEN 500
    WHEN p_limit > 5000 THEN 5000
    ELSE p_limit
  END;

  IF p_from IS NOT NULL THEN
    SET v_from_filter = CONCAT(' AND COALESCE(li2.service_date, DATE(li2.created_at)) >= ''', DATE_FORMAT(p_from, '%Y-%m-%d'), '''');
  END IF;
  IF p_to IS NOT NULL THEN
    SET v_to_filter = CONCAT(' AND COALESCE(li2.service_date, DATE(li2.created_at)) <= ''', DATE_FORMAT(p_to, '%Y-%m-%d'), '''');
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_report_base;

  IF v_report_type = 'reservation' THEN
    CREATE TEMPORARY TABLE tmp_report_base AS
    SELECT
      r.id_reservation,
      r.id_guest,
      r.id_room,
      r.id_category,
      r.id_rateplan,
      r.code AS reservation_code,
      r.status AS reservation_status,
      r.source,
      r.channel_ref,
      r.check_in_date,
      r.check_out_date,
      r.nights,
      r.eta,
      r.etd,
      r.checkin_at,
      r.checkout_at,
      r.adults,
      r.children,
      r.infants,
      r.currency,
      r.deposit_due_cents,
      r.deposit_due_at,
      r.hold_until,
      r.cancel_reason,
      r.canceled_at,
      r.notes_guest,
      r.notes_internal,
      g.names AS guest_names,
      g.last_name AS guest_last_name,
      g.email AS guest_email,
      g.phone AS guest_phone,
      g.nationality AS guest_nationality,
      g.country_residence AS guest_country_residence,
      g.language AS guest_language,
      CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, '')) AS guest_full_name,
      rm.id_room AS room_id,
      rm.code AS room_code,
      rm.name AS room_name,
      rm.floor AS room_floor,
      rm.building AS room_building,
      rm.capacity_total AS room_capacity_total,
      rm.max_adults AS room_max_adults,
      rm.max_children AS room_max_children,
      rc.id_category AS category_id,
      rc.code AS category_code,
      rc.name AS category_name,
      rc.max_occupancy AS category_max_occupancy,
      p.id_property,
      p.code AS property_code,
      p.name AS property_name,
      p.city AS property_city,
      p.state AS property_state,
      p.country AS property_country,
      p.timezone AS property_timezone,
      p.currency AS property_currency,
      COALESCE(r.total_price_cents, 0) AS total_price_cents,
      COALESCE(r.balance_due_cents, 0) AS balance_due_cents,
      COALESCE(li_sum.charges_cents, 0) AS charges_cents,
      COALESCE(li_sum.taxes_cents, 0) AS taxes_cents,
      COALESCE(li_sum.payments_cents, 0) AS payments_cents,
      COALESCE(li_sum.obligations_cents, 0) AS obligations_cents,
      COALESCE(li_sum.incomes_cents, 0) AS incomes_cents,
      (
        COALESCE(li_sum.charges_cents, 0)
        + COALESCE(li_sum.taxes_cents, 0)
        + COALESCE(li_sum.obligations_cents, 0)
        - COALESCE(li_sum.payments_cents, 0)
        - COALESCE(li_sum.incomes_cents, 0)
      ) AS net_cents,
      r.created_at,
      COALESCE(r.check_in_date, DATE(r.created_at)) AS sort_date
    FROM reservation r
    JOIN property p
      ON p.id_property = r.id_property
     AND p.deleted_at IS NULL
     AND p.id_company = v_company_id
    LEFT JOIN room rm
      ON rm.id_room = r.id_room
    LEFT JOIN roomcategory rc
      ON rc.id_category = r.id_category
    LEFT JOIN guest g
      ON g.id_guest = r.id_guest
    LEFT JOIN (
      SELECT
        f.id_reservation,
        SUM(CASE WHEN li.item_type = 'sale_item' THEN li.amount_cents ELSE 0 END) AS charges_cents,
        SUM(CASE WHEN li.item_type = 'tax_item' THEN li.amount_cents ELSE 0 END) AS taxes_cents,
        SUM(CASE WHEN li.item_type = 'payment' THEN li.amount_cents ELSE 0 END) AS payments_cents,
        SUM(CASE WHEN li.item_type = 'obligation' THEN li.amount_cents ELSE 0 END) AS obligations_cents,
        SUM(CASE WHEN li.item_type = 'income' THEN li.amount_cents ELSE 0 END) AS incomes_cents
      FROM folio f
      JOIN line_item li
        ON li.id_folio = f.id_folio
       AND li.deleted_at IS NULL
       AND li.is_active = 1
      WHERE f.deleted_at IS NULL
      GROUP BY f.id_reservation
    ) li_sum
      ON li_sum.id_reservation = r.id_reservation
    WHERE r.deleted_at IS NULL
      AND (p_from IS NULL OR r.check_in_date >= p_from)
      AND (p_to IS NULL OR r.check_in_date <= p_to);

  ELSEIF v_report_type = 'line_item' THEN
    CREATE TEMPORARY TABLE tmp_report_base AS
    SELECT
      li.id_line_item,
      li.item_type,
      li.status AS line_item_status,
      li.reference AS line_item_reference,
      li.external_ref AS line_item_external_ref,
      li.method AS line_item_method,
      li.notes AS line_item_notes,
      COALESCE(li.service_date, DATE(li.created_at)) AS service_date,
      li.quantity,
      li.unit_price_cents,
      li.discount_amount_cents,
      li.amount_cents,
      li.paid_cents,
      li.currency,
      li.id_folio,
      li.id_line_item_catalog,
      lic.item_name AS catalog_name,
      cat.category_name AS subcategory_name,
      parent.category_name AS category_name,
      r.status AS reservation_status,
      r.source AS reservation_source,
      r.check_in_date,
      r.check_out_date,
      r.nights,
      r.adults,
      r.children,
      r.infants,
      r.id_guest,
      g.names AS guest_names,
      g.last_name AS guest_last_name,
      g.email AS guest_email,
      g.phone AS guest_phone,
      g.nationality AS guest_nationality,
      g.country_residence AS guest_country_residence,
      g.language AS guest_language,
      r.id_reservation,
      r.code AS reservation_code,
      p.id_property,
      p.code AS property_code,
      p.name AS property_name,
      p.city AS property_city,
      p.state AS property_state,
      p.country AS property_country,
      p.timezone AS property_timezone,
      p.currency AS property_currency,
      rm.id_room,
      rm.code AS room_code,
      rm.name AS room_name,
      rm.floor AS room_floor,
      rm.building AS room_building,
      rm.capacity_total AS room_capacity_total,
      rm.max_adults AS room_max_adults,
      rm.max_children AS room_max_children,
      rc.id_category,
      rc.code AS category_code,
      rc.name AS category_name_room,
      rc.max_occupancy AS category_max_occupancy,
      CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, '')) AS guest_full_name,
      li.created_at,
      COALESCE(li.service_date, DATE(li.created_at)) AS sort_date
    FROM line_item li
    JOIN folio f
      ON f.id_folio = li.id_folio
     AND f.deleted_at IS NULL
    JOIN reservation r
      ON r.id_reservation = f.id_reservation
     AND r.deleted_at IS NULL
    JOIN property p
      ON p.id_property = r.id_property
     AND p.deleted_at IS NULL
     AND p.id_company = v_company_id
    LEFT JOIN guest g
      ON g.id_guest = r.id_guest
    LEFT JOIN room rm
      ON rm.id_room = r.id_room
    LEFT JOIN roomcategory rc
      ON rc.id_category = r.id_category
    LEFT JOIN line_item_catalog lic
      ON lic.id_line_item_catalog = li.id_line_item_catalog
    LEFT JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
    LEFT JOIN sale_item_category parent
      ON parent.id_sale_item_category = cat.id_parent_sale_item_category
    WHERE li.deleted_at IS NULL
      AND li.is_active = 1
      AND (v_line_item_scope = 'all' OR li.item_type = v_line_item_scope)
      AND (p_from IS NULL OR COALESCE(li.service_date, DATE(li.created_at)) >= p_from)
      AND (p_to IS NULL OR COALESCE(li.service_date, DATE(li.created_at)) <= p_to);

  ELSE
    CREATE TEMPORARY TABLE tmp_report_base AS
    SELECT
      p.id_property,
      p.code AS property_code,
      p.name AS property_name,
      p.city AS property_city,
      p.state AS property_state,
      p.country AS property_country,
      p.timezone AS property_timezone,
      p.currency AS property_currency,
      COALESCE(r_sum.reservation_count, 0) AS reservation_count,
      COALESCE(r_sum.reservation_nights, 0) AS reservation_nights,
      COALESCE(r_sum.reservation_guests, 0) AS reservation_guests,
      COALESCE(r_sum.total_price_cents, 0) AS total_price_cents,
      COALESCE(r_sum.balance_due_cents, 0) AS balance_due_cents,
      COALESCE(li_sum.charges_cents, 0) AS charges_cents,
      COALESCE(li_sum.taxes_cents, 0) AS taxes_cents,
      COALESCE(li_sum.payments_cents, 0) AS payments_cents,
      COALESCE(li_sum.obligations_cents, 0) AS obligations_cents,
      COALESCE(li_sum.incomes_cents, 0) AS incomes_cents,
      (
        COALESCE(li_sum.charges_cents, 0)
        + COALESCE(li_sum.taxes_cents, 0)
        + COALESCE(li_sum.obligations_cents, 0)
        - COALESCE(li_sum.payments_cents, 0)
        - COALESCE(li_sum.incomes_cents, 0)
      ) AS net_cents,
      NOW() AS sort_date
    FROM property p
    LEFT JOIN (
      SELECT
        r.id_property,
        COUNT(*) AS reservation_count,
        SUM(COALESCE(r.nights, 0)) AS reservation_nights,
        SUM(COALESCE(r.adults, 0) + COALESCE(r.children, 0)) AS reservation_guests,
        SUM(COALESCE(r.total_price_cents, 0)) AS total_price_cents,
        SUM(COALESCE(r.balance_due_cents, 0)) AS balance_due_cents
      FROM reservation r
      WHERE r.deleted_at IS NULL
        AND (p_from IS NULL OR r.check_in_date >= p_from)
        AND (p_to IS NULL OR r.check_in_date <= p_to)
      GROUP BY r.id_property
    ) r_sum
      ON r_sum.id_property = p.id_property
    LEFT JOIN (
      SELECT
        r.id_property,
        SUM(CASE WHEN li.item_type = 'sale_item' THEN li.amount_cents ELSE 0 END) AS charges_cents,
        SUM(CASE WHEN li.item_type = 'tax_item' THEN li.amount_cents ELSE 0 END) AS taxes_cents,
        SUM(CASE WHEN li.item_type = 'payment' THEN li.amount_cents ELSE 0 END) AS payments_cents,
        SUM(CASE WHEN li.item_type = 'obligation' THEN li.amount_cents ELSE 0 END) AS obligations_cents,
        SUM(CASE WHEN li.item_type = 'income' THEN li.amount_cents ELSE 0 END) AS incomes_cents
      FROM reservation r
      JOIN folio f
        ON f.id_reservation = r.id_reservation
       AND f.deleted_at IS NULL
      JOIN line_item li
        ON li.id_folio = f.id_folio
       AND li.deleted_at IS NULL
       AND li.is_active = 1
      WHERE r.deleted_at IS NULL
        AND (p_from IS NULL OR COALESCE(li.service_date, DATE(li.created_at)) >= p_from)
        AND (p_to IS NULL OR COALESCE(li.service_date, DATE(li.created_at)) <= p_to)
      GROUP BY r.id_property
    ) li_sum
      ON li_sum.id_property = p.id_property
    WHERE p.deleted_at IS NULL
      AND p.id_company = v_company_id;
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_report_cols;
  CREATE TEMPORARY TABLE tmp_report_cols (
    id_report_config_column BIGINT,
    id_report_config BIGINT,
    column_key VARCHAR(160),
    column_source VARCHAR(32),
    source_field_key VARCHAR(120),
    id_line_item_catalog BIGINT,
    display_name VARCHAR(160),
    display_category VARCHAR(80),
    data_type VARCHAR(32),
    aggregation VARCHAR(32),
    format_hint VARCHAR(64),
    order_index INT,
    is_visible TINYINT,
    is_filterable TINYINT,
    filter_operator_default VARCHAR(32)
  ) ENGINE=MEMORY;

  INSERT INTO tmp_report_cols
  SELECT
    rcc.id_report_config_column,
    rcc.id_report_config,
    rcc.column_key,
    rcc.column_source,
    rcc.source_field_key,
    rcc.id_line_item_catalog,
    rcc.display_name,
    rcc.display_category,
    rcc.data_type,
    rcc.aggregation,
    rcc.format_hint,
    rcc.order_index,
    rcc.is_visible,
    rcc.is_filterable,
    rcc.filter_operator_default
  FROM report_config_column rcc
  WHERE rcc.id_report_config = p_id_report_config
    AND rcc.deleted_at IS NULL
    AND rcc.is_active = 1
  ORDER BY rcc.order_index, rcc.id_report_config_column;

  IF (SELECT COUNT(*) FROM tmp_report_cols) = 0 THEN
    INSERT INTO tmp_report_cols (
      id_report_config_column,
      id_report_config,
      column_key,
      column_source,
      source_field_key,
      id_line_item_catalog,
      display_name,
      display_category,
      data_type,
      aggregation,
      format_hint,
      order_index,
      is_visible,
      is_filterable,
      filter_operator_default
    )
    SELECT
      NULL,
      p_id_report_config,
      rfc.field_key,
      'field',
      rfc.field_key,
      NULL,
      rfc.field_label,
      rfc.field_group,
      rfc.data_type,
      'none',
      NULL,
      rfc.default_order,
      1,
      rfc.supports_filter,
      'eq'
    FROM report_field_catalog rfc
    WHERE rfc.report_type = v_report_type
      AND rfc.is_active = 1
      AND rfc.is_default = 1
    ORDER BY rfc.default_order, rfc.field_label;
  END IF;

  SET @prev_group_concat_max_len = @@SESSION.group_concat_max_len;
  SET SESSION group_concat_max_len = 1024 * 1024;

  SELECT GROUP_CONCAT(
    CASE
      WHEN c.column_source = 'field' THEN
        CONCAT('base.`', c.source_field_key, '` AS `', c.column_key, '`')
      WHEN c.column_source = 'line_item_catalog' THEN
        CASE
          WHEN v_report_type = 'line_item' THEN
            CASE LOWER(COALESCE(c.aggregation, 'sum_amount'))
              WHEN 'sum_quantity' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.quantity ELSE 0 END AS `', c.column_key, '`')
              WHEN 'avg_unit_price' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.unit_price_cents ELSE 0 END AS `', c.column_key, '`')
              WHEN 'sum_discount' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.discount_amount_cents ELSE 0 END AS `', c.column_key, '`')
              WHEN 'sum_paid' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.paid_cents ELSE 0 END AS `', c.column_key, '`')
              WHEN 'count_items' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN 1 ELSE 0 END AS `', c.column_key, '`')
              WHEN 'min_service_date' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.service_date ELSE NULL END AS `', c.column_key, '`')
              WHEN 'max_service_date' THEN
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.service_date ELSE NULL END AS `', c.column_key, '`')
              ELSE
                CONCAT('CASE WHEN base.id_line_item_catalog = ', c.id_line_item_catalog, ' THEN base.amount_cents ELSE 0 END AS `', c.column_key, '`')
            END
          WHEN v_report_type = 'reservation' THEN
            CASE LOWER(COALESCE(c.aggregation, 'sum_amount'))
              WHEN 'sum_quantity' THEN
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.quantity), 0) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'avg_unit_price' THEN
                CONCAT(
                  '(SELECT COALESCE(ROUND(AVG(li2.unit_price_cents)), 0) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'sum_discount' THEN
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.discount_amount_cents), 0) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'sum_paid' THEN
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.paid_cents), 0) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'count_items' THEN
                CONCAT(
                  '(SELECT COALESCE(COUNT(*), 0) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'min_service_date' THEN
                CONCAT(
                  '(SELECT MIN(COALESCE(li2.service_date, DATE(li2.created_at))) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'max_service_date' THEN
                CONCAT(
                  '(SELECT MAX(COALESCE(li2.service_date, DATE(li2.created_at))) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              ELSE
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.amount_cents), 0) ',
                  'FROM folio f2 ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE f2.deleted_at IS NULL ',
                  'AND f2.id_reservation = base.id_reservation ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
            END
          ELSE
            CASE LOWER(COALESCE(c.aggregation, 'sum_amount'))
              WHEN 'sum_quantity' THEN
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.quantity), 0) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'avg_unit_price' THEN
                CONCAT(
                  '(SELECT COALESCE(ROUND(AVG(li2.unit_price_cents)), 0) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'sum_discount' THEN
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.discount_amount_cents), 0) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'sum_paid' THEN
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.paid_cents), 0) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'count_items' THEN
                CONCAT(
                  '(SELECT COALESCE(COUNT(*), 0) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'min_service_date' THEN
                CONCAT(
                  '(SELECT MIN(COALESCE(li2.service_date, DATE(li2.created_at))) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              WHEN 'max_service_date' THEN
                CONCAT(
                  '(SELECT MAX(COALESCE(li2.service_date, DATE(li2.created_at))) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
              ELSE
                CONCAT(
                  '(SELECT COALESCE(SUM(li2.amount_cents), 0) ',
                  'FROM reservation r2 ',
                  'JOIN folio f2 ON f2.id_reservation = r2.id_reservation AND f2.deleted_at IS NULL ',
                  'JOIN line_item li2 ON li2.id_folio = f2.id_folio AND li2.deleted_at IS NULL AND li2.is_active = 1 ',
                  'WHERE r2.deleted_at IS NULL ',
                  'AND r2.id_property = base.id_property ',
                  'AND li2.id_line_item_catalog = ', c.id_line_item_catalog,
                  v_from_filter,
                  v_to_filter,
                  ') AS `', c.column_key, '`'
                )
            END
        END
      ELSE NULL
    END
    ORDER BY c.order_index, c.column_key SEPARATOR ', '
  ) INTO v_select_list
  FROM tmp_report_cols c
  WHERE c.is_visible = 1;

  IF v_select_list IS NULL OR v_select_list = '' THEN
    SET v_select_list = 'base.*';
  END IF;

  DROP TEMPORARY TABLE IF EXISTS tmp_report_filter_map;
  CREATE TEMPORARY TABLE tmp_report_filter_map AS
  SELECT
    rcf.id_report_config_filter,
    rcf.filter_key,
    rcf.operator_key,
    rcf.value_text,
    rcf.value_from_text,
    rcf.value_to_text,
    rcf.value_list_text,
    rcf.order_index,
    COALESCE(rcc.column_source, 'field') AS column_source,
    COALESCE(rcc.source_field_key, rcf.filter_key) AS source_field_key,
    COALESCE(rcc.column_key, rcf.filter_key) AS column_key
  FROM report_config_filter rcf
  LEFT JOIN report_config_column rcc
    ON rcc.id_report_config = rcf.id_report_config
   AND rcc.column_key = rcf.filter_key
   AND rcc.deleted_at IS NULL
   AND rcc.is_active = 1
  WHERE rcf.id_report_config = p_id_report_config
    AND rcf.is_active = 1;

  SELECT GROUP_CONCAT(filter_sql ORDER BY order_index SEPARATOR ' AND ')
    INTO v_where_clause
  FROM (
    SELECT
      tfm.order_index,
      CASE LOWER(COALESCE(tfm.operator_key, 'eq'))
        WHEN 'eq' THEN CONCAT('base.`', tfm.source_field_key, '` = ', QUOTE(COALESCE(tfm.value_text, '')))
        WHEN 'neq' THEN CONCAT('base.`', tfm.source_field_key, '` <> ', QUOTE(COALESCE(tfm.value_text, '')))
        WHEN 'gt' THEN CONCAT('base.`', tfm.source_field_key, '` > ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'gte' THEN CONCAT('base.`', tfm.source_field_key, '` >= ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'lt' THEN CONCAT('base.`', tfm.source_field_key, '` < ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'lte' THEN CONCAT('base.`', tfm.source_field_key, '` <= ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'contains' THEN CONCAT('base.`', tfm.source_field_key, '` LIKE ', QUOTE(CONCAT('%', COALESCE(tfm.value_text, ''), '%')))
        WHEN 'between' THEN CONCAT('base.`', tfm.source_field_key, '` BETWEEN ', QUOTE(COALESCE(tfm.value_from_text, '')), ' AND ', QUOTE(COALESCE(tfm.value_to_text, '')))
        WHEN 'is_null' THEN CONCAT('base.`', tfm.source_field_key, '` IS NULL')
        WHEN 'is_not_null' THEN CONCAT('base.`', tfm.source_field_key, '` IS NOT NULL')
        ELSE NULL
      END AS filter_sql
    FROM tmp_report_filter_map tfm
    WHERE tfm.column_source = 'field'
  ) q
  WHERE q.filter_sql IS NOT NULL AND q.filter_sql <> '';

  SELECT GROUP_CONCAT(filter_sql ORDER BY order_index SEPARATOR ' AND ')
    INTO v_having_clause
  FROM (
    SELECT
      tfm.order_index,
      CASE LOWER(COALESCE(tfm.operator_key, 'eq'))
        WHEN 'eq' THEN CONCAT('`', tfm.column_key, '` = ', QUOTE(COALESCE(tfm.value_text, '')))
        WHEN 'neq' THEN CONCAT('`', tfm.column_key, '` <> ', QUOTE(COALESCE(tfm.value_text, '')))
        WHEN 'gt' THEN CONCAT('`', tfm.column_key, '` > ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'gte' THEN CONCAT('`', tfm.column_key, '` >= ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'lt' THEN CONCAT('`', tfm.column_key, '` < ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'lte' THEN CONCAT('`', tfm.column_key, '` <= ', QUOTE(COALESCE(tfm.value_text, '0')))
        WHEN 'contains' THEN CONCAT('`', tfm.column_key, '` LIKE ', QUOTE(CONCAT('%', COALESCE(tfm.value_text, ''), '%')))
        WHEN 'between' THEN CONCAT('`', tfm.column_key, '` BETWEEN ', QUOTE(COALESCE(tfm.value_from_text, '')), ' AND ', QUOTE(COALESCE(tfm.value_to_text, '')))
        WHEN 'is_null' THEN CONCAT('`', tfm.column_key, '` IS NULL')
        WHEN 'is_not_null' THEN CONCAT('`', tfm.column_key, '` IS NOT NULL')
        ELSE NULL
      END AS filter_sql
    FROM tmp_report_filter_map tfm
    WHERE tfm.column_source = 'line_item_catalog'
  ) q
  WHERE q.filter_sql IS NOT NULL AND q.filter_sql <> '';

  SELECT
    rc.id_report_config,
    rc.report_key,
    rc.report_name,
    rc.report_type,
    rc.line_item_type_scope,
    rc.description,
    rc.is_active,
    rc.created_at,
    rc.updated_at
  FROM report_config rc
  WHERE rc.id_report_config = p_id_report_config
  LIMIT 1;

  SELECT
    c.id_report_config_column,
    c.id_report_config,
    c.column_key,
    c.column_source,
    c.source_field_key,
    c.id_line_item_catalog,
    c.display_name,
    c.display_category,
    c.data_type,
    c.aggregation,
    c.format_hint,
    c.order_index,
    c.is_visible,
    c.is_filterable,
    c.filter_operator_default
  FROM tmp_report_cols c
  ORDER BY c.order_index, c.column_key;

  SELECT
    rcf.id_report_config_filter,
    rcf.id_report_config,
    rcf.filter_key,
    rcf.operator_key,
    rcf.value_text,
    rcf.value_from_text,
    rcf.value_to_text,
    rcf.value_list_text,
    rcf.logic_join,
    rcf.order_index,
    rcf.is_active,
    rcf.created_at,
    rcf.created_by,
    rcf.updated_at
  FROM report_config_filter rcf
  WHERE rcf.id_report_config = p_id_report_config
    AND rcf.is_active = 1
  ORDER BY rcf.order_index, rcf.id_report_config_filter;

  SET v_sql = CONCAT('SELECT ', v_select_list, ' FROM tmp_report_base base');

  IF v_where_clause IS NOT NULL AND v_where_clause <> '' THEN
    SET v_sql = CONCAT(v_sql, ' WHERE ', v_where_clause);
  END IF;

  IF v_having_clause IS NOT NULL AND v_having_clause <> '' THEN
    SET v_sql = CONCAT(v_sql, ' HAVING ', v_having_clause);
  END IF;

  SET v_sql = CONCAT(v_sql, ' ORDER BY base.sort_date DESC LIMIT ', v_limit);

  PREPARE stmt_report_run FROM v_sql;
  EXECUTE stmt_report_run;
  DEALLOCATE PREPARE stmt_report_run;

  SET SESSION group_concat_max_len = @prev_group_concat_max_len;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_definition_upsert` (IN `p_action` VARCHAR(16), IN `p_company_code` VARCHAR(100), IN `p_id_report_config` BIGINT, IN `p_report_key` VARCHAR(64), IN `p_report_name` VARCHAR(160), IN `p_report_type` VARCHAR(32), IN `p_line_item_type_scope` VARCHAR(32), IN `p_description` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_report_id BIGINT;
  DECLARE v_report_key VARCHAR(64);
  DECLARE v_report_type VARCHAR(32);
  DECLARE v_line_item_scope VARCHAR(32);

  SET p_action = LOWER(TRIM(COALESCE(p_action, 'create')));
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_id_report_config IS NOT NULL AND p_id_report_config > 0 THEN
    SELECT id_report_config
      INTO v_report_id
    FROM report_config
    WHERE id_report_config = p_id_report_config
      AND id_company = v_company_id
    LIMIT 1;
  ELSEIF p_report_key IS NOT NULL AND TRIM(p_report_key) <> '' THEN
    SELECT id_report_config
      INTO v_report_id
    FROM report_config
    WHERE id_company = v_company_id
      AND report_key = TRIM(p_report_key)
    LIMIT 1;
  ELSE
    SET v_report_id = NULL;
  END IF;

  IF p_action = 'delete' THEN
    IF v_report_id IS NULL OR v_report_id = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report not found';
    END IF;

    UPDATE report_config
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_report_config = v_report_id;

    SELECT
      rc.id_report_config,
      rc.id_company,
      rc.report_key,
      rc.report_name,
      rc.report_type,
      rc.line_item_type_scope,
      rc.description,
      rc.column_order,
      rc.is_active,
      rc.deleted_at,
      rc.created_at,
      rc.created_by,
      rc.updated_at
    FROM report_config rc
    WHERE rc.id_report_config = v_report_id;

    LEAVE proc;
  END IF;

  IF p_report_name IS NULL OR TRIM(p_report_name) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Report name is required';
  END IF;

  SET v_report_type = LOWER(TRIM(COALESCE(p_report_type, 'reservation')));
  IF v_report_type NOT IN ('reservation','line_item','property') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported report_type';
  END IF;

  SET v_line_item_scope = NULL;
  IF v_report_type = 'line_item' THEN
    SET v_line_item_scope = LOWER(TRIM(COALESCE(p_line_item_type_scope, 'all')));
    IF v_line_item_scope NOT IN ('sale_item','tax_item','payment','obligation','income','all') THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported line_item_type_scope';
    END IF;
  END IF;

  SET v_report_key = LOWER(TRIM(COALESCE(p_report_key, '')));
  IF v_report_key = '' THEN
    SET v_report_key = LOWER(TRIM(p_report_name));
  END IF;

  SET v_report_key = REPLACE(v_report_key, ' ', '_');
  SET v_report_key = REPLACE(v_report_key, '-', '_');
  SET v_report_key = REPLACE(v_report_key, '/', '_');
  SET v_report_key = REPLACE(v_report_key, '.', '_');
  SET v_report_key = REPLACE(v_report_key, ',', '_');
  SET v_report_key = REPLACE(v_report_key, ':', '_');
  SET v_report_key = REPLACE(v_report_key, ';', '_');
  SET v_report_key = REPLACE(v_report_key, '(', '_');
  SET v_report_key = REPLACE(v_report_key, ')', '_');

  WHILE INSTR(v_report_key, '__') > 0 DO
    SET v_report_key = REPLACE(v_report_key, '__', '_');
  END WHILE;

  SET v_report_key = TRIM(BOTH '_' FROM v_report_key);
  IF v_report_key = '' THEN
    SET v_report_key = CONCAT('report_', UNIX_TIMESTAMP());
  END IF;

  IF v_report_id IS NULL OR v_report_id = 0 THEN
    IF EXISTS (
      SELECT 1
      FROM report_config rc
      WHERE rc.id_company = v_company_id
        AND rc.report_key = v_report_key
        AND rc.deleted_at IS NULL
      LIMIT 1
    ) THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'report_key already exists';
    END IF;

    INSERT INTO report_config (
      id_company,
      report_key,
      report_name,
      report_type,
      line_item_type_scope,
      description,
      column_order,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_company_id,
      v_report_key,
      TRIM(p_report_name),
      v_report_type,
      v_line_item_scope,
      p_description,
      NULL,
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    );

    SET v_report_id = LAST_INSERT_ID();
  ELSE
    IF EXISTS (
      SELECT 1
      FROM report_config rc
      WHERE rc.id_company = v_company_id
        AND rc.report_key = v_report_key
        AND rc.id_report_config <> v_report_id
        AND rc.deleted_at IS NULL
      LIMIT 1
    ) THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'report_key already exists';
    END IF;

    UPDATE report_config
       SET report_key = v_report_key,
           report_name = TRIM(p_report_name),
           report_type = v_report_type,
           line_item_type_scope = v_line_item_scope,
           description = p_description,
           is_active = 1,
           deleted_at = NULL,
           updated_at = NOW()
     WHERE id_report_config = v_report_id
       AND id_company = v_company_id;
  END IF;

  SELECT
    rc.id_report_config,
    rc.id_company,
    rc.report_key,
    rc.report_name,
    rc.report_type,
    rc.line_item_type_scope,
    rc.description,
    rc.column_order,
    rc.is_active,
    rc.deleted_at,
    rc.created_at,
    rc.created_by,
    rc.updated_at
  FROM report_config rc
  WHERE rc.id_report_config = v_report_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_report_field_catalog_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_report_type` VARCHAR(32))   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_report_type VARCHAR(32);

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SET v_report_type = LOWER(TRIM(COALESCE(p_report_type, 'reservation')));
  IF v_report_type NOT IN ('reservation','line_item','property') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported report_type';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND TRIM(p_property_code) <> '' THEN
    SELECT id_property
      INTO v_property_id
    FROM property
    WHERE code = TRIM(p_property_code)
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;

    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    rfc.id_report_field_catalog,
    rfc.report_type,
    rfc.field_group,
    rfc.field_key,
    rfc.field_label,
    rfc.data_type,
    rfc.supports_filter,
    rfc.supports_sort,
    rfc.is_default,
    rfc.default_order,
    rfc.select_expression,
    rfc.filter_expression
  FROM report_field_catalog rfc
  WHERE rfc.report_type = v_report_type
    AND rfc.is_active = 1
  ORDER BY rfc.field_group, rfc.default_order, rfc.field_label;

  SELECT
    lic.id_line_item_catalog,
    CONCAT('catalog_', lic.id_line_item_catalog) AS column_key,
    lic.item_name,
    lic.catalog_type,
    COALESCE(parent.category_name, '(sin categoria padre)') AS category_name,
    cat.category_name AS subcategory_name,
    cat.id_property AS category_property_id,
    COALESCE(prop.code, '') AS property_code,
    COALESCE(prop.name, 'Global') AS property_name,
    CONCAT(
      COALESCE(parent.category_name, '(sin categoria padre)'),
      ' / ',
      COALESCE(cat.category_name, '(sin subcategoria)')
    ) AS selection_group,
    CASE
      WHEN lic.catalog_type IN ('sale_item','tax_item','tax_rule','payment','obligation','income') THEN 1
      ELSE 0
    END AS is_supported
  FROM line_item_catalog lic
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.id_company = v_company_id
   AND cat.deleted_at IS NULL
  LEFT JOIN sale_item_category parent
    ON parent.id_sale_item_category = cat.id_parent_sale_item_category
   AND parent.deleted_at IS NULL
  LEFT JOIN property prop
    ON prop.id_property = cat.id_property
  WHERE lic.deleted_at IS NULL
    AND lic.is_active = 1
    AND (
      v_property_id IS NULL
      OR cat.id_property IS NULL
      OR cat.id_property = v_property_id
    )
  ORDER BY
    category_name,
    subcategory_name,
    lic.catalog_type,
    lic.item_name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_add_folio` (IN `p_company_code` VARCHAR(100), IN `p_reservation_id` BIGINT, IN `p_guest_id` BIGINT, IN `p_lodging_catalog_id` BIGINT, IN `p_total_cents_override` INT, IN `p_adults` INT, IN `p_children` INT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_nights INT DEFAULT 0;
  DECLARE v_base_cents INT DEFAULT 0;
  DECLARE v_total_cents INT DEFAULT 0;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_rate_breakdown TEXT;
  DECLARE v_use_rateplan TINYINT DEFAULT 0;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_folio_id BIGINT;
  DECLARE v_code VARCHAR(32);
  DECLARE v_lodging_catalog_id BIGINT;
  DECLARE v_unit_price INT DEFAULT 0;
  DECLARE v_discount INT DEFAULT 0;
  DECLARE v_existing_folios INT DEFAULT 0;
  DECLARE v_snapshot TEXT;
  DECLARE v_breakdown TEXT;
  DECLARE v_status VARCHAR(32);
  DECLARE v_in_tx TINYINT DEFAULT 0;
  DECLARE v_current_ota_account_id BIGINT DEFAULT NULL;
  DECLARE v_current_reservation_source_id BIGINT DEFAULT NULL;
  DECLARE v_detected_ota_account_id BIGINT DEFAULT NULL;
  DECLARE v_detected_ota_platform VARCHAR(32);
  DECLARE v_default_source_id BIGINT DEFAULT NULL;
  DECLARE v_default_source_name VARCHAR(120) DEFAULT 'Directo';
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  DECLARE EXIT HANDLER FOR SQLEXCEPTION
  BEGIN
    IF v_in_tx = 1 THEN
      ROLLBACK;
      SET v_in_tx = 0;
    END IF;
    RESIGNAL;
  END;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_reservation_id IS NULL OR p_reservation_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
  END IF;
  IF p_guest_id IS NULL OR p_guest_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Guest id is required';
  END IF;
  IF p_lodging_catalog_id IS NULL OR p_lodging_catalog_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Lodging catalog is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM guest WHERE id_guest = p_guest_id LIMIT 1) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Guest not found';
  END IF;

  SELECT
    r.status,
    r.id_property,
    r.id_room,
    r.id_category,
    r.check_in_date,
    r.check_out_date,
    r.currency,
    r.code,
    r.id_ota_account,
    r.id_reservation_source,
    p.code
    INTO
      v_status,
      v_id_property,
      v_id_room,
      v_id_category,
      v_check_in,
      v_check_out,
      v_currency,
      v_code,
      v_current_ota_account_id,
      v_current_reservation_source_id,
      v_property_code
  FROM reservation r
  JOIN property p ON p.id_property = r.id_property
  WHERE r.id_reservation = p_reservation_id
    AND r.deleted_at IS NULL
    AND p.id_company = v_company_id
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation not found';
  END IF;

  CALL sp_authz_assert(
    p_company_code,
    p_actor_user_id,
    'reservations.manage_folio',
    v_property_code,
    NULL
  );
  IF v_status NOT IN ('confirmado','encasa','en casa') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation is not confirmed';
  END IF;

  SELECT COUNT(*) INTO v_existing_folios
  FROM folio
  WHERE id_reservation = p_reservation_id
    AND deleted_at IS NULL;

  IF v_existing_folios > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation already has folios';
  END IF;

  SELECT pslc.id_sale_item_catalog
    INTO v_lodging_catalog_id
  FROM pms_settings_lodging_catalog pslc
  JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = pslc.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  WHERE pslc.id_company = v_company_id
    AND (pslc.id_property = v_id_property OR pslc.id_property IS NULL)
    AND pslc.id_sale_item_catalog = p_lodging_catalog_id
    AND pslc.deleted_at IS NULL
    AND pslc.is_active = 1
    AND sic.deleted_at IS NULL
    AND sic.is_active = 1
    AND cat.deleted_at IS NULL
    AND cat.is_active = 1
    AND cat.id_company = v_company_id
  LIMIT 1;

  IF v_lodging_catalog_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Lodging catalog not allowed for property';
  END IF;

  SELECT COALESCE(rc.default_base_price_cents,0), COALESCE(rm.id_rateplan, rc.id_rateplan)
    INTO v_base_cents, v_id_rateplan
  FROM room rm
  JOIN roomcategory rc ON rc.id_category = rm.id_category
  WHERE rm.id_room = v_id_room
  LIMIT 1;

  SET v_nights = DATEDIFF(v_check_out, v_check_in);
  IF v_nights <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'check_out must be after check_in';
  END IF;

  SET v_rate_breakdown = NULL;
  IF v_id_rateplan IS NOT NULL THEN
    CALL sp_rateplan_calc_total(
      v_id_property,
      v_id_rateplan,
      v_id_room,
      v_id_category,
      v_check_in,
      v_check_out,
      v_total_cents,
      v_base_cents,
      v_rate_breakdown
    );
    SET v_use_rateplan = 1;
  ELSE
    SET v_total_cents = v_base_cents * v_nights;
  END IF;
  IF p_total_cents_override IS NOT NULL AND p_total_cents_override > 0 THEN
    SET v_total_cents = p_total_cents_override;
  END IF;

  IF v_currency IS NULL OR v_currency = '' THEN
    SET v_currency = 'MXN';
  END IF;

  START TRANSACTION;
  SET v_in_tx = 1;

  IF p_total_cents_override IS NOT NULL AND p_total_cents_override > 0 THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"override_total"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(v_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(v_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  ELSEIF v_use_rateplan = 1 AND v_rate_breakdown IS NOT NULL AND v_rate_breakdown <> '' THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"rateplan",',
        '"rateplan_id":', v_id_rateplan,
      '}'
    );
    SET v_breakdown = v_rate_breakdown;
  ELSE
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"default_base_price_cents"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(v_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(v_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  END IF;

  UPDATE reservation
     SET id_guest = p_guest_id,
         adults = COALESCE(p_adults, adults),
         children = COALESCE(p_children, children),
         total_price_cents = v_total_cents,
         balance_due_cents = v_total_cents,
         rate_snapshot_json = v_snapshot,
         price_breakdown_json = v_breakdown,
         updated_at = NOW()
   WHERE id_reservation = p_reservation_id;

  INSERT INTO folio (
    id_reservation,
    folio_name,
    status,
    currency,
    total_cents,
    balance_cents,
    due_date,
    is_active,
    created_at,
    created_by,
    updated_at
  ) VALUES (
    p_reservation_id,
    'Principal',
    'open',
    v_currency,
    0,
    0,
    v_check_out,
    1,
    NOW(),
    p_actor_user_id,
    NOW()
  );
  SET v_folio_id = LAST_INSERT_ID();

  SET v_unit_price = CASE
    WHEN (p_total_cents_override IS NOT NULL AND p_total_cents_override > 0) OR v_use_rateplan = 1
      THEN CEILING(v_total_cents / v_nights)
    ELSE v_base_cents
  END;
  SET v_discount = CASE
    WHEN (p_total_cents_override IS NOT NULL AND p_total_cents_override > 0) OR v_use_rateplan = 1
      THEN (v_unit_price * v_nights) - v_total_cents
    ELSE 0
  END;

  CALL sp_sale_item_upsert(
    'create',
    0,
    v_folio_id,
    p_reservation_id,
    v_lodging_catalog_id,
    CONCAT('Reserva ', v_code),
    v_check_in,
    v_nights,
    v_unit_price,
    v_discount,
    'posted',
    p_actor_user_id
  );

  CALL sp_line_item_percent_derived_upsert(
    v_folio_id,
    p_reservation_id,
    v_lodging_catalog_id,
    v_check_in,
    p_actor_user_id
  );

  SET v_detected_ota_account_id = v_current_ota_account_id;
  SET v_detected_ota_platform = NULL;

  IF COALESCE(v_detected_ota_account_id, 0) > 0 THEN
    SELECT oa.platform
      INTO v_detected_ota_platform
    FROM ota_account oa
    WHERE oa.id_ota_account = v_detected_ota_account_id
      AND oa.id_company = v_company_id
      AND oa.deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF COALESCE(v_detected_ota_account_id, 0) <= 0 THEN
    SELECT oa.id_ota_account, oa.platform
      INTO v_detected_ota_account_id, v_detected_ota_platform
    FROM ota_account_lodging_catalog oalc
    JOIN ota_account oa
      ON oa.id_ota_account = oalc.id_ota_account
     AND oa.id_company = v_company_id
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
    WHERE oalc.id_line_item_catalog = v_lodging_catalog_id
      AND oalc.deleted_at IS NULL
      AND oalc.is_active = 1
    ORDER BY oalc.sort_order, oa.id_ota_account
    LIMIT 1;
  END IF;

  IF COALESCE(v_detected_ota_account_id, 0) > 0 THEN
    UPDATE reservation
       SET id_ota_account = v_detected_ota_account_id,
           id_reservation_source = NULL,
           source = CASE LOWER(TRIM(COALESCE(v_detected_ota_platform, '')))
             WHEN 'booking' THEN 'Booking'
             WHEN 'airbnb' THEN 'Airbnb'
             WHEN 'abb' THEN 'Airbnb'
             WHEN 'expedia' THEN 'Expedia'
             ELSE 'OTA'
           END,
           updated_at = NOW()
     WHERE id_reservation = p_reservation_id;
  ELSE
    SELECT rsc.id_reservation_source, rsc.source_name
      INTO v_default_source_id, v_default_source_name
    FROM reservation_source_catalog rsc
    WHERE rsc.id_company = v_company_id
      AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
      AND LOWER(TRIM(COALESCE(rsc.source_name, ''))) = 'directo'
      AND rsc.deleted_at IS NULL
      AND rsc.is_active = 1
    ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END
    LIMIT 1;

    IF v_default_source_id IS NULL OR v_default_source_id <= 0 THEN
      SET v_default_source_id = NULL;
      SET v_default_source_name = 'Directo';
    END IF;

    UPDATE reservation
       SET id_ota_account = NULL,
           id_reservation_source = COALESCE(id_reservation_source, v_default_source_id),
           source = COALESCE(NULLIF(TRIM(v_default_source_name), ''), source, 'Directo'),
           updated_at = NOW()
     WHERE id_reservation = p_reservation_id;
  END IF;

  COMMIT;
  SET v_in_tx = 0;

  SELECT
    r.*,
    g.email       AS guest_email,
    g.names       AS guest_names,
    g.last_name   AS guest_last_name,
    g.phone       AS guest_phone,
    rm.code       AS room_code,
    rm.name       AS room_name,
    rc.code       AS category_code,
    rc.name       AS category_name,
    pr.code       AS property_code,
    pr.name       AS property_name
  FROM reservation r
  JOIN property pr ON pr.id_property = r.id_property
  JOIN room rm ON rm.id_room = r.id_room
  JOIN roomcategory rc ON rc.id_category = r.id_category
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  WHERE r.id_reservation = p_reservation_id
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_confirm_hold` (IN `p_company_code` VARCHAR(100), IN `p_reservation_id` BIGINT, IN `p_guest_id` BIGINT, IN `p_lodging_catalog_id` BIGINT, IN `p_total_cents_override` INT, IN `p_adults` INT, IN `p_children` INT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_nights INT DEFAULT 0;
  DECLARE v_base_cents INT DEFAULT 0;
  DECLARE v_total_cents INT DEFAULT 0;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_rate_breakdown TEXT;
  DECLARE v_use_rateplan TINYINT DEFAULT 0;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_folio_id BIGINT;
  DECLARE v_code VARCHAR(32);
  DECLARE v_lodging_catalog_id BIGINT;
  DECLARE v_unit_price INT DEFAULT 0;
  DECLARE v_discount INT DEFAULT 0;
  DECLARE v_existing_folios INT DEFAULT 0;
  DECLARE v_snapshot TEXT;
  DECLARE v_breakdown TEXT;
  DECLARE v_status VARCHAR(32);
  DECLARE v_current_ota_account_id BIGINT DEFAULT NULL;
  DECLARE v_current_reservation_source_id BIGINT DEFAULT NULL;
  DECLARE v_detected_ota_account_id BIGINT DEFAULT NULL;
  DECLARE v_detected_ota_platform VARCHAR(32);
  DECLARE v_default_source_id BIGINT DEFAULT NULL;
  DECLARE v_default_source_name VARCHAR(120) DEFAULT 'Directo';
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_has_total_override TINYINT DEFAULT 0;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_reservation_id IS NULL OR p_reservation_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
  END IF;
  IF p_guest_id IS NULL OR p_guest_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Guest id is required';
  END IF;

  IF p_total_cents_override IS NOT NULL AND p_total_cents_override >= 0 THEN
    SET v_has_total_override = 1;
  END IF;

  IF p_lodging_catalog_id IS NULL OR p_lodging_catalog_id = 0 THEN
    IF NOT (v_has_total_override = 1 AND GREATEST(p_total_cents_override, 0) = 0) THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Lodging catalog is required';
    END IF;
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM guest WHERE id_guest = p_guest_id LIMIT 1) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Guest not found';
  END IF;

  SELECT
    r.status,
    r.id_property,
    r.id_room,
    r.id_category,
    r.check_in_date,
    r.check_out_date,
    r.currency,
    r.code,
    r.id_ota_account,
    r.id_reservation_source,
    p.code
    INTO
      v_status,
      v_id_property,
      v_id_room,
      v_id_category,
      v_check_in,
      v_check_out,
      v_currency,
      v_code,
      v_current_ota_account_id,
      v_current_reservation_source_id,
      v_property_code
  FROM reservation r
  JOIN property p ON p.id_property = r.id_property
  WHERE r.id_reservation = p_reservation_id
    AND r.deleted_at IS NULL
    AND p.id_company = v_company_id
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation not found';
  END IF;
  IF v_status <> 'apartado' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation is not apartado';
  END IF;

  CALL sp_authz_assert(
    p_company_code,
    p_actor_user_id,
    'reservations.status_change',
    v_property_code,
    NULL
  );

  SELECT COUNT(*) INTO v_existing_folios
  FROM folio
  WHERE id_reservation = p_reservation_id
    AND deleted_at IS NULL;

  IF v_existing_folios > 0 THEN
    SELECT f.id_folio
      INTO v_folio_id
    FROM folio f
    WHERE f.id_reservation = p_reservation_id
      AND f.deleted_at IS NULL
      AND (
        f.status IS NULL
        OR LOWER(TRIM(f.status)) NOT IN ('void', 'canceled', 'cancelled', 'deleted')
      )
      AND (
        LOWER(TRIM(COALESCE(f.folio_name, ''))) = ''
        OR LOWER(TRIM(COALESCE(f.folio_name, ''))) IN ('hospedaje', 'principal', 'main')
        OR (
          LOWER(TRIM(COALESCE(f.folio_name, ''))) LIKE '%hosped%'
          AND LOWER(TRIM(COALESCE(f.folio_name, ''))) NOT LIKE '%servicio%'
          AND LOWER(TRIM(COALESCE(f.folio_name, ''))) NOT LIKE '%service%'
        )
      )
    ORDER BY CASE
        WHEN LOWER(TRIM(COALESCE(f.folio_name, ''))) = 'hospedaje' THEN 0
        WHEN LOWER(TRIM(COALESCE(f.folio_name, ''))) IN ('principal', 'main') THEN 1
        WHEN LOWER(TRIM(COALESCE(f.folio_name, ''))) = '' THEN 2
        WHEN LOWER(TRIM(COALESCE(f.status, ''))) = 'open' THEN 3
        ELSE 4
      END,
      f.id_folio ASC
    LIMIT 1;
  END IF;

  IF p_lodging_catalog_id IS NOT NULL AND p_lodging_catalog_id > 0 THEN
    SELECT pslc.id_sale_item_catalog
      INTO v_lodging_catalog_id
    FROM pms_settings_lodging_catalog pslc
    JOIN line_item_catalog sic
      ON sic.id_line_item_catalog = pslc.id_sale_item_catalog
     AND sic.catalog_type = 'sale_item'
    JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
    WHERE pslc.id_company = v_company_id
      AND (pslc.id_property = v_id_property OR pslc.id_property IS NULL)
      AND pslc.id_sale_item_catalog = p_lodging_catalog_id
      AND pslc.deleted_at IS NULL
      AND pslc.is_active = 1
      AND sic.deleted_at IS NULL
      AND sic.is_active = 1
      AND cat.deleted_at IS NULL
      AND cat.is_active = 1
      AND cat.id_company = v_company_id
    LIMIT 1;

    IF v_lodging_catalog_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Lodging catalog not allowed for property';
    END IF;
  END IF;

  SELECT COALESCE(rc.default_base_price_cents,0), COALESCE(rm.id_rateplan, rc.id_rateplan)
    INTO v_base_cents, v_id_rateplan
  FROM room rm
  JOIN roomcategory rc ON rc.id_category = rm.id_category
  WHERE rm.id_room = v_id_room
  LIMIT 1;

  SET v_nights = DATEDIFF(v_check_out, v_check_in);
  IF v_nights <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'check_out must be after check_in';
  END IF;

  SET v_rate_breakdown = NULL;
  IF v_id_rateplan IS NOT NULL THEN
    CALL sp_rateplan_calc_total(
      v_id_property,
      v_id_rateplan,
      v_id_room,
      v_id_category,
      v_check_in,
      v_check_out,
      v_total_cents,
      v_base_cents,
      v_rate_breakdown
    );
    SET v_use_rateplan = 1;
  ELSE
    SET v_total_cents = v_base_cents * v_nights;
  END IF;
  IF v_has_total_override = 1 THEN
    SET v_total_cents = GREATEST(p_total_cents_override, 0);
  END IF;

  IF v_currency IS NULL OR v_currency = '' THEN
    SET v_currency = 'MXN';
  END IF;

  IF v_has_total_override = 1 THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"override_total"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(v_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(v_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  ELSEIF v_use_rateplan = 1 AND v_rate_breakdown IS NOT NULL AND v_rate_breakdown <> '' THEN
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"rateplan",',
        '"rateplan_id":', v_id_rateplan,
      '}'
    );
    SET v_breakdown = v_rate_breakdown;
  ELSE
    SET v_snapshot = CONCAT(
      '{',
        '"base_nightly_cents":', v_base_cents, ',',
        '"nights":', v_nights, ',',
        '"calc":"default_base_price_cents"',
      '}'
    );
    SET v_breakdown = CONCAT(
      '[{"date_range":["',
        DATE_FORMAT(v_check_in,'%Y-%m-%d'), '","', DATE_FORMAT(v_check_out,'%Y-%m-%d'),
        '"],"nightly_cents":', v_base_cents, ',"nights":', v_nights, ',"amount_cents":', v_total_cents, '}]'
    );
  END IF;

  UPDATE reservation
     SET id_guest = p_guest_id,
         status = 'confirmado',
         adults = COALESCE(p_adults, adults),
         children = COALESCE(p_children, children),
         total_price_cents = v_total_cents,
         balance_due_cents = v_total_cents,
         rate_snapshot_json = v_snapshot,
         price_breakdown_json = v_breakdown,
         updated_at = NOW()
   WHERE id_reservation = p_reservation_id;

  IF v_total_cents > 0 THEN
    IF COALESCE(v_folio_id, 0) <= 0 THEN
      INSERT INTO folio (
        id_reservation,
        folio_name,
        status,
        currency,
        total_cents,
        balance_cents,
        due_date,
        is_active,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        p_reservation_id,
        'Principal',
        'open',
        v_currency,
        v_total_cents,
        v_total_cents,
        v_check_out,
        1,
        NOW(),
        p_actor_user_id,
        NOW()
      );
      SET v_folio_id = LAST_INSERT_ID();
    ELSE
      UPDATE folio
         SET status = 'open',
             folio_name = CASE
               WHEN folio_name IS NULL
                 OR TRIM(folio_name) = ''
                 OR LOWER(TRIM(folio_name)) IN ('principal', 'main')
                 THEN 'Hospedaje'
               ELSE folio_name
             END,
             currency = COALESCE(NULLIF(v_currency, ''), currency),
             due_date = v_check_out,
             is_active = 1,
             updated_at = NOW()
       WHERE id_folio = v_folio_id;
    END IF;

    SET v_unit_price = CASE
      WHEN v_has_total_override = 1 OR v_use_rateplan = 1
        THEN CEILING(v_total_cents / v_nights)
      ELSE v_base_cents
    END;
    SET v_discount = CASE
      WHEN v_has_total_override = 1 OR v_use_rateplan = 1
        THEN (v_unit_price * v_nights) - v_total_cents
      ELSE 0
    END;

    CALL sp_sale_item_upsert(
      'create',
      0,
      v_folio_id,
      p_reservation_id,
      v_lodging_catalog_id,
      CONCAT('Reserva ', v_code),
      v_check_in,
      v_nights,
      v_unit_price,
      v_discount,
      'posted',
      p_actor_user_id
    );

    CALL sp_line_item_percent_derived_upsert(
      v_folio_id,
      p_reservation_id,
      v_lodging_catalog_id,
      v_check_in,
      p_actor_user_id
    );

    CALL sp_folio_recalc(v_folio_id);
  END IF;

  SET v_detected_ota_account_id = v_current_ota_account_id;
  SET v_detected_ota_platform = NULL;

  IF COALESCE(v_detected_ota_account_id, 0) > 0 THEN
    SELECT oa.platform
      INTO v_detected_ota_platform
    FROM ota_account oa
    WHERE oa.id_ota_account = v_detected_ota_account_id
      AND oa.id_company = v_company_id
      AND oa.deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF COALESCE(v_detected_ota_account_id, 0) <= 0 THEN
    SELECT oa.id_ota_account, oa.platform
      INTO v_detected_ota_account_id, v_detected_ota_platform
    FROM ota_account_lodging_catalog oalc
    JOIN ota_account oa
      ON oa.id_ota_account = oalc.id_ota_account
     AND oa.id_company = v_company_id
     AND oa.deleted_at IS NULL
     AND oa.is_active = 1
    WHERE oalc.id_line_item_catalog = v_lodging_catalog_id
      AND oalc.deleted_at IS NULL
      AND oalc.is_active = 1
    ORDER BY oalc.sort_order, oa.id_ota_account
    LIMIT 1;
  END IF;

  IF COALESCE(v_detected_ota_account_id, 0) > 0 THEN
    UPDATE reservation
       SET id_ota_account = v_detected_ota_account_id,
           id_reservation_source = NULL,
           source = CASE LOWER(TRIM(COALESCE(v_detected_ota_platform, '')))
             WHEN 'booking' THEN 'Booking'
             WHEN 'airbnb' THEN 'Airbnb'
             WHEN 'abb' THEN 'Airbnb'
             WHEN 'expedia' THEN 'Expedia'
             ELSE 'OTA'
           END,
           updated_at = NOW()
     WHERE id_reservation = p_reservation_id;
  ELSE
    SELECT rsc.id_reservation_source, rsc.source_name
      INTO v_default_source_id, v_default_source_name
    FROM reservation_source_catalog rsc
    WHERE rsc.id_company = v_company_id
      AND (rsc.id_property = v_id_property OR rsc.id_property IS NULL)
      AND LOWER(TRIM(COALESCE(rsc.source_name, ''))) = 'directo'
      AND rsc.deleted_at IS NULL
      AND rsc.is_active = 1
    ORDER BY CASE WHEN rsc.id_property = v_id_property THEN 0 ELSE 1 END
    LIMIT 1;

    IF v_default_source_id IS NULL OR v_default_source_id <= 0 THEN
      SET v_default_source_id = NULL;
      SET v_default_source_name = 'Directo';
    END IF;

    UPDATE reservation
       SET id_ota_account = NULL,
           id_reservation_source = COALESCE(id_reservation_source, v_default_source_id),
           source = COALESCE(NULLIF(TRIM(v_default_source_name), ''), source, 'Directo'),
           updated_at = NOW()
     WHERE id_reservation = p_reservation_id;
  END IF;

  SELECT
    r.*,
    g.email       AS guest_email,
    g.names       AS guest_names,
    g.last_name   AS guest_last_name,
    g.phone       AS guest_phone,
    rm.code       AS room_code,
    rm.name       AS room_name,
    rc.code       AS category_code,
    rc.name       AS category_name,
    pr.code       AS property_code,
    pr.name       AS property_name
  FROM reservation r
  LEFT JOIN guest g    ON g.id_guest     = r.id_guest
  JOIN room rm         ON rm.id_room     = r.id_room
  JOIN roomcategory rc ON rc.id_category = r.id_category
  JOIN property pr     ON pr.id_property = r.id_property
  WHERE r.id_reservation = p_reservation_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_message_send` (IN `p_company_code` VARCHAR(100), IN `p_reservation_id` BIGINT, IN `p_message_template_id` BIGINT, IN `p_sent_by` BIGINT, IN `p_sent_to_phone` VARCHAR(32), IN `p_message_title` VARCHAR(255), IN `p_message_body` TEXT, IN `p_channel` VARCHAR(32))   proc:BEGIN
  DECLARE v_id_company BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_id_template BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();
  DECLARE v_channel VARCHAR(32) DEFAULT 'whatsapp';
  DECLARE v_is_trackable TINYINT DEFAULT 0;
  DECLARE v_is_required TINYINT DEFAULT 0;
  DECLARE v_log_id BIGINT DEFAULT NULL;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_reservation_id IS NULL OR p_reservation_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
  END IF;
  IF p_message_template_id IS NULL OR p_message_template_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Template id is required';
  END IF;
  IF p_sent_by IS NULL OR p_sent_by <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Actor user id is required';
  END IF;
  IF p_message_title IS NULL OR TRIM(p_message_title) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Message title is required';
  END IF;
  IF p_message_body IS NULL OR TRIM(p_message_body) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Message body is required';
  END IF;

  SELECT id_company
    INTO v_id_company
  FROM company
  WHERE code = p_company_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_company IS NULL OR v_id_company <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SELECT r.id_property, p.code
    INTO v_id_property, v_property_code
  FROM reservation r
  JOIN property p
    ON p.id_property = r.id_property
   AND p.id_company = v_id_company
   AND p.deleted_at IS NULL
  WHERE r.id_reservation = p_reservation_id
    AND r.deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL OR v_id_property <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation not found';
  END IF;

  CALL sp_authz_assert(
    p_company_code,
    p_sent_by,
    'messages.send',
    v_property_code,
    NULL
  );

  SELECT
    mt.id_message_template,
    COALESCE(mt.is_trackable, 0),
    COALESCE(mt.is_required, 0),
    LOWER(TRIM(COALESCE(NULLIF(mt.channel, ''), 'whatsapp')))
    INTO
      v_id_template,
      v_is_trackable,
      v_is_required,
      v_channel
  FROM message_template mt
  WHERE mt.id_message_template = p_message_template_id
    AND mt.id_company = v_id_company
    AND mt.deleted_at IS NULL
    AND mt.is_active = 1
    AND (
      mt.id_property IS NULL
      OR mt.id_property = v_id_property
    )
  LIMIT 1;

  IF v_id_template IS NULL OR v_id_template <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Template not found for reservation';
  END IF;

  SET v_channel = LOWER(TRIM(COALESCE(NULLIF(p_channel, ''), v_channel, 'whatsapp')));
  IF v_channel <> 'manual' AND TRIM(COALESCE(p_sent_to_phone, '')) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Destination phone is required';
  END IF;

  INSERT INTO reservation_message_log (
    id_reservation,
    id_message_template,
    sent_at,
    sent_by,
    sent_to_phone,
    message_title,
    message_body,
    channel,
    created_at
  ) VALUES (
    p_reservation_id,
    p_message_template_id,
    v_now,
    p_sent_by,
    NULLIF(TRIM(COALESCE(p_sent_to_phone, '')), ''),
    TRIM(p_message_title),
    p_message_body,
    v_channel,
    v_now
  );

  SET v_log_id = LAST_INSERT_ID();

  IF v_is_trackable = 1 OR v_is_required = 1 THEN
    INSERT INTO reservation_message_status (
      id_reservation,
      id_message_template,
      tracking_status,
      is_trackable,
      is_required,
      last_sent_at,
      last_sent_by,
      last_channel,
      last_phone,
      last_message_title,
      last_message_body,
      last_id_reservation_message_log,
      created_at,
      created_by,
      updated_at,
      updated_by
    ) VALUES (
      p_reservation_id,
      p_message_template_id,
      'sent',
      v_is_trackable,
      v_is_required,
      v_now,
      p_sent_by,
      v_channel,
      NULLIF(TRIM(COALESCE(p_sent_to_phone, '')), ''),
      TRIM(p_message_title),
      p_message_body,
      v_log_id,
      v_now,
      p_sent_by,
      v_now,
      p_sent_by
    )
    ON DUPLICATE KEY UPDATE
      tracking_status = 'sent',
      is_trackable = VALUES(is_trackable),
      is_required = VALUES(is_required),
      last_sent_at = VALUES(last_sent_at),
      last_sent_by = VALUES(last_sent_by),
      last_channel = VALUES(last_channel),
      last_phone = VALUES(last_phone),
      last_message_title = VALUES(last_message_title),
      last_message_body = VALUES(last_message_body),
      last_id_reservation_message_log = VALUES(last_id_reservation_message_log),
      updated_at = VALUES(updated_at),
      updated_by = VALUES(updated_by);
  END IF;

  SELECT
    rml.id_reservation_message_log,
    rml.id_reservation,
    rml.id_message_template,
    rml.sent_at,
    rml.sent_by,
    rml.sent_to_phone,
    rml.message_title,
    rml.message_body,
    rml.channel
  FROM reservation_message_log rml
  WHERE rml.id_reservation_message_log = v_log_id
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_note_data` (IN `p_company_code` VARCHAR(100), IN `p_id_reservation` BIGINT, IN `p_note_type` VARCHAR(16), IN `p_show_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_reservation_id BIGINT;
  DECLARE v_note_type VARCHAR(16);

  IF p_id_reservation IS NULL OR p_id_reservation = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
  END IF;
  SET v_reservation_id = p_id_reservation;

  SET v_note_type = LOWER(TRIM(COALESCE(p_note_type,'')));
  IF v_note_type NOT IN ('internal','guest','system') THEN
    SET v_note_type = '';
  END IF;

  SELECT
    rn.id_reservation_note,
    rn.id_reservation,
    rn.note_type,
    rn.note_text,
    rn.is_active,
    rn.deleted_at,
    rn.created_at,
    rn.created_by,
    rn.updated_at
  FROM reservation_note rn
  WHERE rn.id_reservation = v_reservation_id
    AND (v_note_type = '' OR rn.note_type = v_note_type)
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR (rn.deleted_at IS NULL AND rn.is_active = 1)
    )
  ORDER BY rn.created_at DESC, rn.id_reservation_note DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_note_upsert` (IN `p_action` VARCHAR(16), IN `p_id_reservation_note` BIGINT, IN `p_id_reservation` BIGINT, IN `p_note_type` VARCHAR(16), IN `p_note_text` TEXT, IN `p_is_active` TINYINT, IN `p_company_code` VARCHAR(100), IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_reservation_id BIGINT;
  DECLARE v_note_id BIGINT;
  DECLARE v_note_type VARCHAR(16);

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_company_code IS NOT NULL AND p_company_code <> '' THEN
    SELECT id_company INTO v_company_id
    FROM company
    WHERE code = p_company_code
    LIMIT 1;
  END IF;

  SET v_note_type = LOWER(TRIM(COALESCE(p_note_type,'internal')));
  IF v_note_type NOT IN ('internal','guest','system') THEN
    SET v_note_type = 'internal';
  END IF;

  IF p_action = 'create' THEN
    IF p_id_reservation IS NULL OR p_id_reservation = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
    END IF;
    IF p_note_text IS NULL OR TRIM(p_note_text) = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Note text is required';
    END IF;

    IF v_company_id IS NOT NULL THEN
      SELECT r.id_reservation INTO v_reservation_id
      FROM reservation r
      JOIN property p ON p.id_property = r.id_property
      WHERE r.id_reservation = p_id_reservation
        AND r.deleted_at IS NULL
        AND p.id_company = v_company_id
        AND p.deleted_at IS NULL
      LIMIT 1;
    END IF;
    IF v_reservation_id IS NULL THEN
      SELECT r.id_reservation INTO v_reservation_id
      FROM reservation r
      WHERE r.id_reservation = p_id_reservation
        AND r.deleted_at IS NULL
      LIMIT 1;
    END IF;
    IF v_reservation_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation not found';
    END IF;

    INSERT INTO reservation_note (
      id_reservation,
      note_type,
      note_text,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_reservation_id,
      v_note_type,
      p_note_text,
      COALESCE(p_is_active,1),
      NOW(),
      p_actor_user_id,
      NOW()
    );

    SET v_note_id = LAST_INSERT_ID();
    SET v_reservation_id = p_id_reservation;
  ELSE
    IF p_id_reservation_note IS NULL OR p_id_reservation_note = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Note id is required';
    END IF;

    IF v_company_id IS NOT NULL THEN
      SELECT rn.id_reservation, rn.id_reservation_note
        INTO v_reservation_id, v_note_id
      FROM reservation_note rn
      JOIN reservation r ON r.id_reservation = rn.id_reservation
      JOIN property p ON p.id_property = r.id_property
      WHERE rn.id_reservation_note = p_id_reservation_note
        AND p.id_company = v_company_id
      LIMIT 1;
    END IF;
    IF v_note_id IS NULL THEN
      SELECT rn.id_reservation, rn.id_reservation_note
        INTO v_reservation_id, v_note_id
      FROM reservation_note rn
      WHERE rn.id_reservation_note = p_id_reservation_note
      LIMIT 1;
    END IF;

    IF v_note_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Note not found';
    END IF;

    IF p_action = 'delete' THEN
      UPDATE reservation_note
         SET is_active = 0,
             deleted_at = NOW(),
             updated_at = NOW()
       WHERE id_reservation_note = v_note_id;
    ELSE
      UPDATE reservation_note
         SET note_type = v_note_type,
             note_text = COALESCE(NULLIF(p_note_text,''), note_text),
             is_active = COALESCE(p_is_active, is_active),
             deleted_at = NULL,
             updated_at = NOW()
       WHERE id_reservation_note = v_note_id;
    END IF;
  END IF;

  SELECT
    rn.id_reservation_note,
    rn.id_reservation,
    rn.note_type,
    rn.note_text,
    rn.is_active,
    rn.deleted_at,
    rn.created_at,
    rn.created_by,
    rn.updated_at
  FROM reservation_note rn
  WHERE rn.id_reservation = v_reservation_id
  ORDER BY rn.created_at DESC, rn.id_reservation_note DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_totals_report` (IN `p_company_code` VARCHAR(100), IN `p_reservation_ids` TEXT)   BEGIN
  DECLARE v_company_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT
    r.id_reservation,
    COALESCE(charges.total, 0) AS charges_cents,
    COALESCE(taxes.total, 0) AS taxes_cents,
    COALESCE(payments.total, 0) AS payments_cents,
    COALESCE(obligations.total, 0) AS obligations_cents,
    COALESCE(incomes.total, 0) AS incomes_cents
  FROM reservation r
  JOIN property p ON p.id_property = r.id_property
  LEFT JOIN (
    SELECT f.id_reservation, COALESCE(SUM(li.amount_cents),0) AS total
    FROM folio f
    JOIN line_item li ON li.id_folio = f.id_folio
    WHERE li.item_type = 'sale_item'
      AND li.deleted_at IS NULL
      AND li.is_active = 1
    GROUP BY f.id_reservation
  ) charges ON charges.id_reservation = r.id_reservation
  LEFT JOIN (
    SELECT f.id_reservation, COALESCE(SUM(ti.amount_cents),0) AS total
    FROM line_item ti
    JOIN folio f ON f.id_folio = ti.id_folio
    WHERE ti.item_type = 'tax_item'
      AND ti.deleted_at IS NULL
      AND ti.is_active = 1
    GROUP BY f.id_reservation
  ) taxes ON taxes.id_reservation = r.id_reservation
  LEFT JOIN (
    SELECT f.id_reservation, COALESCE(SUM(li.amount_cents),0) AS total
    FROM line_item li
    JOIN folio f ON f.id_folio = li.id_folio
    WHERE li.item_type = 'payment'
      AND li.deleted_at IS NULL
      AND li.is_active = 1
    GROUP BY f.id_reservation
  ) payments ON payments.id_reservation = r.id_reservation
  LEFT JOIN (
    SELECT f.id_reservation, COALESCE(SUM(li.amount_cents),0) AS total
    FROM line_item li
    JOIN folio f ON f.id_folio = li.id_folio
    WHERE li.item_type = 'obligation'
      AND li.deleted_at IS NULL
      AND li.is_active = 1
    GROUP BY f.id_reservation
  ) obligations ON obligations.id_reservation = r.id_reservation
  LEFT JOIN (
    SELECT f.id_reservation, COALESCE(SUM(li.amount_cents),0) AS total
    FROM line_item li
    JOIN folio f ON f.id_folio = li.id_folio
    WHERE li.item_type = 'income'
      AND li.deleted_at IS NULL
      AND li.is_active = 1
    GROUP BY f.id_reservation
  ) incomes ON incomes.id_reservation = r.id_reservation
  WHERE p.id_company = v_company_id
    AND (p_reservation_ids IS NULL OR p_reservation_ids = '' OR FIND_IN_SET(r.id_reservation, p_reservation_ids));
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_update` (IN `p_company_code` VARCHAR(100), IN `p_reservation_id` BIGINT, IN `p_status` VARCHAR(32), IN `p_source` VARCHAR(120), IN `p_id_ota_account` BIGINT, IN `p_room_code` VARCHAR(64), IN `p_check_in_date` DATE, IN `p_check_out_date` DATE, IN `p_adults` INT, IN `p_children` INT, IN `p_notes_internal` TEXT, IN `p_notes_guest` TEXT, IN `p_actor_user_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_current_room BIGINT;
  DECLARE v_new_room BIGINT;
  DECLARE v_room_candidate BIGINT;
  DECLARE v_room_code_requested VARCHAR(64);
  DECLARE v_target_property_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_target_property BIGINT DEFAULT NULL;
  DECLARE v_property_for_source BIGINT DEFAULT NULL;
  DECLARE v_room_code_delimiter_pos INT DEFAULT 0;
  DECLARE v_new_category BIGINT;
  DECLARE v_overlap_cnt INT DEFAULT 0;
  DECLARE v_block_overlap_cnt INT DEFAULT 0;
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_status_input VARCHAR(32);
  DECLARE v_status_normalized VARCHAR(32);
  DECLARE v_skip_overlap TINYINT DEFAULT 0;
  DECLARE v_source_input VARCHAR(120);
  DECLARE v_source_name VARCHAR(120);
  DECLARE v_id_ota_account BIGINT DEFAULT NULL;
  DECLARE v_id_reservation_source BIGINT DEFAULT NULL;
  DECLARE v_ota_platform VARCHAR(32);
  DECLARE v_has_ota_update TINYINT DEFAULT 0;
  DECLARE v_has_source_update TINYINT DEFAULT 0;
  DECLARE v_current_source VARCHAR(120);
  DECLARE v_current_id_ota_account BIGINT DEFAULT NULL;
  DECLARE v_current_id_reservation_source BIGINT DEFAULT NULL;
  DECLARE v_current_id_guest BIGINT DEFAULT NULL;
  DECLARE v_has_guest TINYINT DEFAULT 0;
  DECLARE v_has_charges TINYINT DEFAULT 0;
  DECLARE v_is_incomplete TINYINT DEFAULT 0;
  DECLARE v_missing_requirements VARCHAR(64) DEFAULT '';
  DECLARE v_status_block_message VARCHAR(255) DEFAULT '';
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_total_balance_cents INT DEFAULT 0;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_reservation_id IS NULL OR p_reservation_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation id is required';
  END IF;

  SELECT id_company
    INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SELECT
    r.id_property,
    r.id_room,
    r.source,
    r.id_ota_account,
    r.id_reservation_source,
    r.id_guest
    INTO
      v_id_property,
      v_current_room,
      v_current_source,
      v_current_id_ota_account,
      v_current_id_reservation_source,
      v_current_id_guest
  FROM reservation r
  WHERE r.id_reservation = p_reservation_id
    AND r.deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation not found';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM property
    WHERE id_property = v_id_property
      AND id_company = v_company_id
      AND deleted_at IS NULL
  ) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Reservation does not belong to company';
  END IF;

  SELECT p.code
    INTO v_property_code
  FROM property p
  WHERE p.id_property = v_id_property
  LIMIT 1;

  CALL sp_authz_assert(
    p_company_code,
    p_actor_user_id,
    'reservations.edit',
    v_property_code,
    NULL
  );

  SET v_has_guest = CASE WHEN COALESCE(v_current_id_guest, 0) > 0 THEN 1 ELSE 0 END;

  SELECT CASE WHEN EXISTS (
    SELECT 1
    FROM folio f
    JOIN line_item li
      ON li.id_folio = f.id_folio
     AND li.deleted_at IS NULL
     AND COALESCE(li.is_active, 1) = 1
     AND li.item_type = 'sale_item'
     AND (
       li.status IS NULL
       OR LOWER(TRIM(li.status)) NOT IN ('void', 'canceled', 'cancelled')
      )
    WHERE f.id_reservation = p_reservation_id
      AND f.deleted_at IS NULL
      AND (
        f.status IS NULL
        OR LOWER(TRIM(f.status)) NOT IN ('void', 'canceled', 'cancelled', 'deleted')
      )
  ) THEN 1 ELSE 0 END
    INTO v_has_charges;

  SET v_is_incomplete = CASE
    WHEN v_has_guest = 1 AND v_has_charges = 1 THEN 0
    ELSE 1
  END;
  SET v_missing_requirements = '';
  IF v_has_guest = 0 THEN
    SET v_missing_requirements = 'huesped';
  END IF;
  IF v_has_charges = 0 THEN
    SET v_missing_requirements = CASE
      WHEN v_missing_requirements = '' THEN 'cargos'
      ELSE CONCAT(v_missing_requirements, ' y cargos')
    END;
  END IF;

  SET v_check_in = COALESCE(p_check_in_date, (
    SELECT check_in_date FROM reservation WHERE id_reservation = p_reservation_id
  ));
  SET v_check_out = COALESCE(p_check_out_date, (
    SELECT check_out_date FROM reservation WHERE id_reservation = p_reservation_id
  ));

  IF v_check_out <= v_check_in THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Check-out must be after check-in';
  END IF;

  SET v_status_input = NULLIF(TRIM(p_status), '');
  SET v_status_normalized = LOWER(COALESCE(v_status_input, ''));
  IF v_status_normalized IN ('cancelled','canceled','cancelado','cancelada') THEN
    SET v_status_input = 'cancelada';
    SET v_skip_overlap = 1;
  ELSEIF v_status_normalized IN ('no show','noshow','no_show') THEN
    SET v_status_input = 'no-show';
    SET v_skip_overlap = 1;
  ELSEIF v_status_normalized IN ('checkout', 'check out', 'check-out') THEN
    SET v_status_input = 'salida';
  END IF;

  IF v_is_incomplete = 1 THEN
    IF v_status_input IS NOT NULL
       AND LOWER(TRIM(v_status_input)) NOT IN ('apartado', 'cancelada') THEN
      SET v_status_block_message = CASE
        WHEN v_missing_requirements = '' THEN 'La reservacion necesita huesped y cargos para cambiar estatus'
        ELSE CONCAT('La reservacion necesita ', v_missing_requirements, ' para cambiar estatus')
      END;
      SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = v_status_block_message;
    END IF;
    IF v_status_input IS NULL OR LOWER(TRIM(v_status_input)) <> 'cancelada' THEN
      SET v_status_input = 'apartado';
    END IF;
  END IF;

  IF v_status_input IS NOT NULL AND LOWER(TRIM(v_status_input)) = 'salida' THEN
    SELECT COALESCE(SUM(COALESCE(f.balance_cents, 0)), 0)
      INTO v_total_balance_cents
    FROM folio f
    WHERE f.id_reservation = p_reservation_id
      AND f.deleted_at IS NULL
      AND (
        f.status IS NULL
        OR LOWER(TRIM(f.status)) NOT IN ('void', 'canceled', 'cancelled', 'deleted')
      );

    IF v_total_balance_cents < 0 THEN
      SET v_total_balance_cents = 0;
    END IF;

    IF v_total_balance_cents <= 0 THEN
      SELECT GREATEST(COALESCE(r.balance_due_cents, 0), 0)
        INTO v_total_balance_cents
      FROM reservation r
      WHERE r.id_reservation = p_reservation_id
      LIMIT 1;
    END IF;

    IF COALESCE(v_total_balance_cents, 0) > 0 THEN
      SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'La reservacion tiene balance pendiente; no se puede pasar a check-out';
    END IF;
  END IF;

  SET v_room_code_requested = NULLIF(TRIM(p_room_code), '');
  SET v_target_property_code = NULL;
  SET v_target_property = v_id_property;
  IF v_room_code_requested IS NOT NULL THEN
    SET v_room_code_requested = UPPER(v_room_code_requested);
    SET v_room_code_delimiter_pos = LOCATE('|', v_room_code_requested);
    IF v_room_code_delimiter_pos > 0 THEN
      SET v_target_property_code = TRIM(SUBSTRING(v_room_code_requested, 1, v_room_code_delimiter_pos - 1));
      SET v_room_code_requested = TRIM(SUBSTRING(v_room_code_requested, v_room_code_delimiter_pos + 1));
      IF v_target_property_code = '' OR v_room_code_requested = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid room target format';
      END IF;
    END IF;
    IF v_target_property_code IS NOT NULL AND v_target_property_code <> '' THEN
      SELECT p.id_property
        INTO v_target_property
      FROM property p
      WHERE p.code = v_target_property_code
        AND p.id_company = v_company_id
        AND p.deleted_at IS NULL
      LIMIT 1;

      IF v_target_property IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code for company';
      END IF;
    END IF;
  END IF;
  SET v_property_for_source = COALESCE(v_target_property, v_id_property);

  SET v_source_input = NULLIF(TRIM(COALESCE(p_source, '')), '');
  SET v_source_name = NULL;
  SET v_has_source_update = 0;
  SET v_id_reservation_source = v_current_id_reservation_source;
  IF p_source IS NOT NULL THEN
    SET v_has_source_update = 1;
  END IF;

  SET v_has_ota_update = 0;
  SET v_id_ota_account = NULL;
  SET v_ota_platform = NULL;
  IF p_id_ota_account IS NOT NULL THEN
    SET v_has_ota_update = 1;
    IF p_id_ota_account > 0 THEN
      SELECT oa.id_ota_account, oa.platform
        INTO v_id_ota_account, v_ota_platform
      FROM ota_account oa
      WHERE oa.id_ota_account = p_id_ota_account
        AND oa.id_company = v_company_id
        AND oa.deleted_at IS NULL
        AND oa.is_active = 1
      LIMIT 1;

      IF v_id_ota_account IS NULL OR v_id_ota_account <= 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'invalid ota account for company';
      END IF;

      SET v_ota_platform = LOWER(TRIM(COALESCE(v_ota_platform, 'other')));
      SET v_source_name = CASE
        WHEN v_ota_platform = 'booking' THEN 'Booking'
        WHEN v_ota_platform = 'airbnb' OR v_ota_platform = 'abb' THEN 'Airbnb'
        WHEN v_ota_platform = 'expedia' THEN 'Expedia'
        ELSE 'OTA'
      END;
      SET v_has_source_update = 1;
      SET v_id_reservation_source = NULL;
    ELSE
      SET v_id_ota_account = NULL;
      SET v_has_source_update = 1;
    END IF;
  END IF;

  IF v_has_source_update = 1 AND COALESCE(v_id_ota_account, 0) <= 0 THEN
    IF v_source_input IS NOT NULL AND v_source_input REGEXP '^[0-9]+$' THEN
      SELECT rsc.id_reservation_source, rsc.source_name
        INTO v_id_reservation_source, v_source_name
      FROM reservation_source_catalog rsc
      WHERE rsc.id_reservation_source = CAST(v_source_input AS UNSIGNED)
        AND rsc.id_company = v_company_id
        AND (rsc.id_property = v_property_for_source OR rsc.id_property IS NULL)
        AND rsc.deleted_at IS NULL
        AND rsc.is_active = 1
      ORDER BY CASE WHEN rsc.id_property = v_property_for_source THEN 0 ELSE 1 END
      LIMIT 1;
    ELSE
      SET v_source_name = CASE LOWER(TRIM(COALESCE(v_source_input, '')))
        WHEN 'booking' THEN 'Booking'
        WHEN 'airbnb' THEN 'Airbnb'
        WHEN 'abb' THEN 'Airbnb'
        WHEN 'expedia' THEN 'Expedia'
        WHEN 'otro' THEN 'Directo'
        ELSE NULLIF(TRIM(COALESCE(v_source_input, '')), '')
      END;
      IF v_source_name IS NOT NULL THEN
        SELECT rsc.id_reservation_source, rsc.source_name
          INTO v_id_reservation_source, v_source_name
        FROM reservation_source_catalog rsc
        WHERE rsc.id_company = v_company_id
          AND (rsc.id_property = v_property_for_source OR rsc.id_property IS NULL)
          AND TRIM(COALESCE(rsc.source_name, '')) COLLATE utf8mb4_unicode_ci
              = TRIM(v_source_name) COLLATE utf8mb4_unicode_ci
          AND rsc.deleted_at IS NULL
          AND rsc.is_active = 1
        ORDER BY CASE WHEN rsc.id_property = v_property_for_source THEN 0 ELSE 1 END
        LIMIT 1;
      END IF;
    END IF;

    IF v_id_reservation_source IS NULL OR v_id_reservation_source <= 0 THEN
      IF v_source_input IS NOT NULL
         AND TRIM(v_source_input) <> ''
         AND LOWER(TRIM(v_source_input)) NOT IN ('directo','otro') THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown reservation source. Create it first in Settings';
      END IF;

      SELECT rsc.id_reservation_source, rsc.source_name
        INTO v_id_reservation_source, v_source_name
      FROM reservation_source_catalog rsc
      WHERE rsc.id_company = v_company_id
        AND (rsc.id_property = v_property_for_source OR rsc.id_property IS NULL)
        AND LOWER(TRIM(COALESCE(rsc.source_name, ''))) = 'directo'
        AND rsc.deleted_at IS NULL
        AND rsc.is_active = 1
      ORDER BY CASE WHEN rsc.id_property = v_property_for_source THEN 0 ELSE 1 END
      LIMIT 1;

      IF v_id_reservation_source IS NULL OR v_id_reservation_source <= 0 THEN
        SET v_id_reservation_source = v_current_id_reservation_source;
        SET v_source_name = COALESCE(NULLIF(TRIM(v_current_source), ''), 'Directo');
        IF v_source_input IS NOT NULL
           AND TRIM(v_source_input) <> ''
           AND LOWER(TRIM(v_source_input)) IN ('directo','otro') THEN
          SET v_source_name = 'Directo';
        END IF;
      END IF;
    END IF;
  END IF;

  SET v_new_room = NULL;
  SET v_new_category = NULL;

  IF v_room_code_requested IS NOT NULL THEN
    SELECT rm.id_room, rm.id_category
      INTO v_new_room, v_new_category
    FROM room rm
    WHERE rm.code = v_room_code_requested
      AND rm.id_property = v_target_property
      AND rm.deleted_at IS NULL
    LIMIT 1;

    IF v_new_room IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown room code for that property';
    END IF;
  END IF;

  SET v_room_candidate = COALESCE(v_new_room, v_current_room);

  IF v_room_candidate IS NOT NULL AND v_skip_overlap = 0 THEN
  SELECT COUNT(*) INTO v_overlap_cnt
  FROM reservation
  WHERE id_room = v_room_candidate
    AND id_reservation <> p_reservation_id
    AND (deleted_at IS NULL)
    AND (is_active IS NULL OR is_active = 1)
    AND COALESCE(status, 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
    AND NOT (check_out_date <= v_check_in OR check_in_date >= v_check_out);

    IF v_overlap_cnt > 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room not available for requested dates';
    END IF;

    SELECT COUNT(*) INTO v_block_overlap_cnt
    FROM room_block
    WHERE id_room = v_room_candidate
      AND deleted_at IS NULL
      AND is_active = 1
      AND start_date < v_check_out
      AND end_date > v_check_in;

    IF v_block_overlap_cnt > 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room is blocked for requested dates';
    END IF;
  END IF;

  UPDATE reservation
  SET
    status = COALESCE(v_status_input, status),
    source = CASE
      WHEN v_has_source_update = 1 THEN COALESCE(v_source_name, source)
      ELSE source
    END,
    id_ota_account = CASE
      WHEN v_has_ota_update = 1 THEN v_id_ota_account
      WHEN v_has_source_update = 1 AND COALESCE(v_id_reservation_source, 0) > 0 THEN NULL
      ELSE id_ota_account
    END,
    id_reservation_source = CASE
      WHEN v_has_ota_update = 1 AND COALESCE(v_id_ota_account, 0) > 0 THEN NULL
      WHEN v_has_source_update = 1 THEN v_id_reservation_source
      ELSE id_reservation_source
    END,
    id_property = CASE
      WHEN v_new_room IS NOT NULL THEN COALESCE(v_target_property, id_property)
      ELSE id_property
    END,
    id_room = COALESCE(v_room_candidate, id_room),
    id_category = COALESCE(v_new_category, id_category),
    check_in_date = v_check_in,
    check_out_date = v_check_out,
    adults = COALESCE(p_adults, adults),
    children = COALESCE(p_children, children),
    notes_internal = COALESCE(NULLIF(p_notes_internal, ''), notes_internal),
    notes_guest = COALESCE(NULLIF(p_notes_guest, ''), notes_guest),
    updated_at = NOW()
  WHERE id_reservation = p_reservation_id;

  IF v_status_input = 'cancelada' THEN
    DROP TEMPORARY TABLE IF EXISTS tmp_cancel_folios;
    CREATE TEMPORARY TABLE tmp_cancel_folios (
      id_folio BIGINT PRIMARY KEY
    );
    INSERT IGNORE INTO tmp_cancel_folios (id_folio)
    SELECT id_folio
    FROM folio
    WHERE id_reservation = p_reservation_id
      AND deleted_at IS NULL;

    DROP TEMPORARY TABLE IF EXISTS tmp_cancel_sale_items;
    CREATE TEMPORARY TABLE tmp_cancel_sale_items (
      id_sale_item BIGINT PRIMARY KEY
    );
    INSERT IGNORE INTO tmp_cancel_sale_items (id_sale_item)
    SELECT id_line_item
    FROM line_item
    WHERE item_type = 'sale_item'
      AND id_folio IN (SELECT id_folio FROM tmp_cancel_folios)
      AND deleted_at IS NULL;

    /* Anular folios */
    UPDATE folio
       SET is_active = 0,
           status = 'void',
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_folio IN (SELECT id_folio FROM tmp_cancel_folios)
       AND deleted_at IS NULL;

    /* Desactivar cargos, pagos y conceptos relacionados del folio */
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_folio IN (SELECT id_folio FROM tmp_cancel_folios)
       AND item_type IN ('sale_item','tax_item','payment','obligation','income')
       AND deleted_at IS NULL;
  END IF;

  SELECT
    r.id_reservation,
    r.code AS reservation_code,
    r.status,
    r.check_in_date,
    r.check_out_date,
    r.adults,
    r.children,
    r.notes_internal,
    r.notes_guest
  FROM reservation r
  WHERE r.id_reservation = p_reservation_id
    AND r.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_reservation_update_v2` (IN `p_company_code` VARCHAR(100), IN `p_reservation_id` BIGINT, IN `p_status` VARCHAR(32), IN `p_source` VARCHAR(120), IN `p_id_ota_account` BIGINT, IN `p_room_code` VARCHAR(64), IN `p_check_in_date` DATE, IN `p_check_out_date` DATE, IN `p_adults` INT, IN `p_children` INT, IN `p_reservation_code` VARCHAR(100), IN `p_notes_internal` TEXT, IN `p_notes_guest` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  CALL sp_reservation_update(
    p_company_code,
    p_reservation_id,
    p_status,
    p_source,
    p_id_ota_account,
    p_room_code,
    p_check_in_date,
    p_check_out_date,
    p_adults,
    p_children,
    p_notes_internal,
    p_notes_guest,
    p_actor_user_id
  );

  IF p_reservation_code IS NOT NULL AND TRIM(p_reservation_code) <> '' THEN
    SELECT id_company
      INTO v_company_id
    FROM company
    WHERE code = p_company_code
    LIMIT 1;

    SELECT p.code
      INTO v_property_code
    FROM reservation r
    JOIN property p
      ON p.id_property = r.id_property
    WHERE r.id_reservation = p_reservation_id
      AND r.deleted_at IS NULL
      AND p.id_company = v_company_id
    LIMIT 1;

    CALL sp_authz_assert(
      p_company_code,
      p_actor_user_id,
      'reservations.edit',
      v_property_code,
      NULL
    );

    UPDATE reservation r
    JOIN property p ON p.id_property = r.id_property
       SET r.code = UPPER(TRIM(p_reservation_code)),
           r.updated_at = NOW()
     WHERE r.id_reservation = p_reservation_id
       AND p.id_company = v_company_id
       AND r.deleted_at IS NULL;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_role_permission_sync` (IN `p_company_code` VARCHAR(100), IN `p_id_role` BIGINT, IN `p_permission_codes_csv` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_role_property_id BIGINT;
  DECLARE v_role_company_id BIGINT;
  DECLARE v_codes_csv TEXT;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_id_role IS NULL OR p_id_role <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Role id is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
    AND c.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SELECT r.id_property,
         pr.id_company
    INTO v_role_property_id,
         v_role_company_id
  FROM role r
  LEFT JOIN property pr
    ON pr.id_property = r.id_property
  WHERE r.id_role = p_id_role
    AND r.deleted_at IS NULL
  LIMIT 1;

  IF v_role_property_id IS NOT NULL AND v_role_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Role does not belong to company';
  END IF;

  SET v_codes_csv = REPLACE(TRIM(COALESCE(p_permission_codes_csv, '')), ' ', '');

  DELETE FROM role_permission
  WHERE id_role = p_id_role;

  IF v_codes_csv IS NOT NULL AND v_codes_csv <> '' THEN
    INSERT INTO role_permission (
      id_role,
      id_permission,
      allow,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      p_id_role,
      p.id_permission,
      1,
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM permission p
    WHERE p.deleted_at IS NULL
      AND p.is_active = 1
      AND FIND_IN_SET(p.code, v_codes_csv) > 0;
  END IF;

  SELECT
    rp.id_role_permission,
    rp.id_role,
    p.id_permission,
    p.code AS permission_code
  FROM role_permission rp
  JOIN permission p
    ON p.id_permission = rp.id_permission
  WHERE rp.id_role = p_id_role
    AND rp.deleted_at IS NULL
    AND rp.is_active = 1
  ORDER BY p.code;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_role_upsert` (IN `p_company_code` VARCHAR(100), IN `p_id_role` BIGINT, IN `p_property_code` VARCHAR(100), IN `p_name` VARCHAR(120), IN `p_description` TEXT, IN `p_is_system` TINYINT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT DEFAULT NULL;
  DECLARE v_role_property_id BIGINT DEFAULT NULL;
  DECLARE v_role_company_id BIGINT DEFAULT NULL;
  DECLARE v_property_code VARCHAR(100);

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Role name is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
    AND c.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SET v_property_code = NULLIF(TRIM(COALESCE(p_property_code, '')), '');
  IF v_property_code IS NOT NULL THEN
    SELECT pr.id_property
      INTO v_property_id
    FROM property pr
    WHERE pr.code = v_property_code
      AND pr.id_company = v_company_id
      AND pr.deleted_at IS NULL
    LIMIT 1;

    IF v_property_id IS NULL OR v_property_id <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code for company';
    END IF;
  END IF;

  IF p_id_role IS NULL OR p_id_role <= 0 THEN
    INSERT INTO role (
      id_property,
      name,
      description,
      is_system,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_property_id,
      TRIM(p_name),
      p_description,
      COALESCE(p_is_system, 0),
      COALESCE(p_is_active, 1),
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET p_id_role = LAST_INSERT_ID();
  ELSE
    SELECT r.id_property,
           pr.id_company
      INTO v_role_property_id,
           v_role_company_id
    FROM role r
    LEFT JOIN property pr
      ON pr.id_property = r.id_property
    WHERE r.id_role = p_id_role
      AND r.deleted_at IS NULL
    LIMIT 1;

    IF v_role_property_id IS NOT NULL AND v_role_company_id <> v_company_id THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Role does not belong to company';
    END IF;

    UPDATE role
       SET id_property = v_property_id,
           name = TRIM(p_name),
           description = p_description,
           is_system = COALESCE(p_is_system, is_system),
           is_active = COALESCE(p_is_active, is_active),
           updated_at = NOW()
     WHERE id_role = p_id_role;
  END IF;

  SELECT
    r.id_role,
    r.name,
    r.description,
    r.id_property,
    pr.code AS property_code,
    r.is_system,
    r.is_active
  FROM role r
  LEFT JOIN property pr
    ON pr.id_property = r.id_property
  WHERE r.id_role = p_id_role
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_roomcategory_upsert` (IN `p_property_code` VARCHAR(100), IN `p_category_code` VARCHAR(100), IN `p_name` VARCHAR(255), IN `p_description` TEXT, IN `p_base_occupancy` INT, IN `p_max_occupancy` INT, IN `p_order_index` INT, IN `p_default_base_price_cents` INT, IN `p_min_price_cents` INT, IN `p_image_url` VARCHAR(255), IN `p_rateplan_code` VARCHAR(100), IN `p_color_hex` VARCHAR(16), IN `p_has_air_conditioning` TINYINT, IN `p_has_fan` TINYINT, IN `p_has_tv` TINYINT, IN `p_has_private_wifi` TINYINT, IN `p_has_minibar` TINYINT, IN `p_has_safe_box` TINYINT, IN `p_has_workspace` TINYINT, IN `p_includes_bedding_towels` TINYINT, IN `p_has_iron_board` TINYINT, IN `p_has_closet_rack` TINYINT, IN `p_has_private_balcony_terrace` TINYINT, IN `p_has_view` TINYINT, IN `p_has_private_entrance` TINYINT, IN `p_has_hot_water` TINYINT, IN `p_includes_toiletries` TINYINT, IN `p_has_hairdryer` TINYINT, IN `p_includes_clean_towels` TINYINT, IN `p_has_coffee_tea_kettle` TINYINT, IN `p_has_basic_utensils` TINYINT, IN `p_has_basic_food_items` TINYINT, IN `p_is_private` TINYINT, IN `p_is_shared` TINYINT, IN `p_has_shared_bathroom` TINYINT, IN `p_has_private_bathroom` TINYINT, IN `p_amenities_is_active` TINYINT, IN `p_calendar_display_amenities_csv` TEXT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT, IN `p_id_category` BIGINT)   BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_id_category_amenities BIGINT;
  DECLARE v_now DATETIME DEFAULT NOW();
  DECLARE v_calendar_display_csv TEXT;
  DECLARE v_calendar_display_item VARCHAR(64);
  DECLARE v_calendar_display_pos INT DEFAULT 0;
  DECLARE v_calendar_display_order INT DEFAULT 0;
  DECLARE v_calendar_display_allowed TINYINT DEFAULT 0;

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_category_code IS NULL OR p_category_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category code is required';
  END IF;
  IF p_name IS NULL OR p_name = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category name is required';
  END IF;

  SELECT id_property
    INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  IF p_rateplan_code IS NOT NULL AND p_rateplan_code <> '' THEN
    SELECT id_rateplan
      INTO v_id_rateplan
    FROM rateplan
    WHERE id_property = v_id_property
      AND code = p_rateplan_code
      AND deleted_at IS NULL
    LIMIT 1;

    IF v_id_rateplan IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown rate plan code for property';
    END IF;
  ELSE
    SET v_id_rateplan = NULL;
  END IF;

  IF p_id_category IS NOT NULL AND p_id_category > 0 THEN
    SELECT id_category
      INTO v_id_category
    FROM roomcategory
    WHERE id_category = p_id_category
      AND id_property = v_id_property
      AND deleted_at IS NULL
    LIMIT 1;
  ELSE
    SELECT id_category
      INTO v_id_category
    FROM roomcategory
    WHERE id_property = v_id_property
      AND code = p_category_code
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF v_id_category IS NULL THEN
    INSERT INTO roomcategory (
      id_property,
      id_rateplan,
      code,
      name,
      description,
      base_occupancy,
      max_occupancy,
      order_index,
      default_base_price_cents,
      min_price_cents,
      image_url,
      color_hex,
      is_active,
      created_at,
      updated_at,
      created_by
    ) VALUES (
      v_id_property,
      v_id_rateplan,
      p_category_code,
      p_name,
      NULLIF(p_description, ''),
      p_base_occupancy,
      p_max_occupancy,
      COALESCE(p_order_index, 0),
      NULLIF(p_default_base_price_cents, 0),
      NULLIF(p_min_price_cents, 0),
      NULLIF(p_image_url, ''),
      NULLIF(p_color_hex, ''),
      COALESCE(p_is_active, 1),
      v_now,
      v_now,
      p_actor_user_id
    );
    SET v_id_category = LAST_INSERT_ID();
  ELSE
    UPDATE roomcategory
    SET
      code = p_category_code,
      id_rateplan = v_id_rateplan,
      name = p_name,
      description = NULLIF(p_description, ''),
      base_occupancy = p_base_occupancy,
      max_occupancy = p_max_occupancy,
      order_index = COALESCE(p_order_index, order_index),
      default_base_price_cents = NULLIF(p_default_base_price_cents, 0),
      min_price_cents = NULLIF(p_min_price_cents, 0),
      image_url = NULLIF(p_image_url, ''),
      color_hex = COALESCE(NULLIF(p_color_hex, ''), color_hex),
      is_active = COALESCE(p_is_active, is_active),
      updated_at = v_now
    WHERE id_category = v_id_category;
  END IF;

  /* Upsert category amenities */
  SELECT id_category_amenities
    INTO v_id_category_amenities
  FROM category_amenities
  WHERE id_category = v_id_category
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_category_amenities IS NULL THEN
    INSERT INTO category_amenities (
      id_category,
      has_air_conditioning,
      has_fan,
      has_tv,
      has_private_wifi,
      has_minibar,
      has_safe_box,
      has_workspace,
      includes_bedding_towels,
      has_iron_board,
      has_closet_rack,
      has_private_balcony_terrace,
      has_view,
      has_private_entrance,
      has_hot_water,
      includes_toiletries,
      has_hairdryer,
      includes_clean_towels,
      has_coffee_tea_kettle,
      has_basic_utensils,
      has_basic_food_items,
      is_private,
      is_shared,
      has_shared_bathroom,
      has_private_bathroom,
      is_active,
      created_by,
      created_at,
      updated_at
    ) VALUES (
      v_id_category,
      COALESCE(p_has_air_conditioning, 0),
      COALESCE(p_has_fan, 0),
      COALESCE(p_has_tv, 0),
      COALESCE(p_has_private_wifi, 0),
      COALESCE(p_has_minibar, 0),
      COALESCE(p_has_safe_box, 0),
      COALESCE(p_has_workspace, 0),
      COALESCE(p_includes_bedding_towels, 0),
      COALESCE(p_has_iron_board, 0),
      COALESCE(p_has_closet_rack, 0),
      COALESCE(p_has_private_balcony_terrace, 0),
      COALESCE(p_has_view, 0),
      COALESCE(p_has_private_entrance, 0),
      COALESCE(p_has_hot_water, 0),
      COALESCE(p_includes_toiletries, 0),
      COALESCE(p_has_hairdryer, 0),
      COALESCE(p_includes_clean_towels, 0),
      COALESCE(p_has_coffee_tea_kettle, 0),
      COALESCE(p_has_basic_utensils, 0),
      COALESCE(p_has_basic_food_items, 0),
      COALESCE(p_is_private, 0),
      COALESCE(p_is_shared, 0),
      COALESCE(p_has_shared_bathroom, 0),
      COALESCE(p_has_private_bathroom, 0),
      COALESCE(p_amenities_is_active, 1),
      p_actor_user_id,
      v_now,
      v_now
    );
  ELSE
    UPDATE category_amenities
    SET
      has_air_conditioning = COALESCE(p_has_air_conditioning, has_air_conditioning),
      has_fan = COALESCE(p_has_fan, has_fan),
      has_tv = COALESCE(p_has_tv, has_tv),
      has_private_wifi = COALESCE(p_has_private_wifi, has_private_wifi),
      has_minibar = COALESCE(p_has_minibar, has_minibar),
      has_safe_box = COALESCE(p_has_safe_box, has_safe_box),
      has_workspace = COALESCE(p_has_workspace, has_workspace),
      includes_bedding_towels = COALESCE(p_includes_bedding_towels, includes_bedding_towels),
      has_iron_board = COALESCE(p_has_iron_board, has_iron_board),
      has_closet_rack = COALESCE(p_has_closet_rack, has_closet_rack),
      has_private_balcony_terrace = COALESCE(p_has_private_balcony_terrace, has_private_balcony_terrace),
      has_view = COALESCE(p_has_view, has_view),
      has_private_entrance = COALESCE(p_has_private_entrance, has_private_entrance),
      has_hot_water = COALESCE(p_has_hot_water, has_hot_water),
      includes_toiletries = COALESCE(p_includes_toiletries, includes_toiletries),
      has_hairdryer = COALESCE(p_has_hairdryer, has_hairdryer),
      includes_clean_towels = COALESCE(p_includes_clean_towels, includes_clean_towels),
      has_coffee_tea_kettle = COALESCE(p_has_coffee_tea_kettle, has_coffee_tea_kettle),
      has_basic_utensils = COALESCE(p_has_basic_utensils, has_basic_utensils),
      has_basic_food_items = COALESCE(p_has_basic_food_items, has_basic_food_items),
      is_private = COALESCE(p_is_private, is_private),
      is_shared = COALESCE(p_is_shared, is_shared),
      has_shared_bathroom = COALESCE(p_has_shared_bathroom, has_shared_bathroom),
      has_private_bathroom = COALESCE(p_has_private_bathroom, has_private_bathroom),
      is_active = COALESCE(p_amenities_is_active, is_active),
      updated_at = v_now,
      created_by = COALESCE(created_by, p_actor_user_id)
    WHERE id_category = v_id_category;
  END IF;

  /* Upsert amenity icons to display in calendar (selection among checked amenities) */
  IF EXISTS (
    SELECT 1
    FROM information_schema.TABLES
    WHERE TABLE_SCHEMA = DATABASE()
      AND TABLE_NAME = 'category_calendar_amenity_display'
  ) THEN
    DELETE FROM category_calendar_amenity_display
    WHERE id_category = v_id_category;

    SET v_calendar_display_csv = TRIM(COALESCE(p_calendar_display_amenities_csv, ''));
    SET v_calendar_display_order = 0;

    calendar_display_loop:WHILE v_calendar_display_csv <> '' DO
      SET v_calendar_display_pos = LOCATE(',', v_calendar_display_csv);
      IF v_calendar_display_pos > 0 THEN
        SET v_calendar_display_item = TRIM(SUBSTRING(v_calendar_display_csv, 1, v_calendar_display_pos - 1));
        SET v_calendar_display_csv = TRIM(SUBSTRING(v_calendar_display_csv, v_calendar_display_pos + 1));
      ELSE
        SET v_calendar_display_item = TRIM(v_calendar_display_csv);
        SET v_calendar_display_csv = '';
      END IF;

      SET v_calendar_display_allowed = 0;
      CASE v_calendar_display_item
        WHEN 'has_air_conditioning' THEN SET v_calendar_display_allowed = COALESCE(p_has_air_conditioning, 0);
        WHEN 'has_fan' THEN SET v_calendar_display_allowed = COALESCE(p_has_fan, 0);
        WHEN 'has_tv' THEN SET v_calendar_display_allowed = COALESCE(p_has_tv, 0);
        WHEN 'has_private_wifi' THEN SET v_calendar_display_allowed = COALESCE(p_has_private_wifi, 0);
        WHEN 'has_minibar' THEN SET v_calendar_display_allowed = COALESCE(p_has_minibar, 0);
        WHEN 'has_safe_box' THEN SET v_calendar_display_allowed = COALESCE(p_has_safe_box, 0);
        WHEN 'has_workspace' THEN SET v_calendar_display_allowed = COALESCE(p_has_workspace, 0);
        WHEN 'includes_bedding_towels' THEN SET v_calendar_display_allowed = COALESCE(p_includes_bedding_towels, 0);
        WHEN 'has_iron_board' THEN SET v_calendar_display_allowed = COALESCE(p_has_iron_board, 0);
        WHEN 'has_closet_rack' THEN SET v_calendar_display_allowed = COALESCE(p_has_closet_rack, 0);
        WHEN 'has_private_balcony_terrace' THEN SET v_calendar_display_allowed = COALESCE(p_has_private_balcony_terrace, 0);
        WHEN 'has_view' THEN SET v_calendar_display_allowed = COALESCE(p_has_view, 0);
        WHEN 'has_private_entrance' THEN SET v_calendar_display_allowed = COALESCE(p_has_private_entrance, 0);
        WHEN 'has_hot_water' THEN SET v_calendar_display_allowed = COALESCE(p_has_hot_water, 0);
        WHEN 'includes_toiletries' THEN SET v_calendar_display_allowed = COALESCE(p_includes_toiletries, 0);
        WHEN 'has_hairdryer' THEN SET v_calendar_display_allowed = COALESCE(p_has_hairdryer, 0);
        WHEN 'includes_clean_towels' THEN SET v_calendar_display_allowed = COALESCE(p_includes_clean_towels, 0);
        WHEN 'has_coffee_tea_kettle' THEN SET v_calendar_display_allowed = COALESCE(p_has_coffee_tea_kettle, 0);
        WHEN 'has_basic_utensils' THEN SET v_calendar_display_allowed = COALESCE(p_has_basic_utensils, 0);
        WHEN 'has_basic_food_items' THEN SET v_calendar_display_allowed = COALESCE(p_has_basic_food_items, 0);
        WHEN 'is_private' THEN SET v_calendar_display_allowed = COALESCE(p_is_private, 0);
        WHEN 'is_shared' THEN SET v_calendar_display_allowed = COALESCE(p_is_shared, 0);
        WHEN 'has_shared_bathroom' THEN SET v_calendar_display_allowed = COALESCE(p_has_shared_bathroom, 0);
        WHEN 'has_private_bathroom' THEN SET v_calendar_display_allowed = COALESCE(p_has_private_bathroom, 0);
      END CASE;

      IF v_calendar_display_item IN (
        'has_air_conditioning',
        'has_fan',
        'has_tv',
        'has_private_wifi',
        'has_minibar',
        'has_safe_box',
        'has_workspace',
        'includes_bedding_towels',
        'has_iron_board',
        'has_closet_rack',
        'has_private_balcony_terrace',
        'has_view',
        'has_private_entrance',
        'has_hot_water',
        'includes_toiletries',
        'has_hairdryer',
        'includes_clean_towels',
        'has_coffee_tea_kettle',
        'has_basic_utensils',
        'has_basic_food_items',
        'is_private',
        'is_shared',
        'has_shared_bathroom',
        'has_private_bathroom'
      ) AND v_calendar_display_allowed = 1 THEN
        INSERT IGNORE INTO category_calendar_amenity_display (
          id_category,
          amenity_key,
          display_order,
          is_active,
          created_by,
          created_at,
          updated_at
        ) VALUES (
          v_id_category,
          v_calendar_display_item,
          v_calendar_display_order,
          1,
          p_actor_user_id,
          v_now,
          v_now
        );
        SET v_calendar_display_order = v_calendar_display_order + 1;
      END IF;
    END WHILE calendar_display_loop;
  END IF;

  SELECT
    rc.id_category,
    rc.id_property,
    rc.id_rateplan,
    rc.code AS category_code,
    rc.name AS category_name,
    rc.description,
    rc.base_occupancy,
    rc.max_occupancy,
    rc.order_index,
    rc.default_base_price_cents,
    rc.min_price_cents,
    rc.image_url,
    rc.color_hex,
    rc.is_active
  FROM roomcategory rc
  WHERE rc.id_category = v_id_category
    AND rc.deleted_at IS NULL
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_room_upsert` (IN `p_property_code` VARCHAR(100), IN `p_room_code` VARCHAR(100), IN `p_category_code` VARCHAR(100), IN `p_rateplan_code` VARCHAR(100), IN `p_name` VARCHAR(255), IN `p_description` TEXT, IN `p_capacity_total` INT, IN `p_max_adults` INT, IN `p_max_children` INT, IN `p_status` VARCHAR(32), IN `p_housekeeping_status` VARCHAR(32), IN `p_floor` VARCHAR(64), IN `p_building` VARCHAR(120), IN `p_bed_config` VARCHAR(255), IN `p_color_hex` VARCHAR(16), IN `p_order_index` INT, IN `p_is_active` TINYINT, IN `p_id_room` BIGINT)   proc:BEGIN
  DECLARE v_id_property BIGINT;
  DECLARE v_id_room BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_id_rateplan BIGINT;
  DECLARE v_update_category TINYINT DEFAULT 0;
  DECLARE v_update_rateplan TINYINT DEFAULT 0;
  DECLARE v_category_code_trim VARCHAR(100);
  DECLARE v_rateplan_code_trim VARCHAR(100);

  IF p_property_code IS NULL OR p_property_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Property code is required';
  END IF;
  IF p_room_code IS NULL OR p_room_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room code is required';
  END IF;

  SELECT id_property INTO v_id_property
  FROM property
  WHERE code = p_property_code
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  /* Normalize optional category parameter */
  IF p_category_code IS NOT NULL THEN
    SET v_update_category = 1;
    SET v_category_code_trim = TRIM(p_category_code);
    IF v_category_code_trim = '' THEN
      SET v_id_category = NULL;
    ELSE
      SELECT id_category INTO v_id_category
      FROM roomcategory
      WHERE id_property = v_id_property
        AND code = v_category_code_trim
        AND deleted_at IS NULL
      LIMIT 1;
      IF v_id_category IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown room category code for property';
      END IF;
    END IF;
  END IF;

  /* Normalize optional rate plan parameter */
  IF p_rateplan_code IS NOT NULL THEN
    SET v_update_rateplan = 1;
    SET v_rateplan_code_trim = TRIM(p_rateplan_code);
    IF v_rateplan_code_trim = '' THEN
      SET v_id_rateplan = NULL;
    ELSE
      SELECT id_rateplan INTO v_id_rateplan
      FROM rateplan
      WHERE id_property = v_id_property
        AND code = v_rateplan_code_trim
        AND deleted_at IS NULL
      LIMIT 1;
      IF v_id_rateplan IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown rate plan code for property';
      END IF;
    END IF;
  END IF;

  IF p_id_room IS NOT NULL AND p_id_room > 0 THEN
    SELECT id_room INTO v_id_room
    FROM room
    WHERE id_room = p_id_room
      AND id_property = v_id_property
      AND deleted_at IS NULL
    LIMIT 1;
  ELSE
    SELECT id_room INTO v_id_room
    FROM room
    WHERE id_property = v_id_property
      AND code = p_room_code
      AND deleted_at IS NULL
    LIMIT 1;
  END IF;

  IF v_id_room IS NULL THEN
    INSERT INTO room (
      id_property,
      id_category,
      id_rateplan,
      code,
      name,
      description,
      capacity_total,
      max_adults,
      max_children,
      status,
      housekeeping_status,
      floor,
      building,
      bed_config,
      color_hex,
      order_index,
      is_active,
      created_at,
      updated_at
    ) VALUES (
      v_id_property,
      CASE WHEN v_update_category = 1 THEN v_id_category ELSE NULL END,
      CASE WHEN v_update_rateplan = 1 THEN v_id_rateplan ELSE NULL END,
      p_room_code,
      p_name,
      NULLIF(p_description, ''),
      p_capacity_total,
      p_max_adults,
      p_max_children,
      COALESCE(NULLIF(p_status,''), 'vacant'),
      COALESCE(NULLIF(p_housekeeping_status,''), 'clean'),
      NULLIF(p_floor, ''),
      NULLIF(p_building, ''),
      NULLIF(p_bed_config, ''),
      NULLIF(p_color_hex, ''),
      p_order_index,
      COALESCE(p_is_active, 1),
      NOW(),
      NOW()
    );
    SET v_id_room = LAST_INSERT_ID();
  ELSE
    UPDATE room
    SET
      id_category = CASE WHEN v_update_category = 1 THEN v_id_category ELSE id_category END,
      id_rateplan = CASE WHEN v_update_rateplan = 1 THEN v_id_rateplan ELSE id_rateplan END,
      code = p_room_code,
      name = COALESCE(NULLIF(p_name,''), name),
      description = COALESCE(NULLIF(p_description,''), description),
      capacity_total = COALESCE(p_capacity_total, capacity_total),
      max_adults = COALESCE(p_max_adults, max_adults),
      max_children = COALESCE(p_max_children, max_children),
      status = COALESCE(NULLIF(p_status,''), status),
      housekeeping_status = COALESCE(NULLIF(p_housekeeping_status,''), housekeeping_status),
      floor = COALESCE(NULLIF(p_floor,''), floor),
      building = COALESCE(NULLIF(p_building,''), building),
      bed_config = COALESCE(NULLIF(p_bed_config,''), bed_config),
      color_hex = COALESCE(NULLIF(p_color_hex,''), color_hex),
      order_index = COALESCE(p_order_index, order_index),
      is_active = COALESCE(p_is_active, is_active),
      updated_at = NOW()
    WHERE id_room = v_id_room;
  END IF;

  SELECT
    r.*,
    p.code AS property_code,
    p.name AS property_name,
    rc.code AS category_code,
    rc.name AS category_name,
    rp.code AS rateplan_code,
    rp.name AS rateplan_name
  FROM room r
  JOIN property p ON p.id_property = r.id_property
  LEFT JOIN roomcategory rc ON rc.id_category = r.id_category
  LEFT JOIN rateplan rp ON rp.id_rateplan = r.id_rateplan
  WHERE r.id_room = v_id_room;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_catalog_calc_upsert` (IN `p_action` VARCHAR(16), IN `p_id_item` BIGINT, IN `p_id_parent` BIGINT, IN `p_component_ids_csv` TEXT, IN `p_component_signs_csv` TEXT, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_idx INT DEFAULT 1;
  DECLARE v_count INT DEFAULT 0;
  DECLARE v_comp BIGINT;
  DECLARE v_sign_raw VARCHAR(16);
  DECLARE v_sign INT DEFAULT 1;

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'replace';
  END IF;
  IF p_action NOT IN ('replace','clear') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_id_item IS NULL OR p_id_item <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'item id is required';
  END IF;
  IF p_id_parent IS NULL OR p_id_parent <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'parent id is required';
  END IF;

  UPDATE line_item_catalog_calc
     SET is_active = 0,
         deleted_at = NOW(),
         updated_at = NOW()
   WHERE id_line_item_catalog = p_id_item
     AND id_parent_line_item_catalog = p_id_parent
     AND deleted_at IS NULL;

  IF p_action = 'clear' THEN
    LEAVE proc;
  END IF;

  IF p_component_ids_csv IS NULL OR TRIM(p_component_ids_csv) = '' THEN
    LEAVE proc;
  END IF;

  SET v_count = 1 + LENGTH(p_component_ids_csv) - LENGTH(REPLACE(p_component_ids_csv, ',', ''));

  WHILE v_idx <= v_count DO
    SET v_comp = CAST(TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(p_component_ids_csv, ',', v_idx), ',', -1)) AS UNSIGNED);
    SET v_sign_raw = TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(COALESCE(p_component_signs_csv,''), ',', v_idx), ',', -1));
    SET v_sign = IF(v_sign_raw = '-1', -1, 1);

    IF v_comp IS NOT NULL AND v_comp > 0 THEN
      INSERT INTO line_item_catalog_calc (
        id_line_item_catalog,
        id_parent_line_item_catalog,
        id_component_line_item_catalog,
        is_positive,
        is_active,
        deleted_at,
        created_at,
        created_by,
        updated_at
      ) VALUES (
        p_id_item,
        p_id_parent,
        v_comp,
        IF(v_sign >= 0, 1, 0),
        1,
        NULL,
        NOW(),
        p_created_by,
        NOW()
      )
      ON DUPLICATE KEY UPDATE
        is_positive = VALUES(is_positive),
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;

    SET v_idx = v_idx + 1;
  END WHILE;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_catalog_clone` (IN `p_company_code` VARCHAR(100), IN `p_source_item_id` BIGINT, IN `p_clone_item_name` VARCHAR(255), IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_source_catalog_type VARCHAR(32);
  DECLARE v_source_category_id BIGINT;
  DECLARE v_source_item_name VARCHAR(255);
  DECLARE v_source_description TEXT;
  DECLARE v_source_unit_price_cents INT;
  DECLARE v_source_default_amount_cents INT;
  DECLARE v_source_show_in_folio TINYINT;
  DECLARE v_source_allow_negative TINYINT;
  DECLARE v_source_is_active TINYINT;
  DECLARE v_new_item_id BIGINT;
  DECLARE v_new_item_name VARCHAR(255);

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'company code is required';
  END IF;
  IF p_source_item_id IS NULL OR p_source_item_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'source item id is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unknown company';
  END IF;

  SELECT
    lic.catalog_type,
    lic.id_category,
    lic.item_name,
    lic.description,
    COALESCE(lic.default_unit_price_cents, 0),
    COALESCE(lic.default_amount_cents, 0),
    COALESCE(lic.show_in_folio, 1),
    COALESCE(lic.allow_negative, 0),
    COALESCE(lic.is_active, 1)
    INTO
      v_source_catalog_type,
      v_source_category_id,
      v_source_item_name,
      v_source_description,
      v_source_unit_price_cents,
      v_source_default_amount_cents,
      v_source_show_in_folio,
      v_source_allow_negative,
      v_source_is_active
  FROM line_item_catalog lic
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.deleted_at IS NULL
   AND cat.id_company = v_company_id
  WHERE lic.id_line_item_catalog = p_source_item_id
    AND lic.deleted_at IS NULL
  LIMIT 1;

  IF v_source_category_id IS NULL OR v_source_category_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'source concept not found';
  END IF;

  SET v_new_item_name = NULLIF(TRIM(p_clone_item_name), '');
  IF v_new_item_name IS NULL THEN
    SET v_new_item_name = LEFT(
      CONCAT(COALESCE(NULLIF(TRIM(v_source_item_name), ''), CONCAT('Concepto #', p_source_item_id)), ' (copia)'),
      255
    );
  END IF;

  INSERT INTO line_item_catalog (
    catalog_type,
    id_category,
    item_name,
    description,
    default_unit_price_cents,
    show_in_folio,
    allow_negative,
    default_amount_cents,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  ) VALUES (
    v_source_catalog_type,
    v_source_category_id,
    v_new_item_name,
    v_source_description,
    v_source_unit_price_cents,
    v_source_show_in_folio,
    v_source_allow_negative,
    v_source_default_amount_cents,
    v_source_is_active,
    NULL,
    NOW(),
    p_created_by,
    NOW()
  );

  SET v_new_item_id = LAST_INSERT_ID();

  /* Clona relaciones donde el origen era hijo (nuevo concepto conserva mismos padres). */
  INSERT INTO line_item_catalog_parent (
    id_sale_item_catalog,
    id_parent_sale_item_catalog,
    add_to_father_total,
    show_in_folio_relation,
    percent_value,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  )
  SELECT
    v_new_item_id,
    lcp.id_parent_sale_item_catalog,
    COALESCE(lcp.add_to_father_total, 1),
    lcp.show_in_folio_relation,
    lcp.percent_value,
    1,
    NULL,
    NOW(),
    p_created_by,
    NOW()
  FROM line_item_catalog_parent lcp
  JOIN line_item_catalog parent_lic
    ON parent_lic.id_line_item_catalog = lcp.id_parent_sale_item_catalog
   AND parent_lic.deleted_at IS NULL
  JOIN sale_item_category parent_cat
    ON parent_cat.id_sale_item_category = parent_lic.id_category
   AND parent_cat.deleted_at IS NULL
   AND parent_cat.id_company = v_company_id
  WHERE lcp.id_sale_item_catalog = p_source_item_id
    AND lcp.deleted_at IS NULL
    AND lcp.is_active = 1
  ON DUPLICATE KEY UPDATE
    add_to_father_total = VALUES(add_to_father_total),
    show_in_folio_relation = VALUES(show_in_folio_relation),
    percent_value = VALUES(percent_value),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  /* Clona relaciones donde el origen era padre (nuevo concepto hereda hijos). */
  INSERT INTO line_item_catalog_parent (
    id_sale_item_catalog,
    id_parent_sale_item_catalog,
    add_to_father_total,
    show_in_folio_relation,
    percent_value,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  )
  SELECT
    lcp.id_sale_item_catalog,
    v_new_item_id,
    COALESCE(lcp.add_to_father_total, 1),
    lcp.show_in_folio_relation,
    lcp.percent_value,
    1,
    NULL,
    NOW(),
    p_created_by,
    NOW()
  FROM line_item_catalog_parent lcp
  JOIN line_item_catalog child_lic
    ON child_lic.id_line_item_catalog = lcp.id_sale_item_catalog
   AND child_lic.deleted_at IS NULL
  JOIN sale_item_category child_cat
    ON child_cat.id_sale_item_category = child_lic.id_category
   AND child_cat.deleted_at IS NULL
   AND child_cat.id_company = v_company_id
  WHERE lcp.id_parent_sale_item_catalog = p_source_item_id
    AND lcp.deleted_at IS NULL
    AND lcp.is_active = 1
  ON DUPLICATE KEY UPDATE
    add_to_father_total = VALUES(add_to_father_total),
    show_in_folio_relation = VALUES(show_in_folio_relation),
    percent_value = VALUES(percent_value),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  /* Clona calculos donde el origen era hijo. */
  INSERT INTO line_item_catalog_calc (
    id_line_item_catalog,
    id_parent_line_item_catalog,
    id_component_line_item_catalog,
    is_positive,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  )
  SELECT
    v_new_item_id,
    licc.id_parent_line_item_catalog,
    licc.id_component_line_item_catalog,
    COALESCE(licc.is_positive, 1),
    1,
    NULL,
    NOW(),
    p_created_by,
    NOW()
  FROM line_item_catalog_calc licc
  JOIN line_item_catalog parent_lic
    ON parent_lic.id_line_item_catalog = licc.id_parent_line_item_catalog
   AND parent_lic.deleted_at IS NULL
  JOIN sale_item_category parent_cat
    ON parent_cat.id_sale_item_category = parent_lic.id_category
   AND parent_cat.deleted_at IS NULL
   AND parent_cat.id_company = v_company_id
  WHERE licc.id_line_item_catalog = p_source_item_id
    AND licc.deleted_at IS NULL
    AND licc.is_active = 1
  ON DUPLICATE KEY UPDATE
    is_positive = VALUES(is_positive),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  /* Clona calculos donde el origen era padre. */
  INSERT INTO line_item_catalog_calc (
    id_line_item_catalog,
    id_parent_line_item_catalog,
    id_component_line_item_catalog,
    is_positive,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  )
  SELECT
    licc.id_line_item_catalog,
    v_new_item_id,
    licc.id_component_line_item_catalog,
    COALESCE(licc.is_positive, 1),
    1,
    NULL,
    NOW(),
    p_created_by,
    NOW()
  FROM line_item_catalog_calc licc
  JOIN line_item_catalog child_lic
    ON child_lic.id_line_item_catalog = licc.id_line_item_catalog
   AND child_lic.deleted_at IS NULL
  JOIN sale_item_category child_cat
    ON child_cat.id_sale_item_category = child_lic.id_category
   AND child_cat.deleted_at IS NULL
   AND child_cat.id_company = v_company_id
  WHERE licc.id_parent_line_item_catalog = p_source_item_id
    AND licc.deleted_at IS NULL
    AND licc.is_active = 1
  ON DUPLICATE KEY UPDATE
    is_positive = VALUES(is_positive),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();

  SELECT
    lic.id_line_item_catalog AS id_sale_item_catalog,
    lic.catalog_type,
    lic.id_category,
    lic.item_name,
    lic.description,
    lic.default_unit_price_cents,
    lic.default_amount_cents,
    lic.show_in_folio,
    lic.allow_negative,
    lic.is_active,
    lic.created_at,
    lic.updated_at
  FROM line_item_catalog lic
  WHERE lic.id_line_item_catalog = v_new_item_id
  LIMIT 1;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_catalog_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_show_inactive` TINYINT, IN `p_item_id` BIGINT, IN `p_category_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;

    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SELECT
    lic.id_line_item_catalog AS id_sale_item_catalog,
    lic.catalog_type,
    lic.id_category,
    cat.category_name AS category,
    parent_map.parent_first_id AS id_parent_sale_item_catalog,
    parent_first.item_name AS parent_item_name,
    parent_map.parent_item_ids,
    parent_map.add_to_father_total,
    parent_map.is_percent,
    parent_map.percent_value,
    lic.show_in_folio,
    lic.allow_negative,
    lic.item_name,
    lic.description,
    lic.default_unit_price_cents,
    lic.is_active,
    p.code AS property_code,
    CAST(NULL AS CHAR) AS tax_rule_ids
  FROM line_item_catalog lic
  JOIN sale_item_category cat
    ON cat.id_sale_item_category = lic.id_category
   AND cat.id_company = v_company_id
   AND cat.deleted_at IS NULL
  LEFT JOIN (
    SELECT
      lcp.id_sale_item_catalog,
      GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids,
      MIN(lcp.id_parent_sale_item_catalog) AS parent_first_id,
      MIN(lcp.add_to_father_total) AS add_to_father_total,
      MAX(CASE WHEN lcp.percent_value IS NOT NULL THEN 1 ELSE 0 END) AS is_percent,
      MIN(lcp.percent_value) AS percent_value
    FROM line_item_catalog_parent lcp
    JOIN line_item_catalog parent
      ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
     AND parent.deleted_at IS NULL
     AND parent.is_active = 1
    WHERE lcp.deleted_at IS NULL
      AND lcp.is_active = 1
    GROUP BY lcp.id_sale_item_catalog
  ) parent_map ON parent_map.id_sale_item_catalog = lic.id_line_item_catalog
  LEFT JOIN line_item_catalog parent_first
    ON parent_first.id_line_item_catalog = parent_map.parent_first_id
  LEFT JOIN property p ON p.id_property = cat.id_property
  WHERE lic.deleted_at IS NULL
    AND lic.catalog_type IN ('sale_item','payment','obligation','income','tax_rule')
    AND (p_show_inactive IS NOT NULL AND p_show_inactive <> 0 OR lic.is_active = 1)
    AND (p_show_inactive IS NOT NULL AND p_show_inactive <> 0 OR cat.is_active = 1)
    AND (v_property_id IS NULL OR cat.id_property IS NULL OR cat.id_property = v_property_id)
    AND (p_category_id IS NULL OR p_category_id = 0 OR lic.id_category = p_category_id)
  ORDER BY cat.category_name, lic.item_name;

  IF p_item_id IS NULL OR p_item_id = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_sale_item_catalog,
      CAST(NULL AS CHAR) AS catalog_type,
      CAST(NULL AS SIGNED) AS id_category,
      CAST(NULL AS CHAR) AS category,
      CAST(NULL AS SIGNED) AS id_parent_sale_item_catalog,
      CAST(NULL AS CHAR) AS parent_item_name,
      CAST(NULL AS CHAR) AS parent_item_ids,
      CAST(NULL AS SIGNED) AS add_to_father_total,
      CAST(NULL AS SIGNED) AS is_percent,
      CAST(NULL AS DECIMAL(12,6)) AS percent_value,
      CAST(NULL AS SIGNED) AS show_in_folio,
      CAST(NULL AS SIGNED) AS allow_negative,
      CAST(NULL AS CHAR) AS item_name,
      CAST(NULL AS CHAR) AS description,
      CAST(NULL AS SIGNED) AS default_unit_price_cents,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS CHAR) AS property_code,
      CAST(NULL AS CHAR) AS tax_rule_ids
    LIMIT 0;
  ELSE
    SELECT
      lic.id_line_item_catalog AS id_sale_item_catalog,
      lic.catalog_type,
      lic.id_category,
      cat.category_name AS category,
      parent_map.parent_first_id AS id_parent_sale_item_catalog,
      parent_first.item_name AS parent_item_name,
      parent_map.parent_item_ids,
      parent_map.add_to_father_total,
      parent_map.is_percent,
      parent_map.percent_value,
      lic.show_in_folio,
      lic.allow_negative,
      lic.item_name,
      lic.description,
      lic.default_unit_price_cents,
      lic.is_active,
      p.code AS property_code,
      CAST(NULL AS CHAR) AS tax_rule_ids
    FROM line_item_catalog lic
    JOIN sale_item_category cat
      ON cat.id_sale_item_category = lic.id_category
     AND cat.id_company = v_company_id
     AND cat.deleted_at IS NULL
    LEFT JOIN (
      SELECT
        lcp.id_sale_item_catalog,
        GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids,
        MIN(lcp.id_parent_sale_item_catalog) AS parent_first_id,
        MIN(lcp.add_to_father_total) AS add_to_father_total,
        MAX(CASE WHEN lcp.percent_value IS NOT NULL THEN 1 ELSE 0 END) AS is_percent,
        MIN(lcp.percent_value) AS percent_value
      FROM line_item_catalog_parent lcp
      JOIN line_item_catalog parent
        ON parent.id_line_item_catalog = lcp.id_parent_sale_item_catalog
       AND parent.deleted_at IS NULL
       AND parent.is_active = 1
      WHERE lcp.deleted_at IS NULL
        AND lcp.is_active = 1
      GROUP BY lcp.id_sale_item_catalog
    ) parent_map ON parent_map.id_sale_item_catalog = lic.id_line_item_catalog
    LEFT JOIN line_item_catalog parent_first
      ON parent_first.id_line_item_catalog = parent_map.parent_first_id
    LEFT JOIN property p ON p.id_property = cat.id_property
    WHERE lic.id_line_item_catalog = p_item_id
    LIMIT 1;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_catalog_parent_total_upsert` (IN `p_action` VARCHAR(16), IN `p_id_item` BIGINT, IN `p_id_parent` BIGINT, IN `p_add_to_father_total` TINYINT, IN `p_show_in_folio_relation` TINYINT, IN `p_percent_value` DECIMAL(12,6), IN `p_created_by` BIGINT)   BEGIN
  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'upsert';
  END IF;
  IF p_action NOT IN ('upsert') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  IF p_id_item IS NULL OR p_id_item <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'item id is required';
  END IF;
  IF p_id_parent IS NULL OR p_id_parent <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'parent id is required';
  END IF;

  INSERT INTO line_item_catalog_parent (
    id_sale_item_catalog,
    id_parent_sale_item_catalog,
    add_to_father_total,
    show_in_folio_relation,
    percent_value,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  ) VALUES (
    p_id_item,
    p_id_parent,
    IF(COALESCE(p_add_to_father_total, 1) = 1, 1, 0),
    CASE
      WHEN p_show_in_folio_relation IS NULL THEN NULL
      WHEN COALESCE(p_show_in_folio_relation, 0) = 1 THEN 1
      ELSE 0
    END,
    p_percent_value,
    1,
    NULL,
    NOW(),
    p_created_by,
    NOW()
  )
  ON DUPLICATE KEY UPDATE
    add_to_father_total = VALUES(add_to_father_total),
    show_in_folio_relation = VALUES(show_in_folio_relation),
    percent_value = VALUES(percent_value),
    is_active = 1,
    deleted_at = NULL,
    updated_at = NOW();
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_catalog_upsert` (IN `p_action` VARCHAR(16), IN `p_id_item` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_catalog_type` VARCHAR(32), IN `p_id_category` BIGINT, IN `p_parent_ids` TEXT, IN `p_item_name` VARCHAR(255), IN `p_description` TEXT, IN `p_unit_price_cents` INT, IN `p_is_percent` TINYINT, IN `p_percent_value` DECIMAL(9,4), IN `p_tax_rule_ids` TEXT, IN `p_show_in_folio` TINYINT, IN `p_allow_negative` TINYINT, IN `p_is_active` TINYINT, IN `p_add_to_father_total` TINYINT, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_item_id BIGINT;
  DECLARE v_id_category BIGINT;
  DECLARE v_catalog_property_id BIGINT;
  DECLARE v_catalog_type VARCHAR(32);

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SET v_catalog_type = CASE
    WHEN p_catalog_type IS NULL OR CHAR_LENGTH(p_catalog_type) = 0 THEN 'sale_item'
    ELSE p_catalog_type
  END;
  IF v_catalog_type NOT IN ('sale_item','payment','obligation','income','tax_rule') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported catalog type';
  END IF;

  IF p_action = 'create' THEN
    IF p_item_name IS NULL OR p_item_name = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Item name is required';
    END IF;
    IF p_id_category IS NULL OR p_id_category = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category is required';
    END IF;

    SELECT id_sale_item_category, id_property
      INTO v_id_category, v_catalog_property_id
    FROM sale_item_category
    WHERE id_sale_item_category = p_id_category
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_id_category IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category not found';
    END IF;

    INSERT INTO line_item_catalog (
      catalog_type,
      id_category,
      item_name,
      description,
      default_unit_price_cents,
      show_in_folio,
      allow_negative,
      default_amount_cents,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_catalog_type,
      v_id_category,
      p_item_name,
      p_description,
      COALESCE(p_unit_price_cents,0),
      COALESCE(p_show_in_folio,1),
      COALESCE(p_allow_negative,0),
      COALESCE(p_unit_price_cents,0),
      COALESCE(p_is_active,1),
      NOW(),
      p_created_by,
      NOW()
    );
    SET v_item_id = LAST_INSERT_ID();

    IF p_parent_ids IS NOT NULL AND p_parent_ids <> '' THEN
      INSERT INTO line_item_catalog_parent (
        id_sale_item_catalog,
        id_parent_sale_item_catalog,
        add_to_father_total,
        show_in_folio_relation,
        percent_value,
        is_active,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_item_id,
        parent.id_line_item_catalog,
        COALESCE(p_add_to_father_total,1),
        COALESCE(p_show_in_folio,1),
        CASE WHEN COALESCE(p_is_percent,0) = 1 THEN p_percent_value ELSE NULL END,
        1,
        NOW(),
        p_created_by,
        NOW()
      FROM line_item_catalog parent
      LEFT JOIN sale_item_category cat_parent ON cat_parent.id_sale_item_category = parent.id_category
      WHERE parent.deleted_at IS NULL
        AND FIND_IN_SET(parent.id_line_item_catalog, p_parent_ids)
        AND cat_parent.id_company = v_company_id
        AND cat_parent.deleted_at IS NULL
        AND (cat_parent.id_property IS NULL OR v_catalog_property_id IS NULL OR cat_parent.id_property = v_catalog_property_id)
      ON DUPLICATE KEY UPDATE
        add_to_father_total = VALUES(add_to_father_total),
        show_in_folio_relation = VALUES(show_in_folio_relation),
        percent_value = VALUES(percent_value),
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;

    SELECT
      lic.id_line_item_catalog AS id_sale_item_catalog,
      lic.catalog_type,
      lic.id_category,
      parent_map.parent_first_id AS id_parent_sale_item_catalog,
      parent_first.item_name AS parent_item_name,
      parent_map.parent_item_ids,
      parent_map.add_to_father_total,
      lic.item_name,
      lic.description,
      lic.default_unit_price_cents,
      parent_map.is_percent AS is_percent,
      parent_map.percent_value AS percent_value,
      lic.show_in_folio,
      lic.allow_negative,
      lic.is_active,
      lic.deleted_at,
      lic.created_at,
      lic.created_by,
      lic.updated_at
    FROM line_item_catalog lic
    LEFT JOIN (
      SELECT
        lcp.id_sale_item_catalog,
        GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids,
        MIN(lcp.id_parent_sale_item_catalog) AS parent_first_id,
        MIN(lcp.add_to_father_total) AS add_to_father_total,
        MAX(CASE WHEN lcp.percent_value IS NOT NULL THEN 1 ELSE 0 END) AS is_percent,
        MIN(lcp.percent_value) AS percent_value
      FROM line_item_catalog_parent lcp
      WHERE lcp.deleted_at IS NULL
        AND lcp.is_active = 1
      GROUP BY lcp.id_sale_item_catalog
    ) parent_map ON parent_map.id_sale_item_catalog = lic.id_line_item_catalog
    LEFT JOIN line_item_catalog parent_first
      ON parent_first.id_line_item_catalog = parent_map.parent_first_id
    WHERE lic.id_line_item_catalog = v_item_id;

    LEAVE proc;
  END IF;

  IF p_id_item IS NULL OR p_id_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Item id is required';
  END IF;

  SELECT lic.id_line_item_catalog, lic.catalog_type, lic.id_category, cat.id_property
    INTO v_item_id, v_catalog_type, v_id_category, v_catalog_property_id
  FROM line_item_catalog lic
  LEFT JOIN sale_item_category cat ON cat.id_sale_item_category = lic.id_category
  WHERE lic.id_line_item_catalog = p_id_item
    AND cat.id_company = v_company_id
    AND cat.deleted_at IS NULL
  LIMIT 1;

  IF v_item_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Item not found';
  END IF;

  SET v_catalog_type = CASE
    WHEN p_catalog_type IS NULL OR CHAR_LENGTH(p_catalog_type) = 0 THEN v_catalog_type
    ELSE p_catalog_type
  END;
  IF v_catalog_type NOT IN ('sale_item','payment','obligation','income','tax_rule') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported catalog type';
  END IF;

  IF p_parent_ids IS NOT NULL AND p_parent_ids <> '' AND FIND_IN_SET(v_item_id, p_parent_ids) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Parent item cannot be self';
  END IF;

  IF p_action = 'delete' THEN
    UPDATE line_item_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item_catalog = v_item_id;
  ELSE
    IF p_id_category IS NULL OR p_id_category = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category is required';
    END IF;

    SELECT id_sale_item_category, id_property
      INTO v_id_category, v_catalog_property_id
    FROM sale_item_category
    WHERE id_sale_item_category = p_id_category
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_id_category IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category not found';
    END IF;

    UPDATE line_item_catalog
       SET catalog_type = v_catalog_type,
           id_category = v_id_category,
           item_name = CASE
             WHEN p_item_name IS NULL OR CHAR_LENGTH(p_item_name) = 0 THEN item_name
             ELSE p_item_name
           END,
           description = COALESCE(p_description, description),
           default_unit_price_cents = COALESCE(p_unit_price_cents, default_unit_price_cents),
           show_in_folio = COALESCE(p_show_in_folio, show_in_folio),
           allow_negative = COALESCE(p_allow_negative, allow_negative),
           default_amount_cents = COALESCE(p_unit_price_cents, default_amount_cents),
           is_active = COALESCE(p_is_active, is_active),
           updated_at = NOW()
     WHERE id_line_item_catalog = v_item_id;
  END IF;

  IF p_parent_ids IS NOT NULL THEN
    UPDATE line_item_catalog_parent
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_sale_item_catalog = v_item_id;

    IF p_parent_ids <> '' THEN
      INSERT INTO line_item_catalog_parent (
        id_sale_item_catalog,
        id_parent_sale_item_catalog,
        add_to_father_total,
        show_in_folio_relation,
        percent_value,
        is_active,
        created_at,
        created_by,
        updated_at
      )
      SELECT
        v_item_id,
        parent.id_line_item_catalog,
        COALESCE(p_add_to_father_total,1),
        COALESCE(p_show_in_folio,1),
        CASE WHEN COALESCE(p_is_percent,0) = 1 THEN p_percent_value ELSE NULL END,
        1,
        NOW(),
        p_created_by,
        NOW()
      FROM line_item_catalog parent
      LEFT JOIN sale_item_category cat_parent ON cat_parent.id_sale_item_category = parent.id_category
      WHERE parent.deleted_at IS NULL
        AND FIND_IN_SET(parent.id_line_item_catalog, p_parent_ids)
        AND cat_parent.id_company = v_company_id
        AND cat_parent.deleted_at IS NULL
        AND (cat_parent.id_property IS NULL OR v_catalog_property_id IS NULL OR cat_parent.id_property = v_catalog_property_id)
      ON DUPLICATE KEY UPDATE
        add_to_father_total = VALUES(add_to_father_total),
        show_in_folio_relation = VALUES(show_in_folio_relation),
        percent_value = VALUES(percent_value),
        is_active = 1,
        deleted_at = NULL,
        updated_at = NOW();
    END IF;
  END IF;

  SELECT
    lic.id_line_item_catalog AS id_sale_item_catalog,
    lic.catalog_type,
    lic.id_category,
    parent_map.parent_first_id AS id_parent_sale_item_catalog,
    parent_first.item_name AS parent_item_name,
    parent_map.parent_item_ids,
    parent_map.add_to_father_total,
    lic.item_name,
    lic.description,
    lic.default_unit_price_cents,
    parent_map.is_percent AS is_percent,
    parent_map.percent_value AS percent_value,
    lic.show_in_folio,
    lic.allow_negative,
    lic.is_active,
    lic.deleted_at,
    lic.created_at,
    lic.created_by,
    lic.updated_at
  FROM line_item_catalog lic
  LEFT JOIN (
    SELECT
      lcp.id_sale_item_catalog,
      GROUP_CONCAT(DISTINCT lcp.id_parent_sale_item_catalog ORDER BY lcp.id_parent_sale_item_catalog) AS parent_item_ids,
      MIN(lcp.id_parent_sale_item_catalog) AS parent_first_id,
      MIN(lcp.add_to_father_total) AS add_to_father_total,
      MAX(CASE WHEN lcp.percent_value IS NOT NULL THEN 1 ELSE 0 END) AS is_percent,
      MIN(lcp.percent_value) AS percent_value
    FROM line_item_catalog_parent lcp
    WHERE lcp.deleted_at IS NULL
      AND lcp.is_active = 1
    GROUP BY lcp.id_sale_item_catalog
  ) parent_map ON parent_map.id_sale_item_catalog = lic.id_line_item_catalog
  LEFT JOIN line_item_catalog parent_first
    ON parent_first.id_line_item_catalog = parent_map.parent_first_id
  WHERE lic.id_line_item_catalog = v_item_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_category_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_show_inactive` TINYINT, IN `p_category_id` BIGINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  /* listado */
  SELECT
    sic.id_sale_item_category,
    sic.id_parent_sale_item_category,
    parent.category_name AS parent_category_name,
    sic.category_name,
    sic.description,
    sic.is_active,
    p.code AS property_code
  FROM sale_item_category sic
  LEFT JOIN sale_item_category parent ON parent.id_sale_item_category = sic.id_parent_sale_item_category
  LEFT JOIN property p ON p.id_property = sic.id_property
  WHERE sic.id_company = v_company_id
    AND (v_property_id IS NULL OR sic.id_property IS NULL OR sic.id_property = v_property_id)
    AND sic.deleted_at IS NULL
    AND (p_show_inactive IS NOT NULL AND p_show_inactive <> 0 OR sic.is_active = 1)
  ORDER BY sic.category_name;

  /* detalle */
  IF p_category_id IS NULL OR p_category_id = 0 THEN
    SELECT
      CAST(NULL AS SIGNED) AS id_sale_item_category,
      CAST(NULL AS SIGNED) AS id_parent_sale_item_category,
      CAST(NULL AS CHAR) AS parent_category_name,
      CAST(NULL AS CHAR) AS category_name,
      CAST(NULL AS CHAR) AS description,
      CAST(NULL AS SIGNED) AS is_active,
      CAST(NULL AS CHAR) AS property_code
    LIMIT 0;
  ELSE
    SELECT
      sic.id_sale_item_category,
      sic.id_parent_sale_item_category,
      parent.category_name AS parent_category_name,
      sic.category_name,
      sic.description,
      sic.is_active,
      p.code AS property_code
    FROM sale_item_category sic
    LEFT JOIN sale_item_category parent ON parent.id_sale_item_category = sic.id_parent_sale_item_category
    LEFT JOIN property p ON p.id_property = sic.id_property
    WHERE sic.id_sale_item_category = p_category_id
      AND sic.id_company = v_company_id
    LIMIT 1;
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_category_upsert` (IN `p_action` VARCHAR(16), IN `p_id_category` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_category_name` VARCHAR(120), IN `p_description` TEXT, IN `p_is_active` TINYINT, IN `p_created_by` BIGINT, IN `p_id_parent_category` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_id BIGINT;
  DECLARE v_parent_id BIGINT;
  DECLARE v_parent_set TINYINT DEFAULT 0;
  DECLARE v_dup_id BIGINT;
  DECLARE v_category_name VARCHAR(120);

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unsupported action';
  END IF;

  SET v_category_name = TRIM(COALESCE(p_category_name, ''));

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  IF p_id_parent_category IS NOT NULL THEN
    SET v_parent_set = 1;
    IF p_id_parent_category = 0 THEN
      SET v_parent_id = NULL;
    ELSE
      SELECT id_sale_item_category INTO v_parent_id
      FROM sale_item_category
      WHERE id_sale_item_category = p_id_parent_category
        AND id_company = v_company_id
        AND id_property <=> v_property_id
        AND deleted_at IS NULL
      LIMIT 1;
      IF v_parent_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Parent category not found';
      END IF;
    END IF;
  END IF;

  IF p_action = 'create' THEN
    IF v_category_name = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category name is required';
    END IF;
    SET v_dup_id = NULL;
    SELECT id_sale_item_category INTO v_dup_id
    FROM sale_item_category
    WHERE id_company = v_company_id
      AND id_property <=> v_property_id
      AND id_parent_sale_item_category <=> v_parent_id
      AND TRIM(category_name) = v_category_name
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_dup_id IS NOT NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category already exists for this parent category';
    END IF;
    INSERT INTO sale_item_category (
      id_company,
      id_property,
      id_parent_sale_item_category,
      category_name,
      description,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_company_id,
      v_property_id,
      v_parent_id,
      v_category_name,
      p_description,
      COALESCE(p_is_active,1),
      NOW(),
      p_created_by,
      NOW()
    );
    SET v_id = LAST_INSERT_ID();
    SELECT * FROM sale_item_category WHERE id_sale_item_category = v_id;
    LEAVE proc;
  END IF;

  IF p_id_category IS NULL OR p_id_category = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category id is required';
  END IF;

  SELECT id_sale_item_category INTO v_id
  FROM sale_item_category
  WHERE id_sale_item_category = p_id_category
    AND id_company = v_company_id
  LIMIT 1;

  IF v_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category not found';
  END IF;

  IF v_parent_set = 1 AND v_parent_id IS NOT NULL AND v_parent_id = v_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Parent category cannot be self';
  END IF;

  IF p_action = 'delete' THEN
    UPDATE sale_item_category
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_sale_item_category = v_id;
  ELSE
    SET v_dup_id = NULL;
    SELECT id_sale_item_category INTO v_dup_id
    FROM sale_item_category
    WHERE id_company = v_company_id
      AND id_sale_item_category <> v_id
      AND id_property <=> COALESCE(v_property_id, id_property)
      AND id_parent_sale_item_category <=> CASE
        WHEN v_parent_set = 0 THEN id_parent_sale_item_category
        ELSE v_parent_id
      END
      AND TRIM(category_name) = CASE
        WHEN v_category_name = '' THEN TRIM(category_name)
        ELSE v_category_name
      END
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_dup_id IS NOT NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Category already exists for this parent category';
    END IF;
    UPDATE sale_item_category
       SET category_name = CASE
             WHEN v_category_name = '' THEN category_name
             ELSE v_category_name
           END,
           id_parent_sale_item_category = CASE
             WHEN v_parent_set = 0 THEN id_parent_sale_item_category
             ELSE v_parent_id
           END,
           description = COALESCE(p_description, description),
           id_property = COALESCE(v_property_id, id_property),
           is_active = COALESCE(p_is_active, is_active),
           updated_at = NOW()
     WHERE id_sale_item_category = v_id;
  END IF;

  SELECT * FROM sale_item_category WHERE id_sale_item_category = v_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_child_upsert` (IN `p_action` VARCHAR(16), IN `p_id_sale_item` BIGINT, IN `p_id_parent_sale_item` BIGINT, IN `p_id_folio` BIGINT, IN `p_id_reservation` BIGINT, IN `p_id_sale_item_catalog` BIGINT, IN `p_service_date` DATE, IN `p_quantity` DECIMAL(18,6), IN `p_unit_price_cents` INT, IN `p_status` VARCHAR(32), IN `p_created_by` BIGINT)   BEGIN
  /*
    Legacy compatibility wrapper.
    Parent-child linkage in line_item was removed from schema, so child upsert now
    delegates to generic line_item-based sale item upsert.
  */
  IF p_action IS NULL OR TRIM(p_action) = '' THEN
    SET p_action = 'create';
  END IF;

  IF p_action = 'delete' THEN
    CALL sp_sale_item_upsert(
      'delete',
      p_id_sale_item,
      p_id_folio,
      p_id_reservation,
      NULL,
      NULL,
      p_service_date,
      p_quantity,
      p_unit_price_cents,
      0,
      p_status,
      p_created_by
    );
  ELSEIF p_action = 'update' THEN
    CALL sp_sale_item_upsert(
      'update',
      p_id_sale_item,
      p_id_folio,
      p_id_reservation,
      p_id_sale_item_catalog,
      NULL,
      p_service_date,
      p_quantity,
      p_unit_price_cents,
      0,
      p_status,
      p_created_by
    );
  ELSE
    CALL sp_sale_item_upsert(
      'create',
      NULL,
      p_id_folio,
      p_id_reservation,
      p_id_sale_item_catalog,
      NULL,
      p_service_date,
      p_quantity,
      p_unit_price_cents,
      0,
      p_status,
      p_created_by
    );
  END IF;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_report_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE, IN `p_search` TEXT, IN `p_status` VARCHAR(32), IN `p_folio_status` VARCHAR(32), IN `p_parent_category_id` BIGINT, IN `p_category_id` BIGINT, IN `p_catalog_id` BIGINT, IN `p_min_total_cents` INT, IN `p_max_total_cents` INT, IN `p_has_tax` TINYINT, IN `p_show_inactive` TINYINT, IN `p_show_canceled_reservations` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_search TEXT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  DROP TEMPORARY TABLE IF EXISTS tmp_sale_items;
  CREATE TEMPORARY TABLE tmp_sale_items AS
  SELECT
    si.id_line_item AS id_sale_item,
    si.id_folio,
    f.folio_name,
    f.status AS folio_status,
    r.id_reservation,
    r.code AS reservation_code,
    p.code AS property_code,
    p.name AS property_name,
    CONCAT_WS(' ', COALESCE(g.names, ''), COALESCE(g.last_name, '')) AS guest_name,
    g.email AS guest_email,
    g.phone AS guest_phone,
    COALESCE(si.service_date, DATE(si.created_at)) AS service_date,
    si.quantity,
    si.unit_price_cents,
    si.discount_amount_cents,
    si.amount_cents,
    COALESCE(tax.tax_amount_cents,0) AS tax_amount_cents,
    (si.amount_cents + COALESCE(tax.tax_amount_cents,0)) AS total_with_tax_cents,
    si.currency,
    si.status AS sale_status,
    si.description,
    si.created_at,
    sic.id_line_item_catalog AS id_sale_item_catalog,
    sic.item_name AS concept_name,
    cat.id_sale_item_category AS subcategory_id,
    cat.category_name AS subcategory_name,
    parent.id_sale_item_category AS category_id,
    parent.category_name AS category_name
  FROM line_item si
  JOIN folio f ON f.id_folio = si.id_folio
  LEFT JOIN reservation r ON r.id_reservation = f.id_reservation
  LEFT JOIN property p ON p.id_property = r.id_property
  JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = si.id_line_item_catalog
   AND sic.catalog_type = 'sale_item'
  JOIN sale_item_category cat ON cat.id_sale_item_category = sic.id_category
  LEFT JOIN sale_item_category parent ON parent.id_sale_item_category = cat.id_parent_sale_item_category
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  LEFT JOIN (
    SELECT
      s.id_line_item AS id_sale_item,
      COALESCE(SUM(t.amount_cents),0) AS tax_amount_cents
    FROM line_item s
    LEFT JOIN line_item_catalog_parent lcp
      ON lcp.id_parent_sale_item_catalog = s.id_line_item_catalog
     AND lcp.deleted_at IS NULL
     AND lcp.is_active = 1
    LEFT JOIN line_item t
      ON t.id_folio = s.id_folio
     AND t.item_type = 'tax_item'
     AND t.id_line_item_catalog = lcp.id_sale_item_catalog
     AND t.deleted_at IS NULL
     AND t.is_active = 1
     AND (t.service_date <=> s.service_date)
    WHERE s.item_type = 'sale_item'
      AND s.deleted_at IS NULL
      AND s.is_active = 1
    GROUP BY s.id_line_item
  ) tax ON tax.id_sale_item = si.id_line_item
  WHERE cat.id_company = v_company_id
    AND f.deleted_at IS NULL
    AND (r.id_reservation IS NULL OR (r.deleted_at IS NULL AND r.is_active = 1))
    AND (
      p_show_canceled_reservations IS NOT NULL AND p_show_canceled_reservations <> 0
      OR r.id_reservation IS NULL
      OR COALESCE(LOWER(TRIM(r.status)), '') NOT IN ('cancelled','canceled','cancelado','cancelada')
    )
    AND si.item_type = 'sale_item'
    AND (v_property_id IS NULL OR r.id_property = v_property_id)
    AND (p_from IS NULL OR COALESCE(si.service_date, DATE(si.created_at)) >= p_from)
    AND (p_to IS NULL OR COALESCE(si.service_date, DATE(si.created_at)) <= p_to)
    AND (p_status IS NULL OR p_status = '' OR si.status = p_status)
    AND (p_folio_status IS NULL OR p_folio_status = '' OR f.status = p_folio_status)
    AND (p_category_id IS NULL OR p_category_id = 0 OR cat.id_sale_item_category = p_category_id)
    AND (
      p_parent_category_id IS NULL
      OR p_parent_category_id = 0
      OR cat.id_parent_sale_item_category = p_parent_category_id
      OR cat.id_sale_item_category = p_parent_category_id
    )
    AND (p_catalog_id IS NULL OR p_catalog_id = 0 OR sic.id_line_item_catalog = p_catalog_id)
    AND (
      p_min_total_cents IS NULL
      OR p_min_total_cents <= 0
      OR (si.amount_cents + COALESCE(tax.tax_amount_cents,0)) >= p_min_total_cents
    )
    AND (
      p_max_total_cents IS NULL
      OR p_max_total_cents <= 0
      OR (si.amount_cents + COALESCE(tax.tax_amount_cents,0)) <= p_max_total_cents
    )
    AND (p_has_tax IS NULL OR p_has_tax = 0 OR COALESCE(tax.tax_amount_cents,0) > 0)
    AND (
      v_search IS NULL
      OR r.code LIKE CONCAT('%', v_search, '%')
      OR f.folio_name LIKE CONCAT('%', v_search, '%')
      OR g.names LIKE CONCAT('%', v_search, '%')
      OR g.last_name LIKE CONCAT('%', v_search, '%')
      OR g.email LIKE CONCAT('%', v_search, '%')
      OR g.phone LIKE CONCAT('%', v_search, '%')
      OR sic.item_name LIKE CONCAT('%', v_search, '%')
      OR si.description LIKE CONCAT('%', v_search, '%')
    )
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR (si.deleted_at IS NULL AND si.is_active = 1)
    )
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR f.is_active = 1
    );

  SELECT
    id_sale_item,
    id_folio,
    folio_name,
    folio_status,
    id_reservation,
    reservation_code,
    property_code,
    property_name,
    guest_name,
    guest_email,
    guest_phone,
    service_date,
    quantity,
    unit_price_cents,
    discount_amount_cents,
    amount_cents,
    tax_amount_cents,
    total_with_tax_cents,
    currency,
    sale_status,
    description,
    created_at,
    id_sale_item_catalog,
    concept_name,
    subcategory_id,
    subcategory_name,
    category_id,
    category_name
  FROM tmp_sale_items
  ORDER BY service_date DESC, id_sale_item DESC;

  SELECT
    MIN(ti.id_line_item) AS id_tax_item,
    tsi.id_sale_item,
    tsi.currency,
    tr.id_line_item_catalog AS id_tax_rule,
    tr.item_name AS tax_name,
    COALESCE(lcp.percent_value, 0) AS rate_percent,
    COALESCE(SUM(ti.amount_cents),0) AS amount_cents,
    MAX(ti.created_at) AS created_at
  FROM tmp_sale_items tsi
  JOIN line_item s
    ON s.id_line_item = tsi.id_sale_item
   AND s.item_type = 'sale_item'
  JOIN line_item_catalog_parent lcp
    ON lcp.id_parent_sale_item_catalog = s.id_line_item_catalog
   AND lcp.deleted_at IS NULL
   AND lcp.is_active = 1
  JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = lcp.id_sale_item_catalog
   AND tr.catalog_type = 'tax_rule'
  LEFT JOIN line_item ti
    ON ti.id_folio = s.id_folio
   AND ti.item_type = 'tax_item'
   AND ti.id_line_item_catalog = tr.id_line_item_catalog
   AND ti.deleted_at IS NULL
   AND ti.is_active = 1
   AND (ti.service_date <=> s.service_date)
  WHERE (
    p_show_inactive IS NOT NULL AND p_show_inactive <> 0
    OR (ti.deleted_at IS NULL AND ti.is_active = 1)
  )
  GROUP BY tsi.id_sale_item, tsi.currency, tr.id_line_item_catalog, tr.item_name, COALESCE(lcp.percent_value, 0)
  HAVING COALESCE(SUM(ti.amount_cents),0) <> 0 OR COUNT(ti.id_line_item) > 0
  ORDER BY tsi.id_sale_item, tr.item_name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_sale_item_upsert` (IN `p_action` VARCHAR(16), IN `p_id_sale_item` BIGINT, IN `p_id_folio` BIGINT, IN `p_id_reservation` BIGINT, IN `p_id_sale_item_catalog` BIGINT, IN `p_description` TEXT, IN `p_service_date` DATE, IN `p_quantity` DECIMAL(18,6), IN `p_unit_price_cents` INT, IN `p_discount_amount_cents` INT, IN `p_status` VARCHAR(32), IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_id_folio BIGINT;
  DECLARE v_currency VARCHAR(10);
  DECLARE v_catalog_id BIGINT;
  DECLARE v_default_price INT DEFAULT 0;
  DECLARE v_catalog_type VARCHAR(32);
  DECLARE v_catalog_name VARCHAR(255);
  DECLARE v_qty DECIMAL(18,6) DEFAULT 1;
  DECLARE v_unit_price INT DEFAULT 0;
  DECLARE v_discount INT DEFAULT 0;
  DECLARE v_amount_cents INT DEFAULT 0;
  DECLARE v_service_date DATE;
  DECLARE v_target_sale_item BIGINT;
  DECLARE v_item_type VARCHAR(32) DEFAULT 'sale_item';
  DECLARE v_allow_negative TINYINT DEFAULT 0;
  DECLARE v_skip_percent_recalc TINYINT DEFAULT 0;
  DECLARE v_recalc_parent_catalog_id BIGINT;
  DECLARE v_prev_skip_percent_recalc TINYINT DEFAULT 0;
  DECLARE v_reservation_id_eff BIGINT DEFAULT NULL;
  DECLARE v_payment_catalog_is_ota TINYINT DEFAULT 0;
  DECLARE v_ota_from_payment_id BIGINT DEFAULT NULL;
  DECLARE v_ota_from_lodging_id BIGINT DEFAULT NULL;
  DECLARE v_ota_platform_detected VARCHAR(32) DEFAULT NULL;
  DECLARE v_source_detected VARCHAR(120) DEFAULT NULL;
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;
  DECLARE v_property_code VARCHAR(100) DEFAULT NULL;

  IF p_action IS NULL OR TRIM(p_action) = '' THEN
    SET p_action = 'create';
  END IF;

  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for sale_item';
  END IF;

  SET v_skip_percent_recalc = COALESCE(@pms_skip_percent_derived, 0);

  IF p_action IN ('create','update') THEN
    IF p_id_folio IS NULL OR p_id_folio = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio id is required';
    END IF;

    SELECT f.id_folio, f.currency, c.code, p.code
      INTO v_id_folio, v_currency, v_company_code, v_property_code
    FROM folio f
    JOIN reservation r ON r.id_reservation = f.id_reservation
    JOIN property p ON p.id_property = r.id_property
    JOIN company c ON c.id_company = p.id_company
    WHERE f.id_folio = p_id_folio
      AND f.deleted_at IS NULL
    LIMIT 1;

    IF v_id_folio IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'folio not found';
    END IF;
  END IF;

  IF p_action = 'delete' THEN
    IF p_id_sale_item IS NULL OR p_id_sale_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item id is required';
    END IF;
    SELECT li.id_folio
      INTO v_id_folio
    FROM line_item li
    WHERE li.id_line_item = p_id_sale_item
      AND li.deleted_at IS NULL
    LIMIT 1;
    IF v_id_folio IS NULL OR v_id_folio <= 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item not found';
    END IF;
    SELECT f.currency, c.code, p.code
      INTO v_currency, v_company_code, v_property_code
    FROM folio f
    JOIN reservation r ON r.id_reservation = f.id_reservation
    JOIN property p ON p.id_property = r.id_property
    JOIN company c ON c.id_company = p.id_company
    WHERE f.id_folio = v_id_folio
      AND f.deleted_at IS NULL
    LIMIT 1;
  END IF;

  CALL sp_authz_assert(
    v_company_code,
    p_created_by,
    'reservations.post_charge',
    v_property_code,
    NULL
  );

  IF p_action = 'create' THEN
    IF p_id_sale_item_catalog IS NULL OR p_id_sale_item_catalog = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item_catalog id is required';
    END IF;

    SELECT id_line_item_catalog, COALESCE(default_unit_price_cents, 0), catalog_type, item_name, COALESCE(allow_negative, 0)
      INTO v_catalog_id, v_default_price, v_catalog_type, v_catalog_name, v_allow_negative
    FROM line_item_catalog
    WHERE id_line_item_catalog = p_id_sale_item_catalog
      AND deleted_at IS NULL
      AND is_active = 1
    LIMIT 1;

    IF v_catalog_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'catalog item not found';
    END IF;

    SET v_item_type = CASE LOWER(TRIM(COALESCE(v_catalog_type, '')))
      WHEN 'sale_item' THEN 'sale_item'
      WHEN 'tax_rule' THEN 'tax_item'
      WHEN 'tax_item' THEN 'tax_item'
      WHEN 'tax' THEN 'tax_item'
      WHEN 'impuesto' THEN 'tax_item'
      WHEN 'impuestos' THEN 'tax_item'
      WHEN 'payment' THEN 'payment'
      WHEN 'pago' THEN 'payment'
      WHEN 'obligation' THEN 'obligation'
      WHEN 'obligacion' THEN 'obligation'
      WHEN 'obligación' THEN 'obligation'
      WHEN 'income' THEN 'income'
      WHEN 'ingreso' THEN 'income'
      ELSE ''
    END;

    IF v_item_type = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported catalog type for line item';
    END IF;

    SET v_qty = COALESCE(p_quantity, 1);
    SET v_unit_price = COALESCE(p_unit_price_cents, v_default_price, 0);
    SET v_discount = COALESCE(p_discount_amount_cents, 0);
    SET v_amount_cents = (v_qty * v_unit_price) - v_discount;
    SET v_service_date = p_service_date;

    IF COALESCE(v_amount_cents, 0) <= 0
       AND COALESCE(v_allow_negative, 0) = 0 THEN
      SELECT
        CAST(NULL AS SIGNED) AS id_sale_item,
        CAST(NULL AS SIGNED) AS id_user,
        CAST(NULL AS SIGNED) AS id_folio,
        CAST(NULL AS SIGNED) AS id_reservation,
        CAST(NULL AS SIGNED) AS id_sale_item_catalog,
        CAST(NULL AS SIGNED) AS id_parent_sale_item,
        CAST(NULL AS CHAR) AS description,
        CAST(NULL AS DATE) AS service_date,
        CAST(NULL AS DECIMAL(18,6)) AS quantity,
        CAST(NULL AS SIGNED) AS unit_price_cents,
        CAST(NULL AS SIGNED) AS amount_cents,
        CAST(NULL AS CHAR) AS currency,
        CAST(NULL AS SIGNED) AS discount_amount_cents,
        CAST(NULL AS CHAR) AS revenue_account,
        CAST(NULL AS CHAR) AS status,
        CAST(NULL AS CHAR) AS external_ref,
        CAST(NULL AS SIGNED) AS is_active,
        CAST(NULL AS DATETIME) AS deleted_at,
        CAST(NULL AS DATETIME) AS created_at,
        CAST(NULL AS SIGNED) AS created_by,
        CAST(NULL AS DATETIME) AS updated_at
      LIMIT 0;
      LEAVE proc;
    END IF;

    INSERT INTO line_item (
      item_type,
      id_user,
      id_folio,
      id_line_item_catalog,
      item_name,
      description,
      service_date,
      quantity,
      unit_price_cents,
      amount_cents,
      currency,
      method,
      discount_amount_cents,
      revenue_account_code,
      status,
      external_ref,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      v_item_type,
      p_created_by,
      v_id_folio,
      v_catalog_id,
      v_catalog_name,
      p_description,
      v_service_date,
      v_qty,
      v_unit_price,
      v_amount_cents,
      v_currency,
      CASE WHEN v_item_type = 'payment' THEN v_catalog_name ELSE NULL END,
      v_discount,
      NULL,
      COALESCE(NULLIF(p_status,''), 'posted'),
      NULL,
      1,
      NOW(),
      p_created_by,
      NOW()
    );

    SET v_target_sale_item = LAST_INSERT_ID();
  END IF;

  IF p_action = 'update' THEN
    IF p_id_sale_item IS NULL OR p_id_sale_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item id is required';
    END IF;

    SELECT si.id_line_item_catalog,
           si.quantity,
           si.unit_price_cents,
           si.discount_amount_cents,
           si.service_date,
           si.item_type
      INTO v_catalog_id, v_qty, v_unit_price, v_discount, v_service_date, v_item_type
    FROM line_item si
    WHERE si.id_line_item = p_id_sale_item
      AND si.id_folio = v_id_folio
      AND si.deleted_at IS NULL
    LIMIT 1;

    IF v_catalog_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item not found';
    END IF;

    SET v_allow_negative = 0;
    SELECT COALESCE(lic.allow_negative, 0)
      INTO v_allow_negative
    FROM line_item_catalog lic
    WHERE lic.id_line_item_catalog = v_catalog_id
    LIMIT 1;

    IF p_id_sale_item_catalog IS NOT NULL AND p_id_sale_item_catalog <> 0 THEN
      SELECT id_line_item_catalog, COALESCE(default_unit_price_cents, 0), catalog_type, item_name, COALESCE(allow_negative, 0)
        INTO v_catalog_id, v_default_price, v_catalog_type, v_catalog_name, v_allow_negative
      FROM line_item_catalog
      WHERE id_line_item_catalog = p_id_sale_item_catalog
        AND deleted_at IS NULL
        AND is_active = 1
      LIMIT 1;

      SET v_item_type = CASE LOWER(TRIM(COALESCE(v_catalog_type, '')))
        WHEN 'sale_item' THEN 'sale_item'
        WHEN 'tax_rule' THEN 'tax_item'
        WHEN 'tax_item' THEN 'tax_item'
        WHEN 'tax' THEN 'tax_item'
        WHEN 'impuesto' THEN 'tax_item'
        WHEN 'impuestos' THEN 'tax_item'
        WHEN 'payment' THEN 'payment'
        WHEN 'pago' THEN 'payment'
        WHEN 'obligation' THEN 'obligation'
        WHEN 'obligacion' THEN 'obligation'
        WHEN 'obligación' THEN 'obligation'
        WHEN 'income' THEN 'income'
        WHEN 'ingreso' THEN 'income'
        ELSE ''
      END;

      IF v_catalog_id IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'catalog item not found';
      END IF;
      IF v_item_type = '' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported catalog type for line item';
      END IF;
    END IF;

    SET v_qty = COALESCE(p_quantity, v_qty);
    SET v_unit_price = COALESCE(p_unit_price_cents, v_unit_price);
    SET v_discount = COALESCE(p_discount_amount_cents, v_discount);
    SET v_amount_cents = (v_qty * v_unit_price) - v_discount;
    SET v_service_date = COALESCE(p_service_date, v_service_date);
    IF v_item_type = 'payment' AND (v_catalog_name IS NULL OR TRIM(v_catalog_name) = '') THEN
      SELECT item_name INTO v_catalog_name
      FROM line_item_catalog
      WHERE id_line_item_catalog = v_catalog_id
      LIMIT 1;
    END IF;

    IF COALESCE(v_amount_cents, 0) <= 0
       AND COALESCE(v_allow_negative, 0) = 0 THEN
      SET p_action = 'delete';
    ELSE
      UPDATE line_item
         SET id_line_item_catalog = v_catalog_id,
             item_name = COALESCE(v_catalog_name, item_name),
             item_type = v_item_type,
             method = CASE
               WHEN v_item_type = 'payment' THEN COALESCE(v_catalog_name, method)
               ELSE method
             END,
             description = COALESCE(p_description, description),
             service_date = v_service_date,
             quantity = v_qty,
             unit_price_cents = v_unit_price,
             discount_amount_cents = v_discount,
             amount_cents = v_amount_cents,
             status = COALESCE(NULLIF(p_status,''), status),
             updated_at = NOW()
       WHERE id_line_item = p_id_sale_item
         AND id_folio = v_id_folio;

      SET v_target_sale_item = p_id_sale_item;
    END IF;
  END IF;

  IF p_action = 'delete' THEN
    IF p_id_sale_item IS NULL OR p_id_sale_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item id is required';
    END IF;

    SELECT id_folio, id_line_item_catalog, service_date
      INTO v_id_folio, v_catalog_id, v_service_date
    FROM line_item
    WHERE id_line_item = p_id_sale_item
    LIMIT 1;

    UPDATE line_item
       SET is_active = 0,
           status = 'void',
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item = p_id_sale_item
       AND deleted_at IS NULL;

    IF v_skip_percent_recalc = 0
       AND v_id_folio IS NOT NULL
       AND v_catalog_id IS NOT NULL
       AND v_catalog_id > 0 THEN
      SET v_prev_skip_percent_recalc = COALESCE(@pms_skip_percent_derived, 0);
      SET @pms_skip_percent_derived = 1;

      DROP TEMPORARY TABLE IF EXISTS tmp_siu_recalc_parents;
      CREATE TEMPORARY TABLE tmp_siu_recalc_parents (
        parent_catalog_id BIGINT PRIMARY KEY,
        processed TINYINT NOT NULL DEFAULT 0
      ) ENGINE=MEMORY;

      INSERT IGNORE INTO tmp_siu_recalc_parents (parent_catalog_id)
      SELECT lcp.id_parent_sale_item_catalog
      FROM line_item_catalog_parent lcp
      WHERE lcp.id_sale_item_catalog = v_catalog_id
        AND lcp.deleted_at IS NULL
        AND lcp.is_active = 1
        AND lcp.percent_value IS NOT NULL;

      INSERT IGNORE INTO tmp_siu_recalc_parents (parent_catalog_id)
      SELECT licc.id_parent_line_item_catalog
      FROM line_item_catalog_calc licc
      WHERE licc.id_component_line_item_catalog = v_catalog_id
        AND licc.deleted_at IS NULL
        AND licc.is_active = 1;

      IF EXISTS (
        SELECT 1
        FROM line_item_catalog_parent lcp
        WHERE lcp.id_parent_sale_item_catalog = v_catalog_id
          AND lcp.deleted_at IS NULL
          AND lcp.is_active = 1
          AND lcp.percent_value IS NOT NULL
      ) THEN
        INSERT IGNORE INTO tmp_siu_recalc_parents (parent_catalog_id)
        VALUES (v_catalog_id);
      END IF;

      recalc_loop_delete:LOOP
        SET v_recalc_parent_catalog_id = NULL;
        SELECT t.parent_catalog_id
          INTO v_recalc_parent_catalog_id
        FROM tmp_siu_recalc_parents t
        WHERE t.processed = 0
        ORDER BY t.parent_catalog_id
        LIMIT 1;

        IF v_recalc_parent_catalog_id IS NULL OR v_recalc_parent_catalog_id <= 0 THEN
          LEAVE recalc_loop_delete;
        END IF;

        UPDATE tmp_siu_recalc_parents
           SET processed = 1
         WHERE parent_catalog_id = v_recalc_parent_catalog_id;

        CALL sp_line_item_percent_derived_upsert(
          v_id_folio,
          p_id_reservation,
          v_recalc_parent_catalog_id,
          v_service_date,
          p_created_by
        );
      END LOOP;

      DROP TEMPORARY TABLE IF EXISTS tmp_siu_recalc_parents;
      SET @pms_skip_percent_derived = v_prev_skip_percent_recalc;
    END IF;

    IF v_id_folio IS NOT NULL THEN
      CALL sp_folio_recalc(v_id_folio);
    END IF;

    SELECT
      id_line_item AS id_sale_item,
      id_user,
      id_folio,
      CAST(NULL AS SIGNED) AS id_reservation,
      id_line_item_catalog AS id_sale_item_catalog,
      CAST(NULL AS SIGNED) AS id_parent_sale_item,
      description,
      service_date,
      quantity,
      unit_price_cents,
      amount_cents,
      currency,
      discount_amount_cents,
      revenue_account_code AS revenue_account,
      status,
      external_ref,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item
    WHERE id_line_item = p_id_sale_item;

    LEAVE proc;
  END IF;

  /* No auto tax rebuild here. Tax items must be managed as regular line_item rows. */

  IF v_skip_percent_recalc = 0
     AND v_id_folio IS NOT NULL
     AND v_catalog_id IS NOT NULL
     AND v_catalog_id > 0 THEN
    SET v_prev_skip_percent_recalc = COALESCE(@pms_skip_percent_derived, 0);
    SET @pms_skip_percent_derived = 1;

    DROP TEMPORARY TABLE IF EXISTS tmp_siu_recalc_parents;
    CREATE TEMPORARY TABLE tmp_siu_recalc_parents (
      parent_catalog_id BIGINT PRIMARY KEY,
      processed TINYINT NOT NULL DEFAULT 0
    ) ENGINE=MEMORY;

    INSERT IGNORE INTO tmp_siu_recalc_parents (parent_catalog_id)
    SELECT lcp.id_parent_sale_item_catalog
    FROM line_item_catalog_parent lcp
    WHERE lcp.id_sale_item_catalog = v_catalog_id
      AND lcp.deleted_at IS NULL
      AND lcp.is_active = 1
      AND lcp.percent_value IS NOT NULL;

    INSERT IGNORE INTO tmp_siu_recalc_parents (parent_catalog_id)
    SELECT licc.id_parent_line_item_catalog
    FROM line_item_catalog_calc licc
    WHERE licc.id_component_line_item_catalog = v_catalog_id
      AND licc.deleted_at IS NULL
      AND licc.is_active = 1;

    IF EXISTS (
      SELECT 1
      FROM line_item_catalog_parent lcp
      WHERE lcp.id_parent_sale_item_catalog = v_catalog_id
        AND lcp.deleted_at IS NULL
        AND lcp.is_active = 1
        AND lcp.percent_value IS NOT NULL
    ) THEN
      INSERT IGNORE INTO tmp_siu_recalc_parents (parent_catalog_id)
      VALUES (v_catalog_id);
    END IF;

    recalc_loop_upsert:LOOP
      SET v_recalc_parent_catalog_id = NULL;
      SELECT t.parent_catalog_id
        INTO v_recalc_parent_catalog_id
      FROM tmp_siu_recalc_parents t
      WHERE t.processed = 0
      ORDER BY t.parent_catalog_id
      LIMIT 1;

      IF v_recalc_parent_catalog_id IS NULL OR v_recalc_parent_catalog_id <= 0 THEN
        LEAVE recalc_loop_upsert;
      END IF;

      UPDATE tmp_siu_recalc_parents
         SET processed = 1
       WHERE parent_catalog_id = v_recalc_parent_catalog_id;

      CALL sp_line_item_percent_derived_upsert(
        v_id_folio,
        p_id_reservation,
        v_recalc_parent_catalog_id,
        v_service_date,
        p_created_by
      );
    END LOOP;

    DROP TEMPORARY TABLE IF EXISTS tmp_siu_recalc_parents;
    SET @pms_skip_percent_derived = v_prev_skip_percent_recalc;
  END IF;

  CALL sp_folio_recalc(v_id_folio);

  /*
    Si el line item actual es de tipo payment y su catalogo esta ligado
    como concepto de pago OTA, sincroniza el source de la reservacion con
    la OTA detectada por concepto de hospedaje.
  */
  IF p_action IN ('create','update')
     AND v_item_type = 'payment'
     AND v_catalog_id IS NOT NULL
     AND v_catalog_id > 0
     AND v_id_folio IS NOT NULL
     AND v_id_folio > 0 THEN

    SET v_reservation_id_eff = NULL;
    IF p_id_reservation IS NOT NULL AND p_id_reservation > 0 THEN
      SET v_reservation_id_eff = p_id_reservation;
    ELSE
      SELECT f.id_reservation
        INTO v_reservation_id_eff
      FROM folio f
      WHERE f.id_folio = v_id_folio
      LIMIT 1;
    END IF;

    IF v_reservation_id_eff IS NOT NULL AND v_reservation_id_eff > 0 THEN
      SET v_payment_catalog_is_ota = 0;
      SET v_ota_from_payment_id = NULL;
      SET v_ota_from_lodging_id = NULL;
      SET v_ota_platform_detected = NULL;
      SET v_source_detected = NULL;

      SELECT oa.id_ota_account
        INTO v_ota_from_payment_id
      FROM reservation r
      JOIN property p
        ON p.id_property = r.id_property
      JOIN ota_account oa
        ON oa.id_company = p.id_company
       AND oa.id_property = p.id_property
       AND oa.deleted_at IS NULL
       AND oa.is_active = 1
      WHERE r.id_reservation = v_reservation_id_eff
        AND oa.id_service_fee_payment_catalog = v_catalog_id
      LIMIT 1;

      IF v_ota_from_payment_id IS NOT NULL AND v_ota_from_payment_id > 0 THEN
        SET v_payment_catalog_is_ota = 1;

        SELECT oa.id_ota_account, oa.platform
          INTO v_ota_from_lodging_id, v_ota_platform_detected
        FROM reservation r
        JOIN property p
          ON p.id_property = r.id_property
        JOIN folio f
          ON f.id_reservation = r.id_reservation
         AND f.deleted_at IS NULL
        JOIN line_item li
          ON li.id_folio = f.id_folio
         AND li.item_type = 'sale_item'
         AND li.deleted_at IS NULL
         AND li.is_active = 1
        JOIN ota_account_lodging_catalog oalc
          ON oalc.id_line_item_catalog = li.id_line_item_catalog
         AND oalc.deleted_at IS NULL
         AND oalc.is_active = 1
        JOIN ota_account oa
          ON oa.id_ota_account = oalc.id_ota_account
         AND oa.id_company = p.id_company
         AND oa.id_property = p.id_property
         AND oa.deleted_at IS NULL
         AND oa.is_active = 1
        WHERE r.id_reservation = v_reservation_id_eff
        ORDER BY oalc.sort_order, li.id_line_item, oa.id_ota_account
        LIMIT 1;

        IF v_ota_from_lodging_id IS NULL OR v_ota_from_lodging_id <= 0 THEN
          SET v_ota_from_lodging_id = v_ota_from_payment_id;
          SELECT oa.platform
            INTO v_ota_platform_detected
          FROM ota_account oa
          WHERE oa.id_ota_account = v_ota_from_lodging_id
            AND oa.deleted_at IS NULL
            AND oa.is_active = 1
          LIMIT 1;
        END IF;

        IF v_ota_from_lodging_id IS NOT NULL AND v_ota_from_lodging_id > 0 THEN
          SET v_ota_platform_detected = LOWER(TRIM(COALESCE(v_ota_platform_detected, 'other')));
          SET v_source_detected = CASE
            WHEN v_ota_platform_detected = 'booking' THEN 'Booking'
            WHEN v_ota_platform_detected = 'airbnb' OR v_ota_platform_detected = 'abb' THEN 'Airbnb'
            WHEN v_ota_platform_detected = 'expedia' THEN 'Expedia'
            ELSE 'OTA'
          END;

          UPDATE reservation
             SET id_ota_account = v_ota_from_lodging_id,
                 id_reservation_source = NULL,
                 source = v_source_detected,
                 updated_at = NOW()
           WHERE id_reservation = v_reservation_id_eff;
        END IF;
      END IF;
    END IF;
  END IF;

  SELECT
    id_line_item AS id_sale_item,
    id_user,
    id_folio,
    CAST(NULL AS SIGNED) AS id_reservation,
    id_line_item_catalog AS id_sale_item_catalog,
    CAST(NULL AS SIGNED) AS id_parent_sale_item,
    description,
    service_date,
    quantity,
    unit_price_cents,
    amount_cents,
    currency,
    discount_amount_cents,
    revenue_account_code AS revenue_account,
    status,
    external_ref,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item
  WHERE id_line_item = v_target_sale_item;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_search_availability` (IN `p_company_code` VARCHAR(100), IN `p_check_in` DATE, IN `p_nights` INT, IN `p_people` INT)   BEGIN
    DECLARE v_check_out DATE;
    SET v_check_out = DATE_ADD(p_check_in, INTERVAL p_nights DAY);

    /* One row per active room category with at least 1 room available */
    SELECT
      p.id_property,
      p.code  AS property_code,
      p.name  AS property_name,
      p.currency,
      rc.id_category,
      rc.code AS category_code,
      rc.name AS category_name,
      rc.max_occupancy,
      /* totals per category */
      (
        SELECT COUNT(*)
        FROM room r
        WHERE r.id_category = rc.id_category
          AND r.is_active = 1
          AND r.deleted_at IS NULL
      ) AS total_rooms,
      (
        SELECT COUNT(DISTINCT r2.id_room)
        FROM room r2
        WHERE r2.id_category = rc.id_category
          AND r2.is_active = 1
          AND r2.deleted_at IS NULL
          AND (
            EXISTS (
              SELECT 1
              FROM reservation res
              WHERE res.id_room = r2.id_room
                AND res.deleted_at IS NULL
                AND COALESCE(res.status,'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
                AND res.check_in_date  < v_check_out
                AND res.check_out_date > p_check_in
            )
            OR EXISTS (
              SELECT 1
              FROM room_block rb
              WHERE rb.id_room = r2.id_room
                AND rb.deleted_at IS NULL
                AND rb.is_active = 1
                AND rb.start_date < v_check_out
                AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > p_check_in
            )
          )
      ) AS booked_rooms,
      GREATEST(
        (
          SELECT COUNT(*) FROM room r
          WHERE r.id_category = rc.id_category AND r.is_active=1 AND r.deleted_at IS NULL
        ) - (
          SELECT COUNT(DISTINCT r2.id_room) FROM room r2
          WHERE r2.id_category = rc.id_category AND r2.is_active=1 AND r2.deleted_at IS NULL
            AND (
              EXISTS (
                SELECT 1 FROM reservation res
                WHERE res.id_room = r2.id_room
                  AND res.deleted_at IS NULL
                  AND COALESCE(res.status,'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
                  AND res.check_in_date  < v_check_out AND res.check_out_date > p_check_in
              )
              OR EXISTS (
                SELECT 1 FROM room_block rb
                WHERE rb.id_room = r2.id_room
                  AND rb.deleted_at IS NULL
                  AND rb.is_active = 1
                  AND rb.start_date < v_check_out
                  AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > p_check_in
              )
            )
        ), 0
      ) AS available_rooms,
      rc.default_floor_cents,
      rc.default_ceil_cents,
      rc.default_base_price_cents,
      rc.image_url
    FROM roomcategory rc
    INNER JOIN property p ON p.id_property = rc.id_property
    INNER JOIN company  c ON c.id_company = p.id_company
    WHERE c.code = p_company_code
      AND c.deleted_at IS NULL
      AND p.is_active = 1 AND p.deleted_at IS NULL
      AND rc.is_active = 1 AND rc.deleted_at IS NULL
      AND (rc.max_occupancy IS NULL OR rc.max_occupancy >= p_people)
      /* at least one available */
      AND GREATEST(
        (
          SELECT COUNT(*) FROM room r
          WHERE r.id_category = rc.id_category AND r.is_active=1 AND r.deleted_at IS NULL
        ) - (
          SELECT COUNT(DISTINCT r2.id_room) FROM room r2
          WHERE r2.id_category = rc.id_category AND r2.is_active=1 AND r2.deleted_at IS NULL
            AND (
              EXISTS (
                SELECT 1 FROM reservation res
                WHERE res.id_room = r2.id_room
                  AND res.deleted_at IS NULL
                  AND COALESCE(res.status,'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
                  AND res.check_in_date  < v_check_out AND res.check_out_date > p_check_in
              )
              OR EXISTS (
                SELECT 1 FROM room_block rb
                WHERE rb.id_room = r2.id_room
                  AND rb.deleted_at IS NULL
                  AND rb.is_active = 1
                  AND rb.start_date < v_check_out AND DATE_ADD(rb.end_date, INTERVAL 1 DAY) > p_check_in
              )
            )
        ), 0
      ) > 0
    ORDER BY p.name, rc.name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_tax_item_report_data` (IN `p_company_code` VARCHAR(100), IN `p_property_code` VARCHAR(100), IN `p_from` DATE, IN `p_to` DATE, IN `p_tax_rule_id` BIGINT, IN `p_search` TEXT, IN `p_min_amount_cents` INT, IN `p_max_amount_cents` INT, IN `p_show_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_property_id BIGINT;
  DECLARE v_search TEXT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF p_property_code IS NOT NULL AND p_property_code <> '' THEN
    SELECT id_property INTO v_property_id
    FROM property
    WHERE code = p_property_code
      AND id_company = v_company_id
      AND deleted_at IS NULL
    LIMIT 1;
    IF v_property_id IS NULL THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property';
    END IF;
  ELSE
    SET v_property_id = NULL;
  END IF;

  SET v_search = NULLIF(TRIM(p_search), '');

  SELECT
    ti.id_line_item AS id_tax_item,
    ti.id_sale_item,
    ti.id_tax_rule,
    tr.name AS tax_name,
    tr.rate_percent,
    ti.amount_cents,
    ti.is_active,
    COALESCE(si.currency, 'MXN') AS currency,
    COALESCE(si.service_date, DATE(si.created_at)) AS service_date,
    sic.item_name AS sale_item_name,
    si.id_parent_sale_item,
    si.amount_cents AS sale_amount_cents,
    r.id_reservation,
    r.code AS reservation_code,
    p.code AS property_code,
    p.name AS property_name,
    f.folio_name,
    f.status AS folio_status,
    CONCAT_WS(' ', COALESCE(g.names,''), COALESCE(g.last_name,'')) AS guest_name,
    g.email AS guest_email,
    si.description AS sale_description,
    ti.created_at
  FROM line_item ti
  JOIN line_item_catalog tr
    ON tr.id_line_item_catalog = ti.id_tax_rule
   AND tr.catalog_type = 'tax_rule'
  JOIN line_item si
    ON si.id_line_item = ti.id_sale_item
   AND si.item_type = 'sale_item'
  LEFT JOIN line_item_catalog sic
    ON sic.id_line_item_catalog = si.id_sale_item_catalog
   AND sic.catalog_type = 'sale_item'
  JOIN folio f ON f.id_folio = si.id_folio
  LEFT JOIN reservation r ON r.id_reservation = COALESCE(si.id_reservation, f.id_reservation)
  LEFT JOIN property p ON p.id_property = r.id_property
  LEFT JOIN guest g ON g.id_guest = r.id_guest
  WHERE tr.id_company = v_company_id
    AND ti.item_type = 'tax_item'
    AND f.deleted_at IS NULL
    AND (r.id_reservation IS NULL OR r.deleted_at IS NULL)
    AND (v_property_id IS NULL OR r.id_property = v_property_id)
    AND (p_from IS NULL OR COALESCE(si.service_date, DATE(si.created_at)) >= p_from)
    AND (p_to IS NULL OR COALESCE(si.service_date, DATE(si.created_at)) <= p_to)
    AND (p_tax_rule_id IS NULL OR p_tax_rule_id = 0 OR ti.id_tax_rule = p_tax_rule_id)
    AND (
      p_min_amount_cents IS NULL
      OR p_min_amount_cents <= 0
      OR ti.amount_cents >= p_min_amount_cents
    )
    AND (
      p_max_amount_cents IS NULL
      OR p_max_amount_cents <= 0
      OR ti.amount_cents <= p_max_amount_cents
    )
    AND (
      v_search IS NULL
      OR r.code LIKE CONCAT('%', v_search, '%')
      OR f.folio_name LIKE CONCAT('%', v_search, '%')
      OR g.names LIKE CONCAT('%', v_search, '%')
      OR g.last_name LIKE CONCAT('%', v_search, '%')
      OR g.email LIKE CONCAT('%', v_search, '%')
      OR si.description LIKE CONCAT('%', v_search, '%')
      OR tr.name LIKE CONCAT('%', v_search, '%')
    )
    AND (
      p_show_inactive IS NOT NULL AND p_show_inactive <> 0
      OR (ti.deleted_at IS NULL AND ti.is_active = 1)
    )
  ORDER BY COALESCE(si.service_date, DATE(si.created_at)) DESC, ti.id_line_item DESC;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_tax_item_upsert` (IN `p_action` VARCHAR(16), IN `p_id_tax_item` BIGINT, IN `p_id_sale_item` BIGINT, IN `p_id_tax_rule` BIGINT, IN `p_amount_cents` INT, IN `p_created_by` BIGINT)   proc:BEGIN
  DECLARE v_id_sale_item BIGINT;
  DECLARE v_id_tax_rule BIGINT;

  IF p_action IS NULL OR p_action = '' THEN
    SET p_action = 'create';
  END IF;
  IF p_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for tax_item';
  END IF;

  IF p_action = 'delete' THEN
    IF p_id_tax_item IS NULL OR p_id_tax_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_item id is required';
    END IF;
    UPDATE line_item
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item = p_id_tax_item
       AND item_type = 'tax_item';
    CALL sp_obligation_sync_for_tax_item(p_id_tax_item, p_created_by);
    CALL sp_income_sync_for_tax_item(p_id_tax_item, p_created_by);
    SELECT
      id_line_item AS id_tax_item,
      id_sale_item,
      id_tax_rule,
      amount_cents,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item
    WHERE id_line_item = p_id_tax_item;
    LEAVE proc;
  END IF;

  IF p_id_sale_item IS NULL OR p_id_sale_item = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item id is required';
  END IF;
  SELECT id_line_item INTO v_id_sale_item
  FROM line_item
  WHERE id_line_item = p_id_sale_item
    AND item_type = 'sale_item'
    AND deleted_at IS NULL
  LIMIT 1;
  IF v_id_sale_item IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sale_item not found';
  END IF;

  IF p_id_tax_rule IS NULL OR p_id_tax_rule = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_rule id is required';
  END IF;
  SELECT id_line_item_catalog INTO v_id_tax_rule
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_tax_rule
    AND catalog_type = 'tax_rule'
    AND deleted_at IS NULL
  LIMIT 1;
  IF v_id_tax_rule IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_rule not found';
  END IF;

  IF p_action = 'create' THEN
    INSERT INTO line_item (
      item_type,
      id_sale_item,
      id_tax_rule,
      id_line_item_catalog,
      amount_cents,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      'tax_item',
      v_id_sale_item,
      v_id_tax_rule,
      v_id_tax_rule,
      COALESCE(p_amount_cents,0),
      1,
      NOW(),
      p_created_by,
      NOW()
    )
    ON DUPLICATE KEY UPDATE
      amount_cents = VALUES(amount_cents),
      is_active = 1,
      deleted_at = NULL,
      updated_at = NOW();
    SET p_id_tax_item = LAST_INSERT_ID();
  ELSE
    IF p_id_tax_item IS NULL OR p_id_tax_item = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'tax_item id is required';
    END IF;
    UPDATE line_item
       SET id_sale_item = v_id_sale_item,
           id_tax_rule = v_id_tax_rule,
           id_line_item_catalog = v_id_tax_rule,
           amount_cents = COALESCE(p_amount_cents, amount_cents),
           is_active = 1,
           deleted_at = NULL,
           updated_at = NOW()
     WHERE id_line_item = p_id_tax_item
       AND item_type = 'tax_item';
  END IF;

  CALL sp_obligation_sync_for_tax_item(p_id_tax_item, p_created_by);
  CALL sp_income_sync_for_tax_item(p_id_tax_item, p_created_by);
  SELECT
    id_line_item AS id_tax_item,
    id_sale_item,
    id_tax_rule,
    amount_cents,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item
  WHERE id_line_item = p_id_tax_item;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_tax_rule_data` (IN `p_company_code` VARCHAR(100), IN `p_ids` TEXT, IN `p_show_inactive` TINYINT)   BEGIN
  DECLARE v_company_id BIGINT;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;
  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  SELECT
    lic.id_line_item_catalog AS id_tax_rule,
    lic.name,
    lic.rate_percent,
    lic.description,
    lic.show_in_folio,
    lic.is_active
  FROM line_item_catalog lic
  WHERE lic.catalog_type = 'tax_rule'
    AND lic.id_company = v_company_id
    AND lic.deleted_at IS NULL
    AND (p_show_inactive IS NOT NULL AND p_show_inactive <> 0 OR lic.is_active = 1)
    AND (p_ids IS NULL OR p_ids = '' OR FIND_IN_SET(lic.id_line_item_catalog, p_ids))
  ORDER BY lic.id_line_item_catalog;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_tax_rule_upsert` (IN `p_action` VARCHAR(16), IN `p_id_tax_rule` BIGINT, IN `p_company_code` VARCHAR(100), IN `p_name` VARCHAR(255), IN `p_rate_percent` DECIMAL(9,4), IN `p_description` TEXT, IN `p_show_in_folio` TINYINT, IN `p_is_active` TINYINT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_tax_rule_id BIGINT;
  DECLARE v_action VARCHAR(16);

  SET v_action = COALESCE(NULLIF(p_action,''),'create');
  IF v_action NOT IN ('create','update','delete') THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'unsupported action for tax_rule';
  END IF;

  IF p_company_code IS NULL OR p_company_code = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;

  SELECT id_company INTO v_company_id
  FROM company
  WHERE code = p_company_code
  LIMIT 1;

  IF v_company_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company';
  END IF;

  IF v_action = 'create' THEN
    IF p_name IS NULL OR p_name = '' THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Tax rule name is required';
    END IF;

    INSERT INTO line_item_catalog (
      catalog_type,
      id_company,
      name,
      rate_percent,
      description,
      show_in_folio,
      is_active,
      created_at,
      created_by,
      updated_at
    ) VALUES (
      'tax_rule',
      v_company_id,
      p_name,
      COALESCE(p_rate_percent, 0),
      p_description,
      COALESCE(p_show_in_folio, 1),
      COALESCE(p_is_active, 1),
      NOW(),
      p_actor_user_id,
      NOW()
    );
    SET v_tax_rule_id = LAST_INSERT_ID();
    SELECT
      id_line_item_catalog AS id_tax_rule,
      id_company,
      name,
      rate_percent,
      description,
      show_in_folio,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_tax_rule_id;
    LEAVE proc;
  END IF;

  IF p_id_tax_rule IS NULL OR p_id_tax_rule = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Tax rule id is required';
  END IF;

  SELECT id_line_item_catalog INTO v_tax_rule_id
  FROM line_item_catalog
  WHERE id_line_item_catalog = p_id_tax_rule
    AND catalog_type = 'tax_rule'
    AND id_company = v_company_id
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_tax_rule_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Tax rule not found';
  END IF;

  IF v_action = 'delete' THEN
    UPDATE line_item_catalog
       SET is_active = 0,
           deleted_at = NOW(),
           updated_at = NOW()
     WHERE id_line_item_catalog = v_tax_rule_id;
    SELECT
      id_line_item_catalog AS id_tax_rule,
      id_company,
      name,
      rate_percent,
      description,
      show_in_folio,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    FROM line_item_catalog
    WHERE id_line_item_catalog = v_tax_rule_id;
    LEAVE proc;
  END IF;

  UPDATE line_item_catalog
     SET name = COALESCE(NULLIF(p_name,''), name),
         rate_percent = COALESCE(p_rate_percent, rate_percent),
         description = p_description,
         show_in_folio = COALESCE(p_show_in_folio, show_in_folio),
         is_active = COALESCE(p_is_active, is_active),
         updated_at = NOW()
   WHERE id_line_item_catalog = v_tax_rule_id;

  SELECT
    id_line_item_catalog AS id_tax_rule,
    id_company,
    name,
    rate_percent,
    description,
    show_in_folio,
    is_active,
    deleted_at,
    created_at,
    created_by,
    updated_at
  FROM line_item_catalog
  WHERE id_line_item_catalog = v_tax_rule_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_update_room_block` (IN `p_room_block_id` BIGINT, IN `p_property_code` VARCHAR(100), IN `p_room_code` VARCHAR(100), IN `p_start_date` VARCHAR(32), IN `p_end_date` VARCHAR(32), IN `p_description` TEXT, IN `p_actor_user` BIGINT)   proc:BEGIN
  DECLARE v_id_room BIGINT;
  DECLARE v_id_property BIGINT;
  DECLARE v_current_property_code VARCHAR(100);
  DECLARE v_current_room_code VARCHAR(100);
  DECLARE v_target_property_code VARCHAR(100);
  DECLARE v_target_room_code VARCHAR(100);
  DECLARE v_new_property BIGINT;
  DECLARE v_new_room BIGINT;
  DECLARE v_check_in DATE;
  DECLARE v_check_out DATE;
  DECLARE v_actor BIGINT;
  DECLARE v_overlap_res INT DEFAULT 0;
  DECLARE v_overlap_block INT DEFAULT 0;
  DECLARE v_end_exclusive DATE;
  DECLARE v_start_text VARCHAR(32);
  DECLARE v_end_text VARCHAR(32);
  DECLARE v_company_code VARCHAR(100) DEFAULT NULL;

  IF p_room_block_id IS NULL OR p_room_block_id = 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Block id is required';
  END IF;

  SELECT rb.id_room, rb.id_property, pr.code, rm.code
    INTO v_id_room, v_id_property, v_current_property_code, v_current_room_code
  FROM room_block rb
  JOIN property pr ON pr.id_property = rb.id_property
  JOIN room rm ON rm.id_room = rb.id_room
  WHERE rb.id_room_block = p_room_block_id
    AND rb.deleted_at IS NULL
  LIMIT 1;

  IF v_id_room IS NULL OR v_id_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Block not found';
  END IF;

  SET v_current_property_code = UPPER(v_current_property_code);
  SET v_current_room_code = UPPER(v_current_room_code);

  SET v_target_property_code = NULLIF(TRIM(p_property_code), '');
  IF v_target_property_code IS NULL THEN
    SET v_target_property_code = v_current_property_code;
  ELSE
    SET v_target_property_code = UPPER(v_target_property_code);
  END IF;

  SELECT p.id_property, c.code
    INTO v_new_property, v_company_code
  FROM property p
  JOIN company c ON c.id_company = p.id_company
  WHERE p.code = v_target_property_code
    AND p.deleted_at IS NULL
  LIMIT 1;

  IF v_new_property IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown property code';
  END IF;

  SET v_target_room_code = NULLIF(TRIM(p_room_code), '');
  IF v_target_room_code IS NULL THEN
    SET v_target_room_code = v_current_room_code;
  ELSE
    SET v_target_room_code = UPPER(v_target_room_code);
  END IF;

  SELECT id_room
    INTO v_new_room
  FROM room
  WHERE code = v_target_room_code
    AND id_property = v_new_property
    AND deleted_at IS NULL
  LIMIT 1;

  IF v_new_room IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown room code for that property';
  END IF;

  SET v_start_text = TRIM(COALESCE(p_start_date, ''));
  SET v_end_text = TRIM(COALESCE(p_end_date, ''));

  SET v_check_in = COALESCE(
    STR_TO_DATE(v_start_text, '%Y-%m-%d'),
    STR_TO_DATE(v_start_text, '%d/%m/%Y'),
    STR_TO_DATE(v_start_text, '%m/%d/%Y'),
    STR_TO_DATE(v_start_text, '%d-%m-%Y'),
    STR_TO_DATE(v_start_text, '%m-%d-%Y'),
    STR_TO_DATE(v_start_text, '%Y/%m/%d')
  );

  SET v_check_out = COALESCE(
    STR_TO_DATE(v_end_text, '%Y-%m-%d'),
    STR_TO_DATE(v_end_text, '%d/%m/%Y'),
    STR_TO_DATE(v_end_text, '%m/%d/%Y'),
    STR_TO_DATE(v_end_text, '%d-%m-%Y'),
    STR_TO_DATE(v_end_text, '%m-%d-%Y'),
    STR_TO_DATE(v_end_text, '%Y/%m/%d')
  );

  IF v_check_in IS NULL OR v_check_out IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Invalid date format';
  END IF;

  IF v_check_out <= v_check_in THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'End date must be after start date';
  END IF;

  SET v_end_exclusive = DATE_ADD(v_check_out, INTERVAL 1 DAY);

  IF p_actor_user IS NOT NULL AND p_actor_user <> 0 THEN
    SELECT id_user INTO v_actor FROM app_user WHERE id_user = p_actor_user LIMIT 1;
  END IF;

  CALL sp_authz_assert(
    v_company_code,
    COALESCE(v_actor, p_actor_user),
    'calendar.manage_block',
    v_target_property_code,
    NULL
  );

  SELECT COUNT(*)
    INTO v_overlap_res
  FROM reservation
  WHERE id_room = v_new_room
    AND deleted_at IS NULL
    AND COALESCE(status, 'confirmado') NOT IN ('cancelled','canceled','cancelado','cancelada')
    AND check_in_date < v_end_exclusive
    AND check_out_date > v_check_in;

  IF v_overlap_res > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room already has reservations for those dates';
  END IF;

  SELECT COUNT(*)
    INTO v_overlap_block
  FROM room_block
  WHERE id_room = v_new_room
    AND deleted_at IS NULL
    AND is_active = 1
    AND id_room_block <> p_room_block_id
    AND start_date < v_end_exclusive
    AND DATE_ADD(end_date, INTERVAL 1 DAY) > v_check_in;

  IF v_overlap_block > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Room already has blocks for those dates';
  END IF;

  UPDATE room_block
     SET id_property = v_new_property,
         id_room = v_new_room,
         start_date = v_check_in,
         end_date = v_check_out,
         description = COALESCE(NULLIF(p_description, ''), description),
         id_user = COALESCE(v_actor, id_user),
         updated_at = NOW()
   WHERE id_room_block = p_room_block_id;

  SELECT
    rb.id_room_block,
    rb.code,
    rb.description,
    rb.start_date,
    rb.end_date,
    rb.is_active,
    rb.created_at,
    rb.updated_at,
    rb.id_user,
    rb.id_room,
    rm.code AS room_code,
    rm.name AS room_name,
    rb.id_property,
    pr.code AS property_code,
    pr.name AS property_name
  FROM room_block rb
  JOIN room rm ON rm.id_room = rb.id_room
  JOIN property pr ON pr.id_property = rb.id_property
  WHERE rb.id_room_block = p_room_block_id;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_user_property_sync` (IN `p_company_code` VARCHAR(100), IN `p_user_id` BIGINT, IN `p_property_codes_csv` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_user_company_id BIGINT;
  DECLARE v_codes_csv TEXT;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_user_id IS NULL OR p_user_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'User id is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
    AND c.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SELECT au.id_company
    INTO v_user_company_id
  FROM app_user au
  WHERE au.id_user = p_user_id
    AND au.deleted_at IS NULL
  LIMIT 1;

  IF v_user_company_id IS NULL OR v_user_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'User does not belong to company';
  END IF;

  SET v_codes_csv = REPLACE(TRIM(COALESCE(p_property_codes_csv, '')), ' ', '');

  DELETE up
  FROM user_property up
  JOIN property pr
    ON pr.id_property = up.id_property
  WHERE up.id_user = p_user_id
    AND pr.id_company = v_company_id;

  IF v_codes_csv IS NOT NULL AND v_codes_csv <> '' THEN
    INSERT INTO user_property (
      id_user,
      id_property,
      is_primary,
      title,
      notes,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      p_user_id,
      pr.id_property,
      0,
      NULL,
      NULL,
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM property pr
    WHERE pr.id_company = v_company_id
      AND pr.deleted_at IS NULL
      AND FIND_IN_SET(pr.code, v_codes_csv) > 0;
  END IF;

  SELECT
    up.id_user_property,
    up.id_user,
    up.id_property,
    pr.code AS property_code,
    pr.name AS property_name
  FROM user_property up
  JOIN property pr
    ON pr.id_property = up.id_property
   AND pr.id_company = v_company_id
  WHERE up.id_user = p_user_id
    AND up.deleted_at IS NULL
    AND up.is_active = 1
  ORDER BY pr.order_index, pr.name;
END$$

CREATE DEFINER=`u508158532_rod`@`127.0.0.1` PROCEDURE `sp_user_role_sync` (IN `p_company_code` VARCHAR(100), IN `p_user_id` BIGINT, IN `p_role_ids_csv` TEXT, IN `p_actor_user_id` BIGINT)   proc:BEGIN
  DECLARE v_company_id BIGINT;
  DECLARE v_user_company_id BIGINT;
  DECLARE v_role_ids_csv TEXT;

  IF p_company_code IS NULL OR TRIM(p_company_code) = '' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Company code is required';
  END IF;
  IF p_user_id IS NULL OR p_user_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'User id is required';
  END IF;

  SELECT c.id_company
    INTO v_company_id
  FROM company c
  WHERE c.code = p_company_code
    AND c.deleted_at IS NULL
  LIMIT 1;

  IF v_company_id IS NULL OR v_company_id <= 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Unknown company code';
  END IF;

  SELECT au.id_company
    INTO v_user_company_id
  FROM app_user au
  WHERE au.id_user = p_user_id
    AND au.deleted_at IS NULL
  LIMIT 1;

  IF v_user_company_id IS NULL OR v_user_company_id <> v_company_id THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'User does not belong to company';
  END IF;

  SET v_role_ids_csv = REPLACE(TRIM(COALESCE(p_role_ids_csv, '')), ' ', '');

  DELETE ur
  FROM user_role ur
  JOIN role r
    ON r.id_role = ur.id_role
  LEFT JOIN property pr
    ON pr.id_property = r.id_property
  WHERE ur.id_user = p_user_id
    AND (
      r.id_property IS NULL
      OR pr.id_company = v_company_id
    );

  IF v_role_ids_csv IS NOT NULL AND v_role_ids_csv <> '' THEN
    INSERT INTO user_role (
      id_user,
      id_role,
      notes,
      is_active,
      deleted_at,
      created_at,
      created_by,
      updated_at
    )
    SELECT
      p_user_id,
      r.id_role,
      NULL,
      1,
      NULL,
      NOW(),
      p_actor_user_id,
      NOW()
    FROM role r
    LEFT JOIN property pr
      ON pr.id_property = r.id_property
    WHERE r.deleted_at IS NULL
      AND r.is_active = 1
      AND (
        r.id_property IS NULL
        OR (
          pr.id_company = v_company_id
          AND pr.deleted_at IS NULL
        )
      )
      AND FIND_IN_SET(CAST(r.id_role AS CHAR), v_role_ids_csv) > 0;
  END IF;

  SELECT
    ur.id_user_role,
    ur.id_user,
    ur.id_role,
    r.name AS role_name,
    pr.code AS property_code
  FROM user_role ur
  JOIN role r
    ON r.id_role = ur.id_role
  LEFT JOIN property pr
    ON pr.id_property = r.id_property
  WHERE ur.id_user = p_user_id
    AND ur.deleted_at IS NULL
    AND ur.is_active = 1
    AND (
      r.id_property IS NULL
      OR (
        pr.id_company = v_company_id
        AND pr.deleted_at IS NULL
      )
    )
  ORDER BY r.name, pr.code;
END$$

