-- Structure for view `vw_room_busy_period`
--
DROP TABLE IF EXISTS `vw_room_busy_period`;

CREATE ALGORITHM=UNDEFINED DEFINER=`u508158532_rod`@`127.0.0.1` SQL SECURITY DEFINER VIEW `vw_room_busy_period`  AS SELECT 'reservation' AS `source_type`, `r`.`id_reservation` AS `source_id`, `r`.`id_property` AS `id_property`, `r`.`id_room` AS `id_room`, `r`.`check_in_date` AS `start_date`, `r`.`check_out_date` AS `end_date`, coalesce(nullif(`r`.`code`,''),concat('RSV-',`r`.`id_reservation`)) AS `title`, coalesce(`r`.`notes_internal`,`r`.`notes_guest`,'') AS `detail`, coalesce(`r`.`updated_at`,`r`.`created_at`,current_timestamp()) AS `last_modified` FROM `reservation` AS `r` WHERE `r`.`deleted_at` is null AND `r`.`is_active` = 1 AND coalesce(`r`.`status`,'confirmado') not in ('cancelada','cancelado','cancelled','canceled') AND `r`.`id_room` is not null AND `r`.`check_out_date` > `r`.`check_in_date`union all select 'room_block' AS `source_type`,`rb`.`id_room_block` AS `source_id`,`rb`.`id_property` AS `id_property`,`rb`.`id_room` AS `id_room`,`rb`.`start_date` AS `start_date`,`rb`.`end_date` AS `end_date`,coalesce(nullif(`rb`.`code`,''),concat('BLK-',`rb`.`id_room_block`)) AS `title`,coalesce(`rb`.`description`,'') AS `detail`,coalesce(`rb`.`updated_at`,`rb`.`created_at`,current_timestamp()) AS `last_modified` from `room_block` `rb` where `rb`.`deleted_at` is null and `rb`.`is_active` = 1 and `rb`.`end_date` > `rb`.`start_date`  ;

